// -----------------------------------------------------------------------
//  ISPackageInfo
// -----------------------------------------------------------------------
ISPackageInfo = function _ISPackageInfo() { };
ISPackageInfo.DefaultTimestamp = '20101001100000';
ISPackageInfo.PackageTimestamp = '20250331180926';
if (ISPackageInfo.PackageTimestamp.indexOf('%PackageTimestamp') == 0)
{
    ISPackageInfo.PackageTimestamp = ISPackageInfo.DefaultTimestamp;
}

// -----------------------------------------------------------------------
//  ISNamespace
// -----------------------------------------------------------------------
ISNamespace = function _ISNamespace(){}
ISNamespace.Register = function(name)
{
    var ns = ISDomAccessor.GetNamedObject(name);
    if (ns)
    {
        // already registerd
        return;
    }

    ISNamespace.RegisterInternal(name);
}
ISNamespace.RegisterInternal = function(name)
{
    var segmetns = name.split('.');

    // remove last (to be parent), then get last
    var lastName   = segmetns.splice(segmetns.length - 1, 1)[0];
    var parentName = segmetns.join('.');

    // try to get parent
    var ns = parentName ? ISDomAccessor.GetNamedObject(parentName) : null;
    if (!ns && parentName)
    {
        ISNamespace.RegisterInternal(parentName);
    }
    ISNamespace.Set(lastName, parentName);
}
ISNamespace.Set = function(name, parent)
{
    var expression = name + ' = new Function();'
    if (parent)
    {
        expression = parent + '.' + name + ' = new Function();'
    }

    eval(expression);
}


// -----------------------------------------------------------------------
//  ISScriptInfo
// -----------------------------------------------------------------------
ISScriptInfo = function _ISScriptInfo(path, type, loaded)
{
    this.Path = path;
    this.Extension = ISScriptInfo.GetExtension(path);
    this.Type = type;
    this.Loaded = loaded == true ? true : false;
}
ISScriptInfo.GetExtension = function(path)
{
    var extension = '';
    if (path.lastIndexOf('?') != -1)
    {
        var pathWithoutExtension = path.substring(0, path.indexOf('?'));
        extension = pathWithoutExtension.substring(path.lastIndexOf('.'));
    }
    else
    {
        extension = path.substring(path.lastIndexOf('.'));
    }

    return extension;
}
ISScriptInfo.prototype = {
    Path: '',
    Extension: '',
    Type: null,
    Loaded: false
}


// -----------------------------------------------------------------------
//  ISScript
// -----------------------------------------------------------------------
ISScript = function _ISScript() { }
ISScript.LoadingMethodType = { Sequential : 'Sequential',
                               Parallel   : 'Parallel' };
ISScript.LoadingMethod = ISScript.LoadingMethodType.Sequential;
ISScript.UseJQuery = false;
ISScript.DenyDuplicatedLoading = true;
ISScript.LoadedScripts = [];
ISScript.Load = function(path, typeName, callback)
{
    // initialize script info to load
    var infos = new Array();
    if (typeof (path) == 'string')
    {
        var info = new ISScriptInfo(path, typeName);
        infos.push(info);
    }
    else if (path instanceof Array)
    {
        for (var i = 0; i < path.length; i++)
        {
            var scriptPath = path[i];
            var scriptType = null;
            if (typeName instanceof Array)
            {
                scriptType = typeName[i];
            }

            var info = new ISScriptInfo(scriptPath, scriptType);
            infos.push(info);
        }
    }

    // initialize context
    var context = { Index : 0,
                    Infos : infos,
                    Begin : new Date() };

    ISScript.LoadScripts(context, callback);
}
ISScript.LoadScripts = function(context, callback)
{
    // load scripts
    if (ISScript.LoadingMethod == ISScript.LoadingMethodType.Sequential)
    {
        var info = context.Infos[context.Index];
        ISScript.LoadScript(info.Path, info.Type, function()
        {
            context.Index++;
            if (context.Index >= context.Infos.length)
            {
                callback();
            }
            else
            {
                ISScript.LoadScripts(context, callback);
            }
        });
    }
    else
    {
        for (var i = 0; i < context.Infos.length; i++)
        {
            var info = context.Infos[i];
            ISScript.LoadScript(info.Path, info.Type, function()
            {
                context.Index++;
                if (context.Index >= context.Infos.length)
                {
                    callback();
                }
            });
        }
    }
}
ISScript.LoadScript = function(path, typeName, callback)
{
    // check loaded by type and path
    if (ISDomAccessor.GetNamedObject(typeName) || // type
        (ISScript.DenyDuplicatedLoading && ISScript.IsLoadedScript(path))) // path
    {
        if (callback)
        {
            callback();
        }

        return;
    }

    // set unique key
    if (path.indexOf('?') != -1 &&
        path.toUpperCase().indexOf('&rev='.toUpperCase()) != -1) { path += '&rev=' + ISPackageInfo.PackageTimestamp; }
    else                                                         { path += '?rev=' + ISPackageInfo.PackageTimestamp; }

    // load script
    if (ISScript.UseJQuery)
    {
        ISScript.LoadedScripts.push(new ISScriptInfo(path, typeName));
        ISTrace.TraceVerbose('Script begin load: ' + path);
        $.getScript(path, function()
        {
            ISTrace.TraceVerbose('Script Loaded: ' + path);
            callback();
        });
    }
    else
    {
        // check file extension; then load js or css file
        var extension = ISScriptInfo.GetExtension(path);
        if (extension.toUpperCase() == '.JS')
        {
            // create script element to load script
            var element = document.createElement('script');
            element.type = 'text/javascript';

            // append the script element to the page
            var target = document.getElementsByTagName('script')[0];
            target.parentNode.insertBefore(element, target);

            // register callback
            if (callback)
            {
                ISScript.RegisterNotifyOnLoadFunction(element, new ISScriptInfo(path, typeName), callback);
            }

            // load script
            ISTrace.TraceVerbose('Script begin load: ' + path);
            element.src = path;
        }
        else if (extension.toUpperCase() == '.CSS')
        {
            // create link element to load style sheet
            var element = document.createElement('link');
            element.rel = 'stylesheet';
            element.type = 'text/css';

            // append the link element to the page
            var head = document.getElementsByTagName("head")[0];
            head.appendChild(element);

            // register callback
            if (callback)
            {
                ISScript.RegisterNotifyOnLoadFunction(element, new ISScriptInfo(path, typeName), callback);
            }

            // load script
            ISTrace.TraceVerbose('StyleSeet begin load: ' + path);
            element.href = path;
        }
    }
}
ISScript.RegisterNotifyOnLoadFunction = function(element, info, handler)
{
    ISScript.LoadedScripts.push(info);

    // reference
    // http://msdn.microsoft.com/ja-jp/library/ie/hh180173(v=vs.85).aspx

    if (element &&
        element.addEventListener)
    {
        ISDomAccessor.AttachEvent(element, 'load', function ()
        {
            ISTrace.TraceVerbose('Script Loaded: ' + element.src);
            if (!info.Loaded)
            {
                info.Loaded = true;
                handler();
            }
        });
    }
    else
    {
        ISDomAccessor.AttachEvent(element, 'readystatechange', function ()
        {
            if (ISBrowser.IsIE() && ISBrowser.GetDocumentVersion() <= 8 &&
                ISString.EndsWith(info.Extension, 'js')  && (element.readyState == 'loaded' || element.readyState == 'complete') ||
                ISString.EndsWith(info.Extension, 'js')  &&  element.readyState == 'loaded' ||
                ISString.EndsWith(info.Extension, 'css') &&  element.readyState == 'complete')
            {
                var path = element.src;
                if (ISString.EndsWith(info.Extension, 'css'))
                {
                    path = element.href;
                }

                // when ie8, skkip completed event, then wait loaded event comes up.
                if (ISBrowser.IsIE() && ISBrowser.GetDocumentVersion() <= 8 &&
                    ISString.EndsWith(info.Extension, 'js') && element.readyState == 'complete')
                {
                    ISScript.CallAfterScriptLoaded(info, handler);
                    return;
                }

                ISTrace.TraceVerbose('Script Loaded: ' + path);
                if (!info.Loaded)
                {
                    info.Loaded = true;
                    handler();
                }
            }
        });
    }
}
ISScript.CallAfterScriptLoaded = function(info, handler)
{
    if (info.Type)
    {
        if (!info.Loaded && ISScript.IsTypeLoaded(info.Type))
        {
            info.Loaded = true;
            handler();
        }
        else
        {
            setTimeout(function()
            {
                ISScript.CallAfterScriptLoaded(info, handler);
            }, 256);
        }
    }
    else
    {
        // jast wait 1sec, it has not type name.
        setTimeout(function()
        {
            if (!info.Loaded)
            {
                info.Loaded = true;
                handler();
            }
        }, 1024);
    }
}
ISScript.IsTypeLoaded = function(typeName)
{
    var loaded = false;
    try
    {
        loaded = typeof(eval(typeName)) != 'undefined';
    }
    catch(e){}

    return loaded;
}
ISScript.IsLoadedScript = function(path)
{
    var loaded = false;
    var info = ISScript.GetScriptInfo(path);
    if (info)
    {
        loaded = info.Loaded;
    }

    return loaded;
}
ISScript.GetScriptInfo = function(path)
{
    var info = null;
    for (var i = 0; i < ISScript.LoadedScripts.length; i++)
    {
        var script = ISScript.LoadedScripts[i];
        if (script.Path.toUpperCase() == path.toUpperCase())
        {
            info = script;
            break;
        }
    }

    return info;
}

// -----------------------------------------------------------------------
//  ISStyleSheet
// -----------------------------------------------------------------------
ISStyleSheet = function _ISStyleSheet() { }
ISStyleSheet.Load = function(path)
{
    if (typeof(path) == 'string')
    {
        ISStyleSheet.LoadInternal(path);
    }
    else if (path instanceof Array)
    {
        for (var i = 0; i < path.length; i++)
        {
            ISStyleSheet.LoadInternal(path[i]);
        }
    }
}
ISStyleSheet.LoadInternal = function(path)
{
    var link = document.createElement("link");
    link.rel  = 'stylesheet';
    link.type = 'text/css';
    link.href = path;

    var head = document.getElementsByTagName("head")[0];
    head.appendChild(link);
}


// -----------------------------------------------------------------------
//  ISWindow
// -----------------------------------------------------------------------
ISWindow = function _ISWindow(){}
ISWindow.GetWindow = function(name, url)
{
    // reference
    // http://blog.ikemasa.com/2010/04/javascript-window/

    // try to get window
    var wnd = null;
    try
    {
        wnd = window.open('', name);
    }
    catch (e) {}

    // open window
    if (!wnd && url)
    {
        wnd = window.open(url, name);
    }

    return wnd;
}
ISWindow.GetCurrentDirectoryUrl = function()
{
    var url = window.location.href;
    url = url.substring(0, url.lastIndexOf('/'));

    return url;
}


// -----------------------------------------------------------------------
//  ISDomAccessor
// -----------------------------------------------------------------------
ISDomAccessor = function _ISDomAccessor() { }
iDomAccessor = ISDomAccessor;

// -----------------------------------------------------------------------
//  ISDomAccessor: Element Handling
// -----------------------------------------------------------------------
ISDomAccessor.NodeType = { Element:      1,
                           Text:         3,
                           CDATASection: 4,
                           Comment:      8 };
ISDomAccessor.GetElement = function(target, parent)
{
    // fix parent
    var parentElement = ISDomAccessor.GetElementInternal(parent);
    if (!parentElement)
    {
        parentElement = document; 
    }
    
    // get target
    var targetElement = target;
    if (typeof(target) == 'string') 
    {
        targetElement = parentElement.getElementById(target);
    }

    return targetElement;
}
ISDomAccessor.GetElementInternal = function(target)
{
    var targetElement = target;
    if (typeof(target) == 'string') 
    {
        targetElement = document.getElementById(target);
    }

    return targetElement;
}
ISDomAccessor.GetParentElement = function(target)
{
    var targetElement = ISDomAccessor.GetElement(target);

    var parentElement = null;
    if (targetElement)
    {
        parentElement = targetElement.parentElement;
        if (!parentElement) 
        {
            // for FF case
            parentElement = targetElement.parentNode;
        }
    }

    return parentElement;
}
ISDomAccessor.GetChildElement = function(target) 
{
    var element = null;
    var childElements = ISDomAccessor.GetChildElements(target);
    if (childElements && childElements.length > 0)
    {
        element = childElements[0];
    }

    return element;
}
ISDomAccessor.GetChildElements = function(target) 
{
    var targetElement = ISDomAccessor.GetElement(target);

    var childElements = null;
    if (targetElement)
    {
        childElements = targetElement.childNodes;
        if (!childElements) 
        {
            childElements = targetElement.children;  
        }
    }

    return childElements;
}
ISDomAccessor.GetElementByTagName = function(tagName, parent)
{
    var element = null;
    var elements = ISDomAccessor.GetElementsByTagName(tagName, parent);
    if (elements && elements.length > 0)
    {
        element = elements[0];
    }

    return element;
}
ISDomAccessor.GetElementsByTagName = function(tagName, parent)
{
    // fix parent
    var parentElement = ISDomAccessor.GetElementInternal(parent);
    if (!parentElement)
    {
        parentElement = document; 
    }
    
    // get target
    var elements = parentElement.getElementsByTagName(tagName);

    return elements;
}
ISDomAccessor.GetNamedObject = function(name)
{
    if (!name)
    {
        return null;
    }

    var expression = 'function GetNamedObject()'
                   + '{'
                   +   'var obj = null;'
                   +   'try'
                   +   '{'
                   +     'obj = ' + name + ';'
                   +   '}'
                   +   'catch(e)'
                   +   '{'
                   +     'obj = null;'
                   +   '}'
                   +   'return obj;'
                   + '}';

    eval(expression);
    return GetNamedObject();
}

// 指定した比較関数に合致する祖先要素を返す
ISDomAccessor.FindAncestor = function (target, comparer)
{
    var parentElement = ISDomAccessor.GetParentElement(target);
    if (parentElement && !comparer(parentElement))
    {
        return ISDomAccessor.FindAncestor(parentElement, comparer);
    }
    else
    {
        return parentElement;
    }
}

ISDomAccessor.FindAncestorByTagName = function(target, tagName)
{
    var parentElement = ISDomAccessor.GetParentElement(target);
    if (parentElement &&
        typeof (parentElement.tagName) == 'string' &&
        parentElement.tagName.toUpperCase() != tagName.toUpperCase())
    {
        return ISDomAccessor.FindAncestorByTagName(parentElement, tagName);
    }
    else
    {
        return parentElement;
    }
}

ISDomAccessor.FindAncestorByClassName = function(target, name)
{
    if (name instanceof Array)
    {
        return ISDomAccessor.FindAncestorByClassNames(target, name);
    }

    var parentElement = ISDomAccessor.GetParentElement(target);
    if (parentElement &&
        typeof (parentElement.className) == 'string' &&
        parentElement.className.toUpperCase() != name.toUpperCase())
    {
        return ISDomAccessor.FindAncestorByClassName(parentElement, name);
    }
    else
    {
        return parentElement;
    }
}

ISDomAccessor.FindAncestorByClassNames = function(target, names)
{
    var parentElement = ISDomAccessor.GetParentElement(target);
    var match = false;
    if (parentElement &&
        typeof (parentElement.className) == 'string')
    {
        for(var i = 0; i < names.length; i++)
        {
            match = ISString.Contains(parentElement.className, names[i], true);
            if (!match)
            {
                break;
            } 
        }
    }

    if (!match)
    {
        return ISDomAccessor.FindAncestorByClassNames(parentElement, names);
    }
    else
    {
        return parentElement;
    }
}

ISDomAccessor.FindAncestorByContainsClassNames = function (target, name)
{
    if (name instanceof Array)
    {
        return ISDomAccessor.FindAncestorByClassNames(target, name);
    }

    var parentElement = ISDomAccessor.GetParentElement(target);
    if (parentElement &&
        typeof (parentElement.className) == 'string' &&
        ISString.Contains(parentElement.className, name, true))
    {
        return parentElement;
    }
    else
    {
        return ISDomAccessor.FindAncestorByContainsClassNames(parentElement, name); 
    }
}

ISDomAccessor.FindDescendantByTagName = function(target, tagName)
{
    var elements = ISDomAccessor.FindDescendantsByTagName(target, tagName);
    if (elements && elements.length > 0)
    {
        return elements[0];
    }

    return null;
}
ISDomAccessor.FindDescendantsByTagName = function(target, tagName)
{
    var elements = new Array();

    var childElements = ISDomAccessor.GetChildElements(target);
    if (!childElements)
    {
        return null;
    }

    for (var i = 0; i < childElements.length; i++) 
    {
        var childElement = childElements[i];
        if (childElement &&
            typeof(childElement.tagName) == 'string' &&
            childElement.tagName.toUpperCase() == tagName.toUpperCase())
        {
            elements.push(childElement);
        }

        var children = ISDomAccessor.FindDescendantsByTagName(childElement, tagName);
        if (children && children.length > 0)
        {
            elements = elements.concat(children);
        }
    }

    return elements;
}



// -----------------------------------------------------------------------
//  ISDomAccessor: Event Handling
// -----------------------------------------------------------------------
ISDomAccessor.AttachEvent = function(target, event, func)
{
    if (!target || !event || !func)
    {
        return;
    }

    var eventName = event.toLowerCase();

    if (target.attachEvent) 
    {
        target.attachEvent('on' + eventName, func);
    }
    else if (target.addEventListener) 
    {
        target.addEventListener(eventName, func, true);
    } 
    else 
    {
        target['on' + eventName] = func;
    }
}
ISDomAccessor.DetachEvent = function(target, event, func)
{
    if (!target || !event || !func)
    {
        return;
    }

    var eventName = event.toLowerCase();

    // GroupPicker : EntitySelectorに追加時のIngragisticsコードのエラー対応（暫定対応）
    if (target.detachEvent &&
        eventName != "resize")
    {
        target.detachEvent('on' + eventName, func);
    }
    else if (target.removeEventListener) 
    {
        target.removeEventListener(eventName, func, false);
    } 
    else 
    {
        target['on' + eventName] = null;
    }
}

// -----------------------------------------------------------------------
//  ISDomAccessor: Element Size Handling
// -----------------------------------------------------------------------
ISDomAccessor.SetPixel = function(element, property, value)
{
    // check element
    var element = ISDomAccessor.GetElement(element);
    if (!element)
    {
        return;
    }

    // check the value is number
    if (!isFinite(value))
    {
        return;
    }

    // set value
    var argName = ISFunction.GetArgumentNames(arguments.callee)[0];
    var expression = argName + '.' + property + ' = ' + value + ';'
                   + 'var valueSet = ' + argName + '.' + property + ';'
                   + 'if (!valueSet || ISString.EndsWith(valueSet, "px") || ISString.EndsWith(valueSet, "%"))'
                   + '{'
                   +     argName + '.' + property + ' = ' + value + ' + "px";'
                   + '}';
    eval(expression);
}
ISDomAccessor.GetPixel = function(element, property)
{
    // check element
    var element = ISDomAccessor.GetElement(element);
    if (!element)
    {
        return 0;
    }

    var argName = ISFunction.GetArgumentNames(arguments.callee)[0];
    return ISNumber.Parse(eval(argName + '.' + property));
}
ISDomAccessor.GetWidth = function(element)
{
    var width = 0;
    if (element.tagName.toLowerCase() == 'body')
    {
        width = document.documentElement.clientWidth;
    }
    else
    {
        width = element.clientWidth;
    }

    return width;
}
ISDomAccessor.SetWidth = function(element, width)
{
    if (width < 0)
    {
        width = 0;
    }

    ISDomAccessor.SetPixel(element, 'style.width', width);
}
ISDomAccessor.GetHeight = function(element)
{
    var height = 0;
    if (element.tagName.toLowerCase() == 'body')
    {
        height = document.documentElement.clientHeight;
    }
    else
    {
        height = element.clientHeight;
    }

    return height;
}
ISDomAccessor.SetHeight = function(element, height)
{
    if (height < 0)
    {
        height = 0;
    }

    ISDomAccessor.SetPixel(element, 'style.height', height);
}

ISDomAccessor.GetOuterHeight = function(element)
{
    // マージンを計算
    var stryle = null;
    if (document.defaultView)
    {
        style = document.defaultView.getComputedStyle(element, null);
    }
    else
    {
        style = element.currentStyle;
    }

    var margin = 0;
    if (style.marginTop != "auto")
    {
        margin += ISNumber.Parse(ISString.TrimEnd(style.marginTop, 'px'));
    }
    if (style.marginBottom != "auto")
    {
        margin += ISNumber.Parse(ISString.TrimEnd(style.marginBottom, 'px'));
    }

    // offsetHeight (padding, border含む)にmarginを足す
    var height = element.offsetHeight
               + margin;

    return height;
}
ISDomAccessor.GetInnerHeight = function(element)
{
    // マージンを計算
    var stryle = null;
    if (document.defaultView)
    {
        style = document.defaultView.getComputedStyle(element, null);
    }
    else
    {
        style = element.currentStyle;
    }

    var padding = 0;
    if (style.paddingTop != "auto")
    {
        padding += ISNumber.Parse(ISString.TrimEnd(style.paddingTop, 'px'));
    }
    if (style.paddingBottom != "auto")
    {
        padding += ISNumber.Parse(ISString.TrimEnd(style.paddingBottom, 'px'));
    }

    // clientHeight (padding含む)からpaddingを引く
    var height = element.clientHeight
               - padding;

    return height;
}
ISDomAccessor.GetOuterWidth = function(element)
{
    // マージンを計算
    var stryle = null;
    if (document.defaultView)
    {
        style = document.defaultView.getComputedStyle(element, null);
    }
    else
    {
        style = element.currentStyle;
    }

    var margin = 0;
    if (style.marginLeft != "auto")
    {
        margin += ISNumber.Parse(ISString.TrimEnd(style.marginLeft, 'px'));
    }
    if (style.marginRight != "auto")
    {
        margin += ISNumber.Parse(ISString.TrimEnd(style.marginRight, 'px'));
    }

    // offsetWidth (padding, border含む)にmarginを足す
    var width = element.offsetWidth
              + margin;

    return width;
}
ISDomAccessor.GetInnerWidth = function(element)
{
    // マージンを計算
    var stryle = null;
    if (document.defaultView)
    {
        style = document.defaultView.getComputedStyle(element, null);
    }
    else
    {
        style = element.currentStyle;
    }

    var padding = 0;
    if (style.paddingLeft != "auto")
    {
        padding += ISNumber.Parse(ISString.TrimEnd(style.paddingLeft, 'px'));
    }
    if (style.paddingRight != "auto")
    {
        padding += ISNumber.Parse(ISString.TrimEnd(style.paddingRight, 'px'));
    }

    // overflow設定が有効な場合、clientWidthが正確な値を返さないため対応が必要
    var clientWidth = element.clientWidth;
    if (style.overflow == 'auto' && 
        style.width != "auto")
    {
        clientWidth = ISNumber.Parse(ISString.TrimEnd(style.width, 'px'));
    }

    // clientWidth (padding含む)からpaddingを引く
    var width = clientWidth - padding;

    return width;
}

ISDomAccessor.GetTextWidth = function (text, parent)
{
    // 親要素を確定
    var parentElement = parent;
    if (!parentElement)
    {
        parentElement = document.body;
    }

    // 計測用の要素を準備
    var element = document.createElement('span');
    element.style.visibility = 'hidden';
    element.style.position   = 'absolute';
    element.style.whiteSpace = 'nowrap';
    element.innerHTML        = text;

    // 計測
    var width = 0;
    parentElement.appendChild(element);
    width = element.offsetWidth;
    parentElement.removeChild(element);

    return width;
}

// -----------------------------------------------------------------------
//  ISStopwatch
// -----------------------------------------------------------------------
ISStopwatch = function _ISStopwatch(){}
ISStopwatch.prototype = {
    StartTime: null,
    StopTime: null,
    Running: false,

    Start: function()
    {
        if (this.Running)
        {
            return;
        }

        this.Running = true;
        this.StartTime = new Date();
        this.StopTime = null;
    },

    Stop: function()
    {
        if (!this.Running)
        {
            return;
        }

        this.StopTime = new Date();
        this.Running = false;

        return this.GetInterval();        
    },

    GetInterval: function()
    {
        var interval = 0;
        if (this.Running)
        {
            interval = new Date() - this.StartTime;
        }
        else if (this.StartTime && this.StopTime)
        {
            interval = this.StopTime - this.StartTime;
        }

        return interval;
    }
}


// -----------------------------------------------------------------------
//  ISTestResult
// -----------------------------------------------------------------------
ISTestResult = function _ISTestResult(succeeded, description, error)
{
    this.Succeeded   = succeeded == true ? true : false;
    this.Description = description ? description : '';
    this.Error       = error ? error : null;
}
ISTestResult.TypeName = 'ISTestResult';
ISTestResult.prototype = {
    TypeName: ISTestResult.TypeName,
    Succeeded: false,
    Description: '',
    Error: null
}


// -----------------------------------------------------------------------
//  ISTestRunner
// -----------------------------------------------------------------------
ISTestRunner = function _ISTestRunner(){}
ISTestRunner.Tests = [];
ISTestRunner.Scripts = [];
ISTestRunner.Results = [];
ISTestRunner.Run = function(callback, context)
{
    if (!context)
    {
        context = { Index : 0,
                    Begin : new Date() };

        ISTestRunner.Results = [];
        ISTestTrace.TraceInformation('[START] ISTestRunner::Run');
    }

    var name = ISTestRunner.Tests[context.Index];
    ISTestRunner.RunTest(name, function()
    {
        context.Index++;

        if (ISTestRunner.Tests.length > context.Index)
        {
            ISTestRunner.Run(callback, context);
        }
        else
        {
            // count succeeded
            var succeededCount = 0;
            for (var i = 0; i < ISTestRunner.Results.length; i++)
            {
                var result = ISTestRunner.Results[i];
                if (result.Succeeded)
                {
                    succeededCount++;
                }
            }

            // fix succeeded
            var succeeded = succeededCount == ISTestRunner.Results.length;
            var succeededMessage = succeeded ? 'Succeeded' : 'Failed' ;

            // fix message
            var message = succeededCount + '/' + ISTestRunner.Results.length + ' tests completed.' + '<br />'
                        + 'Spent ' + ((new Date()) - context.Begin) + ' ms.';

            // log
            if (succeeded)
            {
                ISTestTrace.TraceInformationGreen('[END] ISTestRunner::Run', succeededMessage, message);
            }
            else
            {
                ISTestTrace.TraceError('[END] ISTestRunner::Run', succeededMessage, message);
            }
            callback();
        }
    });
}
ISTestRunner.RunTest = function(testName, callback)
{
    var begin = new Date();
    ISTestTrace.TraceInformationBlue('[TEST START] ' + testName);

    ISTestRunner.EnsureScripts(function()
    {
        // find test
        var test = ISTestRunner.GetTest(testName);
        if (!test)
        {
            ISTestTrace.TraceError(testName, '', 'Test not found');
            callback();
            return;
        }

        // retrieve method names
        var methodNames = new Array();
        for (var methodName in test)
        {
            methodNames.push(methodName);
        }

        // initialize context
        var context = { TestName        : testName,
                        TestMethodNames : methodNames,
                        Index           : 0,
                        Begin           : begin };

        // initialize test, then run it
        test.Initialize(function()
        {
            ISTestRunner.RunTestInternal(callback, context);
        });
    });
}
ISTestRunner.RunTestInternal = function(callback, context)
{
    // retrieve test method
    var methodName = context.TestMethodNames[context.Index];
    var testMethod = ISTestRunner.GetTestMethod(context.TestName, methodName);

    // increment count
    context.Index++;
    if (context.TestMethodNames.length < context.Index)
    {
        ISTestTrace.TraceInformationBlue('[TEST END] ' + context.TestName, '', 'Spent: ' + ((new Date()) - context.Begin) + ' ms');
        callback();
        return;
    }

    // only run test method
    if (!testMethod ||
        methodName.toUpperCase().indexOf('TEST') != 0)
    {
        ISTestRunner.RunTestInternal(callback, context);
        return;
    }

    // invoke test method, then write result
    try
    {
        testMethod(function(result)
        {
            ISTestRunner.Results.push(result);
            ISTestRunner.LogResult(result, context.TestName, methodName);
            ISTestRunner.RunTestInternal(callback, context);
        });
    }
    catch (e)
    {
        var result = new ISTestResult(false, '', e);
        ISTestRunner.Results.push(result);
        ISTestRunner.LogResult(result, context.TestName, methodName);
        ISTestRunner.RunTestInternal(callback, context);
    }
}
ISTestRunner.LogResult = function(result, testName, testMethodName)
{
    // fix succeeded
    var succeeded = result.Succeeded;

    // update result
    var resultMessage = succeeded ? 'Succeeded' : 'Failed';

    // update description
    var description = result.Description ? result.Description : '';
    if (result.Error)
    {
        description += '<br />'
                    + result.Error.name + '<br />'
                    + result.Error.message + '<br />'
                    + result.Error.stack;
    }

    // logging
    if (succeeded)
    {
        ISTestTrace.TraceInformation(testName + "::" + testMethodName, resultMessage, description);
    }
    else
    {
        ISTestTrace.TraceError(testName + "::" + testMethodName, resultMessage, description);
    }
}
ISTestRunner.EnsureScripts = function(callback)
{
    ISScript.Load(ISTestRunner.Scripts, '', callback);
}
ISTestRunner.GetTest = function(name)
{
    var expression = 'function GetTest()'
                    + '{'
                    +   'var test = null;'
                    +   'try'
                    +   '{'
                    +     'test = ' + name + ';'
                    +   '}'
                    +   'catch(e)'
                    +   '{'
                    +     'test = null;'
                    +   '}'
                    +   'return test;'
                    + '}';

    eval(expression);
    return GetTest();
}
ISTestRunner.GetTestMethod = function(className, methodName)
{
    var expression = 'function GetTestMethod()'
                    + '{'
                    +   'var method = ' + className + '.' + methodName + ';'
                    +   'return method;'
                    + '}';

    eval(expression);
    return GetTestMethod();
}
                   
