iType.GetType = function(obj)
{
    var type = iType.BuiltinType.Null;
    for (;;)
    {
        // check for null, undefined
        if (obj === null)                               { type = iType.BuiltinType.Null;      break; }
        if (typeof obj === iType.BuiltinType.Undefined) { type = iType.BuiltinType.Undefined; break; }

        // check for builtin types
        if (obj instanceof Array)  { type = iType.BuiltinType.Array;  break; }
        if (obj instanceof Date)   { type = iType.BuiltinType.Date;   break; }
        if (obj instanceof RegExp) { type = iType.BuiltinType.RegExp; break; }

        type = typeof obj;
        break;
    }

    return type;
}
iType.GetTypeName = function(obj)
{
    var typeName = null;
    if (obj && obj.TypeName)
    {
        typeName = obj.TypeName;
    }
    else
    {
        typeName = iType.GetType(obj);
    }

    return typeName;
}
                   
