iString.EndsWith = function(soutce, find, ignoreCase)
{
    if (!ignoreCase)
    {
        return soutce.lastIndexOf(find) >= 0 &&
               soutce.lastIndexOf(find) == soutce.length - find.length;
    }
    else
    {
        return soutce.toUpperCase().lastIndexOf(find.toUpperCase()) >= 0 &&
               soutce.toUpperCase().lastIndexOf(find.toUpperCase()) == soutce.length - find.length;
    }
}
