// -----------------------------------------------------------------------
//  String: trimmings
// -----------------------------------------------------------------------
iString.Trim = function(source, trim, ignoreCase)
{
    var trimmed = iString.TrimStart(source, trim, ignoreCase);
    trimmed = iString.TrimEnd(trimmed, trim, ignoreCase);

    return trimmed;
}
iString.TrimStart = function(source, trim, ignoreCase)
{
    if (iString.IsNullOrEmpty(trim))
    {
        trim = ' ';
    }

    var flag = 'g';
    if (ignoreCase)
    {
        flag = 'gi';
    }

    var trimmed = source;
    var escapeTrim = iString.GetEscapeValueForRegExp(trim);
    while (iString.StartsWith(trimmed, trim, ignoreCase))
    {
        trimmed = trimmed.replace(new RegExp('^' + escapeTrim, flag), '');
    }

    return trimmed;
}
iString.TrimEnd = function(source, trim, ignoreCase)
{
    if (iString.IsNullOrEmpty(trim))
    {
        trim = ' ';
    }

    var flag = 'g';
    if (ignoreCase)
    {
        flag = 'gi';
    }

    var trimmed = source;
    var escapeTrim = iString.GetEscapeValueForRegExp(trim);
    while (iString.EndsWith(trimmed, trim, ignoreCase))
    {
        trimmed = trimmed.replace(new RegExp(escapeTrim + '$', flag), '');
    }

    return trimmed;
}

iString.GetEscapeValueForRegExp = function(value)
{
    return value.replace(/[-\/\\^$*+?.()|[\]{}]/g, '\\$&');
}

// -----------------------------------------------------------------------
//  String: replaceings
// -----------------------------------------------------------------------
iString.Replace = function(source, stOld, stNew, ignoreCase)
{
    var flag = 'g';
    if (ignoreCase)
    {
        flag = 'gi';
    }    

    return source.replace(new RegExp(stOld, flag), stNew);
}

// -----------------------------------------------------------------------
//  String: sprittings
// -----------------------------------------------------------------------
iString.Split = function(source, paramsDelimiters)
{
    // process delimiters
    var delimiter = '';
    var delimiters = paramsDelimiters;
    if (!delimiters || delimiters.length < 1)
    {
        throw new Error('There is no arguments.');
    }
    else
    {
        delimiter = delimiters[0];

        if (delimiters.length > 1)
        {
            for (var i = 1; i < delimiters.length; i++)
            {
                source = iString.Replace(source, delimiters[i], delimiter);
            }
        }
    }

    // split
    var strings = source.split(delimiter);
    var results = new Array();
    for (var i = 0; i < strings.length; i++)
    {
        var string = strings[i];
        if (iString.IsNullOrEmpty(string))
        {
            continue;
        }

        results.push(string);
    }

    return results;
}

// -----------------------------------------------------------------------
//  String: surrogate handling
// -----------------------------------------------------------------------
iString.IsHighSurrogate = function(code)
{
    return 0xD800 <= code && code < 0xDC00;
}
iString.IsLowSurrogate = function(code)
{
    return 0xDC00 <= code && code <= 0xDFFF;
}
iString.IsSurrogatePair = function(st)
{
    // check length
    if (iString.IsNullOrEmpty(st) ||
        st.length != 2)
    {
        return false;
    }

    // check surrogate pair
    if (iString.IsHighSurrogate(st.charCodeAt(0)) &&
        iString.IsLowSurrogate(st.charCodeAt(1)))
    {
        return true;
    }

    return false
}
iString.ContainsSurrogatePair = function(st)
{
    for (var i = 0; i < st.length; i++)
    {
        var code = st.charCodeAt(i);
        if (!iString.IsHighSurrogate(code))
        {
            continue;
        }

        if (st.length > i + 1 &&
            !iString.IsLowSurrogate(st.charCodeAt(i + 1)))
        {
            continue;
        }

        return true;
    }

    return false;
}
                   
