    {
        format = 'yyyy-MM-ddTHH:mm:ss';
    }

    var text = iDate.Format(date, format, type);
    if (type == iDate.TimeZoneType.UTC)
    {
        text += 'Z';
    }
    else
    {
        text += iDate.ToISODateTimeTimezoneOffsetText(date, isoFormat);
    }

    return text;
