iArray.Contains = function (array, value, ignoreCase)
{
    var result = false;
    for (var i = 0; i < array.length; i++)
    {
        if (ignoreCase)
        {
            if (array[i].toUpperCase() === value.toUpperCase())
            {
                result = true;
                break;
            }
        }
        else
        {
            if (array[i] === value)
            {
                result = true;
                break;
            }
        }
    }

    return result;
}
