// -----------------------------------------------------------------------
//  Uri
// -----------------------------------------------------------------------
Infoshare.Uri = function Infoshare$Uri(uri)
{
    if (!iType.IsNullOrUndefined(uri))
    {
        var oUri = iUri.Parse(uri);
        iObject.Clone(oUri, this);
    }
}

ISUri = Infoshare.Uri;
iUri = Infoshare.Uri;
iUri.TypeName = 'Infoshare.Uri';

iUri.Parse = function (uri)
{
    var oUri = null;
    if      (iType.GetTypeName(uri) == iUri.TypeName) { oUri = uri; }
    else if (iType.GetTypeName(uri) == iType.BuiltinType.String &&
             !iString.IsNullOrEmpty(uri))
    {
        // RFC3986
        // https://www.ietf.org/rfc/rfc3986.txt

        // scheme
        // 最初のコロンの左側を抽出
        var scheme = null;
        if (iString.Contains(uri, ':'))
        {
            scheme = uri.substring(0, uri.indexOf(':'));
        }

        // authority
        // スキーム直後のコロン・スラッシュ（//まで）を除去し、スラッシュ、クエッション、ナンバーの何れかで終結、あるいは終端まで
        var authority = null;
        if (iString.Contains(uri, '//'))
        {
            authority = uri.substring(uri.indexOf('//') + '//'.length);
            if      (iString.Contains(authority, '/'))                                     { authority = authority.substring(0, authority.indexOf('/')); }
            else if (iString.Contains(authority, '?') && iString.Contains(authority, '#')) { authority = authority.substring(0, Math.min(authority.indexOf('?'), authority.indexOf('#'))); }
            else if (iString.Contains(authority, '?'))                                     { authority = authority.substring(0, authority.indexOf('?')); }
            else if (iString.Contains(authority, '#'))                                     { authority = authority.substring(0, authority.indexOf('#')); }
        }

        // host, port
        // authority をコロンで分割
        var host = null;
        var port = null;
        if (!iString.IsNullOrEmpty(authority))
        {
            if (iString.Contains(authority, ':'))
            {
                host = authority.substring(0, authority.indexOf(':'));
                port = authority.substring(authority.indexOf(':') + 1);
            }
            else
            {
                host = authority;
                post = 80;
            }
        }

        // path
        // オーソリティー以下、クエッション、ナンバーの何れかで終結、あるいは終端まで
        var path = null;
        if (!iString.IsNullOrEmpty(authority))
        {
            path = uri.substring(uri.indexOf(authority) + authority.length); // オーソリティまで除去 (http://host:port/page?k=v#var → /page?k=v#var)
        }
        else
        {
            path = uri.substring(uri.indexOf(':') + ':'.length); // スキーム除去 (scheme:foo/var?k=v#var → foo/var?k=v#var)
        }
        if      (iString.Contains(path, '?') && iString.Contains(path, '#')) { path = path.substring(0, Math.min(path.indexOf('?'), path.indexOf('#'))); }
        else if (iString.Contains(path, '?'))                                { path = path.substring(0, path.indexOf('?')); }
        else if (iString.Contains(path, '#'))                                { path = path.substring(0, path.indexOf('#')); }

        // query
        // クエッション以下、ナンバーで終結、あるいは終端まで
        var query = null;
        if (iString.Contains(uri, '?'))
        {
            query = uri.substring(uri.indexOf('?'));
            if (iString.Contains(query, '#'))
            {
                query = query.substring(0, query.indexOf('#'));
            }
        }

        // fragment
        // ナンバー以下、クエッションで終結、あるいは終端まで
        var fragment = null;
        if (iString.Contains(uri, '#'))
        {
            fragment = uri.substring(uri.indexOf('#'));
            if (iString.Contains(fragment, '?'))
            {
                fragment = fragment.substring(0, fragment.indexOf('?'));
            }
        }

        // origin
        // オーソリティまで
        var origin = null;
        if (!iString.IsNullOrEmpty(authority))
        {
            origin = uri.substring(0, uri.indexOf(authority) + authority.length); // オーソリティ配下を除去 (http://host:port/page?k=v#var → http://host:port/page)
        }

        // オブジェクト生成
        oUri = new iUri();
        oUri.OriginalString = uri;
        oUri.Scheme         = scheme;
        oUri.Authority      = authority;
        oUri.Host           = host;
        oUri.Port           = port;
        oUri.Path           = path;
        oUri.Query          = query;
        oUri.Fragment       = fragment;
        oUri.Origin         = origin;

        // WORKAROUND for iVxContext.EnsureUrls
        oUri.Segments = oUri.Path.split('/').slice(1);
    }

    return oUri;
};

iUri.IsSameOrigin = function (x, y)
{
    return iString.Equals(iUri.Parse(x).Origin, iUri.Parse(y).Origin, true);
}

iUri.Equals = function (x, y)
{
    return iString.Equals(iUri.Normalize(x), iUri.Normalize(y), true);
}

iUri.Normalize = function (uri)
{
    var uriText = ''
    if      (iType.GetTypeName(uri) == iUri.TypeName)            { uriText = iUri.OriginalString; }
    else if (iType.GetTypeName(uri) == iType.BuiltinType.String) { uriText = uri; }

    return iString.TrimEnd(encodeURI(decodeURI(uriText)), '/');
}

// ToDo(skomatsu): 既存実装の互換性維持のために実装を残す、必要性の検討が必要
iUri.GetAbsoluteUrl = function(relativeUrl)
{
    // 絶対パスが渡された場合
    var absoluteUrl = '';
    if (iString.StartsWith(relativeUrl, location.protocol, true))
    {
        absoluteUrl = relativeUrl;
    }
    else
    {
        absoluteUrl = location.protocol 
                    + '//'
                    + location.host;
        if (!iString.IsNullOrEmpty(relativeUrl))
        {
            absoluteUrl += '/'
                         + iString.TrimStart(relativeUrl, '/');
        }
    }

    return absoluteUrl;
}

// ToDo(skomatsu): 既存実装の互換性維持のために実装を残す、必要性の検討が必要
iUri.GetRelativeUrl = function(absoluteUrl)
{
    var relativeUrl = '';

    // 相対パスが渡された場合
    if (!iString.StartsWith(absoluteUrl, location.protocol, true))
    {
        relativeUrl = absoluteUrl;
    }
    else
    {
        // SharePointの関数を利用
        if (iType.GetType(GetServerRelativeUrlFromURL) == iType.BuiltinType.Function)
        {
            relativeUrl = GetServerRelativeUrlFromURL(absoluteUrl);
        }
        else
        {
            // ToDo: 実装
        }
    }

    // 相対Urlの表記
    // ルートサイト：/
    // サイト　　　：/sites/sitename
    relativeUrl = iString.TrimEnd(relativeUrl, '/');
    relativeUrl = "/" + iString.TrimStart(relativeUrl, '/');
    return relativeUrl;
}

iUri.Escape = function(uri)
{
    var uriText = ''
    if      (iType.GetTypeName(uri) == iUri.TypeName)            { uriText = iUri.OriginalString; }
    else if (iType.GetTypeName(uri) == iType.BuiltinType.String) { uriText = uri; }

    return encodeURI(uriText);
}

iUri.Unescape = function(uri)
{
    var uriText = ''
    if      (iType.GetTypeName(uri) == iUri.TypeName)            { uriText = iUri.OriginalString; }
    else if (iType.GetTypeName(uri) == iType.BuiltinType.String) { uriText = uri; }

    return decodeURI(uriText);
}

iUri.EscapeComponent = function(component, strict)
{
    // ToDo(skomatsu): 厳密な実装の確認と検証
    // https://developer.mozilla.org/ja/docs/Web/JavaScript/Reference/Global_Objects/encodeURIComponent
    var encoded = encodeURIComponent(component);
    if (strict)
    {
        encoded = encoded.replace(/[!'()*]/g, function (c)
        {
            return '%' + c.charCodeAt(0).toString(16);
        });
    }

    return encoded;
}

iUri.UnescapeComponent = function(component)
{
    var unescaped = decodeURIComponent(component);

    return unescaped;
}

iUri.prototype = {
    TypeName: iUri.TypeName,

    OriginalString: null,
    Scheme:         null,
    Authority:      null,
    Host:           null,
    Port:           null,
    Path:           null,
    Query:          null,
    Fragment:       null,

    Origin:         null
};


// -----------------------------------------------------------------------
//  UriParameter
// -----------------------------------------------------------------------
Infoshare.UriParameter = function Infoshare$UriParameter(parameter)
{
    if (!iType.IsNullOrUndefined(parameter))
    {
        var oParameter = iUriParameter.Parse(parameter);
        iObject.Clone(oParameter, this);
    }
    else
    {
        this.Parameters = new iDictionary();
    }
}

iUriParameter = Infoshare.UriParameter;
iUriParameter.TypeName = 'Infoshare.UriParameter';

iUriParameter.Parse = function(parameter)
{
    var oParameter = null;
    if      (iType.GetTypeName(parameter) == iUriParameter.TypeName) { oParameter = parameter; }
    else if (iType.GetTypeName(parameter) == iUri.TypeName)          { oParameter = iUriParameter.Parse(parameter.OriginalString); }
    else if (iType.GetTypeName(parameter) == iType.BuiltinType.String &&
             !iString.IsNullOrEmpty(parameter))
    {
        // クエッション以下を抽出、ナンバー以下を除去
        var parameterText = parameter;
        if (iString.Contains(parameterText, '?')) { parameterText = parameterText.substring(parameterText.indexOf('?') + '?'.length); }
        if (iString.Contains(parameterText, '#')) { parameterText = parameterText.substring(0, parameterText.indexOf('#')); }

        // パラメーターを分解して登録
        oParameter = new iUriParameter();
        var params = parameterText.split('&');
        for (var i = 0; i < params.length; i++)
        {
            var param = params[i];
            var name  = param.split('=')[0];
            var value = param.split('=')[1];

            if (iString.IsNullOrEmpty(name) ||
                iString.IsNullOrEmpty(value))
            {
                continue;
            }
            oParameter.Set(name, value);
        }
    }

    return oParameter;
}

iUriParameter.prototype = {
    TypeName: iUriParameter.TypeName,

    Parameters: null,

    Contains: function(name)
    {
        return this.Parameters.Contains(name);
    },

    Get: function(name)
    {
        return this.Parameters.Get(name);
    },

    Set: function(name, value)
    {
        this.Parameters.Set(name, value);
    },

    Remove: function(name)
    {
        this.Parameters.Remove(name);
    },

    ToString: function(withoutEscape)
    {
        var params = new Array();
        var keys = this.Parameters.GetKeys();
        for (var i = 0; i < keys.length; i++)
        {
            var name  = keys[i];
            var value = this.Parameters.Get(name);
            if (iString.IsNullOrEmpty(name) ||
                iString.IsNullOrEmpty(value))
            {
                continue;
            }
            if (!withoutEscape)
            {
                value = iUri.EscapeComponent(value);
            }

            params.push(name + '=' + value);
        }

        var parameter = '';
        if (params.length > 0)
        {
            parameter = params.join('&');
        }

        return parameter;
    }
};
                   
