ISFunction = Infoshare.Function;
iFunction = Infoshare.Function;
iFunction.TypeName = 'Infoshare.Function';

iFunction.GetArgumentNames = function (func)
{
    var sFunc      = func.toString();
    var sArguments = sFunc.substring(sFunc.indexOf('(') + 1, sFunc.indexOf(')'));
    var arguments  = sArguments.split(',');
    for (var i = 0; i < arguments.length; i++) 
    {
        arguments[i] = ISString.Trim(arguments[i]);
    }

    return arguments;
};

iFunction.GetArguments = function (argumentArray)
{
    if (!argumentArray ||
        argumentArray.length < 1)
    {
        throw new Error('There is no arguments.');
    }
    else if (typeof(argumentArray[0]) == 'object' && argumentArray[0].length >= 1) // array
    {
        // ToDo(skomatsu): okey to ignore other arguments?
        return argumentArray[0];
    }
    else
    {
        return argumentArray;
    }
};

iFunction.CreateDelegate = function (func, target)
{
    var delegate = function()
    {
        return func.apply(target, arguments);
    };

    delegate.func   = func;
    delegate.target = target;

    return delegate;
};
                   
