// -----------------------------------------------------------------------
//  JSON / stringify and parse for downlevel browser support
// -----------------------------------------------------------------------
Infoshare.JSON = function Infoshare$JSON() {}
ISJSON = Infoshare.JSON;
ISJSON.stringify = function(obj)
{
    if (JSON && JSON.stringify)
    {
        return JSON.stringify(obj);
    }

	var type = typeof (obj);
	if (type != 'object' || obj === null)
    {
		if (type == 'string')
        {
            obj = '"' + obj + '"';
        }

		return String(obj);
	}
	else
    {
        var json = new Array();
        var isArray = obj && obj.constructor == Array;
        for (var key in obj)
        {
            var value = obj[key];

            type = typeof(value);
            if (type == 'function')
            {
                continue;
            }
            else if (type == 'string')
            {
                value = '"' + value + '"';
            }
            else if (type == 'object' && value != null)
            {
                value = ISJSON.stringify(value);
            }

            json.push((isArray ? '' : '"' + key + '":') + String(value));
        }

        return (isArray ? '[' : '{') + String(json) + (isArray ? ']' : '}');
	}
}
ISJSON.parse = function(str)
{
    if (JSON && JSON.parse)
    {
        return JSON.parse(str);
    }

    if (str === '')
    {
        str = '""';
    }

    // Workaround to eval parse error by replacing break lines
//    if (str.contains('\n') || str.contains('\r'))
//    {
//        str = str.replaceAll('\n', '\\n');
//        str = str.replaceAll('\r', '\\r');
//    }

    // deserialize json
    eval('var o = ' + str + ';');

    return o;
}
                   
