// -----------------------------------------------------------------------
//  Event
// -----------------------------------------------------------------------
Infoshare.Event = function Infoshare$Event() { }
iEvent = Infoshare.Event;

iEvent.prototype = {
    Events: null,

    AddEvent: function(name, handler)
    {
        // イベントハンドラコレクションを初期化
        if (!this.Events)
        {
            this.Events = new ISDictionary();
        }

        // 該当するイベントハンドラを取得
        var handlers = null;
        if (this.Events.Contains(name))
        {
            handlers = this.Events.Get(name);

            // 取得したハンドラが関数だった場合は、配列に詰めなおす
            if (iObject.TypeOf(handlers) == 'function')
            {
                var newHandlers = new Array();
                newHandlers.push(handlers);
                this.Events.Set(name, newHandlers);

                handlers = newHandlers;
            }
        }
        else
        {
            handlers = new Array();
            this.Events.Set(name, handlers);
        }

        // イベントハンドラを追加
        handlers.push(handler);
    },

    RemoveEvent: function(name, handler)
    {
        // イベントハンドラコレクションを確認
        if (!this.Events)
        {
            return;
        }

        if (!handler)
        {
            // ハンドラ指定がない場合は、すべてのイベントを削除
            this.Events.Remove(name);
        }
        else
        {
            var removeHandlres = this.GetEventHandler(name, handler);

            var registerdHandlers = new Array();
            if (this.Events.Contains(name))
            {
                registerdHandlers = this.Events.Get(name);
            }

            // 複数指定されたハンドラから該当するものだけを削除
            var newHandlers = new Array();
            for (var i = 0; i < registerdHandlers.length; i++)
            {
                var registerdHandler = registerdHandlers[i];

                var remove = false;
                for (var j = 0; j < removeHandlres.length; j++)
                {
                    var removeHandler = removeHandlres[j];
                    if (registerdHandler == removeHandler)
                    {
                        remove = true;
                        break;
                    }
                }

                if (!remove)
                {
                    newHandlers.push(registerdHandler);
                }
            }

            this.Events.Set(name, newHandlers);
        }
    },

    HasEvent: function(eventHandler)
    {
        var hasEvent = false;
        for (;;)
        {
            // check function
            if (iObject.TypeOf(eventHandler) == 'function')
            {
                hasEvent = true;
                break;
            }

            // check array case
            if (iObject.TypeOf(eventHandler) == 'array' &&
                eventHandler.length > 0)
            {
                hasEvent = true;
                break;
            }

            break;
        }

        return hasEvent;
    },

    FireEvent: function(eventHandler, args)
    {
        // check
        if (!this.HasEvent(eventHandler))
        {
            return;
        }

        // fire
        if (iObject.TypeOf(eventHandler) == 'function')
        {
            eventHandler(args);
        }
        else
        {
            for (var i = 0; i < eventHandler.length; i++)
            {
                //eventHandler[i](args);

                if (args && args.length > 0)
                {
                    // argument または、配列をばらして引数に設定する
                    eventHandler[i].apply(null, args);
                }
                else
                {
                    eventHandler[i](args);
                }
            }
        }
    },

    FireEventByName: function(name, args)
    {
        var handler = this.GetEventHandler(name);

        this.FireEvent(handler, args);
    },

    GetEventNames: function()
    {
        var names = new Array();
        if (this.Events)
        {
            names = this.Events.GetKeys();
        }

        return names;
    },

    GetEventHandler: function(name, handler)
    {
        var foundHandlers = new Array();
        if (this.Events &&
            this.Events.Contains(name))
        {
            if (!handler)
            {
                // ハンドラ指定がない場合は、すべてのイベントを返す
                foundHandlers = this.Events.Get(name);
            }
            else
            {
                // ハンドラ指定がある場合は、該当するもののみをピックアップ
                var registerdHandlers = this.Events.Get(name);
                if (iObject.TypeOf(handler) == 'function')
                {
                    for (var i = 0; i < registerdHandlers.length; i++)
                    {
                        var registerdHandler = registerdHandlers[i];
                        if (registerdHandler == handler)
                        {
                            foundHandlers.push(registerdHandler);
                            break;
                        }
                    }
                }
                else if(iObject.TypeOf(handler) == 'array')
                {
                    // 複数指定されたハンドラから該当するものだけをピックアップ
                    for (var i = 0; i < registerdHandlers.length; i++)
                    {
                        var registerdHandler = registerdHandlers[i];
                        for (var j = 0; j < handler.length; j++)
                        {
                            var specifiedHandler = handler[j];
                            if (registerdHandler == specifiedHandler)
                            {
                                foundHandlers.push(registerdHandler);
                                break;
                            }
                        }
                    }
                }
            }
        }

        return foundHandlers;
    }
}
                     
