Infoshare.DictionaryEntry = function Infoshare$DictionaryEntry(key, value)
{
    this.SearchKey = key;
    if (key && typeof (key) == 'string')
    {
        this.SearchKey = key.toUpperCase();
    }

    this.Key   = key;
    this.Value = value;
}
iDictionaryEntry = Infoshare.DictionaryEntry;
ISDictionaryEntry = Infoshare.DictionaryEntry;
iDictionaryEntry.TypeName = 'Infoshare.DictionaryEntry';
iDictionaryEntry.prototype = {
    TypeName : iDictionaryEntry.TypeName,
    SearchKey: null,
    Key      : null,
    Value    : null
}


// -----------------------------------------------------------------------
//  Dictionary
// -----------------------------------------------------------------------
Infoshare.Dictionary = function Infoshare$Dictionary()
{
    this.NamedEntries   = new Array();
    this.IndexedEntries = new Array();
}
iDictionary = Infoshare.Dictionary;
ISDictionary = Infoshare.Dictionary;
iDictionary.TypeName = 'Infoshare.Dictionary';
iDictionary.prototype = {
    TypeName: iDictionary.TypeName,
    NamedEntries:   null,
    IndexedEntries: null,

    Add: function(key, value)
    {
        // check contains
        if (this.Contains(key))
        {
            throw new Error('Specified item (' + key + ') already exists.');
        }

        this.Set(key, value);
    },

    AddRange: function(values, keyFieldName)
    {
        // check array
        if (!values || values.length <= 0)
        {
            throw new Error('Specified array has no item.');
        }

        // fix key field name
        var keyFieldName = this.FixKeyFieldName(values[0], keyFieldName);

        // add array
        for (var i = 0; i < values.length; i++)
        {
            var value = values[i];
            var key   = value[keyFieldName];

            this.Add(key, value);
        }
    },

    Set: function(key, value)
    {
        var entry = this.GetEntry(key);
        if (entry)
        {
            entry.Value = value;            
        }
        else
        {
            // create item
            var entry = new iDictionaryEntry(key, value);

            this.NamedEntries[entry.SearchKey] = entry;
            this.IndexedEntries.push(entry);
        }
    },

    Get: function(key)
    {
        var value = null;
        var entry = this.GetEntry(key);
        if (entry && entry.Value)
        {
            value = entry.Value;
        }

        return value;
    },

    GetEntry: function(key)
    {
        var entry = null;
        if (typeof(key) == 'string')
        {
            key = key.toUpperCase();
            entry = this.NamedEntries[key];
        }
        else if (typeof(key) == 'number')
        {
            entry = this.IndexedEntries[key];
        }

        return entry;
    },

    Contains: function(key)
    {
        return this.GetEntry(key) ? true : false;
    },

    FindBy: function(key, fieldName)
    {
        var entries = new Array();
        for (var k in this.NamedEntries)
        {
            var entry = this.GetEntry(k);
            var findKey = entry.Value[fieldName];
            if (typeof (key)     == 'string' &&
                typeof (findKey) == 'string')
            {
                if (findKey.toUpperCase() == key.toUpperCase())
                {
                    entries.push(entry);
                }
            }
            else
            {
                if (findKey == key)
                {
                    entries.push(entry);
                }
            }
        }

        return entries;
    },

    ContainsBy: function(key, fieldName)
    {
        var entries = this.FindBy(key, fieldName);

        return entries && entries.length >= 1;
    },

    Remove: function(key)
    {
        var entry = this.GetEntry(key);
        if (!entry)
        {
            throw new Error('Cannot find item specified by the key "' + key + '".');
        }

        // remove named entry
        delete this.NamedEntries[entry.SearchKey];

        // remove indexed entry
        for (var i = 0; i < this.IndexedEntries.length; i++)
        {
            var idxEntry = this.IndexedEntries[i];
            if (idxEntry.SearchKey != entry.SearchKey)
            {
                continue;
            }

            this.IndexedEntries.splice(i, 1);
            break;
        }
    },
    
    Clear: function()
    {
        this.NamedEntries   = new Array();
        this.IndexedEntries = new Array();
    },

    GetKeys: function()
    {
        var keys = new Array();
        for (var key in this.NamedEntries)
        {
            var entry = this.GetEntry(key);
            if (entry && entry.TypeName == iDictionaryEntry.TypeName)
            {
                keys.push(entry.Key);
            }
        }

        return keys;
    },

    GetValues: function()
    {
        var values = new Array();
        for (var key in this.NamedEntries)
        {
            var value = this.NamedEntries[key].Value;
            values.push(value);
        }

        return values;
    },

    GetLength: function()
    {
        return this.IndexedEntries.length;
    },

    KeyFieldNameCandidates: [ 'Key', 'key', 'ID', 'Id', 'id' ],
    FixKeyFieldName: function(value, keyFieldName)
    {
        if (keyFieldName &&
            value[keyFieldName])
        {
            return keyFieldName;
        }

        // fix key field name from pre-set candidates
        for (var i = 0; i < this.KeyFieldNameCandidates.length; i++)
        {
            if (!value[this.KeyFieldNameCandidates[i]])
            {
                continue;
            }

            keyFieldName = this.KeyFieldNameCandidates[i];
            break;
        }

        // check 
        if (!keyFieldName)
        {
            throw 'Specified keyFieldName (' + keyFieldName + ') is invalid.';
        }

        return keyFieldName;
    }
}

                     
