// -----------------------------------------------------------------------
//  Register namespace
// -----------------------------------------------------------------------
ISNamespace.Register('Infoshare');


// -----------------------------------------------------------------------
//  AsyncInitializableExtender
// -----------------------------------------------------------------------
Infoshare.AsyncInitializableExtender = function Infoshare$AsyncInitializableExtender()
{
}
iAsyncInitializableExtender = Infoshare.AsyncInitializableExtender;
iAsyncInitializableExtender.TypeName = 'Infoshare.AsyncInitializableExtender';

iAsyncInitializableExtender.InitializeFunctionName = 'Initialize';
iAsyncInitializableExtender.InitializeStatus = { Uninitialized: 'Uninitialized',
                                                 Initializing:  'Initializing',
                                                 Initialized:   'Initialized' };
iAsyncInitializableExtender.InitializedEventName = iAsyncInitializableExtender.InitializeStatus.Initialized;

// 旧実装
// ToDo: いずれ新実装（インスタンスメンバの Extend）に置き換える
// 【制限事項】
// ・初期化関数の名称固定（Initialize）
// ・初期化関数の戻り値受け取り不可
iAsyncInitializableExtender.Extend = function(obj)
{
    // 複数回呼び出される可能性のある非同期初期化処理をスレッドセーフに実行できるように
    // 連携されたオブジェクトのInitialize関数を拡張する

    // 初期状態を見初期化に設定
    obj.initializeStatus = iAsyncInitializableExtender.InitializeStatus.Uninitialized;

    // 初期化関数をオーバーライド
    obj.originalInitialize = obj.Initialize;
    obj.Initialize = function(callback)
    {
        if (this.initializeStatus == iAsyncInitializableExtender.InitializeStatus.Uninitialized)
        {
            // 未初期化の場合: 初期化実行
            this.initializeStatus = iAsyncInitializableExtender.InitializeStatus.Initializing;
            this.registerFunctionToNotifyInitialized(callback);

            var ref = this;
            this.originalInitialize(function()
            {
                ref.notifyInitialized();
                ref.initializeStatus = iAsyncInitializableExtender.InitializeStatus.Initialized;
            });
        }
        else if (this.initializeStatus == iAsyncInitializableExtender.InitializeStatus.Initializing)
        {
            // 初期化中の場合: 初期化完了時に呼び出し元に処理を戻すように設定
            this.registerFunctionToNotifyInitialized(callback);
        }
        else if (this.initializeStatus == iAsyncInitializableExtender.InitializeStatus.Initialized)
        {
            // 初期化済みの場合: 呼び出し元に処理を戻す
            setTimeout(function ()
            {
                if (iType.GetType(callback) == iType.BuiltinType.Function)
                {
                    callback();
                }
                else
                {
                    ISTrace.TraceVerbose('[iAsyncInitializableExtender: Extend - Initialize] registered object was not a function.');
                }
            }, 1);
        }
    }

    obj.notifyInitialized = function()
    {
        // 初期化完了時に登録されている関数を順次呼び出す
        if (this.initializeEvents)
        {
            this.initializeEvents.FireEventByName(iAsyncInitializableExtender.InitializedEventName);
        }
    }

    obj.registerFunctionToNotifyInitialized = function(fn)
    {
        if (iType.GetType(fn) != iType.BuiltinType.Function)
        {
            ISTrace.TraceVerbose('[iAsyncInitializableExtender: registerFunctionToNotifyInitialized] registered object was not a function.');
            return;
        }

        if (iType.IsNullOrUndefined(this.initializeEvents))
        {
            this.initializeEvents = new iEvent();
        }

        // 初期化完了時のイベントに関数を登録
        this.initializeEvents.AddEvent(iAsyncInitializableExtender.InitializedEventName, fn);
    }
}

iAsyncInitializableExtender.prototype = {
    InitializeFunctionName: iAsyncInitializableExtender.InitializeFunctionName,

    Extend: function ()
    {
        // 複数回呼び出される可能性のある非同期初期化処理をスレッドセーフに実行できるように
        // 連携されたオブジェクトの初期化関数（規定値: Initialize）を拡張する

        // 拡張用のコンテキストを用意
        var context = { FunctionName: this.InitializeFunctionName,
                        OriginalFunctionName: 'original' + this.InitializeFunctionName,
                        Status: null,
                        Results: null,
                        Events: null,
                        NotifyInitialized: null,
                        RegisterEventListener: null };

        // 拡張用コンテキスト登録
        obj.initializableExtenderContext = context;

        // 初期状態を未初期化に設定
        context.Status = iAsyncInitializableExtender.InitializeStatus.Uninitialized;

        // 初期化完了通知
        context.NotifyInitialized = function ()
        {
            // 初期化完了時に登録されている関数を順次呼び出す
            if (this.Events)
            {
                // 初期化処理の引数とともに初期化完了を通知
                this.Events.FireEventByName(iAsyncInitializableExtender.InitializedEventName,
                                            this.Results);
            }
        }

        // 初期化完了イベント登録
        context.RegisterEventListener = function (listener)
        {
            if (iType.GetType(listener) != iType.BuiltinType.Function)
            {
                ISTrace.TraceVerbose('[iAsyncInitializableExtender: RegisterEventListener] registered object was not a function.');
                return;
            }

            if (iType.IsNullOrUndefined(this.Events))
            {
                this.Events = new iEvent();
            }

            // 初期化完了時のイベントに関数を登録
            this.Events.AddEvent(iAsyncInitializableExtender.InitializedEventName, listener);
        }

        // 初期化関数を別名で退避
        obj[context.OriginalFunctionName] = obj[context.FunctionName];

        // 初期化処理をオーバーライド
        obj[context.FunctionName] = function (callback)
        {
            if (this.initializableExtenderContext.Status == iAsyncInitializableExtender.InitializeStatus.Uninitialized)
            {
                // 未初期化の場合: 初期化実行
                this.initializableExtenderContext.Status = iAsyncInitializableExtender.InitializeStatus.Initializing;
                this.initializableExtenderContext.RegisterEventListener(callback);

                var ref = this;
                this[this.initializableExtenderContext.OriginalFunctionName](function ()
                {
                    // 初期化処理の引数をキャッシュ
                    ref.initializableExtenderContext.Results = arguments;

                    ref.initializableExtenderContext.NotifyInitialized();
                    ref.initializableExtenderContext.Status = iAsyncInitializableExtender.InitializeStatus.Initialized;
                });
            }
            else if (this.initializableExtenderContext.Status == iAsyncInitializableExtender.InitializeStatus.Initializing)
            {
                // 初期化中の場合: 初期化完了時に呼び出し元に処理を戻すように設定
                this.initializableExtenderContext.RegisterEventListener(callback);
            }
            else if (this.initializableExtenderContext.Status == iAsyncInitializableExtender.InitializeStatus.Initialized)
            {
                // 初期化済みの場合: 呼び出し元に処理を戻す
                setTimeout(function ()
                {
                    if (iType.GetType(callback) == iType.BuiltinType.Function)
                    {
                        callback();
                    }
                    else
                    {
                        ISTrace.TraceVerbose('[iAsyncInitializableExtender: Extend - Initialize] registered object was not a function.');
                    }
                }, 1);
            }
        }
    }
};
									
