Infoshare.License = function Infoshare$License(id, xml)
{
    this.Id  = id;
    this.Xml = xml;
    if (!iString.IsNullOrEmpty(this.Xml))
    {
        this.EnsureProperties();
    }
}
iLicense = Infoshare.License;
iLicense.TypeName = 'Infoshare.License';

iLicense.Type = { Invalid:      'Invalid',
                  Server:       'Server',
                  Perpetual:    'Perpetual',
                  Subscription: 'Subscription',
                  Evaluation:   'Evaluation',
                  Development:  'Development',
                  Internal:     'Internal' };

iLicense.Condition = { Invalid: 'Invalid',
                       Valid:    'Valid',
                       Caution:  'Caution',    // 注意:   有効期間 30日未満など
                       Warning:  'Warning',    // 警告:   有効期間 14日未満など
                       Error:    'Error',      // エラー: 超過 30日以内など
                       Critical: 'Critical' }; // 重大:   超過 30日以上など

iLicense.PropertyType = { String: 'String',
                          Date:   'Date',
                          Custom: 'Custom' };

iLicense.PropertyDefinitions = { Key:             { Name: 'Key',             Type: iLicense.PropertyType.String },
                                 Valid:           { Name: 'Valid',           Type: iLicense.PropertyType.Custom },
                                 Condition:       { Name: 'Condition',       Type: iLicense.PropertyType.Custom },
                                 ValidationDate:  { Name: 'ValidationDate',  Type: iLicense.PropertyType.Date },
                                 ExpirationDate:  { Name: 'ExpirationDate',  Type: iLicense.PropertyType.Date },
                                 IssueDate:       { Name: 'IssueDate',       Type: iLicense.PropertyType.Date },
                                 Publisher:       { Name: 'Publisher',       Type: iLicense.PropertyType.String },
                                 Type:            { Name: 'Type',            Type: iLicense.PropertyType.Custom },
                                 Platform:        { Name: 'Platform',        Type: iLicense.PropertyType.Custom },
                                 FarmServerCount: { Name: 'FarmServerCount', Type: iLicense.PropertyType.Custom },
                                 FarmServerNames: { Name: 'FarmServerNames', Type: iLicense.PropertyType.Custom },
                                 SeatCount:       { Name: 'SeatCount',       Type: iLicense.PropertyType.Custom },
                                 TenantNames:     { Name: 'TenantNames',     Type: iLicense.PropertyType.Custom },
                                 ProductName:     { Name: 'ProductName',     Type: iLicense.PropertyType.String },
                                 ProductVersion:  { Name: 'ProductVersion',  Type: iLicense.PropertyType.String },
                                 UserName:        { Name: 'UserName',        Type: iLicense.PropertyType.String },
                                 Remarks:         { Name: 'Remarks',         Type: iLicense.PropertyType.String } };

iLicense.LicenseKeyPrefix = 'Infoshare.ProductLicense';
iLicense.GroupPickerKey                    = iLicense.LicenseKeyPrefix + '.GroupPicker';
iLicense.InfoCallKey                       = iLicense.LicenseKeyPrefix + '.InfoCall';
iLicense.InfoCallOrganizationManagementKey = iLicense.LicenseKeyPrefix + '.InfoCallOrganizationManagement';
iLicense.InfoCallSmartphoneViewKey         = iLicense.LicenseKeyPrefix + '.InfoCallSmartphoneView';
iLicense.InfoCallOutlookVSTOAddInKey       = iLicense.LicenseKeyPrefix + '.InfoCallOutlookVSTOAddIn';
iLicense.InfoCallMemberSearchKey           = iLicense.LicenseKeyPrefix + '.InfoCallMemberSearch';
iLicense.Keys = [ iLicense.GroupPickerKey,
                  iLicense.InfoCallKey,
                  iLicense.InfoCallOrganizationManagementKey,
                  iLicense.InfoCallSmartphoneViewKey,
                  iLicense.InfoCallOutlookVSTOAddInKey,
                  iLicense.InfoCallMemberSearchKey ];

iLicense.GracePeriod = 30;

iLicense.IsPerpetualType = function (type)
{
    return iString.Equals(type, iLicense.Type.Server, true) ||
           iString.Equals(type, iLicense.Type.Perpetual, true);
}

iLicense.IsOperationalType = function (type)
{
    return iString.Equals(type, iLicense.Type.Server, true) ||
           iString.Equals(type, iLicense.Type.Perpetual, true) ||
           iString.Equals(type, iLicense.Type.Subscription, true);
}

iLicense.GetTypeDisplayName = function (type)
{
    var displayName = iResxResource.GetString('License.TypeDisplayName.' + type);
    if (!displayName)
    {
        displayName = iResxResource.GetString('License.TypeDisplayName.Invalid');
    }

    return displayName;
}

iLicense.GetStatusDisplayName = function (valid)
{
    var resourceKey = valid ? 'License.StatusDisplayName.Valid'
                            : 'License.StatusDisplayName.InValid';

    var displayName = iResxResource.GetString(resourceKey);
    return displayName;
}

iLicense.GetPlatformDisplayName = function (platform)
{
    var displayName = iResxResource.GetString('License.PlatformDisplayName.' + platform);
    if (iString.IsNullOrEmpty(platform))
    {
        displayName = '';
    }

    return displayName;
}

iLicense.GetPropertyDisplayName = function (name)
{
    return iResxResource.GetString(iString.Format('License.DisplayName.{0}', name));
}

iLicense.prototype = {
    TypeName: iLicense.TypeName,

    Id:  null,
    Xml: null,

    Valid:         false,
    Violating:     false,
    RemainingDays: 0,

    Properties: { Id:                null,
                  Condition:         null,
                  AssignedSeatCount: null,
                  ValidationDate:    null,

                  // ライセンスファイル設定情報
                  IssueDate:       null,
                  Publisher:       null,
                  IsBypassType:    null,
                  Type:            null,
                  Platform:        null,
                  Category:        null,
                  Key:             null,
                  ExpirationDate:  null,
                  FarmServerCount: null,
                  FarmServerNames: null,
                  SeatCount:       null,
                  TenantNames:     null,
                  ProductName:     null,
                  ProductVersion:  null,
                  UserName:        null,
                  Remarks:         null,

                  // ライセンス状態情報
                  Valid:                      false,
                  RemainingDays:              0,
                  RemainingDaysForValidation: 0 },

    // XML情報からオブジェクトのプロパティを設定
    EnsureProperties: function ()
    {
        var xmlDocument = iXml.LoadXml(this.Xml);
        var infoElement = iXml.SelectNodeByPath(xmlDocument.documentElement, 'Info');
        var attributes = iXml.GetAttributesByArray(infoElement , null);        
        this.Properties = attributes;

        // それぞれのプロパティの設定
        // -----------------------------------------------------------------------
        //  RemainingDays
        //  CurrentDateとExpirationDateを比較して、ライセンスの残り期限を設定する
        // -----------------------------------------------------------------------
        // 旧スキーマの暫定対応
        // ToDo: 同期ツール側のスキーマ更新

        // クライアント・サーバーの時間差を計算
        // ToDo: SharePoint 依存(_spPageContextInfo)をどうするか検討
        // _spPageContextInfoを自作した場合、clientServerTimeDeltaが設定されていなくてもundefinedにならないようにする
        var clientServerTimeDelta = 0;
        if (typeof _spPageContextInfo != 'undefined' && typeof _spPageContextInfo.clientServerTimeDelta != 'undefined')
        {
            clientServerTimeDelta = _spPageContextInfo.clientServerTimeDelta;
        }

        // Condition
        this.Condition = this.Properties.Condition;

        // RemainingDays
        this.Properties.RemainingDays = 0;
        if (!iLicense.IsPerpetualType(this.Properties.Type) &&
            !iString.IsNullOrEmpty(this.Properties.ExpirationDate))
        {
            // ExpirationDateは文字列として記録されているためDateオブジェクトに変換
            var expirationDate = new Date(this.Properties.ExpirationDate);

            // ExpirationDateは、（当日中有効だが）当日午前零時を指しているため、1日加算して時間計算を行う
            iDate.AddDays(expirationDate, 1);

            // 現在の時間をサーバー時間から取得する
            var currentDate = new Date((new Date()).getTime() + clientServerTimeDelta);

            // 少数点切り上げした残り日数を設定する（1000ミリ秒 * 60秒 * 60分 * 24時間）
            var remainingDateTime = expirationDate.getTime() - currentDate.getTime();
            var remainingDays = Math.ceil(remainingDateTime / (1000 * 60 * 60 * 24));
            if (remainingDays <= 0)
            {
                // 残日数が負の場合（超過）、失効当日を超過1日目とカウントするため1日減算する
                remainingDays -= 1;
            }
            this.Properties.RemainingDays = remainingDays
        }

        // RemainingDays for Validation
        this.Properties.RemainingDaysForValidation = 0;
        if (!iString.IsNullOrEmpty(this.Properties.ValidationDate))
        {
            // ValidationDateは文字列として記録されているためDateオブジェクトに変換
            var validationDate = new Date(this.Properties.ValidationDate);

            // 現在の時間をサーバー時間から取得する
            var currentDate = new Date((new Date()).getTime() + clientServerTimeDelta);

            // 少数点切り上げした残り日数を設定する（1000ミリ秒 * 60秒 * 60分 * 24時間）
            var validationDateTime = validationDate.getTime() - currentDate.getTime();
            this.Properties.RemainingDaysForValidation = Math.ceil(validationDateTime / (1000 * 60 * 60 * 24));
        }

        // ライセンス情報参照用プロパティ
        this.RemainingDays              = this.Properties.RemainingDays;
        this.RemainingDaysForValidation = this.Properties.RemainingDaysForValidation;

        this.Valid = this.Properties.Condition == iLicense.Condition.Valid ||
                     this.Properties.Condition == iLicense.Condition.Caution ||
                     this.Properties.Condition == iLicense.Condition.Warning ||
                     this.Properties.Condition == iLicense.Condition.Error;

        // 違反状態の設定
        if (this.Properties.Condition == iLicense.Condition.Error)
        {
            this.Violating = true;
        }

        // 期限に関する判断
        for (;;)
        {
            // 有効期限の判断
            if (!iLicense.IsPerpetualType(this.Properties.Type))
            {
                if (iLicense.IsOperationalType(this.Properties.Type))
                {
                    // 運用ライセンスの場合は、猶予期間を考慮（失効後30日間）
                    if (this.RemainingDays <= 0 && this.RemainingDays >= -1 * iLicense.GracePeriod)
                    {
                        this.Valid     = true;
                        this.Violating = true;

                        // 猶予期間判断がOKでも、後続の検証期限が切れている場合があるため、
                        // breakせず、後続の検証期限の判断も行う
                        //break;
                    }
                    else if (this.RemainingDays < -1 * iLicense.GracePeriod)
                    {
                        this.Valid     = false;
                        this.Violating = true;
                        break;
                    }
                }
                else
                {
                    // 非運用ライセンスの場合は、失効とともに無効
                    if (this.RemainingDays <= 0)
                    {
                        this.Valid = false;
                        break;
                    }
                }
            }

            // ライセンス検証の期限が切れている場合は、無効
            // ただし、内部利用ライセンスの場合は再検証を要求しない
            if (this.Properties.Type != iLicense.Type.Internal &&
                this.RemainingDaysForValidation <= 0)
            {
                this.Valid = false;
                break;
            }

            break;
        }
    }
}
									
