// -----------------------------------------------------------------------
//  CustomActionBasedService
// -----------------------------------------------------------------------
Infoshare.CustomActionBasedService = function Infoshare$CustomActionBasedService() { }
iCustomActionBasedService = Infoshare.CustomActionBasedService;
iCustomActionBasedService.TypeName = 'Infoshare.CustomActionBasedService';

iCustomActionBasedService.prototype = {
    TypeName: iCustomActionBasedService.TypeName,

    GetActionsByTitlePrefix: function (url, titlePrefix, callback)
    {
        // 指定されたタイトルで始まる正規表現を生成し、カスタムアクションを取得する
        var expression = '^' + iString.GetEscapeValueForRegExp(titlePrefix);
        var flags      = 'gi';
        var regExpression = new RegExp(expression, flags);

        var service = new SRUserCustomActionsService(url, null, false);
        service.GetUserCustomActionsByTitle(regExpression, function (actions)
        {
            var rawData = new iDictionary();
            for (var i = 0; i < actions.length; i++)
            {
                var action = actions[i];

                // タイトルが重複する情報は破棄
                if (rawData.Contains(action.Title))
                {
                    var message = iString.Format("[iCustomActionBasedService.GetActionsByTitlePrefix] Duplicated action named {0} found. [Url: {1}]", action.Title, url);
                    ISTrace.TraceWarning(message);
                    continue;
                }

                // 説明が設定されていない情報は破棄
                if (iString.IsNullOrEmpty(action.Description))
                {
                    var message = iString.Format("[iCustomActionBasedService.GetActionsByTitlePrefix] The action detaile named {0} does not set. [Url: {1}]", action.Title, url);
                    ISTrace.TraceWarning(message);
                    continue;
                }

                rawData.Set(action.Title, action.Description);
            }

            if (rawData.GetLength() <= 0)
            {
                var message = iString.Format("[iCustomActionBasedService.GetActionsByTitlePrefix] Specified actions does not found. [Url: {0}, Title: {1}]", url, titlePrefix);
                ISTrace.TraceWarning(message);
            }

            if (iType.GetType(callback) == iType.BuiltinType.Function)
            {
                callback(rawData);
            }
        });
    }
};


// -----------------------------------------------------------------------
//  LicenseService
// -----------------------------------------------------------------------
Infoshare.LicenseService = function Infoshare$LicenseService() { }
iLicenseService = Infoshare.LicenseService;
iLicenseService.TypeName = 'Infoshare.LicenseService';

iLicenseService.instance = null;
iLicenseService.GetCurrent = function ()
{
    if (!iLicenseService.instance)
    {
        var instance = new iLicenseService();
        iLicenseService.instance = instance;
    }

    return iLicenseService.instance;
}

iLicenseService.prototype = {
    TypeName: iLicenseService.TypeName,

    AdminSiteUrl: null,

    GetLicenses: function(callback)
    {
        // クッキーに保持されるライセンス情報の確認
        var rawData = this.getRawDataFromCookie();
        if (rawData && rawData.GetLength() > 0)
        {
            // 有効なライセンスのみの場合は、そのまま返して初期化を終了
            var licenses = this.buildLicenses(rawData);
            if (!this.containsInvalidLicense(licenses))
            {
                if (iType.GetType(callback) == iType.BuiltinType.Function)
                {
                    setTimeout(function ()
                    {
                        callback(licenses);
                    }, 1);
                }
                return;
            }
        }

        // クッキーにライセンスが保持されていない場合は、カスタムアクションから取得
        var ref = this;
        this.getRawDataFromCustomAction(this.AdminSiteUrl, function (rawData)
        {
            var licenses = ref.buildLicenses(rawData);

            // クッキーに情報をキャッシュ
            ref.setRawDataToCookie(rawData);

            if (iType.GetType(callback) == iType.BuiltinType.Function)
            {
                callback(licenses);
            }
        });
    },

    buildLicenses: function(rawData)
    {
        var licenses = new iDictionary();
        var keys = rawData.GetKeys();
        for (var i = 0; i < keys.length; i++)
        {
            var key   = keys[i];
            var value = rawData.Get(key);
            var license = new iLicense(key, value);

            licenses.Set(license.Id, license);
        }

        return licenses;
    },

    containsInvalidLicense: function (licenses)
    {
        var contains = false;
        for (var i = 0; i < licenses.GetLength(); i++)
        {
            var license = licenses.Get(i);
            if (license.Valid === false)
            {
                contains = true;
                break;
            }
        }

        return contains;
    },

    getRawDataFromCookie: function()
    {
        var rawData = new iDictionary();
        for (var i = 0; i < iLicense.Keys.length ; i++)
        {
            var key   = iLicense.Keys[i];
            var value = iCookie.Get(key.toUpperCase());
            if (!iString.IsNullOrEmpty(value))
            {
                rawData.Set(key, value);
            }
        }

        return rawData;
    },

    setRawDataToCookie: function(rawData)
    {
        var keys = rawData.GetKeys();
        for (var i = 0; i < keys.length; i++)
        {
            var key   = keys[i];
            var value = rawData.Get(key);
            iCookie.Set(key.toUpperCase(), value, 1);
        }
    },

    SetCookieTextInfomations: function()
    {
        if (this.TextInfomations)
        {
            for (var i = 0; i < this.TextInfomations.GetLength(); i++)
            {
                var licenseTextInfo = this.TextInfomations.GetEntry(i);
                // クッキーにセット
                ISCookie.Set(licenseTextInfo.Key.toUpperCase(), licenseTextInfo.Value, 1);
            }
        }
    },

    getRawDataFromCustomAction: function(url, callback)
    {
        // 別サイトへのリクエストを実行するため、コンテキストキャッシュを削除
        ISSPContextWebInformation.Current = null;

        var service = new iCustomActionBasedService();
        service.GetActionsByTitlePrefix(url, iLicense.LicenseKeyPrefix, callback);
    }
};


// -----------------------------------------------------------------------
//  ProductService
// -----------------------------------------------------------------------
Infoshare.ProductService = function Infoshare$ProductService() { }
iProductService = Infoshare.ProductService;
iProductService.TypeName = 'Infoshare.ProductService';

iProductService.instance = null;
iProductService.GetCurrent = function ()
{
    if (!iProductService.instance)
    {
        var instance = new iProductService();
        iProductService.instance = instance;
    }

    return iProductService.instance;
}

iProductService.prototype = {
    TypeName: iProductService.TypeName,

    AdminSiteUrl: null,

    GetProducts: function(callback)
    {
        var ref = this;
        this.getRawDataFromCustomAction(this.AdminSiteUrl, function (rawData)
        {
            var products = ref.buildProducts(rawData);
            if (iType.GetType(callback) == iType.BuiltinType.Function)
            {
                callback(products);
            }
        });
    },

    buildProducts: function(rawData)
    {
        var products = new iDictionary();
        var keys = rawData.GetKeys();
        for (var i = 0; i < keys.length; i++)
        {
            var key   = keys[i];
            var value = rawData.Get(key);
            var product = new iProduct(key, value);

            products.Set(product.Id, product);
        }

        return products;
    },

    getRawDataFromCustomAction: function(url, callback)
    {
        // 別サイトへのリクエストを実行するため、コンテキストキャッシュを削除
        ISSPContextWebInformation.Current = null;

        var service = new iCustomActionBasedService();
        service.GetActionsByTitlePrefix(url, iProduct.ProductKeyPrefix, callback);
    }
};
									
