// -----------------------------------------------------------------------
//  LicenseValidator
// -----------------------------------------------------------------------
Infoshare.LicenseValidator = function Infoshare$LicenseValidator()
{
}
iLicenseValidator = Infoshare.LicenseValidator;
iLicenseValidator.TypeName = 'Infoshare.LicenseValidator';

iLicenseValidator.LicensedClassList = null;
iLicenseValidator.AddLicensedClassList = function (key, list)
{
    if (!iLicenseValidator.LicensedClassList)
    {
        iLicenseValidator.LicensedClassList = new iDictionary();
    }

    // 配列に成形
    if (iObject.TypeOf(list) == 'string')
    {
        list = [ list ];
    }

    // リストに追加
    if (iLicenseValidator.LicensedClassList.Contains(key))
    {
        var existingList = iLicenseValidator.LicensedClassList.Get(key);
        var updatedList = existingList.concat(list);

        iLicenseValidator.LicensedClassList.Set(key, updatedList);
    }
    else
    {
        iLicenseValidator.LicensedClassList.Add(key, list);
    }
}
iLicenseValidator.GetLicensedClassList = function (key)
{
    var list = new Array();
    if (iLicenseValidator.LicensedClassList && 
        iLicenseValidator.LicensedClassList.Contains(key))
    {
        list = iLicenseValidator.LicensedClassList.Get(key);
    }

    return list;
};

iLicenseValidator.prototype = {
    TypeName: iLicenseValidator.TypeName,

    Validate : function(licenseInfo, classInfo)
    {
        var valid = false;
        var licenses  = this.getLicenses(licenseInfo);
        var className = iClass.GetClassName(classInfo);
        for (var i = 0; i < licenses.length; i++)
        {
            var license = licenses[i];
            if (!license.Valid)
            {
                continue;
            }

            var classList = iLicenseValidator.GetLicensedClassList(license.Id);
            if (iArray.Contains(classList, className))
            {
                valid = true;
                break;
            }
        }

        return valid;
    },

    getLicenses: function(license)
    {
        var licenses = new Array();
        for (;;)
        {
            // Infoshare.Licenseの場合
            if (iObject.TypeOf(license) == iType.BuiltinType.Object &&
                iString.Equals(license.TypeName, iLicense.TypeName, true))
            {
                licenses.push(license);
                break;
            }

            // 配列の場合
            if (iObject.TypeOf(license) == iType.BuiltinType.Array)
            {
                licenses = license;
                break;
            }

            // ディクショナリの場合
            if (iObject.TypeOf(license) == iType.BuiltinType.Object &&
                iString.Equals(license.TypeName, iDictionary.TypeName, true))
            {
                licenses = license.GetValues();
                break;
            }

            break;
        }

        return licenses;
    }
}
                                   
