// -----------------------------------------------------------------------
//  Register namespace
// -----------------------------------------------------------------------
ISNamespace.Register('Infoshare');


// -----------------------------------------------------------------------
//  LicenseMessage
// -----------------------------------------------------------------------
Infoshare.LicenseMessage = function Infoshare$LicenseMessage()
{
    this.MessageDisplayTime = iLicenseMessage.DefaultMessageDisplayTime;
}
iLicenseMessage = Infoshare.LicenseMessage;
iLicenseMessage.TypeName = 'Infoshare.LicenseMessage';
iLicenseMessage.DefaultMessageDisplayTime = 5000;

iLicenseMessage.prototype = {
    TypeName: iLicenseMessage.TypeName,
    MessageDisplayTime: iLicenseMessage.DefaultMessageDisplayTime,

    BuildMessage : function(license, typeName)
    {
        // ToDo(skomatsu): getLicenses 関数の配置先を検討
        var licenses = (new iLicenseValidator()).getLicenses(license);
        if (licenses.length <= 0)
        {
            // ライセンスが取得できない場合は、無効判定させるため null を詰める
            licenses.push(null);
        }

        // ToDo(skomatsu): 程度の重いメッセージを優先して出力するか検討
        var message = '';
        for (var i = 0; i < licenses.length; i++)
        {
            var license = licenses[i];
            for (;;)
            {
                // 無効メッセージ
                if (!license || !license.Valid)
                {
                    message = iResxResource.GetString('License.InvalidMessage');
                    break;
                }

                // 違反メッセージ
                if (license && license.Valid && license.Violating)
                {
                    message = iResxResource.GetString('License.ViolatingMessage');
                    break;
                }

                // 警告メッセージ（ライセンス期限切れ）
                if (license && license.Valid &&
                    license.Properties.Type != iLicense.Type.Perpetual &&
                    license.RemainingDays < 15)
                {
                    message = iString.Format(iResxResource.GetString('License.ExpiringMessageFormat'), license.RemainingDays);
                    break;
                }

                // 警告メッセージ（ライセンス再検証）
                if (license && license.Valid &&
                    license.RemainingDaysForValidation < 8)
                {
                    message = iString.Format(iResxResource.GetString('License.NeedReVerificationMessageFormat'), license.RemainingDaysForValidation);
                    break;
                }

                break;
            }

            if (!iString.IsNullOrEmpty(message))
            {
                break;
            }
        }

        // 利用可能な機能かどうかを確認
        if (!iString.IsNullOrEmpty(typeName) &&
            iString.IsNullOrEmpty(message))
        {
            if (!(new iLicenseValidator()).Validate(GPContext.Licenses, GPNavigation.TypeName))
            {
                message = iString.Format(iResxResource.GetString('License.CannotUserFeatureMessage'));
            }
        }

        return message;
    }
}
                                   
									
                                         
