// -----------------------------------------------------------------------
//  Register namespace
// -----------------------------------------------------------------------
ISNamespace.Register('Infoshare.Text');


// -----------------------------------------------------------------------
//  Xml
// -----------------------------------------------------------------------
Infoshare.Text.Xml = function Infoshare$Text$Xml() { }
iXml = Infoshare.Text.Xml;
iXml.Escape = function(xml)
{
    if (!xml || xml.length <= 0)
    {
        return '';
    }

    if (typeof (xml) != 'string')
    {
        return xml;
    }

    var escaped = '';
    for (var i = 0; i < xml.length; i++)
    {
        var c = xml.charAt(i);
        switch (c)
        {
            case '&'  : c = '&amp;';  break;
            case '<'  : c = '&lt;';   break;
            case '>'  : c = '&gt;';   break;
            case '"'  : c = '&quot;'; break;
            case '\'' : c = '&apos;'; break;

            // ToDo(skomatsu): バッククォートの必要性を確認
            //case '`'  : c = '&#x60;'; break;
        }

        escaped += c;
    }

    return escaped;
}
iXml.Unescape = function(xml)
{
    var unescaped = xml;

    unescaped = ISString.Replace(unescaped, '&lt;',   '<',  true);
    unescaped = ISString.Replace(unescaped, '&gt;',   '>',  true);
    unescaped = ISString.Replace(unescaped, '&quot;', '"',  true);
    unescaped = ISString.Replace(unescaped, '&apos;', '\'', true);
    unescaped = ISString.Replace(unescaped, '&amp;',  '&',  true);

    return unescaped;
}
iXml.LoadXml = function(xml)
{
    var doc = null;

    if (!window.XPathEvaluator)
    {
        var doc = null;
        try
        {
            // for IE6 upper
            doc = new ActiveXObject('Msxml2.DOMDocument');
        }
        catch (e)
        {
            try
            {
                // for IE5.5
                doc = new ActiveXObject('Microsoft.XMLDOM');
            }
            catch (e)
            {
                // 
                try
                {
                    document = new ActiveXObject('Msxml2.DOMDocument60');
                }
                catch(e)
                {
                }
            }
        }

        if (doc)
        {
            doc.async = false;
            doc.loadXML(xml);
        }
        else
        {
            var dom = new DOMParser();
            doc = dom.parseFromString(xml, "application/xml");
        }
    }
    else
    {
        // for FF, Safari, etc...
        var dom = new DOMParser();
        doc = dom.parseFromString(xml, "application/xml");
    }

    return doc;
}
iXml.GetOwnerDocument = function (element)
{
    var document = null;
    if (element && element.ownerDocument)
    {
        document = element.ownerDocument;
    }
    else if (element && element.documentElement)
    {
        document = element.documentElement.ownerDocument;
    }

    return document;
}
iXml.GetDocumentElement = function (element)
{
    var document = iXml.GetOwnerDocument(element);
    var element = document.documentElement;

    return element;
}
iXml.GetOuterXml = function(element)
{
    var xml = '';
    if (element.xml)
    {
        xml = element.xml;
    }
    else
    {
        xml = element.outerHTML;
    }

    return xml;
}
iXml.GetInnerXml = function(element)
{
    var xml = iXml.GetOuterXml(element);
    xml = xml.substring(iString.IndexOf(xml, '>') + 1);
    xml = xml.substring(0, iString.LastIndexOf(xml, '<'));

    return xml;
}

iXml.SelectSingleNode = function (element, xpath, namespaces)
{
    var node = null;
    if (!window.XPathEvaluator) // for IE
    {
        // evaluate namespaces
        if (!ISString.IsNullOrEmpty(namespaces))
        {
            var doc = element;
            if (element.noteTypeString == 'document')
            {
                doc = element.ownerDocument;
            }

            // reference: 
            // http://support.microsoft.com/kb/294797
            // http://www.nczonline.net/blog/2009/04/04/xpath-in-javascript-part-3/
            doc.setProperty("SelectionLanguage", "XPath");
            doc.setProperty("SelectionNamespaces", namespaces);
        }

        node = element.selectSingleNode(xpath);
    }
    else // for FF, Safari, etc...
    {
        // ToDo(skomatsu): need namespace support
        var evaluator = new XPathEvaluator();
        var result = evaluator.evaluate(xpath, element, null, XPathResult.FIRST_ORDERED_NODE_TYPE, null);
        if (result)
        {
            node = result.singleNodeValue;
        }
    }

    return node;
}
iXml.SelectNodeByPath = function(element, path)
{
    var names = path.split('/');
    var target = element;
    for (var i = 0; i < names.length; i++)
    {
        var name = names[i];

        // get child by name
        var foundNode = null;
        for (var j = 0; j < target.childNodes.length; j++)
        {
            var childNode = target.childNodes[j];
            if (childNode.nodeName == name ||
                childNode.localName == name)
            {
                foundNode = childNode;
                break;
            }
        }

        target = foundNode;
        if (!target)
        {
            break;
        }
    }

    return target;
}

iXml.GetChildElement = function(element, comparer)
{
    var elements = iXml.GetChildElements(element, comparer);
    if (elements && elements.length >= 1)
    {
        return elements[0];
    }

    return null;
}
iXml.GetChildElements = function(element, comparer)
{
    var elements = new Array();
    for (var i = 0; i < element.childNodes.length; i++)
    {
        var childNode = element.childNodes[i];
        if (comparer && !comparer(childNode))
        {
            // 指定条件以外除外
            continue;
        }

        elements.push(childNode);
    }

    return elements;
}
iXml.GetChildElementByName = function(element, name)
{
    return iXml.GetChildElement(element, function (childElement)
           {
               return iString.Equals(childElement.nodeName, name, true);
           });
}
iXml.GetChildElementsByName = function(element, name)
{
    return iXml.GetChildElements(element, function (childElement)
           {
                return iString.Equals(childElement.nodeName, name, true);
           });
}
iXml.GetChildElementsByArray = function(element, needlessNamePrefix)
{
    var elements = new Array();
    for (var i = 0; i < element.childNodes.length; i++)
    {
        var childNode = element.childNodes[i];
        var key   = childNode.nodeName;
        var value = childNode.text ? childNode.text
                                   : childNode.textContent;

        if (needlessNamePrefix)
        {
            key = key.replace(needlessNamePrefix, '');
        }

        elements[key] = value;
    }

    return elements;
}
iXml.GetElementByTagName = function(element, name)
{
    var foundElement = null;
    for (;;)
    {
        if (!element)
        {
            break;
        }

        var elements = element.getElementsByTagName(name);
        if (!elements)
        {
            break;
        }

        var foundElement = elements[0];

        break;
    }

    return foundElement;
}

iXml.GetAttributeValue = function (element, names)
{
    // 指定された名前の順番で値の取得を試みる
    var attributeNames = names;
    if (iObject.TypeOf(names) == 'string')
    {
        attributeNames = [names];
    }

    var value = null;
    for (var i = 0; i < attributeNames.length; i++)
    {
        var attributeName = attributeNames[i];
        var attribute = element.attributes.getNamedItem(attributeName);
        if (attribute)
        {
            value = attribute.value;
            break;
        }
    }

    return value;
}
iXml.SetAttributeValue = function(element, names, value)
{
    // 指定された名前の順番で値の設定を試みる
    var attributeNames = names;
    if (iObject.TypeOf(names) == 'string')
    {
        attributeNames = [names];
    }

    for (var i = 0; i < attributeNames.length; i++)
    {
        var attributeName = attributeNames[i];
        var attribute = element.attributes.getNamedItem(attributeName);
        if (attribute)
        {
            attribute.value = value;
            break;
        }
    }
}
iXml.GetAttributesByArray = function(element, needlessNamePrefix)
{
    var attributes = new Array();
    for (var i = 0; i < element.attributes.length; i++)
    {
        var attribute = element.attributes[i];
        var key   = attribute.name;
        var value = attribute.value;
        if (needlessNamePrefix)
        {
            key = key.replace(needlessNamePrefix, '');
        }

        attributes[key] = value;
    }

    return attributes;
}




// -----------------------------------------------------------------------
//  XmlSerializer
// -----------------------------------------------------------------------
Infoshare.Text.XmlSerializer = function Infoshare$Text$XmlSerializer() { }
iXmlSerializer = Infoshare.Text.XmlSerializer;
iXmlSerializer.Serialize = function (obj)
{
    var text = '';
    var type = iXmlSerializer.GetSerializeObjectType(obj);
    if (type == 'object' || type == 'array')
    {
        text = "<data name='root' type='" + type + "'>"
             + iXmlSerializer.SerializeInternal(obj)
             + "</data>";
    }
    else
    {
        text = String(obj);
    }

    return text;
}
iXmlSerializer.SerializeInternal = function (obj)
{
    // objectの型を判定
    var objType = iXmlSerializer.GetSerializeObjectType(obj);

    // 各属性値を処理して文字列に変換
    var xml = new Array();
    for (var key in obj)
    {
        var value = obj[key];

        // valueの型を判定
        var type = iXmlSerializer.GetSerializeObjectType(value);

        // valueの型によって文字列への変換処理を分岐
        // function: 処理をスキップ
        // string: 文字列のエスケープ
        // object/array: 再帰処理
        if (type == 'function')
        {
            continue;
        }
        else if (type == 'string')
        {
            value = iXml.Escape(value);
        }
        else if ((type == 'object' || type == 'array') && value != null)
        {
            value = iXmlSerializer.SerializeInternal(value);
        }

        // objectの型によって、メンバー（value）の出力内容を分岐
        // <value name='name' type='type'>value</value>
        // <value index='name' type='type'>value</value>
        if (objType == 'array') { xml.push("<data index='" + key + "' type='" + type + "'>" + value + "</data>"); }
        else                    { xml.push("<data name='"  + key + "' type='" + type + "'>" + value + "</data>"); }
    }

    return xml.join('');
}
iXmlSerializer.Deserialize = function (element)
{
    if (typeof (element) == 'string')
    {
        element = iXml.LoadXml(element);
    }
    var root = iXml.GetDocumentElement(element);

    var json = null;
    var type = iXml.GetAttributeValue(root, 'type');
    if      (type == 'object') { json = '{' + iXmlSerializer.DeserializeInternal(root) + '}'; }
    else if (type == 'array')  { json = '[' + iXmlSerializer.DeserializeInternal(root) + ']'; }

    return ISJSON.parse(json);
}
iXmlSerializer.DeserializeInternal = function (element)
{
    var json = new Array();
    var objType = iXml.GetAttributeValue(element, 'type');
    for (var i = 0; i < element.childNodes.length; i++)
    {
        var propertyElement = element.childNodes[i];

        var property = '';
        var name = iXml.GetAttributeValue(propertyElement, 'name');
        var type = iXml.GetAttributeValue(propertyElement, 'type');
        if      (type == 'object') { property = '{' + iXmlSerializer.DeserializeInternal(propertyElement) + '}'; }
        else if (type == 'array')  { property = '[' + iXmlSerializer.DeserializeInternal(propertyElement) + ']'; }
        else if (type == 'string') { property = '"' + propertyElement.text + '"'; }
        else                       { property = propertyElement.text; }
        if (objType != 'array')
        {
            property = '"' + name + '":' + property;
        }

        json.push(property);
    }

    return json.join(',');
}
iXmlSerializer.GetSerializeObjectType = function (obj)
{
    var type = typeof (obj);
    if (obj && obj.constructor == Array)
    {
        type = 'array';
    }

    return type
}
        
