// -----------------------------------------------------------------------
//  HyperTextConverter
// -----------------------------------------------------------------------
Infoshare.Text.HyperTextConverter = function Infoshare$Text$HyperTextConverter(){}
ISHyperTextConverter = Infoshare.Text.HyperTextConverter;
ISHyperTextConverter.Expressions = [ { Name: 'Url',       Expression: new RegExp('(https?|ftp):\/\/[-_.!~*\'()a-zA-Z0-9;\/?:\@&=+\$,%#]+', 'ig'), Format: "<a href='{0}'>{0}</a>" },
                                     { Name: 'Mail',      Expression: new RegExp('(([A-Za-z0-9!#%&`_=\\/$\'*+?^{}|~.-])+@([A-Za-z0-9!#%&`_=\\\\/$\'*+?^{}|~.-])+)', 'ig'), Format: "<a href='mailto:{0}'>{0}</a>" },
                                     { Name: 'BreakLine', Expression: new RegExp('[\n]', 'g'), Format: "<br />" },
                                     { Name: 'BreakLine', Expression: /\\n/g, Format: "<br />" } ]
ISHyperTextConverter.prototype = {
    EnableUrlLink:   true,
    EnableMailLink:  true,
    EnableBreakLine: true,

    Convert: function(source)
    {
        var markup = source;
        for (var i = 0; i < HyperTextConverter.Expressions.length; i++)
        {
            var expression = HyperTextConverter.Expressions[i];
            if (!this.EnableUrlLink   && expression.Name == 'Url')       { continue; }
            if (!this.EnableMailLink  && expression.Name == 'Mail')      { continue; }
            if (!this.EnableBreakLine && expression.Name == 'BreakLine') { continue; }

            markup = this.ConvertInternal(markup, expression.Expression, expression.Format);
        }

        return markup;
    },

    ConvertInternal: function(source, expression, format)
    {
        var markup = source;
        if (format.indexOf('{0}') > 0)
        {
            // find matches
            var candidates = new Array();
            while((matches = expression.exec(source)) != null)
            {
                candidates.push(matches[0]);
            }

            // sort by length
            candidates.sort(function(x, y)
            {
                if (x.length > y.length) { return -1; }
                if (x.length < y.length) { return 1; }
                return 0;
            });

            // exclude dup entry
            var matches = new Array();
            for (var i = 0; i < candidates.length; i++)
            {
                var candidate = candidates[i];
                if (matches.indexOf(candidate) >= 0)
                {
                    continue;
                }

                matches.push(candidate);
            }

            // replace to token
            var tokens = new Array();
            for(var i = 0; i < matches.length; i++)
            {
                var match = matches[i];
                var token = '%' + i + '%';
                tokens.push(token);
                markup = markup.replaceAll(match, token);           
            }

            // replace
            for(var i = 0; i < matches.length; i++)
            {
                var match = matches[i];
                var token = tokens[i];
                markup = markup.replaceAll(token, ISString.Format(format, match));           
            }
        }
        else
        {
            markup = markup.replace(expression, format);
        }

        return markup;
    }
}
        
