// -----------------------------------------------------------------------
//  CSV
// -----------------------------------------------------------------------
Infoshare.Text.CSV = function Infoshare$Text$CSV(){}
ISCSV = Infoshare.Text.CSV;
ISCSV.prototype = {
    Quotation:      '"',
    FieldSeparator: ',',
    RowSeparator:   ['\n', '\r', '\r\n'],
    
    Parse: function(source)
    {
        var rows  = new Array();
        var row   = new Array();
        var field = '';

        var parseInField = false;

        for (var i = 0; i < source.length; i++)
        {
            var c = source.charAt(i);

            // special case for \r\n
            if (!parseInField &&
                c == '\n' && i > 1 && source.charAt(i - 1))
            {
                continue;
            }

            if (!parseInField &&
                (c == this.FieldSeparator ||
                 this.IsRowSeparator(c)))
            {
                row.push(field);
                field = '';

                if (this.IsRowSeparator(c))
                {
                    rows.push(row);
                    row = new Array();
                }
            }
            else if (c == this.Quotation)
            {
                // begin quote
                if (!parseInField &&
                    ISString.IsNullOrEmpty(field))
                {
                    parseInField = true;
                }
                // end quote
                else if (source.length - 1 > i && // not last
                         (source.charAt(i + 1) == this.FieldSeparator ||
                          this.IsRowSeparator(source.charAt(i + 1))))
                {
                    parseInField = false;
                }
                // quote escape
                else if (i > 1 && // not fast
                         source.charAt(i - 1) == this.Quotation)
                {
                    field += c;
                }
            }
            else
            {
                field += c;
            }
        }
        if (!ISString.IsNullOrEmpty(field))
        {
            row.push(field);
            rows.push(row);
        }

        return rows;
    },

    IsRowSeparator: function(c)
    {
        var isSeparator = false;
        if (ISObject.TypeOf(this.RowSeparator) == 'array')
        {
            for (var i = 0; i < this.RowSeparator.length; i++)
            {
                if (c == this.RowSeparator[i])
                {
                    isSeparator = true;
                    break;
                }
            }
        }
        else
        {
            isSeparator = c == this.RowSeparator;
        }

        return isSeparator;
    }
}
        
