// -----------------------------------------------------------------------
//  StringSplitter
// -----------------------------------------------------------------------
Infoshare.Text.StringSplitter = function Infoshare$Text$StringSplitter() { }
iStringSplitter = Infoshare.Text.StringSplitter

iStringSplitter.prototype = {
    Separator: [' ', '\u3000'],
    Delimiter: ';#',

    Split: function(source)
    {
        var trimmed = this.TrimSeparator(source);
        if (ISString.IsNullOrEmpty(trimmed))
        {
            return null;
        }
            
        var splitted = this.SplitInternal(trimmed);

        return splitted;
    },

    IsDelimiterOnly: function(source)
    {
        var trimmed = this.TrimSeparator(keyword);
        if (ISString.IsNullOrEmpty(trimmed))
        {
            return false;
        }
            
        var isDelimiterOnly = true;
        var splitted = ISString.Split(trimmed, this.Separator)
        for (var i = 0; i < splitted.length; i++)
        {
            if (!ISString.IsNullOrEmpty(splitted[i]) && 
                !ISString.Contains(this.Delimiter, splitted[i]))
            {
                isDelimiterOnly = false;
                break;
            }
        }

        return isDelimiterOnly;
    },

    TrimSeparator: function(source)
    {
        var trimmed = source;
        if (ISString.IsNullOrEmpty(source))
        {
            trimmed = '';
        }
        else if (typeof(this.Separator) == 'string')
        {
            trimmed = ISString.Trim(trimmed, this.Separator);
        }
        else if (this.Separator instanceof Array &&
                 this.Separator.length == 1)
        {
            trimmed = ISString.Trim(trimmed, this.Separator[0]);
        }
        else if (this.Separator instanceof Array &&
                 this.Separator.length > 1)
        {
            var primarySeparator = this.Separator[0];
            for (var i = 1; i < this.Separator.length; i++)
            {
                trimmed = ISString.Replace(trimmed, this.Separator[i], primarySeparator);
            }

            trimmed = ISString.Trim(trimmed, primarySeparator);
        }

        return trimmed;
    },

    SplitInternal: function(source)
    {
        var processeds = new Array();
        var splitted = ISString.Split(source, this.Separator);
        for (var i = 0; i < splitted.length; i++)
        {
            var processed = this.ProcessDelimiter(splitted[i]);
            if (ISString.IsNullOrEmpty(processed))
            {
                continue;
            }

            processeds.push(processed);
        }

        return processeds;
    },

    ProcessDelimiter: function(st)
    {
        // skip processing delimiters when it's not available
        if (ISString.IsNullOrEmpty(this.Delimiter))
        {
            return st;
        }

        // check keyword is only delimiter, or it is a part of delimiter,
        // then return empty string
        if (ISString.Contains(this.Delimiter, st))
        {
            return '';
        }

        var processed = st;

        // for start delimiter
        for (var i = 0; i < this.Delimiter.length; i++)
        {
            var partOfDelimiter = this.Delimiter.substr(i);
            if (!ISString.StartsWith(processed, partOfDelimiter))
            {
                continue;
            }

            // append last delimiter character in front of keyword
            processed = this.Delimiter.substr(this.Delimiter.length - 1) + processed;
            break;
        }

        // for end delimiter
        for (var i = this.Delimiter.length; i > 0; i--)
        {
            var partOfDelimiter = this.Delimiter.substring(0, i);
            if (!ISString.EndsWith(processed, partOfDelimiter))
            {
                continue;
            }

            // append first delimiter character at end of keyword
            processed += this.Delimiter.substring(0, 1);
            break;
        }

        return processed;
    }
}
                  
                                         
