iBrowser.GetBrowserName = function() 
{
    var name = null;
    var browserType = iBrowser.GetBrowserType();
    if (browserType)
    {
        name = browserType.Name;
    }

    return name;
}
iBrowser.GetBrowserVersion = function() 
{
    var version = null;
    var browserType = iBrowser.GetBrowserType();
    if (browserType)
    {
        var userAgent = navigator.userAgent.toLowerCase();
        if (browserType.Name == iBrowser.BrowserTypes.InternetExplorer.Name)
        {
            var prefixes = [ 'msie', 'rv:' ];
            var tokens = iBrowser.GetUserAgentTokens();
            for (var i = 0; i < tokens.length; i++)
            {
                var token = iString.Trim(tokens[i]);
                for (var j = 0; j < prefixes.length; j++)
                {
                    var prefix = prefixes[j];
                    if (iString.StartsWith(token, prefix))
                    {
                        version = iString.Trim(token.substr(prefix.length));
                        break;
                    }
                }
            }
        }
        else if (browserType.Name == iBrowser.BrowserTypes.Netscape.Name)
        {
            // ToDo(skomatsu): implement
        }
        else if (browserType.Name == iBrowser.BrowserTypes.Opera.Name)
        {
            // ToDo(skomatsu): implement
        }
        else
        {
            var userAgent = navigator.userAgent;
            var browserInfo = userAgent.substring(iString.IndexOf(userAgent, browserType.UserAgentKeys + '/', true));
            if (iString.Contains(browserInfo, ' ') && 
                browserInfo.length > iString.IndexOf(browserInfo, ' '))
            {
                version = browserInfo.substring((browserType.UserAgentKeys + '/').length, iString.IndexOf(browserInfo, ' '));
            }
            else
            {
                version = browserInfo.substring((browserType.UserAgentKeys + '/').length);
            }
        }
    }

    return version;
}
iBrowser.GetUserAgentTokens = function()
{
    var userAgent = navigator.userAgent.toLowerCase();
    var tokenText = userAgent.substring(userAgent.indexOf('(') + 1, userAgent.indexOf(')'));
    var tokens = tokenText.split(';');

    return tokens;
}
iBrowser.GetDocumentVersion = function() 
{
    var version = null;
    if (iBrowser.IsIE())
    {
        version = document.documentMode;
    }

    return version;
}
iBrowser.IsCompatibleMode = function()
{
    var compatible = null;
    if (iBrowser.IsIE())
    {
        var tokens = iBrowser.GetUserAgentTokens();
        compatible = iArray.Contains(tokens, 'compatible', true)
    }

    return compatible;
}
iBrowser.IsIE = function()
{
    return iBrowser.GetBrowserName() == iBrowser.BrowserTypes.InternetExplorer.Name;
}
iBrowser.IsIE6 = function()
{
    return iBrowser.IsIE() &&
           iString.StartsWith(iBrowser.GetBrowserVersion(), '6');
}
iBrowser.IsIE8 = function()
{
    return iBrowser.IsIE() &&
           iString.StartsWith(iBrowser.GetBrowserVersion(), '8');
}
iBrowser.IsChrome = function() 
{
    return iBrowser.GetBrowserName() == iBrowser.BrowserTypes.Chrome.Name;
}
iBrowser.IsSafari = function()
{
    return iBrowser.GetBrowserName() == iBrowser.BrowserTypes.Safari.Name;
}
iBrowser.IsFireFox = function() 
{
    return iBrowser.GetBrowserName() == iBrowser.BrowserTypes.Firefox.Name;
}
iBrowser.IsEdgeLegacy = function ()
{
    return iBrowser.GetBrowserName() == iBrowser.BrowserTypes.EdgeLegacy.Name;
}
iBrowser.IsEdge = function() 
{
    return iBrowser.GetBrowserName() == iBrowser.BrowserTypes.Edge.Name;
}

iBrowser.GetLanguage = function ()
{
    // 言語リストを初期化
    var languages = null;
    for (;;)
    {
        // 言語リストを取得
        languages = window.navigator.languages;
        if (languages)
        {
            break;
        }

        // 言語情報を取得
        if (window.navigator.language)
        {
            languages = [window.navigator.language];
            break;
        }
                
        // 言語情報取得（IE向け: ユーザー言語）
        if (window.navigator.userLanguage)
        {
            languages = [window.navigator.userLanguage];
            break;
        }

        // 言語情報取得（IE向け: ブラウザ言語）
        if (window.navigator.browserLanguage)
        {
            languages = [window.navigator.browserLanguage];
            break;
        }

        break;
    }

    var language = '';
    if (languages)
    {
        language = languages[0];
    }

    return language;
}
iBrowser.GetMaxUrlLength = function ()
{
    // Maximum URL length is 2,083 characters in Internet Explorer 
    // http://support.microsoft.com/kb/208427/ja-jp
    // https://qiita.com/_matuzaki/items/70fb639f7ed7463f9943
    // URL path length restrictions (SharePoint Server 2010)
    // http://technet.microsoft.com/ja-jp/library/ff919564.aspx
    // Referer
    // https://developer.mozilla.org/ja/docs/Web/HTTP/Headers/Referer

    var ie7UnderMaxLength = 1024;
    // Referer            : 4096まで許容  
    var othresMaxLangth   = 4096;

    var maxLength = 0;
    if (iBrowser.IsIE())
    {
        if (iString.StartsWith(iBrowser.GetBrowserVersion(), '5') ||
            iString.StartsWith(iBrowser.GetBrowserVersion(), '6') ||
            iString.StartsWith(iBrowser.GetBrowserVersion(), '7'))
        {
            maxLength = ie7UnderMaxLength;
        }
        else
        {
            maxLength = othresMaxLangth;
        }
    }
    else
    {
        maxLength = othresMaxLangth;
    }

    return maxLength;
}
iBrowser.CookieEnabled = function()
{
    //ToDo(skomatsu): implement
}
iBrowser.LocalStorageEnabled = function ()
{
    return ('localStorage' in window) && (window.localStorage !== null);
}
iBrowser.IsHighContrastMode = function(deadLinkImageUrl)
{
    if (!iBrowser.IsIE())
    {
        return false;
    }

    // render a div with background image
    var imageUrl = deadLinkImageUrl ? deadLinkImageUrl : 'http://temp';
    var element = document.createElement('div');
    element.innerHTML = "<div style='display: none; width: 0px; height: 0px;' /></div>";
    document.body.appendChild(element);
    element.style.backgroundImage = 'url(' + imageUrl + ')';

    // try to get background image
    var image = null;
    if (window.getComputedStyle)
    {
        var style = window.getComputedStyle(element, '');
        image = style.getPropertyValue('background-image');
    }
    else
    {
        image = element.currentStyle.backgroundImage;
    }

    // check is high contrast mode or not
    var isHighContrast = image == 'none';

    // cleanup element
    document.body.removeChild(element);

    return isHighContrast;
}
                       
