Infoshare.Web.QueryString = function Infoshare$Web$QueryString() { };
ISQueryString = Infoshare.Web.QueryString;
iQueryString = Infoshare.Web.QueryString;
iQueryString.TypeName = 'Infoshare.Web.QueryString';

iQueryString.parameter = null;
iQueryString.ensureParameter = function ()
{
    if (!iQueryString.parameter)
    {
        iQueryString.parameter = iUriParameter.Parse(location.href);
    }
};

iQueryString.Contains = function (key)
{
    iQueryString.ensureParameter();
    return iQueryString.parameter.Contains(key);
};

iQueryString.GetValue = function(key) 
{
    iQueryString.ensureParameter();
    return iQueryString.parameter.Get(key);
};

iQueryString.GetKeys = function ()
{
    iQueryString.ensureParameter();
    return iQueryString.parameter.GetKeys();
};

iQueryString.AddValue = function (url, key, value, withoutEscape)
{
    var uri = iUri.Parse(url);
    var parameter = iUriParameter.Parse(url);
    parameter.Set(key, value);

    var newUrl = uri.Origin + uri.Path
               + '?' + parameter.ToString(withoutEscape)
               + (iString.IsNullOrEmpty(uri.Fragment) ? '' : uri.Fragment);

    return newUrl;
};
                       
