// -----------------------------------------------------------------------
//  CookieEntry
// -----------------------------------------------------------------------
Infoshare.Web.CookieEntry = function Infoshare$Web$CookieEntry(key, value, availableDays)
{
    this.Key   = key;
    this.Value = value;

    // calculate expires and max-age
    if (availableDays == -1)
    {
        var expiryDate = new Date();
        expiryDate.setTime(0);
        this.Expires = expiryDate.toUTCString();
        this.MaxAge  = 0;
    }
    else if (availableDays)
    {
        // calculate expires
        var expiryDate = new Date(new Date().getTime() + 60 * 60 * 24 * 1000 * availableDays);
        this.Expires = expiryDate.toUTCString();

        // calculate max-age
        this.MaxAge = 60 * 60 * 24 * availableDays;
    }
}

ISCookieEntry = Infoshare.Web.CookieEntry;
iCookieEntry = Infoshare.Web.CookieEntry;
iCookieEntry.TypeName = 'Infoshare.Web.CookieEntry';

iCookieEntry.ToCookieString = function (entry)
{
    var entryString = entry.Key + '=' + encodeURIComponent(entry.Value) + ';';

    if (entry.Expires)
    {
        entryString += ' expires=' + entry.Expires + ';';
    }
    if (entry.MaxAge || entry.MaxAge == 0)
    {
        entryString += ' max-age=' + entry.MaxAge + ';';
    }

    return entryString;
}

iCookieEntry.FromCookieString = function (raw)
{
    // expect 'key=value' format
    var key   = raw.split('=')[0];
    var value = decodeURIComponent(raw.split('=')[1]);

    return new iCookieEntry(key, value);
}

iCookieEntry.prototype = {
    TypeName: iCookieEntry.TypeName,
    Key:     '',
    Value:   '',
    Expires: null,
    MaxAge:  null,

    ToCookieString: function()
    {
        return iCookieEntry.ToCookieString(this);
    }
}


// -----------------------------------------------------------------------
//  Cookie
// -----------------------------------------------------------------------
Infoshare.Web.Cookie = function Infoshare$Web$Cookie() { };

ISCookie = Infoshare.Web.Cookie;
iCookie = Infoshare.Web.Cookie;
iCookie.TypeName = 'Infoshare.Web.Cookie';

iCookie.AvailableDays = null;

iCookie.Get = function (key)
{
    var value = '';

    // check enabled
    if (!iCookie.Enabled())
    {
        return value;
    }

    // get cookie
    var cookies = iCookie.GetEntries();
    if (cookies && cookies[key])
    {
        entry = cookies[key];
        if (entry && entry.TypeName == iCookieEntry.TypeName)
        {
            value = entry.Value;
        }
    }

    return value;
}

iCookie.GetEntries = function ()
{
    var cookies = new Array();

    // check enabled
    if (!iCookie.Enabled())
    {
        return cookies;
    }

    // get cookies
    if (document.cookie)
    {
        var entries = document.cookie.split('; ');
        for (var i = 0; i < entries.length; i++)
        {
            try
            {
                var entry = iCookieEntry.FromCookieString(entries[i]);

                cookies[entry.Key] = entry;
            }
            catch(e)
            {
                var entryString = entries[i];
                ISTrace.TraceWarning(e);
                ISTrace.TraceWarning("Can not docode this string. " + entryString);
            }
        }
    }

    return cookies;
}

iCookie.Set = function (key, value, availableDays)
{
    // check enabled
    if (!iCookie.Enabled())
    {
        return;
    }

    // set cookie
    var entry = new iCookieEntry(key, value, (availableDays ? availableDays : iCookie.AvailableDays));
    document.cookie = entry.ToCookieString();
}

iCookie.Remove = function (key)
{
    // check enabled
    if (!iCookie.Enabled())
    {
        return;
    }

    // set cookie
    var entry = new iCookieEntry(key, '', -1);
    document.cookie = entry.ToCookieString();
}

iCookie.Clear = function ()
{
    // check enabled
    if (!iCookie.Enabled())
    {
        return;
    }

    var cookies = iCookie.GetEntries();
    for (var key in cookies)
    {
        var cookie = cookies[key];
        if (cookie.TypeName != iCookieEntry.TypeName)
        {
            continue;
        }

        var entry = new iCookieEntry(cookie.Key, '', -1);
        document.cookie = entry.ToCookieString();
    }
}

iCookie.Enabled = function ()
{
    return window.navigator.cookieEnabled;
}
                       
