Infoshare.Web.Clipboard = function Infoshare$Web$Clipboard()
{
}
iClipboard = Infoshare.Web.Clipboard
iClipboard.TypeName = 'Infoshare.Web.Clipboard';

iClipboard.prototype = {
    TypeName: iClipboard.TypeName,

    Get: function(callback)
    {
        if (navigator.clipboard)
        {
            navigator.clipboard.readText().then(function (value)
            {
                if (typeof (callback) == 'function')
                {
                    callback(value);
                }
            });
        }
        else if (window.clipboardData)
        {
            var value = window.clipboardData.getData('Text');
            if (typeof (callback) == 'function')
            {
                callback(value);
            }
        }
        else
        {
            if (typeof (callback) == 'function')
            {
                callback(undefined);
            }
        }
    },

    Set: function(value, callback)
    {
        if (navigator.clipboard)
        {
            navigator.clipboard.writeText(value);
        }
        else if (window.clipboardData)
        {
            window.clipboardData.setData('Text', value);
        }

        if (typeof (callback) == 'function')
        {
            setTimeout(function () { callback(); }, 0);
        }
    },

    // ToDo(skomatsu): �������{������ق����ǂ�������
    toClipboard: function(text, callback)
    {
        // �l��ꎞ�I�ɕێ�����v�f��쐬�i���s��܂ޒl��l�����邽�߁Atextarea�Ƃ���j
        var element = document.createElement('textarea');
        element.type         = 'text';
        element.innerHTML    = text;
        element.style.height = '0px';
        //element.style.display = 'none'; // ��\���ɂ���ƒl������Ȃ�
        document.body.appendChild(element);

        // �v�f��I����A�N���b�v�{�[�h�ɒl��ݒ�
        element.select();
        document.execCommand('copy');

        // �v�f��폜����
        document.body.removeChild(element);

        // �Ăяo����ƂɕԂ�
        if (typeof(callback) == 'function')
        {
            setTimeout(function () { callback(); }, 0);
        }
    }
};
                       
