Infoshare.Web.Navigation = function Infoshare$Web$Navigation() {}
iNavigation = Infoshare.Web.Navigation;
iNavigation.TransitionType = { Navigate:   'Navigate',
                               Redirect:   'Redirect',
                               OpenWindow: 'OpenWindow',
                               NewWindow:  'NewWindow',
                               Background: 'Background',
                               Dialog:     'Dialog' };
iNavigation.Navigate = function(url)
{
    window.location.href = url;
}
iNavigation.BackgroundNavigate = function (url, frameId)
{
    var elementId = 'iNavigation$BackgroundNavigateFrame';
    if (!iString.IsNullOrEmpty(frameId))
    {
        elementId = frameId;
    }

    var element = document.getElementById(elementId);
    if (element == null)
    {
        // IEで未定義エラーが発生するため、iframe要素のsrcにURLは設定しない。
        // 初期描画時のみ処理が成功するが、要素の再利用をしようとすると未定義エラーが発生。
        var markup = "<iframe style='display: none;' src=''></iframe>";
        element = document.createElement('div');
        element.innerHTML = markup;
        element.id        = elementId;

        document.body.appendChild(element);
    }

    var wnd = element.getElementsByTagName('iframe')[0].contentWindow;
    var interval = GPContext.Configuration.GetSetting('AppInstallCheckWaitInterval');
    if (interval && !iString.StartsWith(url, new iMailLinker().BaseUrl))
    {
        this.CheckAppInstallAndOpenURL(wnd, url, ISNumber.Parse(interval));
    }
    else
    {
        wnd.location.href = url;
    }
}
iNavigation.CheckAppInstallAndOpenURL = function(wnd, url, interval)
{
    // 使用するアプリケーションがインストールされていないときの処理
    var timeout = setTimeout(function()
    {
        var message = iResxResource.GetString('Action.AppNotInstalledMessage');
        (new iNotifyer()).Notify(message, (new iLicenseMessage()).MessageDisplayTime);
        target.removeEventListener('blur', onBlur, false);
    }, interval);

    // 使用するアプリケーションがインストールされているときの処理
    var onBlur = function()
    {
        clearTimeout(timeout);
        target.removeEventListener('blur', onBlur, false);
    }

    // handle page running in an iframe (blur must be registered with top level window)
    var target = wnd;
    while (target != target.parent)
    {
        target = target.parent;
    }
    target.addEventListener('blur', onBlur, false);

    // iframeのlocation.href実行時にblurイベントが発生するかどうかで使用アプリのインストール確認を行う
    // 使用するアプリケーションがインストールされている場合、iframeのlocation.href実行時にblurイベントが発生する
    // 使用するアプリケーションがインストールされていない場合、iframeのlocation.href実行時にblurイベントが発生しない
    wnd.location.href = url;
}
iNavigation.OpenWindow = function(url, title, options)
{
        // オプション設定
    var op = '';
    var focus = false;
    if (options &&
        ISObject.TypeOf(options) == 'string')
    {
        op = options;
    }
    else
    {
        if (!options)
        {
            options = new iNavigationOption();
        }

        focus = options.Focus;

        op = 'menubar='    + (options.EnableMenubar   ? 'yes' : 'no') + ', '
           + 'location='   + (options.EnableLocation  ? 'yes' : 'no') + ', '
           + 'toolbar='    + (options.EnableToolbar   ? 'yes' : 'no') + ', '
           + 'status='     + (options.EnableStatusbar ? 'yes' : 'no') + ', '
           + 'resizable='  + (options.Resizable       ? 'yes' : 'no') + ', '
           + 'scrollbars=' + (options.Scrollable      ? 'yes' : 'no') + ', '
           + 'width='      + options.Width + ', '
           + 'height='     + options.Height;
    }

    // ウィンドウを開く
    var wnd = window.open(url, title, op);

    // フォアグラウンドに設定
    if (focus)
    {
        try
        {
            wnd.focus();
        }
        catch (e)
        {
        }
    }
}
iNavigation.BulkOpenWindow = function(options, count, interval)
{
    if (iObject.IsNullOrUndefined(count))    { count    = 3; }
    if (iObject.IsNullOrUndefined(interval)) { interval = 1000 * 2; }
    for (var i = 0; i < options.length; i++)
    {
        if (i >= count)
        {
            setTimeout(function ()
            {
                iNavigation.BulkOpenWindow(options.slice(i), count, interval);
            }, interval);
            break;
        }

        var option = options[i];
        iNavigation.OpenWindow(option.Url, option.Title, option.Option);
    }
}


