Infoshare.Web.PageUnloadBlocker = function Infoshare$Web$PageUnloadBlocker(){}
PageUnloadBlocker = Infoshare.Web.PageUnloadBlocker;
PageUnloadBlocker.BlockType = { Sleep:  'Sleep', 
                                Dialog: 'Dialog' };
PageUnloadBlocker.BlockBy       = PageUnloadBlocker.BlockType.Dialog;
PageUnloadBlocker.DialogMessage = '';
PageUnloadBlocker.SleepLength   = 300;
PageUnloadBlocker.CanUnload     = false;
PageUnloadBlocker.Enable = function()
{
    PageUnloadBlocker.CanUnload = false;
    if (!PageUnloadBlocker.Initialized)
    {
        window.onbeforeunload = PageUnloadBlocker.OnBeforeUnload;
    }
    //window.attachEvent('onbeforeunload', PageUnloadBlocker.OnBeforeUnload);
}
PageUnloadBlocker.Disable = function()
{
    PageUnloadBlocker.CanUnload = true;
    //window.detachEvent('onbeforeunload', PageUnloadBlocker.OnBeforeUnload);
}
PageUnloadBlocker.OnBeforeUnload = function()
{
    if (PageUnloadBlocker.BlockBy == PageUnloadBlocker.BlockType.Dialog)
    {
        if (!PageUnloadBlocker.CanUnload)
        {
            return PageUnloadBlocker.DialogMessage;
        }
    }
    else
    {
        while (!PageUnloadBlocker.CanUnload)
        {
            PageUnloadBlocker.BusySleep(PageUnloadBlocker.SleepLength);
        }
    }
}
PageUnloadBlocker.BusySleep = function(wait)
{
    var start = (new Date()).getTime();
    while (true)
    {
        if ((new Date()).getTime() <= start + wait * 1)
        {
            continue;
        }

        break;
    }
}


