Infoshare.Web.BrowserFile = function Infoshare$Web$BrowserFile() { };
iBrowserFile = Infoshare.Web.BrowserFile;
iBrowserFile.TypeName = 'Infoshare.Web.BrowserFile';

iBrowserFile.prototype = {
    TypeName: iBrowserFile.TypeName,

    Download: function(content, type, filename)
    {
        var blob = new Blob([content], { type: type });
        if (iBrowser.IsIE())
        {
            window.navigator.msSaveOrOpenBlob(blob, filename);
        }
        else
        {
            // for ios
            // https://teratail.com/questions/201662

            // ファイル名を指定してダウンロードさせる
            var link = document.createElement('a');
            link.href     = URL.createObjectURL(blob);
            link.target   = '_blank';
            link.download = filename;

            link.click();
        }
    }
};
                       
