Infoshare.Web.Hash = function Infoshare$Web$Hash(){}
ISHash = Infoshare.Web.Hash;
ISHash.EndsWith = function(value)
{
    var endsWith = false;
    var hash = document.location.hash;

    if (!ISString.IsNullOrEmpty(hash))
    {
        // クエリストリング部分を除去
        var hashValue = hash.split("?")[0];
        if(ISString.EndsWith(hashValue, value, true))
        {
            endsWith = true;
        }      
    }

    return endsWith;
}                       
