Infoshare.Web.UrlApplicationLinker = function Infoshare$Web$UrlApplicationLinker() { };
iUrlApplicationLinker = Infoshare.Web.UrlApplicationLinker;
iUrlApplicationLinker.TypeName = 'Infoshare.Web.UrlApplicationLinker';

iUrlApplicationLinker.OpenBy = { Foreground: 'Foreground',
                                 Background: 'Background',
                                 WindowOpen: 'WindowOpen' };

iUrlApplicationLinker.prototype = {
    TypeName: iUrlApplicationLinker.TypeName,

    OpenBy: iUrlApplicationLinker.OpenBy.Background,
    BaseUrl: '',

    Open: function()
    {
        var url = this.BuildUrl();
        var openBy = this.OpenBy;
        if ((iBrowser.IsiPhone() || iBrowser.IsiPad()) &&
            openBy == iUrlApplicationLinker.OpenBy.Background)
        {
            // iOS�n�ł́Aiframe�ɂ��o�b�N�O���E���h�J�ڂ��ł��Ȃ����߁A�t�H�A�O���E���h�őJ�ڂ���
            openBy = iUrlApplicationLinker.OpenBy.Foreground;
        }

        ISTrace.TraceVerbose('iUrlApplicationLinker.Open [Url: ' + url + ' | OpenBy: ' + openBy + ']');
        switch(openBy)
        {
            case iUrlApplicationLinker.OpenBy.Foreground: iNavigation.Navigate(url);           break;
            case iUrlApplicationLinker.OpenBy.Background: iNavigation.BackgroundNavigate(url); break;
            case iUrlApplicationLinker.OpenBy.WindowOpen: iNavigation.OpenWindow(url);         break;
        }
    },

    BuildUrl: function()
    {
        var url = this.buildBaseUrl()
                + this.buildQuery()
                + this.buildFragment();

        return url;
    },

    buildBaseUrl: function()
    {
        // implement by each sub classes
        return this.BaseUrl;
    },

    buildQuery: function()
    {
        // implement by each sub classes
        return '';
    },

    buildFragment: function()
    {
        // implement by each sub classes
        return '';
    },

    valueJoinSeparator: ',',
    buildParameterValueText: function(value)
    {
        var text = '';
        if (!iType.IsNullOrUndefined(value))
        {
            if      (iType.GetType(value) == iType.BuiltinType.String) { text = value; }
            else if (iType.GetType(value) == iType.BuiltinType.Array)  { text = value.join(this.valueJoinSeparator); }
            else if (iType.GetType(value) == iType.BuiltinType.Date)   { text = iDate.ToISODateTimeText(value, iDate.ISODateFormat.Basic, iDate.TimeZoneType.UTC); }
        }

        return text;
    }
};


// -----------------------------------------------------------------------
//  MailLinker
// -----------------------------------------------------------------------
Infoshare.Web.MailLinker = function Infoshare$Web$MailLinker()
{
    Infoshare.Web.UrlApplicationLinker.apply(this, arguments);

    this.BaseUrl = 'mailto:';

    // Windows �̏ꍇ�́AOutlook �𗘗p����O��Ƃ��Ď���
    // Windows �� Outlook �́A���[���A�h���X��Z�~�R�����ŋ�؂�Ȃ���Ύ󂯕t���Ȃ��i�Ȃ������A�h���X�Ƃ��ĔF�����Ă��܂��j
    if (iBrowser.IsWindows())
    {
        this.valueJoinSeparator = ';';
    }
};
iMailLinker = Infoshare.Web.MailLinker;
iMailLinker.TypeName = 'Infoshare.Web.MailLinker';

iMailLinker.ParameterFormat = { IncludeToKey: 'IncludeToKey',
                                ExcludToKey:  'ExcludToKey' };

iMailLinker.prototype = new Infoshare.Web.UrlApplicationLinker();
iMailLinker.prototype.TypeName = iMailLinker.TypeName;

iMailLinker.prototype.ParameterFormat = iMailLinker.ParameterFormat.IncludeToKey;
iMailLinker.prototype.To      = null;
iMailLinker.prototype.CC      = null;
iMailLinker.prototype.BCC     = null;
iMailLinker.prototype.Subject = null;
iMailLinker.prototype.Body    = null;

iMailLinker.prototype.buildQuery = function ()
{
    var query = '';
    if (this.ParameterFormat == iMailLinker.ParameterFormat.ExcludToKey)
    {
        // {0}?cc={1}&bcc={2}&subject={3}&body={4}
        var parameter = new iUriParameter();
        parameter.Set('cc',      this.buildParameterValueText(this.CC));
        parameter.Set('bcc',     this.buildParameterValueText(this.BCC));
        parameter.Set('subject', this.buildParameterValueText(this.Subject));
        parameter.Set('body',    this.buildParameterValueText(this.Body));

        var query = this.buildParameterValueText(this.To)
                  + '?' + parameter.ToString();
    }
    else
    {
        // ?to={0}&cc={1}&bcc={2}&subject={3}&body={4}
        var parameter = new iUriParameter();
        parameter.Set('to',      this.buildParameterValueText(this.To));
        parameter.Set('cc',      this.buildParameterValueText(this.CC));
        parameter.Set('bcc',     this.buildParameterValueText(this.BCC));
        parameter.Set('subject', this.buildParameterValueText(this.Subject));
        parameter.Set('body',    this.buildParameterValueText(this.Body));

        query = '?' + parameter.ToString();
    }

    return query;
};


// -----------------------------------------------------------------------
//  CalendarLinker
// -----------------------------------------------------------------------
Infoshare.Web.CalendarLinker = function Infoshare$Web$CalendarLinker()
{
    Infoshare.Web.UrlApplicationLinker.apply(this, arguments);

    this.OpenBy = iCalendarLinker.OpenBy.OpenBlob;
};
iCalendarLinker = Infoshare.Web.CalendarLinker;
iCalendarLinker.TypeName = 'Infoshare.Web.CalendarLinker';

iCalendarLinker.OpenBy = iObject.Clone(iUrlApplicationLinker.OpenBy);
iCalendarLinker.OpenBy.OpenBlob = 'OpenBlob';
iCalendarLinker.OpenBy.WebDAV   = 'WebDAV';
iCalendarLinker.AttendeeType = { Attendee:      'Attendee',
                                 ConfrenceRoom: 'ConferenceRoom' };

iCalendarLinker.prototype = new Infoshare.Web.UrlApplicationLinker();
iCalendarLinker.prototype.TypeName = iCalendarLinker.TypeName;

iCalendarLinker.prototype.Organizer = null;
iCalendarLinker.prototype.Attendees = null;
iCalendarLinker.prototype.Resources = null;
iCalendarLinker.prototype.ConferenceRooms = null;
iCalendarLinker.prototype.Subject = null;
iCalendarLinker.prototype.Content = null;
iCalendarLinker.prototype.StartTime = null;
iCalendarLinker.prototype.EndTime = null;

iCalendarLinker.prototype.OriginalOpen = iCalendarLinker.prototype.Open;
iCalendarLinker.prototype.Open = function()
{
    var calendarText = this.buildCalendarText();
    ISTrace.TraceVerbose('iCalendarLinker.Open [Calendar Text: ' + calendarText + ' | OpenBy: ' + this.OpenBy + ']');

    if (this.OpenBy == iCalendarLinker.OpenBy.OpenBlob)
    {
        (new iBrowserFile()).Download(calendarText, 'text/calendar;charset=utf-8', 'calendar.ics');
    }
    else if (this.OpenBy == iCalendarLinker.OpenBy.WebDAV)
    {
        var ref = this;
        (new iWebFile()).Upload(ref.BaseUrl, calendarText, function (result, status)
        {
            if (!result)
            {
                var message = iString.Format('iCalendarLinker.Open - Failed upload iCalendar file to the spcified url. (url: {0} | status: {1})',
                                             ref.BaseUrl, status);
                ISTestTrace.TraceError(message);

                return;
            }

            // ios �Ȃ� �t�H�A�O���E���h�A����ȊO�Ȃ�o�b�N�O���E���h�J��
            //if (iBrowser.IsiPad() || iBrowser.IsiPhone())
            if (iBrowser.IsiPad())
            {
                iNavigation.Navigate(ref.BaseUrl);
            }
            else
            {
                iNavigation.BackgroundNavigate(ref.BaseUrl);
            }
        });
    }
};

iCalendarLinker.prototype.buildQuery = function ()
{
    var calendarText = this.buildCalendarText();
    //calendarText = escape(calendarText);

    return calendarText;
};

// http://www.asahi-net.or.jp/~ci5m-nmr/iCal/ref.html
iCalendarLinker.prototype.calendarFormat = 'BEGIN:VCALENDAR' + '\r\n'
                                         + 'VERSION:2.0'     + '\r\n'
                                         //+ 'PRODID:-//Infoshare//InfoCall//JPN' + '\r\n'
                                         + 'METHOD:PUBLISH'  + '\r\n'
                                         + 'BEGIN:VEVENT'    + '\r\n'
                                         + 'CLASS:PUBLIC'    + '\r\n'
                                         + '{0}' // summary section (subject)
                                         + '{1}' // description section (content)
                                         + '{2}' // location section
                                         + '{3}' // dtstart section
                                         + '{4}' // dtend section
                                         + '{5}' // organizer section
                                         + '{6}' // attendee section
                                         + 'END:VEVENT'      + '\r\n'
                                         + 'END:VCALENDAR'   + '\r\n';
iCalendarLinker.prototype.buildCalendarText = function ()
{
    var calendarText = '';

    // Summary section
    var summaryText = this.buildSummaryText(this.Subject);

    // Description section
    var descriptionText = this.buildDescriptionText(this.Content);

    // Location section
    var locationText = this.buildLocationsText(this.ConferenceRooms);

    // Start Date (dtstart) section
    // iOS �̏ꍇ�ADTSTART �Z�N�V�����Ȃ��ł̓J�����_�[�ɘA�g�ł��Ȃ�
    var start = this.StartTime;
    if (iType.IsNullOrUndefined(start))
    {
        start = new Date();
    }
    var startDateText = this.buildStartDateText(start);

    // End Date (dtend) section
    var endDateText = '';

    // Organizer section
    var organizerText = this.buildOrganizerText(this.Organizer);

    // Attendee section
    var attendeesText = this.buildAttendeesText(this.Attendees, iCalendarLinker.AttendeeType.Attendee);
    attendeesText += this.buildAttendeesText(this.Resources, iCalendarLinker.AttendeeType.Attendee);
    attendeesText += this.buildAttendeesText(this.ConferenceRooms, iCalendarLinker.AttendeeType.ConfrenceRoom);

    // builder calendar
    var calendarText = iString.Format(this.calendarFormat, summaryText, descriptionText, locationText, startDateText, endDateText, organizerText, attendeesText);
    return calendarText;
};

iCalendarLinker.prototype.summaryFormat = 'SUMMARY:{0}' + '\r\n';
iCalendarLinker.prototype.buildSummaryText = function (subject)
{
    var summaryText = '';
    if (!iString.IsNullOrEmpty(subject))
    {
        summaryText = iString.Format(this.summaryFormat, subject);
    }

    return summaryText;
};

iCalendarLinker.prototype.descriptionFormat = 'DESCRIPTION:{0}' + '\r\n';
iCalendarLinker.prototype.buildDescriptionText = function (content)
{
    var descriptionText = '';
    if (!iString.IsNullOrEmpty(content))
    {
        descriptionText = iString.Format(this.descriptionFormat, content);
    }

    return descriptionText;
};

iCalendarLinker.prototype.locationFormat = 'LOCATION:{0}' + '\r\n';
iCalendarLinker.prototype.buildLocationsText = function (contacts)
{
    var locationsText = '';

    var principals = this.convertToContactPrincipals(contacts);
    if (iType.GetType(principals) == iType.BuiltinType.Array)
    {
        var locations = '';
        for (var i = 0; i < principals.length; i++)
        {
            var principal = principals[i];

            // �\����������΁A�\�������Ȃ���΃��[���A�h���X�ŏ�����g�ݗ��Ă�
            var name = principal.DisplayName;
            if (iString.IsNullOrEmpty(name))
            {
                name = principal.MailAddress;
            }
            if (iString.IsNullOrEmpty(name))
            {
                continue;
            }

            if (!iString.IsNullOrEmpty(locations))
            {
                locations += '; ';
            }
            locations += name;
        }

        if (!iString.IsNullOrEmpty(locations))
        {
            locationsText = iString.Format(this.locationFormat, locations);
        }
    }

    return locationsText;
};

iCalendarLinker.prototype.startDateFormat = 'DTSTART:{0}' + '\r\n';
iCalendarLinker.prototype.buildStartDateText = function (date)
{
    var startDateText = '';

    var dateText = this.buildParameterValueText(date);
    if (!iString.IsNullOrEmpty(dateText))
    {
        startDateText = iString.Format(this.startDateFormat, dateText);
    }

    return startDateText;
};

iCalendarLinker.prototype.organizerFormat = 'ORGANIZER;CN="{0}":mailto:{1}' + '\r\n';
iCalendarLinker.prototype.buildOrganizerText = function (contact)
{
    var organizerText = '';

    var principals = this.convertToContactPrincipals([contact]);
    if (principals && principals.length == 1)
    {
        var principal = principals[0];
        var name = iString.IsNullOrEmpty(principal.DisplayName) ? '' : principal.DisplayName;
        var mail = iString.IsNullOrEmpty(principal.MailAddress) ? '' : principal.MailAddress;

        if (!iString.IsNullOrEmpty(mail))
        {
            organizerText = iString.Format(this.organizerFormat, name, mail);
        }
    }

    return organizerText;
}

iCalendarLinker.prototype.attendeeFormat       = 'ATTENDEE;CN="{0}";' + 'CUTYPE=INDIVIDUAL;' + 'ROLE=REQ-PARTICIPANT;' + 'RSVP=TRUE:' + 'mailto:{1}' + '\r\n';
iCalendarLinker.prototype.conferenceRoomFormat = 'ATTENDEE;CN="{0}";' + 'CUTYPE=RESOURCE;'   + 'ROLE=NON-PARTICIPANT;' + 'RSVP=TRUE:' + 'mailto:{1}' + '\r\n';
iCalendarLinker.prototype.buildAttendeesText = function (contacts, type)
{
    var attendeesText = '';

    var principals = this.convertToContactPrincipals(contacts);
    if (iType.GetType(principals) == iType.BuiltinType.Array)
    {
        for (var i = 0; i < principals.length; i++)
        {
            var principal = principals[i];

            // ���Ȃ��Ƃ���[���A�h���X������Ώ�����g�ݗ��Ă�
            if (!iString.IsNullOrEmpty(principal.MailAddress))
            {
                var attendeeText = '';

                // ������g�ݗ��Ă�
                var format = '';
                switch (type)
                {
                    case iCalendarLinker.AttendeeType.Attendee:      format = this.attendeeFormat;       break;
                    case iCalendarLinker.AttendeeType.ConfrenceRoom: format = this.conferenceRoomFormat; break;
                }
                if (!iString.IsNullOrEmpty(format))
                {
                    var name = iString.IsNullOrEmpty(principal.DisplayName) ? '' : principal.DisplayName;
                    var mail = iString.IsNullOrEmpty(principal.MailAddress) ? '' : principal.MailAddress;
                    attendeeText = iString.Format(format, name, mail);
                }

                if (!iString.IsNullOrEmpty(attendeeText))
                {
                    attendeesText += attendeeText;
                }
            }
        }
    }

    return attendeesText;
};

iCalendarLinker.prototype.convertToContactPrincipals = function(contacts)
{
    var contactPrincipals = new Array();

    for (;;)
    {
        if (iType.IsNullOrUndefined(contacts) ||
            iString.IsNullOrEmpty(contacts))
        {
            break;
        }

        // ���͒l�̌`������낦��
        var principals = null;
        if (iType.GetType(contacts) == iType.BuiltinType.String)
        { 
            // ������Ƃ��ă��[���A�h���X��Z�~�R������J���}�ŋ�؂�����̂�󂯕t����
            if      (iString.Contains(contacts, ';')) { principals = contacts.split(';'); }
            else if (iString.Contains(contacts, ',')) { principals = contacts.split(','); }
            else                                      { principals = [ contacts ]; }
        }
        else if (iType.GetTypeName(contacts) == iContactPrincipal.TypeName)
        {
            principals = [ contacts ];
        }
        else if (iType.GetType(contacts) == iType.BuiltinType.Array)
        {
            principals = contacts;
        }
        if (iType.IsNullOrUndefined(principals))
        {
            break;
        }

        // ContactPrincipal �ɕϊ�����
        for (var i = 0; i < principals.length; i++)
        {
            var principal = principals[i];

            if (iType.GetTypeName(principal) == iContactPrincipal.TypeName)
            {
                contactPrincipals.push(principal);
            }
            else
            {
                // ContactPrincipal �łȂ��ꍇ�̓��[���A�h���X�Ƃ��ď���
                var contactPrincipal = new iContactPrincipal(null, principal);
                contactPrincipals.push(contactPrincipal);
            }
        }

        break;
    }

    return contactPrincipals;
}


