ISWebRequestStatus.UnInitialized = 0; // The object has been created, but not initialized (open method has not been called).
ISWebRequestStatus.Loading       = 1; // The object has been created, but the send method has not been called.
ISWebRequestStatus.Loaded        = 2; // The send method has been called and the status and headers are available, but the response is not yet available.
ISWebRequestStatus.Interactive   = 3; // Some data has been received. You can call responseBody and responseText to get the current partial results.
