//  WebRequestData
// -----------------------------------------------------------------------
Infoshare.Web.WebRequestData = function Infoshare$Web$WebRequestData() { }
ISWebRequestData = Infoshare.Web.WebRequestData;
ISWebRequestData.Create = function(request)
{
    var data = new ISWebRequestData();

    data.Asynchronous = request.Asynchronous ? true : false;

    data.Method  = request.Method  ? request.Method  : data.Method;
    data.Url     = request.Url     ? request.Url     : data.Url;
    data.Headers = request.Headers ? request.Headers : data.Headers;
    data.Body    = request.Body    ? request.Body    : data.Body;

    data.UserName   = request.UserName   ? request.UserName   : data.UserName;
    data.DomainName = request.DomainName ? request.DomainName : data.DomainName;
    data.Password   = request.Password   ? request.Password   : data.Password;

    data.InvocationId = request.InvocationId;
    data.ResponseText = request.GetResponseText ? request.GetResponseText() : '';

    var responseXml = request.GetResponseXml ? request.GetResponseXml() : null;
    if (responseXml)
    {
        data.ResponseXmlText = iXml.GetOuterXml(responseXml);
    }

    return data;
}
ISWebRequestData.prototype = {
    Asynchronous : false,

    Method  : 'GET',
    Url     : '',
    Headers : [ new ISWebRequestHeader('Cache-Control', 'no-cache') ],
    Body    : '',

    UserName   : null,
    DomainName : null,
    Password   : null,

    ResponseText    : '',
    ResponseXmlText : ''
}
                       
