// -----------------------------------------------------------------------
ISNamespace.Register('Infoshare.Web');


// -----------------------------------------------------------------------
//  WebRequestBroker
// -----------------------------------------------------------------------
Infoshare.Web.WebRequestBroker = function Infoshare$Web$WebRequestBroker()
{
    this.InvocationId = ISGuid.New();
    this.AppWebUrl    = ISWebRequestBroker.AppWebUrl;
    this.RecieverUrl  = ISWebRequestBroker.RecieverUrl;
}
ISWebRequestBroker = Infoshare.Web.WebRequestBroker;
ISWebRequestBroker.GetAcceptType = function(headers)
{
    var type = null;
    for (var i = 0; i < headers.length; i++)
    {
        var header = headers[i];
        if (header.Key.toUpperCase() == 'ACCEPT')
        {
            var accept = header.Value.toUpperCase();
            if      (accept.startsWith(ISWebRequest.AcceptResponseType.HTML.toUpperCase())) { type = ISWebRequest.AcceptResponseType.HTML; }
            else if (accept.startsWith(ISWebRequest.AcceptResponseType.XML.toUpperCase()))  { type = ISWebRequest.AcceptResponseType.XML; }
            else if (accept.startsWith(ISWebRequest.AcceptResponseType.JSON.toUpperCase())) { type = ISWebRequest.AcceptResponseType.JSON; }

            break;
        }
    }

    return type;
}
ISWebRequestBroker.AppWebUrl = '';
ISWebRequestBroker.RecieverUrl = '';
ISWebRequestBroker.BrokerType = { WebRequestBroker: 'Infoshare.Web.WebRequestBroker',
                                  RequestExecutor: 'SP.RequestExecutor' };
ISWebRequestBroker.GetBrokerType = function(obj)
{
    var type = null;
    if      (ISWebRequestBroker.AppWebUrl)   { type = ISWebRequestBroker.BrokerType.WebRequestBroker; }
    else if (ISWebRequestBroker.RecieverUrl) { type = ISWebRequestBroker.BrokerType.RequestExecutor; }

    return type;
}
ISWebRequestBroker.EnableReciever = function()
{
    ISDomAccessor.AttachEvent(window, 'message', function(eventArg)
    {
        var data = ISJSON.parse(eventArg.data);
        var request = ISWebRequest.Create(data);
        request.UseWebRequestBroker = false;
        request.CallbackHandler = function()
        {
            var data   = ISWebRequestData.Create(request);
            var origin = '*';
            var parentWnd = window.parent;
            parentWnd.postMessage(ISJSON.stringify(data), origin);
        };
        request.Invoke();
    });
}
ISWebRequestBroker.prototype = {
    AppWebUrl: '',
    RecieverUrl: '',

    AcceptType: null,

    InvocationId: null,

    InlineFrameControl: null,
    OnCompleteDelegate: null,

    CallbackHandler: null,

    Invoke: function(request)
    {
        this.AcceptType = ISWebRequestBroker.GetAcceptType(request.Headers);
        if (!this.AcceptType)
        {
            this.AcceptType = ISWebRequest.AcceptResponseType.XML;
        }

        if (this.AppWebUrl)
        {
            this.InvokeByRequestExecutor(request);
        }
        else if (this.RecieverUrl)
        {
            this.InvokeByRequestBroker(request);
        }
    },

    InvokeByRequestExecutor: function(request)
    {
        // ensure scripts for SP.RequestExecutor
        var layoutsPath = this.AppWebUrl.trimEnd('/') + '/_layouts/15/';
        var scripts = [ layoutsPath + 'MicrosoftAjax.js',
                        layoutsPath + 'SP.Runtime.js',
                        layoutsPath + 'SP.js',
                        layoutsPath + 'SP.RequestExecutor.js' ];
        ISScript.Load(scripts, null, ISFunction.CreateDelegate(function()
        {
            // attach event for callback
            this.OnCompleteDelegate = ISFunction.CreateDelegate(this.OnCompleteForRequestExecutor, this);

            // prepare request info
            var info = new SP.RequestInfo();
            info.method  = request.Method;
            info.url     = request.Url;
            info.body    = request.Body;
            info.success = this.OnCompleteDelegate;
            info.error   = this.OnCompleteDelegate;

            // set request headers to request info
            var headres = new Object();
            for (var i = 0; i < request.Headers.length; i++)
            {
                var header = request.Headers[i];
                headres[header.Key] = header.Value;
            }
            info.headers = headres;

            // initialize executor, then invoke request
            var executor = new SP.RequestExecutor(this.AppWebUrl.trimEnd('/') + '/');
            executor.executeAsync(info);
        }, this));
    },

    InvokeByRequestBroker: function(request)
    {
        var broker = this;
        this.EnsureInlineFrame(function()
        {
            // assign invocation id
            request.InvocationId = broker.InvocationId;

            // attach event for callback
            broker.OnCompleteDelegate = ISFunction.CreateDelegate(broker.OnCompleteForRequestBroker, broker);
            ISDomAccessor.AttachEvent(window, 'message', broker.OnCompleteDelegate);

            // invoke
            var wnd = broker.InlineFrameControl.GetContentWindow();
            var data = ISWebRequestData.Create(request);
            wnd.postMessage(ISJSON.stringify(data), '*');
        });
    },

    OnCompleteForRequestExecutor: function(data, errorCode, errorMessage)
    {
        var result = { ResponseText: '',
                       ResponseXmlText: '' };
        if (this.AcceptType == ISWebRequest.AcceptResponseType.XML)
        {
            result.ResponseXmlText = data.body;
        }
        else if (this.AcceptType == ISWebRequest.AcceptResponseType.JSON)
        {
            result.ResponseText = data.body;
        }

        // cleanup
        //ISDomAccessor.DetachEvent(window, 'message', this.OnCompleteDelegate);

        // callback
        if (this.CallbackHandler)
        {
            this.CallbackHandler(result);
        }
    },

    OnCompleteForRequestBroker: function(postMessageEventArg)
    {
        var data = ISJSON.parse(postMessageEventArg.data);
        if (data.InvocationId != this.InvocationId)
        {
            return;
        }

        // cleanup
        ISDomAccessor.DetachEvent(window, 'message', this.OnCompleteDelegate);
        this.InlineFrameControl.Remove();

        // callback
        if (this.CallbackHandler)
        {
            this.CallbackHandler(data);
        }
    },

    EnsureInlineFrame: function(callback)
    {
        if (ISWebRequestBroker.InlineFrameControl)
        {
            callback();
            return;
        }

        var broker = this;
        var control = new ISInlineFrame();
        control.Url     = this.RecieverUrl;
        control.Display = false;
        control.OnLoadEventHandler = function()
        {
            broker.InlineFrameControl = control;
            callback();
        }
        control.Render();
    }
}
                       
