// -----------------------------------------------------------------------
//  SoapRequest
// -----------------------------------------------------------------------
Infoshare.Web.SoapRequest = function Infoshare$Web$SoapRequest(){}
ISSoapRequest = Infoshare.Web.SoapRequest;

ISSoapRequest.prototype = {
    OperationName: '',
    ServiceNamespace: '',

    ServiceUrl: '',
    SoapBody: '',

    // request related
    Request             : null,
	Asynchronous        : false,
    InvocationCompleted : false,

    Method  : 'POST',
    Url     : '',
    Headers : null,
    Body    : '',

	UserName   : null,
	DomainName : null,
	Password   : null,

	CallbackHandler   : null,
    CallbackParameter : null,


    Invoke: function()
    {
        try 
        {
            // initialize flag
            this.InvocationCompleted = false;

            // initialize request
            this.Request = this.BuildRequest();

            // send request
            this.Request.Invoke();
        }
        catch (e) 
        {
            throw new Error('Failed to invoke soap request, caused by "' + e.message + "'");
        }
    },

    BuildRequest: function()
    {
        var request = null;
        try
        {
            // update headers
            this.Headers = [ new ISWebRequestHeader('Cache-Control', 'no-cache'),
                             new ISWebRequestHeader('Content-Type', 'text/xml; charset=utf-8'),
                             new ISWebRequestHeader('SOAPAction', this.ServiceNamespace + this.OperationName) ];

            // build url
            this.ServiceUrl = this.Url + '?op=' + this.OperationName;

            // build body
            this.SoapBody = this.BuildBody();

            // build request
            request = new ISWebRequest();
            request.InvocationCompleted = this.InvocationCompleted;
            request.Asynchronous = this.Asynchronous;

            request.Method  = this.Method;
            request.Url     = this.ServiceUrl;
            request.Headers = this.Headers;
            request.Body    = this.SoapBody;

            request.UserName   = this.UserName;
            request.DomainName = this.DomainName;
            request.Password   = this.Password;

            request.CallbackHandler = ISFunction.CreateDelegate(this.CallbackHandler, this);
            //request.CallbackParameter = this.CallbackParameter;
        }
        catch(e)
        {
            throw new Error('Failed to create soap request object, caused by "' + e.message + '".');
        }

        return request;
    },

    BuildBody: function()
    {
        // build body
        var body = "<?xml version='1.0' encoding='utf-8'?>"
			     + "<soap:Envelope "
                 + " xmlns:xsi='http://www.w3.org/2001/XMLSchema-instance' "
                 + " xmlns:xsd='http://www.w3.org/2001/XMLSchema' "
                 + " xmlns:soap='http://schemas.xmlsoap.org/soap/envelope/' "
                 + ">"
                 +   "<soap:Body>"
                 +     "<" + this.OperationName + " xmlns='" + this.ServiceNamespace + "'>"
			     +       this.Body
                 +     "</" + this.OperationName + ">"
			     +   "</soap:Body>"
			     + "</soap:Envelope>";

        return body;
    },

    OnCompleted: function()
    {
        if (this.Asynchronous && this.CallbackHandler)
        {
            this.CallbackHandler(this.CallbackParameter);
        }
    },

    GetResponseXml: function()
    {
        return this.Request.GetResponseXml();
    },

    GetResponseText: function()
    {
        return this.Request.GetResponseText();
    },

    GetResponse: function()
    {
        return this.Request.GetResponse();
    }
}
                       
