// -----------------------------------------------------------------------
//  WebContent
// -----------------------------------------------------------------------
Infoshare.Web.WebContent = function Infoshare$Web$WebContent(){}
iWebContent = Infoshare.Web.WebContent;
iWebContent.prototype = {

    Exists: function(url, callback)
    {
        var request = new ISWebRequest();
        request.Asynchronous    = true;
        request.Method          = Infoshare.Web.HttpMethod.Head;
        request.Url             = url;
        request.CallbackHandler = function()
        {
            var exists = false;
            var status = request.GetStatusCode();
            if (status == Infoshare.Web.HttpStatusCode.OK ||
                status == Infoshare.Web.HttpStatusCode.Forbidden)
            {
                exists = true;
            }
            callback(exists, status);
        };
        request.Invoke();
    },

    Delete: function(url, callback)
    {
        var request = new ISWebRequest();
        request.Asynchronous    = true;
        request.Method          = Infoshare.Web.HttpMethod.Delete;
        request.Url             = url;
        request.CallbackHandler = function()
        {
            var result = false;
            var status = request.GetStatusCode();
            if (status == Infoshare.Web.HttpStatusCode.NoContent)
            {
                result = true;
            }
            callback(result, status);
        };
        request.Invoke();
    },

    Copy: function(source, destination, callback)
    {
        var request = new ISWebRequest();
        request.Asynchronous = true;
        request.Method       = Infoshare.Web.HttpMethod.Copy;
        request.Url          = source;
        request.Headers.push(new ISWebRequestHeader('Destination', destination));

        request.CallbackHandler = function()
        {
            var result = false;
            var status = request.GetStatusCode();
            if (status == Infoshare.Web.HttpStatusCode.Created ||
                status == Infoshare.Web.HttpStatusCode.NoContent)
            {
                result = true;
            }
            callback(result, status);
        };
        request.Invoke();
    },

    Move: function(source, destination, callback)
    {
        var request = new ISWebRequest();
        request.Asynchronous = true;
        request.Method       = Infoshare.Web.HttpMethod.Move;
        request.Url          = source;
        request.Headers.push(new ISWebRequestHeader('Destination', destination));

        request.CallbackHandler = function()
        {
            var result = false;
            var status = request.GetStatusCode();
            if (status == Infoshare.Web.HttpStatusCode.Created ||
                status == Infoshare.Web.HttpStatusCode.NoContent)
            {
                result = true;
            }
            callback(result, status);
        };
        request.Invoke();
    },

    GetFiles: function(url, callback)
    {
        this.GetContents(url, function(result, responses, status)
        {
            var files = new Array();
            for (var i = 0; i < responses.length; i++)
            {
                var response = responses[i];
                if (!response.IsFolder)
                {
                    files.push(response.Href);
                }
            }

            callback(result, files, status);
        });
    },

    GetFolders: function(url, callback)
    {
        this.GetContents(url, function(result, responses, status)
        {
            var folders = new Array();
            for (var i = 0; i < responses.length; i++)
            {
                var response = responses[i];
                if (response.IsFolder)
                {
                    folders.push(response.Href);
                }
            }

            callback(result, folders, status);
        });
    },

    GetContents: function(url, callback)
    {
        var request = new ISWebRequest();
        request.Asynchronous = true;
        request.Method       = Infoshare.Web.HttpMethod.PropFind;
        request.Url          = url;
        request.Headers.push(new ISWebRequestHeader('Depth', 1));

        var webFile = this;
        request.CallbackHandler = function()
        {
            var responseXml = request.GetResponseXml();
            var rawResponses = webFile.BuildResponsesFromResponseXml(responseXml);

            // 自身のフォルダも結果セットに含まれるため除外する
            var responses = new Array();
            for (var i = 0; i < rawResponses.length; i++)
            {
                var response = rawResponses[i];
                if (!iUri.Equals(response.Href, url))
                {
                    responses.push(response);
                }
            }

            var result = false;
            var status = request.GetStatusCode();
            if (status == Infoshare.Web.HttpStatusCode.MultiStatus)
            {
                result = true;
            }
            callback(result, responses, status);
        };
        request.Invoke();
    },

    BuildResponsesFromResponseXml: function(responseXml)
    {
/* -----------------------------------------------------------------------
<D:multistatus xmlns:D="DAV:" 
               xmlns:Office="urn:schemas-microsoft-com:office:office" 
               xmlns:Repl="http://schemas.microsoft.com/repl/" 
               xmlns:Z="urn:schemas-microsoft-com:">
  <D:response>
    <D:href>http://k4devgp01/Shared%20Documents/</D:href>
    <D:propstat>
      <D:prop>
        <D:displayname>Shared Documents</D:displayname>
        <D:lockdiscovery/>
        <D:supportedlock/>
        <D:isFolder>t</D:isFolder>
        <D:iscollection>1</D:iscollection>
        <D:ishidden>0</D:ishidden>
----------------------------------------------------------------------- */

        var resources = new Array();
        var responseElements = responseXml.getElementsByTagName('D:response');
        for (var i = 0; i < responseElements.length; i++)
        {
            var responseElement = responseElements[i];
            var resource = iWebContentResponse.FromXml(responseElement);
            resources.push(resource);
        }

        return resources;
    }
}


// -----------------------------------------------------------------------
//  WebContentResponse
// -----------------------------------------------------------------------
Infoshare.Web.WebContentResponse = function Infoshare$Web$WebContentResponse()
{
    this.Properties = new Array();
}
iWebContentResponse = Infoshare.Web.WebContentResponse;
iWebContentResponse.FromXml = function(element)
{
    var response = new iWebContentResponse();
    
    // href
    var hrefElement = iXml.SelectNodeByPath(element, 'D:href');
    response.Href = hrefElement.text;

    // properties
    var propertiesElement = iXml.SelectNodeByPath(element, 'D:propstat/D:prop');
    response.Properties = iXml.GetChildElementsByArray(propertiesElement);

    response.DisplayName = response.Properties['D:displayname'];
    response.IsFolder    = response.Properties['D:isFolder'] == 't';

    return response;
}
iWebContentResponse.prototype = {
    Href: '',

    DisplayName: '',
    IsFolder: false,

    Properties: null
}


