// -----------------------------------------------------------------------
//  TraceConsole
// -----------------------------------------------------------------------
Infoshare.Web.TraceConsole = function Infoshare$Web$TraceConsole() {}
ISTraceConsole = Infoshare.Web.TraceConsole;
ISTraceConsole.EventType = { Verbose:     'Verbose',
                             Information: 'Information',
                             Warning:     'Warning',
                             Error:       'Error' };
ISTraceConsole.Write = function(type, message)
{
    var msg = '[' + ISTraceConsole.FormatDateTime(new Date(), true) + ']' + ' '
            + message;

    // trace should not be bloked any UI
    window.setTimeout(function()
    {
        try
        {
            ISTraceConsole.WriteInternal(type, msg);
        }
        catch (e) { }
    }, 32);
}
ISTraceConsole.WriteInternal = function(type, message)
{
    switch (type)
    {
        case ISTraceConsole.EventType.Error:       window.console.error(message); break;
        case ISTraceConsole.EventType.Warning:     window.console.warn(message);  break;
        case ISTraceConsole.EventType.Information: window.console.info(message);  break;
        case ISTraceConsole.EventType.Verbose:     // fall through
        default:                                   window.console.log(message);   break;
    }
}
ISTraceConsole.WriteVerbose = function(message)
{
    ISTraceConsole.Write(ISTraceConsole.EventType.Verbose, message);
}
ISTraceConsole.WriteInformation = function(message)
{
    ISTraceConsole.Write(ISTraceConsole.EventType.Information, message);
}
ISTraceConsole.WriteWarning = function(message)
{
    ISTraceConsole.Write(ISTraceConsole.EventType.Warning, message);
}
ISTraceConsole.WriteError = function(message)
{
    ISTraceConsole.Write(ISTraceConsole.EventType.Error, message);
}
ISTraceConsole.FormatDateTime = function(dt, withMiliSec)
{
    var formatted = iDate.Format(dt, 'yyyy/MM/dd HH:mm:ss');
    if (withMiliSec)
    {
        formatted += ':' + iDate.GetMilliseconds(dt, true);
    }

    return formatted;
}
                       
