// -----------------------------------------------------------------------
//  TraceGridStyle
// -----------------------------------------------------------------------
Infoshare.Web.TraceGridStyle = function Infoshare$Web$TraceGridStyle(){}
ISTraceGridStyle = Infoshare.Web.TraceGridStyle;
ISTraceGridStyle.prototype = {
    FontFamily: '"メイリオ", "MS ゴシック", sans-serif',

    HeaderColor:           '#ffffff',
    HeaderBackgroundColor: '#0066cc;',

    RowColorVerbose:     '#999999',
    RowColorInformation: '#000000',
    RowColorWarning:     '#ff9900',
    RowColorError:       '#990000',
    RowColorCritical:    '#ff0000',

    RowColorGreen: '#006600',
    RowColorBlue:  '#330099',

    RowBackgroundColorLight: '#ffffff',
    RowBackgroundColorDark:  '#eeefff',

    EnableEllipsisRendering: true
}


// -----------------------------------------------------------------------
//  TraceGrid
// -----------------------------------------------------------------------
Infoshare.Web.TraceGrid = function Infoshare$Web$TraceGrid()
{
    this.Style = new ISTraceGridStyle();
    this.Columns = [new ISTraceGridColumnInfo('DateTime', 160)];
}
ISTraceGrid = Infoshare.Web.TraceGrid;
ISTraceGrid.WritePosition = { Top:    'Top',
                              Bottom: 'Bottom' }
ISTraceGrid.prototype = {
    Window:      null,
    WindowId:    'ISTraceGrid.Window',
    WindowTitle: 'Infoshare Trace Window',
    WindowUrl:   '',

    Region:   null,
    RegionId: 'ISTraceGrid.Region',

    Grid:   null,
    GridId: 'ISTraceGrid.Grid',

    Style: null,
    WritePosition: ISTraceGrid.WritePosition.Top,
    Columns: null,

    // this function expected, color, time, other field values ...
    Write: function()
    {
        var index = 0;

        // fix color
        var color = arguments[index];
        if (typeof color != 'string' ||
            color.indexOf('#') != 0)
        {
            color = this.Style.RowColorStandard;
        }
        else
        {
            index++;
        }

        // fix date time
        var time = arguments[index];
        if (!(time instanceof Date))
        {
            time = new Date();
        }
        else
        {
            index++;
        }

        // fix field values
        var values = new Array();
        for (var i = index; i < arguments.length; i++)
        {
            values.push(arguments[i]);
        }

        // trace should not be bloked any UI
        var trace = this;
        window.setTimeout(function()
        {
            try
            {
                trace.WriteInternal(color, time, values);
            }
            catch (e) { }
        }, 32);
    },

    WriteInternal: function(color, time, values) // and other row data
    {
        this.Ensure();

        try
        {
            // insert row
            var position = 1;
            if (this.WritePosition != ISTraceGrid.WritePosition.Top)
            {
                position = this.Grid.rows.length;
            }
            var row = this.Grid.insertRow(position);

            // apply styles
            row.style.color = color;
            row.style.backgroundColor = this.Style.RowBackgroundColorLight;
            if (this.Grid.rows.length % 2 == 0)
            {
                row.style.backgroundColor = this.Style.RowBackgroundColorDark;                
            }

            // write date time
            var dateCell = row.insertCell(-1);
            dateCell.innerHTML = ISTraceConsole.FormatDateTime(time, true);

            // write row
            for (var i = 0; i < values.length; i++)
            {
                var value = values[i] ? values[i] : '';

                // write date
                var cell = row.insertCell(-1);
                cell.innerHTML = value;

                if (this.Style.EnableEllipsisRendering)
                {
                    cell.style.overflow     = 'hidden';
                    cell.style.textOverflow = 'ellipsis';
                    cell.title              = value;
                }
            }
        }
        catch (e)
        {
        }        
    },

    Ensure: function()
    {
        // check grid
        if (this.Grid)
        {
            return;
        }
    
        // ----------------------------------------------------
        // at first, try to ensure grid on current document
        // ----------------------------------------------------
        this.Grid = this.EnsureGrid(null);
        if (this.Grid)
        {
            return;
        }

        // ----------------------------------------------------
        // then next, try to ensure grid on another document
        // ----------------------------------------------------
        // ensure window
        if (!this.Window)
        {
            this.Window = ISWindow.GetWindow(this.WindowId, this.WindowUrl);
        }

        // try to ensure grid
        this.Grid = this.EnsureGrid(this.Window.document);
        if (this.Grid)
        {
            return;
        }
        
        // ----------------------------------------------------
        // finally, write fully markup for grid
        // ----------------------------------------------------
        var doc = this.Window.document;
        doc.open();
        doc.write(this.BuildMarkup());
        doc.close();

        this.Grid = ISDomAccessor.GetElement(this.GridId, doc);        
    },

    EnsureGrid: function(parent)
    {
        // at first, try to ensure grid on current document
        var grid = null;
        for (;;)
        {
            // try to get grid
            grid = ISDomAccessor.GetElement(this.GridId, parent);
            if (grid)
            {
                break;
            }

            // try to get region
            var region = ISDomAccessor.GetElement(this.RegionId, parent);
            if (!region)
            {
                break;
            }

            // when the region is found, render grid markup
            region.innerHTML = this.BuildGridMarkup();
            grid = ISDomAccessor.GetElement(this.GridId, parent);
            break;
        }

        return grid;
    },

    BuildMarkup: function()
    {
        // write markup
        var builder = new Array();
        builder[builder.length] = "<html>";
        builder[builder.length] =   "<head>";
        builder[builder.length] =     "<title>" + this.WindowTitle + "</title>";
        builder[builder.length] =   "</head>";
        builder[builder.length] =   "<body>";

        // write markup for grid
        this.BuildGridMarkup(builder);

        builder[builder.length] =   "</body>";
        builder[builder.length] = "</html>";

        return builder.join('');
    },

    BuildGridMarkup: function(parentBuilder)
    {
        // ensure builder
        var builder = parentBuilder;
        if (!builder)
        {
            builder = new Array();
        }

        // write markup
        builder[builder.length] = "<table id='" + this.GridId + "' ";
        builder[builder.length] =        "cellpadding='0' cellspacing='0' ";
        builder[builder.length] =        "style='table-layout: fixed; ";
        builder[builder.length] =               "width: 100%; ";
        builder[builder.length] =               "font-family: " + this.Style.FontFamily + "; ";
        builder[builder.length] =               "font-size: smaller;'>";
        builder[builder.length] =   "<tr style='padding-left: 2px; ";
        builder[builder.length] =              "padding-right: 2px; ";
        builder[builder.length] =              "color: " + this.Style.HeaderColor + "; ";
        builder[builder.length] =              "background-color: " + this.Style.HeaderBackgroundColor + ";'>";

        for (var i = 0; i < this.Columns.length; i++)
        {
            var column = this.Columns[i];
            
            // fix width: last field width should be maximized
            var width = column.Width + 'px';
            if (i == this.Columns.length - 1)
            {
                width = '';
            }

            builder[builder.length] = "<th style='width: " + width + ";'>" + column.Title + "</th>";
        }

        builder[builder.length] =   "</tr>";
        builder[builder.length] = "</table>";

        // build markup
        var markup = '';
        if (!parentBuilder)
        {
            markup = builder.join('');
        }

        return markup;
    },

    FormatDateTime: function(dt, withMiliSec)
    {
        var formated = (dt.getYear() < 2000 ? dt.getYear() + 1900 : dt.getYear())
                     + '/'
                     + (dt.getMonth() < 9 ? '0' + (dt.getMonth() + 1) : dt.getMonth() + 1)
                     + '/'
                     + (dt.getDate() < 10 ? '0' + dt.getDate() : dt.getDate())
                     + ' '
                     + (dt.getHours() < 10 ? '0' + dt.getHours() : dt.getHours())
                     + ':'
                     + (dt.getMinutes() < 10 ? '0' + dt.getMinutes() : dt.getMinutes())
                     + ':'
                     + (dt.getSeconds() < 10 ? '0' + dt.getSeconds() : dt.getSeconds());

        if (withMiliSec)
        {
            var milisec = dt.getMilliseconds().toString();
            while(milisec.length < 3) { milisec = '0' + milisec; }
            formated += ':' + milisec;
        }

        return formated;
    }
}


