Infoshare.Web.TraceGridColumnInfo = function Infoshare$Web$ISTraceGridColumnInfo(title, width)
{
    this.Title = title;
    this.Width = width ? width : this.Width;
}
ISTraceGridColumnInfo = Infoshare.Web.TraceGridColumnInfo;
ISTraceGridColumnInfo.prototype = {
    Title: '',
    Width: 100
}
                       
