// -----------------------------------------------------------------------
//  Trace
// -----------------------------------------------------------------------
Infoshare.Web.Trace = function Infoshare$Web$Trace(){}
ISTrace = Infoshare.Web.Trace;
ISTrace.EventType = { Verbose:     'Verbose',
                      Information: 'Information',
                      Warning:     'Warning',
                      Error:       'Error',
                      Critical:    'Critical' };
ISTrace.TraceLevel = { Off:         'Off',
                       Verbose:     'Verbose',
                       Information: 'Information',
                       Warning:     'Warning',
                       Error:       'Error',
                       Critical:    'Critical',
                       All:         'All' };
ISTrace.OutTargetType = { Console:   'Console',
                          TraceGrid: 'TraceGrid' };
ISTrace.OutTarget   = ISTrace.OutTargetType.Console;
ISTrace.Level       = ISTrace.TraceLevel.Off;
ISTrace.WindowName  = 'ISTraceWindow';
ISTrace.WindowTitle = 'Infoshare Trace Window';
ISTrace.TargetUrl   = '';
ISTrace.RegionId    = '';
ISTrace.TableId     = 'ISTraceWindow.Table';
ISTrace.TraceGrid   = null;
ISTrace.TraceStyle  = null;
ISTrace.Initialized = false;
ISTrace.Initialize = function()
{
    if (ISTrace.Initialized)
    {
        return;
    }

    var debugString = ISQueryString.GetValue('Debug');
    var traceLevel  = ISQueryString.GetValue('TraceLevel');
    var traceTarget = ISQueryString.GetValue('TraceTarget');

    // デバッグフラグの設定
    if (!ISObject.IsNullOrUndefined(debugString))
    {
        var debug = false;
        try
        {
            debug = ISBoolean.Parse(debugString);
        }
        catch (e) { }

        if (debug)
        {
            ISTrace.Level = ISTrace.TraceLevel.All;
        }
    }
    else if (!ISObject.IsNullOrUndefined(traceLevel) &&
             !ISString.IsNullOrEmpty(traceLevel))
    {
        var level = ISTrace.TraceLevel.Off;
        switch (traceLevel.toLowerCase())
        {
            case ISTrace.TraceLevel.Off.toLowerCase():         level = ISTrace.TraceLevel.Off;         break;
            case ISTrace.TraceLevel.Verbose.toLowerCase():     level = ISTrace.TraceLevel.Verbose;     break;
            case ISTrace.TraceLevel.Information.toLowerCase(): level = ISTrace.TraceLevel.Information; break;
            case ISTrace.TraceLevel.Warning.toLowerCase():     level = ISTrace.TraceLevel.Warning;     break;
            case ISTrace.TraceLevel.Error.toLowerCase():       level = ISTrace.TraceLevel.Error;       break;
            case ISTrace.TraceLevel.Critical.toLowerCase():    level = ISTrace.TraceLevel.Critical;    break;
            case ISTrace.TraceLevel.All.toLowerCase():         level = ISTrace.TraceLevel.All;         break;
            default:                                           level = ISTrace.TraceLevel.Off;         break;
        }

        ISTrace.Level = level;
    }

    // ターゲット設定
    if (!ISObject.IsNullOrUndefined(traceTarget) &&
        !ISString.IsNullOrEmpty(traceTarget))
    {
        var target = ISTrace.OutTargetType.Console;
        switch (traceTarget.toLowerCase())
        {
            case ISTrace.OutTargetType.Console.toLowerCase():   target = ISTrace.OutTargetType.Console;   break;
            case ISTrace.OutTargetType.TraceGrid.toLowerCase(): target = ISTrace.OutTargetType.TraceGrid; break;
            default:                                            target = ISTrace.OutTargetType.Console;   break;
        }

        ISTrace.OutTarget = target;
    }

    // 初期化完了
    ISTrace.Initialized = true;
}
ISTrace.EnsureGrid = function(force)
{
    if (ISTrace.TraceGrid)
    {
        return;
    }

    // initialize base trace
    var trace = new ISTraceGrid();
    trace.WindowId    = ISTrace.WindowName;
    trace.WindowTitle = ISTrace.WindowTitle;
    trace.WindowUrl   = ISTrace.TargetUrl;
    trace.RegionId    = ISTrace.RegionId;
    trace.GridId      = ISTrace.TableId;
    trace.WritePosition = ISTraceGrid.WritePosition.Top;
    trace.Columns.push(new ISTraceGridColumnInfo('Type', 100));
    trace.Columns.push(new ISTraceGridColumnInfo('Id',   200));
    trace.Columns.push(new ISTraceGridColumnInfo('Message'));
    ISTrace.TraceGrid = trace;

    // initialize trace style
    ISTrace.TraceStyle = new ISTraceGridStyle();
}
ISTrace.WriteTrace = function(type, name, result, description)
{
    if (ISTrace.OutTarget == ISTrace.OutTargetType.Console && window.console)
    {
        this.WriteConsole(type, name, result, description);
    }
    else
    {
        this.WriteGrid(type, name, result, description);
    }
}
ISTrace.WriteGrid = function(type, message, id)
{
    ISTrace.EnsureGrid();

    try
    {
        // fix color
        var color = ISTrace.TraceStyle.RowColorInformation;
        switch(type)
        {
            case ISTrace.EventType.Verbose:  color = ISTrace.TraceStyle.RowColorVerbose;     break;
            case ISTrace.EventType.Warning:  color = ISTrace.TraceStyle.RowColorWarning;     break;
            case ISTrace.EventType.Error:    color = ISTrace.TraceStyle.RowColorError;       break;
            case ISTrace.EventType.Critical: color = ISTrace.TraceStyle.RowColorCritical;    break;
            default:                         color = ISTrace.TraceStyle.RowColorInformation; break;
        }

        // write
        ISTrace.TraceGrid.Write(color, type, id, message);
    }
    catch (e)
    {
        ISTrace.Ensure(true);
        ISTrace.WriteTrace(type, message, id);
    }
}
ISTrace.WriteConsole = function(type, message, id)
{
    var msg = message;
    if (id)
    {
        msg += ' (' + id + ')';
    }

    switch (type)
    {
        case ISTrace.EventType.Critical:    // fall through
        case ISTrace.EventType.Error:       ISTraceConsole.WriteError(msg);       break;
        case ISTrace.EventType.Warning:     ISTraceConsole.WriteWarning(msg);     break;
        case ISTrace.EventType.Information: ISTraceConsole.WriteInformation(msg); break;
        default:                            ISTraceConsole.WriteVerbose(msg);     break;
    }
}
ISTrace.CanTrace = function(type)
{
    var canTrace = false;
    switch(type)
    {
        case ISTrace.TraceLevel.Verbose:
            canTrace = ISTrace.Level == ISTrace.TraceLevel.All ||
                       ISTrace.Level == ISTrace.TraceLevel.Verbose;
            break;
        case ISTrace.TraceLevel.Information:
            canTrace = ISTrace.Level == ISTrace.TraceLevel.All ||
                       ISTrace.Level == ISTrace.TraceLevel.Information ||
                       ISTrace.Level == ISTrace.TraceLevel.Verbose;
            break;
        case ISTrace.TraceLevel.Warning:
            canTrace = ISTrace.Level == ISTrace.TraceLevel.All ||
                       ISTrace.Level == ISTrace.TraceLevel.Warning ||
                       ISTrace.Level == ISTrace.TraceLevel.Information ||
                       ISTrace.Level == ISTrace.TraceLevel.Verbose;
            break;
        case ISTrace.TraceLevel.Error:
            canTrace = ISTrace.Level == ISTrace.TraceLevel.All ||
                       ISTrace.Level == ISTrace.TraceLevel.Error ||
                       ISTrace.Level == ISTrace.TraceLevel.Warning ||
                       ISTrace.Level == ISTrace.TraceLevel.Information ||
                       ISTrace.Level == ISTrace.TraceLevel.Verbose;
            break;
        case ISTrace.TraceLevel.Critical:
            canTrace = ISTrace.Level == ISTrace.TraceLevel.All ||
                       ISTrace.Level == ISTrace.TraceLevel.Critical ||
                       ISTrace.Level == ISTrace.TraceLevel.Error ||
                       ISTrace.Level == ISTrace.TraceLevel.Warning ||
                       ISTrace.Level == ISTrace.TraceLevel.Information ||
                       ISTrace.Level == ISTrace.TraceLevel.Verbose;
            break;
        default:
            canTrace = false;
            break;
    }

    return canTrace;
}
ISTrace.TraceEvent = function(type, message, id)
{
    // クエリストリングのフラグ等の確認
    ISTrace.Initialize();

    if (!ISTrace.CanTrace(type))
    {
        return;
    }

    ISTrace.WriteTrace(type, message, id);
}
ISTrace.TraceVerbose = function(message, id)
{
    ISTrace.TraceEvent(ISTrace.EventType.Verbose, message, id);
}
ISTrace.TraceInformation = function(message, id)
{
    ISTrace.TraceEvent(ISTrace.EventType.Information, message, id);
}
ISTrace.TraceWarning = function(message, id)
{
    ISTrace.TraceEvent(ISTrace.EventType.Warning, message, id);
}
ISTrace.TraceError = function(message, id)
{
    ISTrace.TraceEvent(ISTrace.EventType.Error, message, id);
}
ISTrace.TraceCritical = function(message, id)
{
    ISTrace.TraceEvent(ISTrace.EventType.Critical, message, id);
}

                       
