Infoshare.Web.TestTrace = function Infoshare$Web$TestTrace(){}
ISTestTrace = Infoshare.Web.TestTrace;
ISTestTrace.TraceType = { Verbose:     'Verbose',
                          Information: 'Information',
                          Warning:     'Warning',
                          Error:       'Error',
                          Critical:    'Critical',
                          InformationGreen: 'InformationGreen',
                          InformationBlue:  'InformationBlue' };
ISTestTrace.OutTargetType = { Console:   'Console',
                              TraceGrid: 'TraceGrid' };
ISTestTrace.OutTarget   = ISTestTrace.OutTargetType.TraceGrid;
ISTestTrace.WindowName  = 'ISTestTraceWindow';
ISTestTrace.WindowTitle = 'Infoshare Test Trace Window';
ISTestTrace.TargetUrl   = '';
ISTestTrace.RegionId    = 'ISTestTrace.Region';
ISTestTrace.TableId     = 'ISTestTrace.Grid';
ISTestTrace.TraceGrid  = null;
ISTestTrace.TraceStyle = null;
ISTestTrace.EnsureGrid = function(force)
{
    if (ISTestTrace.TraceGrid)
    {
        return;
    }

    // initialize base trace
    var trace = new ISTraceGrid();
    trace.WindowId    = ISTestTrace.WindowName;
    trace.WindowTitle = ISTestTrace.WindowTitle;
    trace.WindowUrl   = ISTestTrace.TargetUrl;
    trace.RegionId    = ISTestTrace.RegionId;
    trace.GridId      = ISTestTrace.TableId;
    trace.WritePosition = ISTraceGrid.WritePosition.Top;
    trace.Columns.push(new ISTraceGridColumnInfo('Test Name', 400));
    trace.Columns.push(new ISTraceGridColumnInfo('Result',    100));
    trace.Columns.push(new ISTraceGridColumnInfo('Description'));
    ISTestTrace.TraceGrid = trace;

    // initialize trace style
    ISTestTrace.TraceStyle = new ISTraceGridStyle();
}
ISTestTrace.Write = function(type, name, result, description)
{
    if (ISTestTrace.OutTarget == ISTestTrace.OutTargetType.Console && window.console)
    {
        this.WriteConsole(type, name, result, description);
    }
    else
    {
        this.WriteGrid(type, name, result, description);
    }
}
ISTestTrace.WriteGrid = function(type, name, result, description)
{
    ISTestTrace.EnsureGrid();

    try
    {
        // fix color
        var color = ISTestTrace.TraceStyle.RowColorInformation;
        switch(type)
        {
            case ISTestTrace.TraceType.Verbose:  color = ISTestTrace.TraceStyle.RowColorVerbose;  break;
            case ISTestTrace.TraceType.Warning:  color = ISTestTrace.TraceStyle.RowColorWarning;  break;
            case ISTestTrace.TraceType.Error:    color = ISTestTrace.TraceStyle.RowColorError;    break;
            case ISTestTrace.TraceType.Critical: color = ISTestTrace.TraceStyle.RowColorCritical; break;

            case ISTestTrace.TraceType.InformationGreen: color = ISTestTrace.TraceStyle.RowColorGreen; break;
            case ISTestTrace.TraceType.InformationBlue:  color = ISTestTrace.TraceStyle.RowColorBlue;  break;

            default: color = ISTestTrace.TraceStyle.RowColorInformation; break;
        }

        // write
        ISTestTrace.TraceGrid.Write(color, name, result, description);
    }
    catch (e)
    {
        ISTestTrace.Ensure(true);
        ISTestTrace.Write(name, result, description);
    }
}
ISTestTrace.WriteConsole = function(type, name, result, description)
{
    var msg = '[' + name + ' : ' + result + '] '
            + description;

    switch (type)
    {
        case ISTestTrace.TraceType.Critical:         // fall through
        case ISTestTrace.TraceType.Error:            ISTraceConsole.WriteError(msg);       break;
        case ISTestTrace.TraceType.Warning:          ISTraceConsole.WriteWarning(msg);     break;
        case ISTestTrace.TraceType.InformationGreen: // fall through
        case ISTestTrace.TraceType.InformationBlue:  // fall through
        case ISTestTrace.TraceType.Information:      ISTraceConsole.WriteInformation(msg); break;
        default:                                     ISTraceConsole.WriteVerbose(msg);     break;
    }
}
ISTestTrace.TraceVerbose = function(name, result, description)
{
    ISTestTrace.Write(ISTestTrace.TraceType.Verbose, name, result, description);
}
ISTestTrace.TraceInformation = function(name, result, description)
{
    ISTestTrace.Write(ISTestTrace.TraceType.Information, name, result, description);
}
ISTestTrace.TraceWarning = function(name, result, description)
{
    ISTestTrace.Write(ISTestTrace.TraceType.Warning, name, result, description);
}
ISTestTrace.TraceError = function(name, result, description)
{
    ISTestTrace.Write(ISTestTrace.TraceType.Error, name, result, description);
}
ISTestTrace.TraceCritical = function(name, result, description)
{
    ISTestTrace.Write(ISTestTrace.TraceType.Critical, name, result, description);
}
ISTestTrace.TraceInformationGreen = function(name, result, description)
{
    ISTestTrace.Write(ISTestTrace.TraceType.InformationGreen, name, result, description);
}
ISTestTrace.TraceInformationBlue = function(name, result, description)
{
    ISTestTrace.Write(ISTestTrace.TraceType.InformationBlue, name, result, description);
}
                       
ISTrace.Level = ISTrace.TraceLevel.All; 
                                         
