// -----------------------------------------------------------------------
Infoshare.Web.Control.ContainerControlStyle = function Infoshare$Web$Control$ContainerControlStyle() { }
iContainerControlStyle = Infoshare.Web.Control.ContainerControlStyle;
iContainerControlStyle.prototype = {
    ClassName:        'is-ContainerControl',
    EnableClassName:  'is-ContainerControl-Enable',
    DisableClassName: 'is-ContainerControl-Disable',

    ActiveClassName:  'is-ContainerControl-Active'
}


// -----------------------------------------------------------------------
//  ContainerControl
// -----------------------------------------------------------------------
Infoshare.Web.Control.ContainerControl = function Infoshare$Web$Control$ContainerControl(style)
{
    Infoshare.Web.Control.Control.apply(this, arguments);

    this.Style = style ? style : new iContainerControlStyle();
    this.Controls = new ISDictionary();

    // イベント登録
    this.AddEvent(iControl.ControlEventName.EndPostRender, ISFunction.CreateDelegate(this.ContainerControl$EndPostRender, this));
}
iContainerControl = Infoshare.Web.Control.ContainerControl;
iContainerControl.TypeName = 'Infoshare.Web.Control.ContainerControl';

iContainerControl.prototype = new Infoshare.Web.Control.Control();
iContainerControl.prototype.TypeName = iContainerControl.TypeName;
iContainerControl.prototype.Controls = null;

iContainerControl.prototype.AppendChildControl = function(control)
{
    if (ISObject.TypeOf(control) == 'array')
    {
        for (var i = 0; i < control.length; i++)
        {
            this.AppendChildControlInternal(control[i]);
        }
    }
    else
    {
        this.AppendChildControlInternal(control);
    }
}
iContainerControl.prototype.AppendChildControlInternal = function(control)
{
    control.ParentControl = this;
    this.Controls.Add(control.Id, control);
}
iContainerControl.prototype.RemoveChildControl = function(control)
{
    if (ISObject.TypeOf(control) == 'array')
    {
        for (var i = 0; i < control.length; i++)
        {
            this.RemoveChildControlInternal(control[i]);
        }
    }
    else
    {
        this.RemoveChildControlInternal(control);
    }
}
iContainerControl.prototype.RemoveChildControlInternal = function(control)
{
    var id = control;
    if (control &&
        ISObject.TypeOf(control.Id) != 'undefined')
    {
        id = control.Id;
    }

    if (this.Controls.Contains(id))
    {
        this.Controls.Remove(id);
    }
}
iContainerControl.prototype.ContainerControl$EndPostRender = function()
{
    // 子コントロールのレンダリング後処理
    for (var i = 0; i < this.Controls.GetLength(); i++)
    {
        var control = this.Controls.Get(i);
        control.PostRender();
    }
}
                    
