// -----------------------------------------------------------------------
//  MovableExtender
// -----------------------------------------------------------------------
Infoshare.Web.Control.MovableExtender = function Infoshare$Web$Control$MovableExtender() { }
iMovableExtender = Infoshare.Web.Control.MovableExtender;
iMovableExtender.prototype = {
    EventSourceElement: null,
    MovingTargetElement: null,
    MovingContext: null,

    Extend: function(eventSourceElement, movingTargetElement)
    {
        this.EventSourceElement  = eventSourceElement;
        this.MovingTargetElement = movingTargetElement;
        if (!this.MovingTargetElement)
        {
            this.MovingTargetElement = this.EventSourceElement;
        }

        ISDomAccessor.AttachEvent(this.EventSourceElement, 'mousedown', ISFunction.CreateDelegate(this.BeginMove, this));
    },

    BeginMove: function()
    {
        // コンテキストを用意
        this.MovingContext = { Element: this.MovingTargetElement,
                               Position: new iPosition(event.x, event.y),

                               MouseUpEventHandler:     ISFunction.CreateDelegate(this.EndMove, this),
                               MouseMoveEventHandler:   ISFunction.CreateDelegate(this.OnMove, this),
                               SelectStartEventHandler: ISFunction.CreateDelegate(this.OnSelectStart, this) };

        // イベントをアタッチ
        ISDomAccessor.AttachEvent(document, 'mouseup',     this.MovingContext.MouseUpEventHandler);
        ISDomAccessor.AttachEvent(document, 'mousemove',   this.MovingContext.MouseMoveEventHandler);
        ISDomAccessor.AttachEvent(document, 'selectstart', this.MovingContext.SelectStartEventHandler);
    },

    EndMove: function()
    {
        // コンテキストを確認
        if (!this.MovingContext)
        {
            return;
        }

        // cache objects, then clear context
        var mouseUpEventHandler     = this.MovingContext.MouseUpEventHandler;
        var mouseMoveEventHandler   = this.MovingContext.MouseMoveEventHandler;
        var selectStartEventHandler = this.MovingContext.SelectStartEventHandler;
        this.MovingContext = null;

        // detach events
        ISDomAccessor.DetachEvent(document, 'mouseup',     mouseUpEventHandler);
        ISDomAccessor.DetachEvent(document, 'mousemove',   mouseMoveEventHandler);
        ISDomAccessor.DetachEvent(document, 'selectstart', selectStartEventHandler);
    },

    OnMove: function()
    {
        // コンテキストを確認
        if (!this.MovingContext)
        {
            return;
        }

        var element  = this.MovingContext.Element;
        var position = this.MovingContext.Position;

        // X座標を計算
        var left = ISDomAccessor.GetPixel(element, 'style.left')
                 + event.x - position.X;        
        if (ISDomAccessor.GetInnerWidth(document.body) > event.x &&
            event.x > 0)
        {
            ISDomAccessor.SetPixel(element, 'style.left', left);
            position.X = event.x;
        }

        // Y座標を計算
        var headerHeight = ISDomAccessor.GetInnerHeight(this.EventSourceElement);
        var top = ISDomAccessor.GetPixel(element, 'style.top')
                + event.y - position.Y;
        if (ISDomAccessor.GetInnerHeight(document.body) - headerHeight > event.y  &&
            event.y > headerHeight)
        {
            ISDomAccessor.SetPixel(element, 'style.top', top);
            position.Y = event.y;
        }
    },

    OnSelectStart: function()
    {
        return false;
    }
}


// -----------------------------------------------------------------------
//  ResizableExtender
// -----------------------------------------------------------------------
Infoshare.Web.Control.ResizableExtender = function Infoshare$Web$Control$ResizableExtender(panel, separator, strechOption, primaryControl, secondaryControl, minSize, maxSize)
{
    this.Panel = panel;

    this.Saparator = separator;
    this.EventSourceElement = separator.GetElement();
    this.StretchOption = strechOption;
    this.PrimaryControl = primaryControl;
    this.SecondaryControl = secondaryControl;

    if (this.StretchOption == iPanelStyle.StretchOption.Vertical)
    {
        this.MinHeight = minSize;
        this.MaxHeight = maxSize;
    }
    else if (this.StretchOption == iPanelStyle.StretchOption.Horizontal)
    {
        this.MinWidth = minSize;
        this.MaxWidth = maxSize;
    }
}
iResizableExtender = Infoshare.Web.Control.ResizableExtender;
iResizableExtender.prototype = {
    EventSourceElement: null,
    StretchOption: null,
    PrimaryControl: null,
    SecondaryControl: null,

    MinWidth: 1,
    MaxWidth: 1920,
    MinHeight: 1,
    MaxHeight: 1280,

    ResizeContext: {
        Position: null,
        MouseUpEventHandler: null,
        MouseMoveEventHandler: null,
        SelectStartEventHandler: null
    },

    Extend: function()
    {
        ISDomAccessor.AttachEvent(this.EventSourceElement, 'mousedown', ISFunction.CreateDelegate(this.BeginResize, this));
    },

    BeginResize: function()
    {
        // コンテキストを用意
        this.ResizeContext = { Position: new iPosition(event.x, event.y),
                               MouseUpEventHandler:     ISFunction.CreateDelegate(this.EndResize, this),
                               MouseMoveEventHandler:   ISFunction.CreateDelegate(this.OnResize, this),
                               SelectStartEventHandler: ISFunction.CreateDelegate(this.OnSelectStart, this) };

        // イベントをアタッチ
        ISDomAccessor.AttachEvent(document, 'mouseup',     this.ResizeContext.MouseUpEventHandler);
        ISDomAccessor.AttachEvent(document, 'mousemove',   this.ResizeContext.MouseMoveEventHandler);
        ISDomAccessor.AttachEvent(document, 'selectstart', this.ResizeContext.SelectStartEventHandler);        
    },

    EndResize: function()
    {
        // コンテキストを確認
        if (!this.ResizeContext)
        {
            return;
        }

        // cache objects, then clear context
        var mouseUpEventHandler     = this.ResizeContext.MouseUpEventHandler;
        var mouseMoveEventHandler   = this.ResizeContext.MouseMoveEventHandler;
        var selectStartEventHandler = this.ResizeContext.SelectStartEventHandler;
        this.ResizeContext = null;

        // detach events
        ISDomAccessor.DetachEvent(document, 'mouseup',     mouseUpEventHandler);
        ISDomAccessor.DetachEvent(document, 'mousemove',   mouseMoveEventHandler);
        ISDomAccessor.DetachEvent(document, 'selectstart', selectStartEventHandler);
    },

    OnResize: function()
    {
        // コンテキストを確認
        if (!this.ResizeContext)
        {
            return;
        }

        var element  = this.EventSourceElement;
        var position = this.ResizeContext.Position;

        // X方向のリサイズ
        if (this.StretchOption == iPanelStyle.StretchOption.Horizontal)
        {
            // X座標の差分を確認
            var xdif = event.clientX - position.X;
            if (xdif == 0)
            {
                return;
            }

            var primaryElmWidth   = this.PrimaryControl.Style.Size.Width;
            var secondaryElmWidth = this.SecondaryControl.Style.Size.Width;

            if (primaryElmWidth + xdif > this.MinWidth &&
                primaryElmWidth + xdif < this.MaxWidth &&
                event.clientX > 0)
            {
                this.PrimaryControl.Style.Size.Width   = primaryElmWidth + xdif;
                this.SecondaryControl.Style.Size.Width = secondaryElmWidth - xdif;
                position.X = event.clientX;
            }
            else
            {
                return;
            }
        }

        // Y方向のリサイズ
        if (this.StretchOption == iPanelStyle.StretchOption.Vertical)
        {
            // Y座標の差分を確認
            var ydif = event.clientY - position.Y;
            if (ydif == 0)
            {
                return;
            }

            var primaryElmHeight   = ISDomAccessor.GetHeight(this.primaryControl);
            var secondaryElmHeight = ISDomAccessor.GetHeight(this.secondaryControl);
            if (primaryElmHeight   + ydif > this.MinWidth &&
                primaryElmHeight   + ydif < this.MaxWidth &&
                event.clientY > 0)
            {
                ISDomAccessor.SetHeightWithMaxMin(this.primaryControl,   primaryElmHeight   + ydif);
                ISDomAccessor.SetHeightWithMaxMin(this.secondaryControl, secondaryElmHeight - ydif);
                position.Y = event.clientY;
            }
        }

        this.Panel.OnResize();
    },

    OnSelectStart: function()
    {
        return false;
    }
}
                    
