// -----------------------------------------------------------------------
//  Panel
// -----------------------------------------------------------------------
Infoshare.Web.Control.Panel = function Infoshare$Web$Control$Panel(style)
{
    Infoshare.Web.Control.ContainerControl.apply(this, arguments);

    this.Style = style ? style : new iPanelStyle();

    // イベント登録
    this.AddEvent(iControl.ControlEventName.PostRender, ISFunction.CreateDelegate(this.Panel$PostRender, this));
    this.AddEvent(iControl.ControlEventName.EndAttachEvents, ISFunction.CreateDelegate(this.Panel$EndAttachEvents, this));
}
iPanel = Infoshare.Web.Control.Panel;
iPanel.TypeName = 'Infoshare.Web.Control.Panel';

iPanel.prototype = new Infoshare.Web.Control.ContainerControl();
iPanel.prototype.TypeName = iPanel.TypeName;
iPanel.prototype.EnableDelayedEvent = false;
iPanel.prototype.RenderMarkup = function(writer)
{
    // スタイル設定: インラインスタイルの場合の特殊対応
    var style = '';
    if (this.Style.DisplayType == iPanelStyle.DisplayType.Inline)
    {
        //style = "style='display:inline-block; /display: inline; /zoom: 1;' ";
        style += 'float: ' + this.Style.Alignment + ';';
    }

    // スタイル設定: 表示位置
    if (this.Style.Position)
    {
        if (this.Style.Position.X > 0) { style += 'left: ' + this.Style.Position.X + 'px;' }
        if (this.Style.Position.Y > 0) { style += 'top: '  + this.Style.Position.Y + 'px;' }
    }

    // スタイル設定
    if (!iString.IsNullOrEmpty(style))
    {
        if (this.Attributes.Contains('style'))
        {
            style += this.Attributes.Get('style');
            this.Attributes.Set('style', style);
        }
        else
        {
            this.Attributes.Add('style', style);
        }
    }

    // レンダリング
    writer[writer.length] = "<div ";
    this.RenderAttributes(writer);
    writer[writer.length] =      "id='" + this.GetElementId() + "' ";
    writer[writer.length] =      "class='" + this.GetClassName() + "' ";
    writer[writer.length] =      "title='" + iXml.Escape(this.Tooltip) + "'";
    writer[writer.length] = ">";

    // コントロールまたはテキストをレンダリング
    if (this.Controls.GetLength() > 0)
    {
        for (var i = 0; i < this.Controls.GetLength(); i++)
        {
            var control = this.Controls.Get(i);
            control.PreRender();
            control.RenderMarkup(writer);
        }
    }
    else
    {
        // 改行処理
        var text = iXml.Escape(this.Text);
        text = iString.Replace(text, '\r\n', '<br />');
        text = iString.Replace(text, '[\r\n]', '<br />');

        writer[writer.length] = text;
    }

    writer[writer.length] = "</div>";
}
iPanel.prototype.Panel$PostRender = function()
{
    this.OnResize();
}
iPanel.prototype.Panel$EndAttachEvents = function()
{
    if (this.EnableDelayedEvent) { this.AttachDomEvent(iControl.DomEventName.Resize, iFunction.CreateDelegate(this.OnResizeWrapper, this)); }
    else                         { this.AttachDomEvent(iControl.DomEventName.Resize, iFunction.CreateDelegate(this.OnResize, this)); }
}

// -----------------------------------------------------------------------
//  Panel: Size handling
// -----------------------------------------------------------------------
iPanel.prototype.ResizeEventWait = 128;
iPanel.prototype.ResizeEventTimerId = null;
iPanel.prototype.OnResizeWrapper = function(args)
{
    // 先行するリサイズイベント待ちがある場合はクリアする
    clearTimeout(this.ResizeEventTimerId);

    // リサイズイベントを時間差実行
    var instance = this;
    this.ResizeEventTimerId = setTimeout(function()
    {
        instance.OnResize(args);
    }, this.ResizeEventWait);
}
iPanel.prototype.OnResize = function(args)
{
    this.FireEventByName(iControl.ControlEventName.BeginResize, this);

    //ISTrace.TraceVerbose('[' + this.TypeName + ']::OnResize');

    // -----------------------------------------------------
    // リサイズ対象要素確認
    // -----------------------------------------------------
    var element = this.GetElement();
    if (!element)
    {
        ISTrace.TraceError('[' + this.TypeName + ']::OnResize: Cannot find panel element.');
        return;
    }

    // -----------------------------------------------------
    //  静的なサイズを設定
    // -----------------------------------------------------
    // 横方向のサイズ調整
    if (this.Style.StretchOption == iPanelStyle.StretchOption.Vertical ||
        this.Style.StretchOption == iPanelStyle.StretchOption.None)
    {
        this.SetWidthInternal(element, this.Style.Size.Width);
    }

    // 縦方向のサイズ調整
    if (this.Style.StretchOption == iPanelStyle.StretchOption.Horizontal ||
        this.Style.StretchOption == iPanelStyle.StretchOption.None)
    {
        this.SetHeightInternal(element, this.Style.Size.Height);
    }

    // -----------------------------------------------------
    //  動的なサイズを設定
    // -----------------------------------------------------
    // 横方向のサイズ調整
    if (this.Style.StretchOption == iPanelStyle.StretchOption.Horizontal ||
        this.Style.StretchOption == iPanelStyle.StretchOption.Both)
    {
        var parent = this.GetParentElement();
        var width = ISDomAccessor.GetInnerWidth(parent);
        if (parent.tagName.toUpperCase() == 'BODY')
        {
            // 親がbodyの場合は、ウィンドウサイズを考慮してリサイズする
            var documentWidth = ISDomAccessor.GetInnerWidth(document.documentElement);

            // margin、border、paddingを考慮
            var outerWidth = ISDomAccessor.GetOuterWidth(parent);
            var innerWidth = ISDomAccessor.GetInnerWidth(parent);
            width = documentWidth - (outerWidth - innerWidth);
        }

        this.SetWidthInternal(element, width);

        //ISTrace.TraceVerbose('[' + this.TypeName + ']::OnResize: width: ' + width + ' px');
    }

    // 縦方向のサイズ調整
    if (this.Style.StretchOption == iPanelStyle.StretchOption.Vertical ||
        this.Style.StretchOption == iPanelStyle.StretchOption.Both)
    {
        var parent = this.GetParentElement();
        var height = ISDomAccessor.GetInnerHeight(parent);
        if (parent.tagName.toUpperCase() == 'BODY')
        {
            // 親がbodyの場合は、ウィンドウサイズを考慮してリサイズする
            var documentHeight = ISDomAccessor.GetInnerHeight(document.documentElement);

            // margin、border、paddingを考慮
            var outerHeight = ISDomAccessor.GetOuterHeight(parent);
            var innerHeight = ISDomAccessor.GetInnerHeight(parent);
            height = documentHeight - (outerHeight - innerHeight);
        }

        this.SetHeightInternal(element, height);

        //ISTrace.TraceVerbose('[' + this.TypeName + ']::OnResize: height: ' + height + ' px');
    }

    // 子コントロールのリサイズ
    this.OnResizeChildControls(args);

    this.FireEventByName(iControl.ControlEventName.EndResize, this);
}
iPanel.prototype.OnResizeChildControls = function(args)
{
    this.FireEventByName(iControl.ControlEventName.BeginResizeChildren, this);

    for (var i = 0; i < this.Controls.GetLength() ; i++)
    {
        var control = this.Controls.Get(i);
        if (control &&
            ISObject.TypeOf(control.OnResize) == 'function')
        {
            control.OnResize(args);
        }
    }

    this.FireEventByName(iControl.ControlEventName.EndResizeChildren, this);
}

// -----------------------------------------------------------------------
//  Panel: Utilities
// -----------------------------------------------------------------------
iPanel.prototype.GetWidth = function()
{
    return ISDomAccessor.GetWidth(this.GetElement());
}
iPanel.prototype.GetHeight = function()
{
    return ISDomAccessor.GetHeight(this.GetElement());
}
iPanel.prototype.SetWidth = function(width)
{
    this.Style.Width = width;
    this.SetWidthInternal(null, width);
}
iPanel.prototype.SetHeight = function(height)
{
    this.Style.Height = height;
    this.SetHeightInternal(null, height);
}
iPanel.prototype.SetWidthInternal = function(element, width)
{
    if (!element)
    {
        element = this.GetElement();
    }

    // 幅が負の場合は高さを設定しない（auto sizing）
    if (width < 0)
    {
        return;
    }

    // margin, border, paddingを考慮
    var outerWidth = ISDomAccessor.GetOuterWidth(element);
    var innerWidth = ISDomAccessor.GetInnerWidth(element);

    // 最大幅を超えず、最小幅より小さくならないように幅を設定
    if (this.Style.MaxSize.Width >= 0) { width = Math.min(width, this.Style.MaxSize.Width); }
    if (this.Style.MinSize.Width >= 0) { width = Math.max(width, this.Style.MinSize.Width); }
    ISDomAccessor.SetWidth(element, width - (outerWidth - innerWidth));

    // 最大幅・最小幅を設定
    var isInlineStyle = this.Style.DisplayType == iPanelStyle.DisplayType.Inline;
    if (this.Style.MaxSize.Width >= 0) { ISDomAccessor.SetPixel(element, 'style.maxWidth', this.Style.MaxSize.Width); }
    else if (isInlineStyle)            { ISDomAccessor.SetPixel(element, 'style.maxWidth', width); }
    if (this.Style.MinSize.Width >= 0) { ISDomAccessor.SetPixel(element, 'style.minWidth', this.Style.MinSize.Width); }
    else if (isInlineStyle)            { ISDomAccessor.SetPixel(element, 'style.minWidth', width); }
}
iPanel.prototype.SetHeightInternal = function(element, height)
{
    if (!element)
    {
        element = this.GetElement();
    }

    // 高さが負の場合は高さを設定しない（auto sizing）
    if (height < 0)
    {
        return;
    }

    // margin, border, paddingを考慮
    var outerHeight = ISDomAccessor.GetOuterHeight(element);
    var innerHeight = ISDomAccessor.GetInnerHeight(element);

    // 最大高を超えず、最少高より小さくならないように高さを設定
    if (this.Style.MaxSize.Height >= 0) { height = Math.min(height, this.Style.MaxSize.Height); }
    if (this.Style.MinSize.Height >= 0) { height = Math.max(height, this.Style.MinSize.Height); }
    ISDomAccessor.SetHeight(element, height - (outerHeight - innerHeight));

    // 最大高・最少高を設定
    var isInlineStyle = this.Style.DisplayType == iPanelStyle.DisplayType.Inline;
    if (this.Style.MaxSize.Height >= 0) { ISDomAccessor.SetPixel(element, 'style.maxHeight', this.Style.MaxSize.Height); }
    else if (isInlineStyle)             { ISDomAccessor.SetPixel(element, 'style.minHeight', height); }
    if (this.Style.MinSize.Height >= 0) { ISDomAccessor.SetPixel(element, 'style.minHeight', this.Style.MinSize.Height); }
    else if (isInlineStyle)             { ISDomAccessor.SetPixel(element, 'style.minHeight', height); }
}
                    
