{
    Infoshare.Web.Control.PanelStyle.apply(this);

    this.ClassName        = 'is-SplitPanel';
    this.EnableClassName  = 'is-SplitPanel-Enable';
    this.DisableClassName = 'is-SplitPanel-Disable';

    this.ActiveClassName  = 'is-SplitPanel-Active';

    this.Mode  = iSplitPanelStyle.Mode.Horizontal;
    this.Count = 1;
    this.SeparatorSize = 3;
}
iSplitPanelStyle = Infoshare.Web.Control.SplitPanelStyle;
iSplitPanelStyle.Mode = { Horizontal: 'Horizontal',
                          Vertical:   'Vertical' };
iSplitPanelStyle.prototype = new Infoshare.Web.Control.PanelStyle();
iSplitPanelStyle.prototype.Mode = null;
iSplitPanelStyle.prototype.Count = null;
iSplitPanelStyle.prototype.ContainerStyles = null;
iSplitPanelStyle.prototype.SeparatorStyle  = null;

