// -----------------------------------------------------------------------
//  TabPanel
// -----------------------------------------------------------------------
Infoshare.Web.Control.TabPanel = function Infoshare$Web$Control$TabPanel(style)
{
    Infoshare.Web.Control.Panel.apply(this, arguments);

    this.Style = style ? style : new iTabPanelStyle();
    this.Tabs = new Array();

    // イベント登録
    this.AddEvent(iControl.ControlEventName.EndPreRender, ISFunction.CreateDelegate(this.TabPanel$PreRender, this));
    this.AddEvent(iControl.ControlEventName.BeginResizeChildren, ISFunction.CreateDelegate(this.TabPanel$Resise, this));
}
iTabPanel = Infoshare.Web.Control.TabPanel;
iTabPanel.TypeName = 'Infoshare.Web.Control.TabPanel';
iTabPanel.EventName = { SelectedTabChanged: 'SelectedTabChanged' };

iTabPanel.prototype = new Infoshare.Web.Control.Panel();
iTabPanel.prototype.TypeName = iTabPanel.TypeName;
iTabPanel.prototype.Tabs = null;
iTabPanel.prototype.Header = null;
iTabPanel.prototype.HeaderTitle = null;
iTabPanel.prototype.HeaderButtonArea = null;
iTabPanel.prototype.Body = null;

// -----------------------------------------------------------------------
//  TabPanel: Rendering
// -----------------------------------------------------------------------
iTabPanel.prototype.TabPanel$PreRender = function()
{
    this.InitializeHeader();
    this.InitializeBody();
}
iTabPanel.prototype.InitializeHeader = function()
{
    // ヘッダ
    this.Header = new iPanel(this.Style.HeaderStyle);
    this.AppendChildControl(this.Header);

    // タブ
    var selectedIndex = 0;
    for (var i = 0; i < this.Tabs.length; i++)
    {
        // タブの初期化
        var info = this.Tabs[i];
        var tab = new iPanel(this.Style.TabStyle);
        tab.Style.DisplayType = iPanelStyle.DisplayType.Inline;
        tab.Text = info.Title;
        tab.AddEvent(iControl.DomEventName.Click, ISFunction.CreateDelegate(this.ActivateTab, this));
        info.Tab = tab;

        // 選択状態を取
        if (info.Active)
        {
            selectedIndex = i;
        }

        this.Header.AppendChildControl(tab);
    }

    // 選択状態を設定
    // 選択状態がない場合は最初のタブをアクティブとする
    // 複数選択されている場合は最後に選択状態にあるものをアクティブとする
    for (var i = 0; i < this.Tabs.length; i++)
    {
        var info = this.Tabs[i];
        info.Active = i == selectedIndex;
        info.Tab.Active = info.Active;
    }
}
iTabPanel.prototype.InitializeBody = function()
{
    // ボディ
    this.Body = new iPanel(this.Style.BodyStyle);
    this.Body.Style.Size.Height = this.Style.Size.Height - this.Style.HeaderStyle.Size.Height;
    this.AppendChildControl(this.Body);

    // パネルコンテナ
    for (var i = 0; i < this.Tabs.length; i++)
    {
        // コンテナの初期化
        var info = this.Tabs[i];
        var container = new iPanel(this.Style.ContainerStyle);
        container.Style.StretchOption = iPanelStyle.StretchOption.Both;
        container.Hidden = !info.Active;
        info.Container = container;

        this.Body.AppendChildControl(container);
    }
}
iTabPanel.prototype.TabPanel$Resise = function()
{
    this.Body.SetHeightInternal(null, this.GetHeight() - this.Header.GetHeight());
}

// -----------------------------------------------------------------------
//  TabPanel: Events
// -----------------------------------------------------------------------
iTabPanel.prototype.SelectedTab = null;
iTabPanel.prototype.ActivateTab = function(arg)
{
    var elementId = null;
    // arg が TabIdの場合
    if (typeof(arg) == 'string')
    {
        elementId = arg;
    }
    // arg が Tab の場合    
    if (typeof(arg) == 'object')
    {
        elementId = arg.ElementId;
    }
    // arg が TabIndexの場合
    if (typeof(arg) == 'number')
    {
        elementId = this.Tabs[arg].Tab.ElementId;
    }

    for (var i = 0; i < this.Tabs.length; i++)
    {
        var info = this.Tabs[i];
        info.Active = info.Tab.ElementId == elementId;

        // タブの状態切り替え
        info.Tab.Active = info.Active;
        info.Tab.ApplyStyle();

        // コンテナの状態切り替え
        info.Container.Hidden = !info.Active;
        info.Container.ApplyStyle();

        // 選択状態のタブを取得
        if (info.Active)
        {
            this.SelectedTab = info;
        }
    }

    this.FireEventByName(iTabPanel.EventName.SelectedTabChanged, this);
}
                    
