iInlineFrameStyle.prototype = {
    Url: ''
}


// -----------------------------------------------------------------------
//  InlineFrame
// -----------------------------------------------------------------------
Infoshare.Web.Control.InlineFrame = function Infoshare$Web$Control$InlineFrame(style)
{
    Infoshare.Web.Control.Panel.apply(this, arguments);

    this.Style = style ? style : new iInlineFrameStyle();

    // イベント登録
    this.AddEvent(iControl.ControlEventName.BeginAttachEvents, ISFunction.CreateDelegate(this.InlineFrame$BeginAttachEvents, this));
}
iInlineFrame = Infoshare.Web.Control.InlineFrame;
iInlineFrame.TypeName = 'Infoshare.Web.Control.InlineFrame';
iInlineFrame.EventName = { Load: 'Load' };
iInlineFrame.State = { Loading:     'loading',
                       Interactive: 'interactive',
                       Complete:    'complete' };

iInlineFrame.prototype = new Infoshare.Web.Control.Panel();
iInlineFrame.prototype.TypeName = iInlineFrame.TypeName;
iInlineFrame.prototype.EnableDelayedEvent = false;
iInlineFrame.prototype.RenderMarkup = function(writer)
{
    // レンダリング
    writer[writer.length] = "<iframe id='" + this.GetElementId() + "'";
    writer[writer.length] =         "style='display: " + (this.Hidden ? 'none' : '') + "; '";
    writer[writer.length] =         "src='" + this.Style.Url + "' ";

    if(ISBrowser.IsIE() &&
       ISBrowser.GetDocumentVersion() <= 8)
    {
        writer[writer.length] = "frameborder='0' ";
    }

    writer[writer.length] =         ">";
    writer[writer.length] = "</iframe>";
}
iInlineFrame.prototype.InlineFrame$BeginAttachEvents = function()
{
    this.AttachDomEvent(iControl.DomEventName.Load,             iFunction.CreateDelegate(this.OnLoad, this));
    this.AttachDomEvent(iControl.DomEventName.ReadyStateChange, iFunction.CreateDelegate(this.OnLoad, this));
}
iInlineFrame.prototype.LoadCompleted = false;
iInlineFrame.prototype.OnLoad = function(eventArg)
{
    if (this.LoadCompleted)
    {
        return;
    }

    if (eventArg.type == 'readystatechange')
    {
        if (eventArg.srcElement.readyState == ISInlineFrame.State.Complete)
        {
            this.LoadCompleted = true;
        }
    }
    else // load event case
    {
        this.LoadCompleted = true;
    }

    if (this.LoadCompleted)
    {
        this.FireEventByName(iInlineFrame.EventName.Load, this);
    }
}
iInlineFrame.prototype.GetContentWindow = function()
{
    return this.GetElement().contentWindow;
}
                    
