ISNamespace.Register('Infoshare.Web.Control');


// -----------------------------------------------------------------------
//  ISPosition
// -----------------------------------------------------------------------
Infoshare.Web.Control.InlineFrame = function Infoshare$Web$Control$InlineFrame() { }
ISInlineFrame = Infoshare.Web.Control.InlineFrame;
ISInlineFrame.TypeName = 'Infoshare.Web.Control.InlineFrame';
ISInlineFrame.State = { Loading:     'loading',
                        Interactive: 'interactive',
                        Complete:    'complete' };

ISInlineFrame.prototype = {
    TypeName: ISInlineFrame.TypeName,
    Name: '',

    ParentElement: null,
    ElementId: '',
    Element: null,

    Width   : 320,
    Height  : 240,
    Display : true,
    Url     : '',

    OnLoadEventHandler: null,

    ParentElementCreated: false,
    OnReadyStateChangeComplated: false,
    ReadyStateChangeDelegate: null,

    GetContentWindow: function()
    {
        var wnd = null;
        if (this.Element)
        {
            wnd = this.Element.contentWindow;
        }

        return wnd;
    },

    Render: function()
    {
        // ensure parent
        if (!this.ParentElement)
        {
            this.ParentElementCreated = true;
            this.ParentElement = document.createElement('div');
            document.body.appendChild(this.ParentElement);
        }

        // ensure id
        if (ISString.IsNullOrEmpty(this.ElementId))
        {
            this.ElementId = ISControlUtility.BuildId(this.TypeName, this.Name);
        }

        // build markup
        var markup = new Array();
        markup[markup.length] = "<iframe id='" + this.ElementId + "'";
        markup[markup.length] =         "style='width: "   + this.Width  + "px; ";
        markup[markup.length] =                "height: "  + this.Height + "px; ";
        markup[markup.length] =                "display: " + (this.Display ? '' : 'none') + "; ";
        markup[markup.length] =                "'";
        markup[markup.length] =         ">";
        markup[markup.length] = "</iframe>";

        // insert iframe
        this.ParentElement.innerHTML = markup.join('');

        // attach event
        this.Element = ISDomAccessor.GetChildElement(this.ParentElement);
        this.ReadyStateChangeDelegate = ISFunction.CreateDelegate(this.OnReadyStateChange, this);
        ISDomAccessor.AttachEvent(this.Element, 'load',             this.ReadyStateChangeDelegate);
        ISDomAccessor.AttachEvent(this.Element, 'readystatechange', this.ReadyStateChangeDelegate);

        // set url
        this.Element.src = this.Url;
    },

    Remove: function()
    {
        // check element
        if (!this.Element)
        {
            return;
        }

        // detach event
        ISDomAccessor.DetachEvent(this.Element, 'load',             this.ReadyStateChangeDelegate);
        ISDomAccessor.DetachEvent(this.Element, 'readystatechange', this.ReadyStateChangeDelegate);
        this.ReadyStateChangeDelegate = null;

        // remove element
        if (this.ParentElementCreated)
        {
            var parent = ISDomAccessor.GetParentElement(this.ParentElement);
            parent.removeChild(this.ParentElement);                    
        }
        else
        {
            var parent = ISDomAccessor.GetParentElement(this.Element);
            parent.removeChild(this.Element);
        }

        // clear references
        if (this.ParentElementCreated)
        {
            this.ParentElement = null;
            this.ParentElementCreated = false;
        }
        this.Element = null
        this.ElementId = '';
    },

    OnReadyStateChange: function(eventArg)
    {
        if (!this.OnReadyStateChangeComplated &&
            this.OnLoadEventHandler)
        {
            if (eventArg.type == 'readystatechange')
            {
                if (eventArg.srcElement.readyState == ISInlineFrame.State.Complete)
                {
                    this.OnReadyStateChangeComplated = true;
                    this.OnLoadEventHandler();
                }
            }
            else // load event case
            {
                this.OnReadyStateChangeComplated = true;
                this.OnLoadEventHandler();
            }
        }
    }
}
                    
