//  Imagebutton
// -----------------------------------------------------------------------
Infoshare.Web.Control.ImageButton = function Infoshare$Web$Control$ImageButton(style)
{
    Infoshare.Web.Control.Button.apply(this, arguments);

    this.Style = style ? style : new iImageButtonStyle();

    // イベント登録
    this.AddEvent(iControl.ControlEventName.EndApplyStyle, ISFunction.CreateDelegate(this.ImageButton$ApplyStyle, this));
}
iImageButton = Infoshare.Web.Control.ImageButton;
iImageButton.TypeName = 'Infoshare.Web.Control.Imagebutton';

iImageButton.prototype = new Infoshare.Web.Control.Button();
iImageButton.prototype.TypeName = iImageButton.TypeName;
iImageButton.prototype.AlternativeText = '';
iImageButton.prototype.RenderMarkup = function(writer)
{
    writer[writer.length] = "<img id='" + this.GetElementId() + "' ";
    writer[writer.length] =      "class='" + this.GetClassName() + "' ";
    writer[writer.length] =      "src='" + this.GetImageUrl() + "' ";
    writer[writer.length] =      "alt='" + this.AlternativeText + "' ";
    writer[writer.length] =      "title='" + this.Tooltip + "' />";
}
iImageButton.prototype.ImageButton$ApplyStyle = function()
{
    var element = this.GetElement();
    element.src = this.GetImageUrl();
}
iImageButton.prototype.GetImageUrl = function()
{
    var url = '';
    for (;;)
    {
        // プレス
        if (this.Pressed)
        {
            url = this.Style.Images.Press;
            break;
        }

        // 有効・無効
        if (this.Enabled)
        {
            if (this.Hovered) { url = this.Style.Images.EnableHover; }
            else              { url = this.Style.Images.Enable; }
        }
        else
        {
            if (this.Hovered) { url = this.Style.Images.DisableHover; }
            else              { url = this.Style.Images.Disable; }
        }

        break;
    }

    return url;
}
                    
