Infoshare.Web.Control.Label = function Infoshare$Web$Control$Label(style)
{
    Infoshare.Web.Control.Control.apply(this, arguments);

    this.Style = style ? style : new iLabelStyle();
}
iLabel = Infoshare.Web.Control.Label;
iLabel.TypeName = 'Infoshare.Web.Control.Label';

iLabel.prototype = new Infoshare.Web.Control.Control();
iLabel.prototype.TypeName = iLabel.TypeName;
iLabel.prototype.RenderMarkup = function(writer)
{
    // 有効・無効を判断
    var disabled = '';
    if (!this.Enabled)
    {
        this.Attributes.Add('disabled', 'disabled')
    }

    // 改行処理
    var text = iXml.Escape(this.Text);
    text = iString.Replace(text, '\r\n',   '<br />');
    text = iString.Replace(text, '[\r\n]', '<br />');

    // レンダリング
    writer[writer.length] = "<span ";
    this.RenderAttributes(writer);
    writer[writer.length] =        "id='" + this.GetElementId() + "' ";
    writer[writer.length] =        "class='" + this.GetClassName() + "' ";
    writer[writer.length] =        "title='" + iXml.Escape(this.Tooltip) + "'";
    writer[writer.length] = ">";
    writer[writer.length] =   text;
    writer[writer.length] = "</span>";
}
                    
