Infoshare.Web.Control.CheckBox = function Infoshare$Web$Control$CheckBox(style)
{
    Infoshare.Web.Control.Control.apply(this, arguments);

    this.Style = style ? style : new iCheckBoxStyle();

    // イベント登録
    this.AddEvent(iControl.ControlEventName.BeginAttachEvents, ISFunction.CreateDelegate(this.CheckBox$BeginAttachEvents, this));
}
iCheckBox = Infoshare.Web.Control.CheckBox;
iCheckBox.TypeName = 'Infoshare.Web.Control.CheckBox';

iCheckBox.prototype = new Infoshare.Web.Control.Control();
iCheckBox.prototype.TypeName = iCheckBox.TypeName;
iCheckBox.prototype.Checked = false;
iCheckBox.prototype.Dirty = false;

iCheckBox.prototype.RenderMarkup = function(writer)
{
    // 有効・無効を判断
    var disabled = '';
    if (!this.Enabled)
    {
        disabled = "disabled='disabled' ";
    }

    // チェック・案チェックを判断
    var checked = '';
    if (this.checked)
    {
        checked = "checked='true' ";
    }

    // レンダリング
    writer[writer.length] = "<input id='" + this.GetElementId() + "' ";
    writer[writer.length] =        "type='checkbox' ";
    writer[writer.length] =        "class='" + this.GetClassName() + "' ";
    writer[writer.length] =        disabled;
    writer[writer.length] =        checked;
    writer[writer.length] =        "value='" + iXml.Escape(this.Title) + "' ";
    writer[writer.length] =        "title='" + iXml.Escape(this.Tooltip) + "' />";
}
iCheckBox.prototype.CheckBox$BeginAttachEvents = function()
{
    this.AttachDomEvent(iControl.DomEventName.Change, iFunction.CreateDelegate(this.OnChange, this));
}
iCheckBox.prototype.OnChange = function()
{
    this.Dirty = true;

    this.FireEventByName(iControl.DomEventName.Change, this);
}
iCheckBox.prototype.Check = function(withoutEventFireing)
{
    this.ChangeState(true, withoutEventFireing);
}
iCheckBox.prototype.UnCheck = function(withoutEventFireing)
{
    this.ChangeState(false, withoutEventFireing);
}
iCheckBox.prototype.ChangeState = function(state, withoutEventFireing)
{
    var currentState = this.IsChecked();

    this.GetElement().checked = state;

    if (state != currentState &&
        !withoutEventFireing)
    {
        this.OnChange();
    }
}
iCheckBox.prototype.IsChecked = function()
{
    return this.GetElement().checked;
}


