// -----------------------------------------------------------------------
//  ListBox
// -----------------------------------------------------------------------
Infoshare.Web.Control.ListBox = function Infoshare$Web$Control$ListBox(style)
{
    Infoshare.Web.Control.Control.apply(this, arguments);

    this.Style = style ? style : new iListBoxStyle();

    // イベント登録
    this.AddEvent(iControl.ControlEventName.BeginAttachEvents, ISFunction.CreateDelegate(this.ListBox$BeginAttachEvents, this));
}
iListBox = Infoshare.Web.Control.ListBox;
iListBox.TypeName = 'Infoshare.Web.Control.ListBox';

iListBox.prototype = new Infoshare.Web.Control.Control();
iListBox.prototype.TypeName = iListBox.TypeName;
iListBox.prototype.RowCount = 1;
iListBox.prototype.AllowMultipleSelection = false;
iListBox.prototype.Options = null;
iListBox.prototype.RenderMarkup = function(writer)
{
    var attributes = '';

    // 有効・無効を判断
    if (!this.Enabled)               { attributes += "disabled='disabled' "; }
    // 複数選択
    if (this.AllowMultipleSelection) { attributes += "multiple='true' "; }
    // 表示行数
    if (this.RowCount > 1)           { attributes += "size='" + this.RowCount + "' "; }

    // レンダリング
    writer[writer.length] = "<select id='" + this.GetElementId() + "' ";
    writer[writer.length] =         "class='" + this.GetClassName() + "' ";
    writer[writer.length] =         attributes;
    writer[writer.length] =         "title='" + iXml.Escape(this.Tooltip) + "' >";

    // 選択状態を初期化（複数選択許可の場合と複数行表示の場合は考慮しない）
    // すべてのオプションの中で最後に選択されているものを選択されていることとする
    // 何も選択されていない場合は最初の要素を選択させる
    if (!this.AllowMultipleSelection &&
        this.RowCount <= 1)
    {
        var selectedIndex = -1;
        for (var i = 0; i < this.Options.length; i++)
        {
            var option = this.Options[i];
            if (option.Selected && !option.Disabled)
            {
                selectedIndex = i;
            }

            // 最後に初期化するためいったんfalseを設定
            option.Selected = false;
        }
        if (selectedIndex < 0)
        {
            selectedIndex = 0;
        }
        this.Options[selectedIndex].Selected = true;
    }

    // レンダリング: オプション
    var selectedIndex = -1;
    for (var i = 0; i < this.Options.length; i++)
    {
        var option = this.Options[i];
        var selected = '';
        if (option.Selected)
        {
            selected = "selected='true' ";
        }

        writer[writer.length] =   "<option value='" + option.Key + "' ";
        writer[writer.length] =            selected;
        writer[writer.length] =   ">";
        writer[writer.length] =     iXml.Escape(option.Value);
        writer[writer.length] =   "</option>";
    }

    writer[writer.length] = "</select>";
}
iListBox.prototype.ListBox$BeginAttachEvents = function()
{
    this.AttachDomEvent(iControl.DomEventName.Change, iFunction.CreateDelegate(this.OnChange, this));
}
iListBox.prototype.OnChange = function()
{
    this.FireEventByName(iControl.DomEventName.Change, this);
}
iListBox.prototype.GetSelectedItems = function()
{
    var items = new Array();
    var element = this.GetElement();
    for (var i = 0; i < element.options.length; i++)
    {
        var option = element.options[i];
        if (option.selected)
        {
            items.push(this.Options[i]);
        }
    }

    return items;
}


// -----------------------------------------------------------------------
//  ListBoxItem
// -----------------------------------------------------------------------
Infoshare.Web.Control.ListBoxItem = function Infoshare$Web$Control$ListBoxItem(key, value, selected, disabled)
{
    this.Key      = ISString.IsNullOrEmpty(key)   ? this.Key   : key;
    this.Value    = ISString.IsNullOrEmpty(value) ? this.Value : value;
    this.Selected = ISObject.IsNullOrUndefined(selected) ? this.Selected : ISBoolean.Parse(selected);
    this.Disabled = ISObject.IsNullOrUndefined(disabled) ? this.Disabled : ISBoolean.Parse(disabled);
}
iListBoxItem = Infoshare.Web.Control.ListBoxItem;
iListBoxItem.prototype = {
    TypeName: iListBoxItem.TypeName,

    Key: '',
    Value: '',
    Selected: false,
    Disabled: false
};
                    
