// -----------------------------------------------------------------------
//  TextBox
// -----------------------------------------------------------------------
Infoshare.Web.Control.TextBox = function Infoshare$Web$Control$TextBox(style)
{
    Infoshare.Web.Control.Control.apply(this, arguments);

    this.Style = style ? style : new iTextBoxStyle();

    // イベント登録
    this.AddEvent(iControl.ControlEventName.BeginAttachEvents, ISFunction.CreateDelegate(this.TextBox$BeginAttachEvents, this));
    this.AddEvent(iControl.ControlEventName.EndPostRender, ISFunction.CreateDelegate(this.TextBox$EndPostRender, this));
}
iTextBox = Infoshare.Web.Control.TextBox;
iTextBox.TypeName = 'Infoshare.Web.Control.TextBox';

iTextBox.prototype = new Infoshare.Web.Control.Control();
iTextBox.prototype.TypeName = iTextBox.TypeName;
iTextBox.prototype.Value = '';
iTextBox.prototype.Watermark = '';
iTextBox.prototype.Dirty = false;

//--------------------------------------------------------------------
// TextBox: Rendering
//--------------------------------------------------------------------
iTextBox.prototype.RenderMarkup = function(writer)
{
    // 初期値を設定
    var defaultValue = this.Value;
    if (ISString.IsNullOrEmpty(defaultValue))
    {
        defaultValue = '';
    }
    this.Dirty = !ISString.IsNullOrEmpty(defaultValue);

    // レンダリング
    writer[writer.length] = "<input "
    this.RenderAttributes(writer);
    writer[writer.length] =        "type='text' ";
    writer[writer.length] =        "id='"    + this.GetElementId() + "' ";
    writer[writer.length] =        "class='" + this.GetClassName() + "' ";
    writer[writer.length] =        "title='" + iXml.Escape(this.Tooltip) + "' ";
    writer[writer.length] =        "value='" + iXml.Escape(defaultValue) + "' ";
    writer[writer.length] = " />";
}
iTextBox.prototype.TextBox$BeginAttachEvents = function()
{
    this.AttachDomEvent(iControl.DomEventName.Focus,    iFunction.CreateDelegate(this.OnFocus, this));
    this.AttachDomEvent(iControl.DomEventName.Blur,     iFunction.CreateDelegate(this.OnBlur, this));
    this.AttachDomEvent(iControl.DomEventName.Change,   iFunction.CreateDelegate(this.OnChange, this));
    this.AttachDomEvent(iControl.DomEventName.KeyPress, iFunction.CreateDelegate(this.OnKeyPress, this));
    this.AttachDomEvent(iControl.DomEventName.KeyUp,    iFunction.CreateDelegate(this.OnKeyUp, this));
}
iTextBox.prototype.TextBox$EndPostRender = function()
{
    this.OnBlur();
}

//--------------------------------------------------------------------
// TextBox: events
//--------------------------------------------------------------------
iTextBox.prototype.ColorCache = '';
iTextBox.prototype.OnFocus = function()
{
    if (!this.Dirty)
    {
        this.SetValue('', true);

        var element = this.GetElement();
        element.style.color = this.ColorCache;
    }

    this.FireEventByName(iControl.DomEventName.Focus, this);
}
iTextBox.prototype.OnBlur = function()
{
    if (!this.Dirty)
    {
        this.SetValue(this.Watermark, true);

        var element = this.GetElement();
        this.ColorCache = element.style.color;
        element.style.color = 'gray';
    }

    this.FireEventByName(iControl.DomEventName.Blur, this);
}
iTextBox.prototype.OnChange = function()
{
    this.Dirty = !ISString.IsNullOrEmpty(this.GetElement().value);

    this.FireEventByName(iControl.DomEventName.Change, this);
}
iTextBox.prototype.OnKeyPress = function()
{
    // マウス操作によるペースト + Enterキーのパターンなどで、
    // OnChangeやOnKeyUpイベントが呼ばれる前にGetValueが呼ばれるパターンがあるのでKeyPressでもDirty判断を行う
    this.Dirty = !ISString.IsNullOrEmpty(this.GetElement().value);

    this.FireEventByName(iControl.DomEventName.KeyPress, this);
}
iTextBox.prototype.OnKeyUp = function()
{
    this.Dirty = !ISString.IsNullOrEmpty(this.GetElement().value);

    this.FireEventByName(iControl.DomEventName.KeyUp, this);
}

//--------------------------------------------------------------------
// TextBox: Value handling
//--------------------------------------------------------------------
iTextBox.prototype.GetValue = function()
{
    var value = '';
    if (this.Dirty)
    {
        value = this.GetElement().value;
    }

    return value;
}
iTextBox.prototype.SetValue = function(value, withoutDirty)
{
    var element = this.GetElement();
    element.style.color = this.ColorCache;

    if (!withoutDirty)
    {
        this.Dirty = !ISString.IsNullOrEmpty(value);
    }

    this.GetElement().value = value;
}
                    
