// -----------------------------------------------------------------------
//  SearchTextBox
// -----------------------------------------------------------------------
Infoshare.Web.Control.SearchTextBox = function Infoshare$Web$Control$SearchTextBox(style)
{
    Infoshare.Web.Control.Panel.apply(this, arguments);

    this.Style = style ? style : new iSearchTextBoxStyle();

    // イベント登録
    this.AddEvent(iControl.ControlEventName.PreRender, ISFunction.CreateDelegate(this.SearchTextBox$PreRender, this));
}
iSearchTextBox = Infoshare.Web.Control.SearchTextBox;
iSearchTextBox.TypeName = 'Infoshare.Web.Control.SearchTextBox';
iSearchTextBox.EventName = { Search: 'Search' };

iSearchTextBox.prototype = new Infoshare.Web.Control.Panel();
iSearchTextBox.prototype.TypeName = iSearchTextBox.TypeName;
iSearchTextBox.prototype.Value = '';
iSearchTextBox.prototype.Watermark = '';
iSearchTextBox.prototype.TextBox = null;
iSearchTextBox.prototype.Button = null;
iSearchTextBox.prototype.SearchTextBox$PreRender = function()
{
    // テキストボックス
    this.TextBox = new iTextBox(this.Style.TextBoxStyle);
    this.TextBox.Value     = this.Value;
    this.TextBox.Watermark = this.Watermark;

    // KeyUpイベント   ： IMEの確定イベント（変換後のエンターキー等）の場合も発火する
    // KeyPressイベント： IMEの確定イベントでは発火しない
    // 検索用のテキストボックスとしてはKeyPressの動作が好ましい為KeyPressイベントを追加する
    this.TextBox.AddEvent(iControl.DomEventName.KeyPress, ISFunction.CreateDelegate(this.OnSearchByEnterKey, this));
    this.AppendChildControl(this.TextBox);

    // ボタン
    if (this.Style.ButtonStyle && 
        this.Style.ButtonStyle.Images)
    {
        this.Button = new iImageButton(this.Style.ButtonStyle);
    }
    else
    {
        this.Button = new iButton(this.Style.ButtonStyle);
        this.Button.Title = 'search';
    }
    this.Button.AddEvent(iControl.DomEventName.Click, ISFunction.CreateDelegate(this.OnSearch, this));
    this.AppendChildControl(this.Button);
}

iSearchTextBox.prototype.GetValue = function()
{
    return this.TextBox.GetValue();
}
iSearchTextBox.prototype.SetValue = function(value)
{
    this.TextBox.SetValue(value);
}

iSearchTextBox.prototype.OnSearch = function()
{
    this.FireEventByName(iSearchTextBox.EventName.Search, this);
}
iSearchTextBox.prototype.OnSearchByEnterKey = function()
{
    if (event.keyCode == 13)
    {
        // ChromeやFirefoxにてEnterKeyイベントがページの編集に遷移する問題の対応
        // https://sharepoint.stackexchange.com/questions/135482/edit-mode-with-the-enter-key
        // https://social.technet.microsoft.com/Forums/en-US/33df42ba-00b3-41a8-8fb9-f8187cfc216d/strange-behavior-in-firefox-input-text-with-enter-opens-page-for-editing?forum=sharepointgeneralprevious
        if (event && typeof event.preventDefault == "function")
        {
            event.preventDefault();
        }
        
        this.OnSearch();
    }
}
                    
