// -----------------------------------------------------------------------
//  Dialog
// -----------------------------------------------------------------------
Infoshare.Web.Control.Dialog = function Infoshare$Web$Control$Dialog(style)
{
    Infoshare.Web.Control.Panel.apply(this, arguments);

    this.Style = style ? style : new iDialogStyle();

    this.RenderingMode = iControl.RenderingMode.Append;
    this.ControlsForBody = new Array();

    // イベント登録
    this.AddEvent(iControl.ControlEventName.PreRender, ISFunction.CreateDelegate(this.Dialog$PreRender, this));
    this.AddEvent(iControl.ControlEventName.PostRender, ISFunction.CreateDelegate(this.Dialog$PostRender, this));
}
iDialog = Infoshare.Web.Control.Dialog;
iDialog.TypeName = 'Infoshare.Web.Control.Dialog';
iDialog.EventName = { InlineFrameContentsLoaded: 'InlineFrameContentsLoaded',
                      Close:                     'Close' };

iDialog.prototype = new Infoshare.Web.Control.Panel();
iDialog.prototype.TypeName = iDialog.TypeName;
iDialog.prototype.Option = null;
iDialog.prototype.ScreenBlocker = null;
iDialog.prototype.Header = null;
iDialog.prototype.HeaderTitle = null;
iDialog.prototype.HeaderButtonArea = null;
iDialog.prototype.Body = null;
iDialog.prototype.BodyInlineFrame = null;
iDialog.prototype.Footer = null;
iDialog.prototype.OKButton = null;
iDialog.prototype.CancelButton = null;

// -----------------------------------------------------------------------
//  Dialog: Open/Close operation
// -----------------------------------------------------------------------
iDialog.prototype.Open = function(option)
{
    // ---------------------------------------------------------
    //  オプション設定
    // ---------------------------------------------------------
    this.Option = option;

    // タイトル
    this.Title = option.Title;

    // 親設定
    if (this.ParentElement)
    {
        // 親情報をキャッシュ（Render後は空のDivがParentElementにセットされる為）
        this.Parent = this.ParentElement;

        // レンダリング先を変更
        this.ParentElement = this.ParentElement.ownerDocument.body;
    }

    // サイズ設定: オプションで渡されたサイズを適応（未指定の場合はダイアログの規定値を使う）
    if (option.Size)
    {
        this.Style.Size.Width  = option.Size.Width  > 0 ? option.Size.Width  : this.Style.Size.Width;
        this.Style.Size.Height = option.Size.Height > 0 ? option.Size.Height : this.Style.Size.Height;

        // ダイアログ表示位置の設定（親が存在する場合は、親要素の中央に表示する）
        if (this.Parent)
        {
            var parent = this.Parent;
            var x = ISDomAccessor.GetPixel(parent, 'style.left')
                  + (ISDomAccessor.GetWidth(parent) - this.Style.Size.Width)/2;
            var y = ISDomAccessor.GetPixel(parent, 'style.top')
                  + (ISDomAccessor.GetHeight(parent) - this.Style.Size.Height)/2;

            this.Style.Position.X = x;
            this.Style.Position.Y = y;
        }
    }

    // 背景をブロックする
    if (option.Modal)
    {
        if (!this.ScreenBlocker)
        {
            this.ScreenBlocker = new iScreenBlocker();
            this.ScreenBlocker.ParentElement = this.GetParentElement();
            this.ScreenBlocker.Render();
        }
        else
        {
            this.ScreenBlocker.Show();
        }
    }

    this.Render();
}
iDialog.prototype.Close = function(result)
{
    this.FireEventByName(iDialog.EventName.Close, new iDialogResult(this, result));

    // 親ノードを削除
    this.ParentElement.parentNode.removeChild(this.ParentElement);
    this.ParentElement = null;

    // 背景ブロックを解除
    if (this.Option.Modal)
    {
        if (this.ScreenBlocker)
        {
            this.ScreenBlocker.Hide();
        }
    }
}
iDialog.prototype.OKClose = function()
{
    this.Close(iDialogResult.ResultType.OK);
}
iDialog.prototype.CancelClose = function()
{
    this.Close(iDialogResult.ResultType.Cancel);
}

// -----------------------------------------------------------------------
//  Dialog: ContentsLoaded
// -----------------------------------------------------------------------
iDialog.prototype.OnContentsLoaded = function(eventArg)
{
    this.FireEventByName(iDialog.EventName.InlineFrameContentsLoaded, this);
}

// -----------------------------------------------------------------------
//  Dialog: Rendering
// -----------------------------------------------------------------------
iDialog.prototype.Dialog$PreRender = function()
{
    // ヘッダ・ボディ・フッタの初期化
    this.InitializeHeader();
    this.InitializeBody();
    this.InitializeFooter();
}
iDialog.prototype.InitializeHeader = function()
{
    // ヘッダ
    this.Header = new iPanel(this.Style.HeaderStyle);
    this.AppendChildControl(this.Header);

    // タイトル
    this.HeaderTitle = new iPanel(this.Style.HeaderStyle.TitleStyle);
    this.HeaderTitle.Text = this.Title;
    this.Header.AppendChildControl(this.HeaderTitle);

    // ボタンエリア
    this.HeaderButtonArea = new iPanel(this.Style.HeaderStyle.ButtonAreaStyle);
    this.Header.AppendChildControl(this.HeaderButtonArea);

    // ウィンドウモード ボタン
    if (this.Option.AllowMaximize)
    {
        var modeButton = null;
        if (this.Style.HeaderStyle.WindowModeButtonStyle)
        {
            modeButton = new iImageButton(this.Style.HeaderStyle.WindowModeButtonStyle);
        }
        else
        {
            modeButton = new iLinkButton();
            modeButton.Title = 'o';
        }
        modeButton.AddEvent(iControl.DomEventName.Click, ISFunction.CreateDelegate(this.OnToggleMaximize, this));
        this.HeaderButtonArea.AppendChildControl(modeButton);
    }

    // クローズ ボタン
    var closeButton = null;
    if (this.Style.HeaderStyle.WindowCloseButtonStyle)
    {
        closeButton = new iImageButton(this.Style.HeaderStyle.WindowCloseButtonStyle);
        closeButton.AlternativeText = '[Close dialog]';
    }
    else
    {
        closeButton = new iLinkButton();
        closeButton.Title = 'x';
    }
    closeButton.AddEvent(iControl.DomEventName.Click, ISFunction.CreateDelegate(this.CancelClose, this));
    this.HeaderButtonArea.AppendChildControl(closeButton);
}
iDialog.prototype.InitializeBody = function()
{
    // ボディ
    this.Body = new iPanel(this.Style.BodyStyle);

    // ボディにコントロールを追加
    if (!ISString.IsNullOrEmpty(this.Option.Url))
    {
        var iframe = new iInlineFrame();
        iframe.Style.StretchOption = iPanelStyle.StretchOption.Both;
        iframe.Style.Url = this.Option.Url;
        iframe.AddEvent(iInlineFrame.EventName.Load, ISFunction.CreateDelegate(this.OnContentsLoaded, this));
        this.BodyInlineFrame = iframe;

        this.Body.AppendChildControl(this.BodyInlineFrame);
    }
    else
    {
        for (var i = 0; i < this.ControlsForBody.length; i++)
        {
            var control = this.ControlsForBody[i];
            this.Body.AppendChildControl(control);
        }
    }

    this.AppendChildControl(this.Body);
}
iDialog.prototype.InitializeFooter = function()
{
    if (!this.Option.FooterEnabled)
    {
        return;
    }

    // フッタ
    this.Footer = new iPanel(this.Style.FooterStyle);
    this.AppendChildControl(this.Footer);

    // OK ボタン
    var okButton = new iButton();
    okButton.Title = 'OK';
    okButton.AddEvent(iControl.DomEventName.Click, ISFunction.CreateDelegate(this.OKClose, this));
    this.OKButton = okButton;

    // キャンセル ボタン
    var cancelButton = new iButton();
    cancelButton.Title = 'Cancel';
    cancelButton.AddEvent(iControl.DomEventName.Click, ISFunction.CreateDelegate(this.CancelClose, this));
    this.CancelButton = cancelButton;

    // ボタンエリア
    this.FooterButtonArea = new iPanel(this.Style.FooterStyle.ButtonAreaStyle);
    this.FooterButtonArea.AppendChildControl(okButton);
    this.FooterButtonArea.AppendChildControl(cancelButton);
    this.Footer.AppendChildControl(this.FooterButtonArea);
}
iDialog.prototype.Dialog$PostRender = function()
{
    // サイズ・ポジション設定
    // 最大化していることにして実行 → ウィンドウモードでリサイズされる
    this.Maximized = true;
    this.OnToggleMaximize();

    // ダイアログを移動可能にする
    if (this.Option.AllowMoving)
    {
        var extender = new iMovableExtender();
        extender.Extend(this.Header.GetElement(), this.GetElement());
    }
}
iDialog.prototype.GetAvailableSize = function()
{
    var parent = this.GetParentElement().ownerDocument.body;
    var bodyHeight = ISDomAccessor.GetHeight(parent),
        bodyWidth  = ISDomAccessor.GetWidth(parent);

    return { Height:          bodyHeight,
             Width:           bodyWidth,
             AvailableHeight: bodyHeight - this.Style.WindowMargin * 2,
             AvailableWidth:  bodyWidth  - this.Style.WindowMargin * 2 };
}

// -----------------------------------------------------------------------
//  Dialog: Child control handling
// -----------------------------------------------------------------------
iDialog.prototype.ControlsForBody = null;
iDialog.prototype.AppendChildControlForBody = function(control)
{
    if (!this.ControlsForBody)
    {
        this.ControlsForBody = new Array();
    }

    this.ControlsForBody.push(control);
}

// -----------------------------------------------------------------------
//  Dialog: Maximizing
// -----------------------------------------------------------------------
iDialog.prototype.Maximized = false;
iDialog.prototype.OnToggleMaximize = function()
{
    var width  = -1;
    var height = -1;
    var left   = -1;
    var top    = -1;
    var availableSize = this.GetAvailableSize();
    if (!this.Maximized)
    {
        // サイズ調整
        width  = availableSize.AvailableWidth;
        height = availableSize.AvailableHeight;

        // ポジション調整
        left = this.Style.WindowMargin;
        top  = this.Style.WindowMargin;

        this.Maximized = true;
    }
    else
    {
        // サイズ調整: 有効サイズを反映
        width  = (this.Style.Size.Width  > availableSize.AvailableWidth)  ? availableSize.AvailableWidth  : this.Style.Size.Width;
        height = (this.Style.Size.Height > availableSize.AvailableHeight) ? availableSize.AvailableHeight : this.Style.Size.Height;

        // ポジション調整
        left = (this.Style.Position.X < 0) ? availableSize.AvailableWidth  / 2 - width  / 2 : this.Style.Position.X;
        top  = (this.Style.Position.Y < 0) ? availableSize.AvailableHeight / 2 - height / 2 : this.Style.Position.Y;

        this.Maximized = false;
    }

    // ポジション設定
    var dialog = this.GetElement();
    ISDomAccessor.SetPixel(dialog, 'style.left', left);
    ISDomAccessor.SetPixel(dialog, 'style.top',  top);

    // サイズ変更: ダイアログ
    ISDomAccessor.SetWidth(dialog,  width);
    ISDomAccessor.SetHeight(dialog, height);

    // サイズ変更: ボディ（最初期化時は高さが計算されていない可能性があるため、ヘッダとフッタではスタイル設定値を考慮する）
    var dialogHeight = ISDomAccessor.GetInnerHeight(dialog);
    var headerHeight = this.Header ? ISDomAccessor.GetOuterHeight(this.Header.GetElement()) : 0;
    if (this.Header && headerHeight <= 0)
    {
        headerHeight = this.Header.Style.Size.Height;
    }
    var footerHeight = this.Footer ? ISDomAccessor.GetOuterHeight(this.Footer.GetElement()) : 0;
    if (this.Footer && footerHeight <= 0)
    {
        footerHeight = this.Footer.Style.Size.Height;
    }

    // margin, border, paddingを考慮してサイズ変更
    var body = this.Body.GetElement();
    var bodyOuterHeight = ISDomAccessor.GetOuterHeight(body);
    var bodyInnerHeight = ISDomAccessor.GetInnerHeight(body);
    ISDomAccessor.SetHeight(this.Body.GetElement(), dialogHeight - headerHeight - footerHeight - (bodyOuterHeight - bodyInnerHeight));

    var dialogWidth = ISDomAccessor.GetInnerWidth(dialog);
    var bodyOuterWidth = ISDomAccessor.GetOuterWidth(body);
    var bodyInnerWidth = ISDomAccessor.GetInnerWidth(body);
    ISDomAccessor.SetWidth(body, dialogWidth - (bodyOuterWidth - bodyInnerWidth));

    // ボディ内のコントロールをリサイズ
    this.Body.OnResize();
}
                    
