// -----------------------------------------------------------------------
//  Notifyer
// -----------------------------------------------------------------------
Infoshare.Web.Control.Notifyer = function Infoshare$Web$Control$Notifyer(style)
{
    Infoshare.Web.Control.FloatingPanel.apply(this, arguments);

    this.Style = style ? style : new iFloatingPanelStyle();
    this.Style.Size.Width = 420;

    this.RenderingMode = iControl.RenderingMode.Append;
    this.ControlsForBody = new Array();
}
iNotifyer = Infoshare.Web.Control.Notifyer;
iNotifyer.TypeName = 'Infoshare.Web.Control.Notifyer';
iNotifyer.Position = { Custom:      'Custom',
                       RightTop:    'RightTop',
                       RightBottom: 'RightBottom' };

iNotifyer.prototype = new Infoshare.Web.Control.FloatingPanel();
iNotifyer.prototype.TypeName = iNotifyer.TypeName;
iNotifyer.prototype.Position = iNotifyer.Position.RightTop;

iNotifyer.prototype.Notify = function (message, displayTime)
{
    // 表示サイズ調整
    // ToDo(skomatsu): 多段表示検討？
    var displayMessage = iString.Replace(iString.Replace(message, '<', '＜'), '>', '＞'); // タグ内の長さが計算されないため、全角文字に変更して長さを確認する
    var width = ISDomAccessor.GetTextWidth(displayMessage, this.GetParentElement());
    this.Style.Size.Width = width + this.Style.WindowMargin;

    // 表示位置調整
    if (this.Position == iNotifyer.Position.RightTop)
    {
        this.Style.Position.X = ISDomAccessor.GetWidth(document.body) - this.Style.Size.Width - this.Style.WindowMargin;
        this.Style.Position.Y = this.Style.WindowMargin;
    }
    else if (this.Position == iNotifyer.Position.RightBottom)
    {
        this.Style.Position.X = ISDomAccessor.GetWidth(document.body)  - this.Style.Size.Width  - this.Style.WindowMargin;
        this.Style.Position.Y = ISDomAccessor.GetHeight(document.body) - this.Style.Size.Height - this.Style.WindowMargin;
    }

    // 表示
    var notifyer = this;
    if (displayTime)
    {
        setTimeout(function () {
            notifyer.Open(message);
            setTimeout(function () {
                notifyer.Close();
            }, displayTime);
        }, 1);
    }
    else
    {
        setTimeout(function () {
            notifyer.Open(message);
        }, 1);
    }
}
                    
