// -----------------------------------------------------------------------
//  ScreenBlocker
// -----------------------------------------------------------------------
Infoshare.Web.Control.ScreenBlocker = function Infoshare$Web$Control$ScreenBlocker(style)
{
    Infoshare.Web.Control.Panel.apply(this, arguments);

    this.Style = style ? style : new iScreenBlockerStyle();

    this.RenderingMode = iControl.RenderingMode.Append;

    // イベント登録
    this.AddEvent(iControl.ControlEventName.EndPostRender, ISFunction.CreateDelegate(this.ScreenBlocker$PostRender, this));
    this.AddEvent(iControl.DomEventName.Show, ISFunction.CreateDelegate(this.ScreenBlocker$Show, this));
    this.AddEvent(iControl.DomEventName.Hide, ISFunction.CreateDelegate(this.ScreenBlocker$Hide, this));
}
iScreenBlocker = Infoshare.Web.Control.ScreenBlocker;
iScreenBlocker.TypeName = 'Infoshare.Web.Control.ScreenBlocker';

iScreenBlocker.prototype = new Infoshare.Web.Control.Panel();
iScreenBlocker.prototype.TypeName = iScreenBlocker.TypeName;

iScreenBlocker.prototype.Image = null;
iScreenBlocker.prototype.Text = null;

iScreenBlocker.prototype.RenderCompleted = false;
iScreenBlocker.prototype.ScreenBlocker$PostRender = function()
{
    var element = this.GetElement();
    element.style.textAlign = 'center';
    element.innerHTML = (this.Image ? '<img src="' + this.Image + '" style="margin-top: 200px;" />' : '')
                      + (this.Text  ? '<br />' + '<strong>' + this.Text + '</strong>' : '');

    this.AttachResizeEvent(ISDomAccessor.GetElementByTagName('body'), ISFunction.CreateDelegate(this.OnResize, this));
    this.RenderCompleted = true;
}
iScreenBlocker.prototype.OnResize = function()
{
    var element = this.GetElement();
    var parentElement = this.GetParentElement().ownerDocument.body;

    ISDomAccessor.SetPixel(element, 'style.top', 0);
    ISDomAccessor.SetPixel(element, 'style.left', 0);

    if (ISBrowser.IsSafari())
    {
        ISDomAccessor.SetHeight(element, parentElement.scrollHeight);
        ISDomAccessor.SetWidth(element, parentElement.scrollWidth);
    }
    else
    {
        ISDomAccessor.SetHeight(element, ISDomAccessor.GetHeight(parentElement));
        ISDomAccessor.SetWidth(element, ISDomAccessor.GetWidth(parentElement));
    }
}

iScreenBlocker.prototype.ReferenceCount = 0;
iScreenBlocker.prototype.ReferenceCountHandling = false;

iScreenBlocker.prototype.ScreenBlocker$Show = function()
{
    if (!this.RenderCompleted)
    {
        this.Render();
    }

    if (!this.ReferenceCountHandling)
    {
        return;
    }

    this.ReferenceCount++;
}
iScreenBlocker.prototype.ScreenBlocker$Hide = function()
{
    if (!this.ReferenceCountHandling)
    {
        return;
    }

    this.ReferenceCount--;
    if (this.ReferenceCount > 0)
    {
        this.Hidden = false;
        this.ApplyStyle();
    }
}

// -----------------------------------------------------------------------
//  ScreenBlockerUtility
// -----------------------------------------------------------------------
Infoshare.Web.Control.ScreenBlockerUtility = function Infoshare$Web$Control$ScreenBlockerUtility() { }

iScreenBlockerUtility = Infoshare.Web.Control.ScreenBlockerUtility;
iScreenBlockerUtility.UltimateScreenBlockerInstance = null;
iScreenBlockerUtility.Base64Image = 'data:image/gif;base64,';

iScreenBlockerUtility.Show = function()
{
    // スクリーンブロッカーのインスタンスが現在のDOMに存在しない場合、インスタンスを作成する
    if (!iScreenBlockerUtility.UltimateScreenBlockerInstance ||
        !iScreenBlockerUtility.UltimateScreenBlockerInstance.Element.parentElement)
    {
        iScreenBlockerUtility.UltimateScreenBlockerInstance = new iScreenBlocker(new iUltimateScreenBlockerStyle());

        if (iVxContext.MasterSourcesPath)
        {
            iScreenBlockerUtility.UltimateScreenBlockerInstance.Image = ISString.TrimEnd(iVxContext.MasterSourcesPath, '/') + '/Infoshare/loading.gif';
        }
        else
        {
            iScreenBlockerUtility.UltimateScreenBlockerInstance.Image = iScreenBlockerUtility.Base64Image;
        }
        
        iScreenBlockerUtility.UltimateScreenBlockerInstance.ReferenceCountHandling = true;
    }
    iScreenBlockerUtility.UltimateScreenBlockerInstance.Show();
}

iScreenBlockerUtility.Hide = function ()
{
    if (iScreenBlockerUtility.UltimateScreenBlockerInstance)
    {
        iScreenBlockerUtility.UltimateScreenBlockerInstance.Hide();
    }
}                    
