//  TagHolder
// -----------------------------------------------------------------------
Infoshare.Web.Control.TagHolder = function Infoshare$Web$Control$TagHolder(style)
{
    Infoshare.Web.Control.Panel.apply(this, arguments);

    this.Style = style ? style : new iTagHolderStyle();
}
iTagHolder = Infoshare.Web.Control.TagHolder;
iTagHolder.TypeName = 'Infoshare.Web.Control.TagHolder';
iTagHolder.EventName = { SelectionChanged: 'SelectionChanged',
                         TagChanged:       'TagChanged' };

iTagHolder.prototype = new Infoshare.Web.Control.Panel();
iTagHolder.prototype.TypeName = iTagHolder.TypeName;
iTagHolder.prototype.AddTag = function(tag)
{
    if (ISObject.TypeOf(tag) == 'array')
    {
        for (var i = 0; i < tag.length; i++)
        {
            tag[i].Style.CloseButtonStyle = this.Style.ItemCloseButtonStyle;
            tag[i].AddEvent(iTagItem.EventName.Delete, ISFunction.CreateDelegate(this.RemoveTag, this));
            tag[i].AddEvent(iTagItem.EventName.StateChanged, ISFunction.CreateDelegate(this.OnSelectionChanged, this));
        }
    }
    else
    {
        tag.Style.CloseButtonStyle = this.Style.ItemCloseButtonStyle;
        tag.AddEvent(iTagItem.EventName.Delete, ISFunction.CreateDelegate(this.RemoveTag, this));
        tag.AddEvent(iTagItem.EventName.StateChanged, ISFunction.CreateDelegate(this.OnSelectionChanged, this));
    }

    this.AppendChildControl(tag);
    this.RenderTags();

    this.FireEventByName(iTagHolder.EventName.TagChanged, this);
}
iTagHolder.prototype.RemoveTag = function(tag)
{
    this.RemoveChildControl(tag);
    this.RenderTags();

    this.FireEventByName(iTagHolder.EventName.TagChanged, this);
}
iTagHolder.prototype.ClearTag = function()
{
    this.Controls = new ISDictionary();
    this.RenderTags();

    this.FireEventByName(iTagHolder.EventName.TagChanged, this);
}
iTagHolder.prototype.RenderTags = function()
{
    // 初期描画が完了していない場合は再レンダリングしない
    if (!this.PostRenderComplete)
    {
        return;
    }

    // タグの再描画
    var writer = new Array();
    if (this.Controls.GetLength() > 0)
    {
        for (var i = 0; i < this.Controls.GetLength() ; i++)
        {
            var control = this.Controls.Get(i);
            control.DetachEvents();
            control.PreRender();
            control.RenderMarkup(writer);
        }
    }
    this.GetElement().innerHTML = writer.join('');

    // 描画後処理
    if (this.Controls.GetLength() > 0)
    {
        for (var i = 0; i < this.Controls.GetLength() ; i++)
        {
            var control = this.Controls.Get(i);
            control.PostRender();
        }
    }
}

iTagHolder.prototype.OnSelectionChanged = function()
{
    this.FireEventByName(iTagHolder.EventName.SelectionChanged, this);
}
iTagHolder.prototype.GetSelectedTags = function()
{
    var tags = new Array();
    for (var i = 0; i < this.Controls.GetLength() ; i++)
    {
        var control = this.Controls.Get(i);
        if (control.Active)
        {
            tags.push(control);
        }
    }

    return tags;
}


// -----------------------------------------------------------------------
//  TagItem
// -----------------------------------------------------------------------
Infoshare.Web.Control.TagItem = function Infoshare$Web$Control$TagItem(style)
{
    Infoshare.Web.Control.Panel.apply(this, arguments);

    this.Style = style ? style : new iTagItemStyle();

    // イベント登録
    this.AddEvent(iControl.DomEventName.Click, ISFunction.CreateDelegate(this.TagItem$Click, this));
}
iTagItem = Infoshare.Web.Control.TagItem;
iTagItem.TypeName = 'Infoshare.Web.Control.TagItem';
iTagItem.EventName = { Delete: 'Delete',
                       StateChanged: 'StateChanged' };

iTagItem.prototype = new Infoshare.Web.Control.Panel();
iTagItem.prototype.TypeName = iTagItem.TypeName;
iTagItem.prototype.Description = '';
iTagItem.prototype.TitleImage = null;
iTagItem.prototype.TitleButton = null;
iTagItem.prototype.DeleteButton = null;
iTagItem.prototype.DisableDeleteButton = false;

iTagItem.prototype.RenderMarkup = function(writer)
{
    // スタイル設定: インラインスタイルの場合の特殊対応
    var style = '';
    if (this.Style.DisplayType == iPanelStyle.DisplayType.Inline)
    {
        style = "style='float: left;'";
    }

    // レンダリング: 外部のDiv
    writer[writer.length] = "<div id='" + this.GetElementId() + "' ";
    writer[writer.length] =      "class='" + this.GetClassName() + "' ";
    writer[writer.length] =      style;
    writer[writer.length] =      "title='" + iXml.Escape(this.Tooltip) + "'>";

    // レンダリング: 内部のTable
    writer[writer.length] =   "<table>";
    writer[writer.length] =     "<tr>";

    // タイトル: イメージ
    writer[writer.length] =       "<td>";
    if (!ISString.IsNullOrEmpty(this.TitleImage))
    {
        writer[writer.length] =         "<img src='" + this.TitleImage + "' />";
        //writer[writer.length] =         "<img src='" + this.TitleImage + "' onerror='this.parentNode.removeChild(this)' />";
    }
    writer[writer.length] =       "</td>";

    // タイトル: テキスト
    writer[writer.length] =       "<td>";
    writer[writer.length] =         this.Title;
    writer[writer.length] =       "</td>";

    // 削除ボタン：非表示設定の場合には追加しない
    if (!this.DisableDeleteButton)
    {
        writer[writer.length] =       "<td style='text-align: right;'>";
        if (this.Style.CloseButtonStyle)
        {
            this.DeleteButton = new iImageButton(this.Style.CloseButtonStyle);
        }
        else
        {
            this.DeleteButton = new iLinkButton();
            this.DeleteButton.Title = 'x';
        }
        this.DeleteButton.RenderMarkup(writer);
        this.DeleteButton.AddEvent(iControl.DomEventName.Click, ISFunction.CreateDelegate(this.OnDelete, this));
        this.AppendChildControl(this.DeleteButton);
    }

    writer[writer.length] =       "</td>";
    writer[writer.length] =     "</tr>";

    // 説明
    if (this.Description)
    {
        writer[writer.length] =     "<tr>";
        writer[writer.length] =       "<td colspan='3'>";
        writer[writer.length] =       iXml.Escape(this.Description);
        writer[writer.length] =       "</td>";
        writer[writer.length] =     "</tr>";
    }

    writer[writer.length] =     "</table>";

    writer[writer.length] = "</div>";
}

iTagItem.prototype.TagItem$Click = function()
{
    this.Active = !this.Active;

    this.ApplyStyle();

    this.OnStateChanged();
}

iTagItem.prototype.OnStateChanged = function()
{
    this.FireEventByName(iTagItem.EventName.StateChanged, this);
}

iTagItem.prototype.OnDelete = function()
{
    this.FireEventByName(iTagItem.EventName.Delete, this);
}
                    
