// -----------------------------------------------------------------------
//  Pager
// -----------------------------------------------------------------------
Infoshare.Web.Control.Pager = function Infoshare$Web$Control$Pager(style)
{
    Infoshare.Web.Control.Panel.apply(this, arguments);

    this.Style = style ? style : new iPagerStyle();

    // イベント登録
    this.AddEvent(iControl.ControlEventName.PreRender, ISFunction.CreateDelegate(this.Pager$PreRender, this));
}
iPager = Infoshare.Web.Control.Pager;
iPager.TypeName = 'Infoshare.Web.Control.Pager';
iPager.EventName = { SelectedPageChanged: 'SelectedPageChanged' };

iPager.prototype = new Infoshare.Web.Control.Panel();
iPager.prototype.TypeName = iPager.TypeName;

iPager.prototype.EnableSummary = true;
iPager.prototype.ItemCount = 0;
iPager.prototype.PageSize = 25;
iPager.prototype.PageSizeCandidates = null;
iPager.prototype.PageButtonCount = 5;
iPager.prototype.CurrentPageNumber = 0;

iPager.prototype.DisplayItemLabel = null;
iPager.prototype.PageSizeListBox = null;
iPager.prototype.PagerArea = null;

iPager.prototype.Pager$PreRender = function()
{
    this.EnsureItemSummary();
    this.EnsurePager();
    this.EnsurePageSizeCandidate();
}
iPager.prototype.EnsureItemSummary = function()
{
    if (!this.EnableSummary)
    {
        return;
    }

    var label = new iLabel();

    var startIndex = (this.CurrentPageNumber - 1) * this.PageSize + 1;
    var endIndex = startIndex + this.PageSize - 1;
    if (endIndex > this.ItemCount)
    {
        endIndex = this.ItemCount;
    }

    label.Text = startIndex + ' - ' + endIndex + ' / ' + this.ItemCount;
    this.AppendChildControl(label);
}
iPager.prototype.EnsurePageSizeCandidate = function()
{
    if (!this.PageSizeCandidates ||
        this.PageSizeCandidates.length <= 1)
    {
        return;
    }

    var candidatePanel = new iPanel();
    candidatePanel.Style.DisplayType = iPanelStyle.DisplayType.Inline;
    candidatePanel.Style.Alignment = iPanelStyle.Alignment.Right;
    this.AppendChildControl(candidatePanel);

    var list = new iListBox();
    list.Options = new Array();
    for (var i = 0; i < this.PageSizeCandidates.length; i++)
    {
        var itemCount = this.PageSizeCandidates[i];
        list.Options.push(new iListBoxItem(itemCount, itemCount, itemCount == this.PageSize));
    }
    list.AddEvent(iControl.DomEventName.Change, ISFunction.CreateDelegate(this.OnPageSizeChanged, this));

    candidatePanel.AppendChildControl(list);
}
iPager.prototype.EnsurePager = function()
{
    var pagerPanel = new iPanel();
    pagerPanel.Style.DisplayType = iPanelStyle.DisplayType.Inline;
    pagerPanel.Style.Alignment = iPanelStyle.Alignment.Right;
    this.AppendChildControl(pagerPanel);

    // 最初のページへ
    var firstPageButton = new iButton(this.Style.ButtonStyle);
    firstPageButton.Title = '<<';
    firstPageButton.PageNumber = 1;
    firstPageButton.AddEvent(iControl.DomEventName.Click, ISFunction.CreateDelegate(this.OnSelectedPageChanged, this));
    firstPageButton.Enabled = this.CurrentPageNumber > 1;
    pagerPanel.AppendChildControl(firstPageButton);

    // 前のページへ
    var previousPageButton = new iButton(this.Style.ButtonStyle);
    previousPageButton.Title = '<';
    previousPageButton.PageNumber = this.CurrentPageNumber - 1;
    previousPageButton.AddEvent(iControl.DomEventName.Click, ISFunction.CreateDelegate(this.OnSelectedPageChanged, this));
    previousPageButton.Enabled = this.CurrentPageNumber > 1;
    pagerPanel.AppendChildControl(previousPageButton);

    this.EnsurePageButtons(pagerPanel);

    // 次のページへ
    var nextPageButton = new iButton(this.Style.ButtonStyle);
    nextPageButton.Title = '>';
    nextPageButton.PageNumber = this.CurrentPageNumber + 1;
    nextPageButton.AddEvent(iControl.DomEventName.Click, ISFunction.CreateDelegate(this.OnSelectedPageChanged, this));
    nextPageButton.Enabled = this.CurrentPageNumber < this.GetPageCount();
    pagerPanel.AppendChildControl(nextPageButton);

    // 最後のページへ
    var lastPageButton = new iButton(this.Style.ButtonStyle);
    lastPageButton.Title = '>>';
    lastPageButton.PageNumber = this.GetPageCount();
    lastPageButton.AddEvent(iControl.DomEventName.Click, ISFunction.CreateDelegate(this.OnSelectedPageChanged, this));
    lastPageButton.Enabled = this.CurrentPageNumber < this.GetPageCount();
    pagerPanel.AppendChildControl(lastPageButton);
}
iPager.prototype.EnsurePageButtons = function(parent)
{
    // ページ総数を取得
    var pageCount = this.GetPageCount();

    // 開始・終了ページ番号を決定
    var startNumber = 1;
    var endNumber   = pageCount;
    if ((this.CurrentPageNumber - startNumber) >= Math.round(this.PageButtonCount / 2))
    {
        startNumber = this.CurrentPageNumber - Math.floor(this.PageButtonCount / 2);
        if (startNumber > (pageCount - this.PageButtonCount))
        {
            startNumber = pageCount - this.PageButtonCount + 1;
            if (startNumber <= 0)
            {
                startNumber = 1;
            }
        }
    }
    if ((endNumber - startNumber) >= this.PageButtonCount)
    {
        endNumber = startNumber + this.PageButtonCount - 1;
    }

    // 左省略ボタン
    if (startNumber > 1)
    {
        var button = new iButton(this.Style.ButtonStyle);
        button.Title = '...';
        button.PageNumber = this.CurrentPageNumber - this.PageButtonCount;
        button.AddEvent(iControl.DomEventName.Click, ISFunction.CreateDelegate(this.OnSelectedPageChanged, this));
        parent.AppendChildControl(button);
    }

    // ボタン作成
    for (var i = startNumber; i <= endNumber; i++)
    {
        var button = new iButton(this.Style.ButtonStyle);
        button.Title = i;

        // アクティブボタン設定
        if (i == this.CurrentPageNumber)
        {
            button.Active = true;
        }

        // イベント設定
        button.PageNumber = i;
        button.AddEvent(iControl.DomEventName.Click, ISFunction.CreateDelegate(this.OnSelectedPageChanged, this));

        parent.AppendChildControl(button);
    }

    // 右省略ボタン
    if (endNumber < pageCount)
    {
        var button = new iButton(this.Style.ButtonStyle);
        button.Title = '...';
        button.PageNumber = this.CurrentPageNumber + this.PageButtonCount;
        button.AddEvent(iControl.DomEventName.Click, ISFunction.CreateDelegate(this.OnSelectedPageChanged, this));
        parent.AppendChildControl(button);
    }
}

iPager.prototype.OnPageSizeChanged = function(sender)
{
    this.PageSize = sender.GetSelectedItems()[0].Value;
    this.ChangePage(1);
}
iPager.prototype.OnSelectedPageChanged = function(sender)
{
    this.ChangePage(sender.PageNumber);
}
iPager.prototype.ChangePage = function(selectedPageNumber)
{
    this.CurrentPageNumber = selectedPageNumber;
    if      (this.CurrentPageNumber < 1)                   { this.CurrentPageNumber = 1; }
    else if (this.CurrentPageNumber > this.GetPageCount()) { this.CurrentPageNumber = this.GetPageCount(); }

    this.Pager$RenderControls();

    this.FireEventByName(iPager.EventName.SelectedPageChanged, this);
}

iPager.prototype.Pager$RenderControls = function()
{
    this.Controls.Clear();

    this.EnsureItemSummary();
    this.EnsurePager();
    this.EnsurePageSizeCandidate();

    // コントロールの再描画
    var writer = new Array();
    if (this.Controls.GetLength() > 0)
    {
        for (var i = 0; i < this.Controls.GetLength() ; i++)
        {
            var control = this.Controls.Get(i);
            control.DetachEvents();
            control.PreRender();
            control.RenderMarkup(writer);
        }
    }
    this.GetElement().innerHTML = writer.join('');

    // 描画後処理
    if (this.Controls.GetLength() > 0)
    {
        for (var i = 0; i < this.Controls.GetLength() ; i++)
        {
            var control = this.Controls.Get(i);
            control.PostRender();
        }
    }
}

iPager.prototype.GetPageCount = function()
{
    var count = Math.floor(this.ItemCount / this.PageSize);
    if (count < 1)
    {
        count = 1;
    }
    else if (this.ItemCount % this.PageSize != 0)
    {
        count++;
    }

    return count;
}
                    
