//  MenuStyle
// -----------------------------------------------------------------------
Infoshare.Web.Control.MenuStyle = function Infoshare$Web$Control$MenuStyle()
{
    Infoshare.Web.Control.PanelStyle.apply(this);

    this.ClassName        = 'is-Menu';
    this.EnableClassName  = 'is-Menu-Enable';
    this.DisableClassName = 'is-Menu-Disable';

    this.ActiveClassName = 'is-Menu-Active';

    this.Position = new iPosition(-1, -1);
    this.WindowMargin = 10;
}
iMenuStyle = Infoshare.Web.Control.MenuStyle;
iMenuStyle.prototype = new Infoshare.Web.Control.PanelStyle();
iMenuStyle.prototype.Position = null;


// -----------------------------------------------------------------------
//  Menu
// -----------------------------------------------------------------------
Infoshare.Web.Control.Menu = function Infoshare$Web$Conrtol$Menu(style)
{
    Infoshare.Web.Control.FloatingPanel.apply(this, arguments);

    this.Style = style ? style : new iMenuStyle();

    this.RenderingMode   = iControl.RenderingMode.Append;
    this.ControlsForBody = new Array();

    this.MenuItems = new iDictionary();

    this.AppendChildControl(new iMenuItemRenderer(this));
    iMenu.RegisterInstance(this);

    // イベント登録
    this.AddEvent(iControl.ControlEventName.PostRender, iFunction.CreateDelegate(this.Menu$PostRender, this));
};
iMenu = Infoshare.Web.Control.Menu;
iMenu.TypeName = 'Infoshare.Web.Control.Menu';

iMenu.Alignment = { TopLeft:     'TopLeft',
                    TopRight:    'TopRight',
                    BottomLeft:  'BottomLeft',
                    BottomRight: 'BottomRight' };

iMenu.Instances = null;
iMenu.RegisterInstance = function(instance)
{
    if (iMenu.Instances == null)
    {
        iMenu.Instances = new iDictionary();
    }

    iMenu.Instances.Add(instance.Id, instance);
}
iMenu.UnregisterInstance = function (instance)
{
    if (iMenu.Instances == null)
    {
        return;
    }

    iMenu.Instances.Remove(instance.Id);
}
iMenu.GetInstance = function(id)
{
    var instance = null;
    if (iMenu.Instances)
    {
        instance = iMenu.Instances.Get(id);
    }

    return instance;
}

iMenu.prototype = new Infoshare.Web.Control.FloatingPanel();
iMenu.prototype.TypeName = iMenu.TypeName;
iMenu.prototype.IsOpend = false;
iMenu.prototype.Alignment = iMenu.Alignment.TopLeft;
iMenu.prototype.MenuItems = null;
iMenu.prototype.SelectedMenuItemId = null;

iMenu.prototype.RegisterOpenEvent = function (element, eventName)
{
    var targetElement   = element ? element : document;
    var targetEventName = eventName ? eventName : iControl.DomEventName.Click.toLowerCase();
    ISDomAccessor.AttachEvent(targetElement, targetEventName, iFunction.CreateDelegate(this.Open, this));

    // Openイベントの登録先がdocumentでない場合、
    // メニュー外のクリックを検出し、閉じる必要があるため、documentにもイベントを登録する
    if (targetElement.nodeType != Node.DOCUMENT_NODE)
    {
        ISDomAccessor.AttachEvent(document, targetEventName, iFunction.CreateDelegate(this.Close, this));
    }
}

iMenu.prototype.Open = function (event)
{
    if (this.IsOpend)
    {
        // メニューをクリックされたかどうかを確認
        // （自身のTypeNameをidに持つ親がいればメニュー内をクリックしたと判断する）
        var ancestor = ISDomAccessor.FindAncestor(event.srcElement, function (element)
        {
            return element &&
                   !iString.IsNullOrEmpty(element.id) &&
                   iString.StartsWith(element.id, iMenu.TypeName, true)
        });

        // メニュー内でなければメニューを閉じる
        if (!ancestor)
        {
            this.Close();
        }

        // メニュー内であった場合は、再オープンしないように処理を戻す
        return;
    }

    // クリックイベントなどに紐づいている場合は保持
    // PostRenderで表示位置の計算に使用
    if (event)
    {
        //this.ClickEvent = event;
        this.ClickEvent = { x: event.x,
                            y: event.y };
    }

    // メニュー表示位置制御のため、まずは非表示で描画しPostRenderで位置を調整して表示する
    // べきだが、表示しないとTableのサイズが確定しないため、表示状態のまま描画する
    //this.Hidden = true;

    // Open直後にCloseが呼ばれてしまうので、
    // レンダリングと、フラグ操作は非同期待ち後に実行する
    var ref = this;
    setTimeout(function ()
    {
        ref.Render();
        ref.IsOpend = true;
    }, 0);
}

iMenu.prototype.Menu$PostRender = function()
{
    // 表示位置調整
    if (this.ClickEvent && this.ClickEvent.x && this.ClickEvent.y)
    {
        var top    = -1;
        var left   = -1;
        var height = iDomAccessor.GetOuterHeight(this.GetElement());
        var width  = iDomAccessor.GetOuterWidth(this.GetElement());
        if (this.Alignment == iMenu.Alignment.TopLeft)
        {
            top  = this.ClickEvent.y;
            left = this.ClickEvent.x;
        }
        else if (this.Alignment == iMenu.Alignment.TopRight)
        {
            top  = this.ClickEvent.y;
            left = this.ClickEvent.x - width;
        }
        else if (this.Alignment == iMenu.Alignment.BottomLeft)
        {
            top  = this.ClickEvent.y - height;
            left = this.ClickEvent.x;
        }
        else if (this.Alignment == iMenu.Alignment.BottomRight)
        {
            top  = this.ClickEvent.y - height;
            left = this.ClickEvent.x - width;
        }

        iDomAccessor.SetPixel(this.GetElement(), 'style.left', left);
        iDomAccessor.SetPixel(this.GetElement(), 'style.top',  top);

        // キャッシュしたイベントを破棄
        this.ClickEvent = null;
    }

    // 位置調整が終わったら表示状態にする
    this.Show();
}

iMenu.prototype.BaseClose = iMenu.prototype.Close;
iMenu.prototype.Close = function ()
{
    if (!this.IsOpend)
    {
        return;
    }

    this.BaseClose();
    this.IsOpend = false;
}

iMenu.prototype.OnMenuItemClick = function(id)
{
    var item = this.MenuItems.Get(id);
    item.ExecuteAction();

    this.Close();
}


// -----------------------------------------------------------------------
//  MenuItemRenderer
// -----------------------------------------------------------------------
Infoshare.Web.Control.MenuItemRenderer = function Infoshare$Web$Control$MenuItemRenderer(menu)
{
    this.Menu = menu;
}
iMenuItemRenderer = Infoshare.Web.Control.MenuItemRenderer;
iMenuItemRenderer.TypeName = 'Infoshare.Web.Control.MenuItemRenderer';

iMenuItemRenderer.prototype = {
    TypeName: iMenuItemRenderer.TypeName,

    Menu: null,

    PreRender: function ()
    {
    },

    PostRender: function ()
    {
    },

    RenderMarkup: function(writer)
    {
        writer[writer.length] = "<table cellpadding='0' cellspacing='0'>";

        for (var i = 0; i < this.Menu.MenuItems.GetLength() ; i++)
        {
            var item = this.Menu.MenuItems.Get(i);

            if (item.Type == iMenuItem.Type.Item)
            {
                var cssClass = 'is-MenuItem';
                if (!item.IsEnabled()) { cssClass = 'is-MenuItem-Disable'; }

                writer[writer.length] = "<tr class='" + cssClass + "' ";
                if (item.IsEnabled())
                {
                    writer[writer.length] = "onclick='iMenu.GetInstance(\"" + this.Menu.Id + "\").OnMenuItemClick(\"" + item.Id + "\");' >";
                }
                else
                {
                    writer[writer.length] = ">";
                }

                writer[writer.length] = "<td class='is-MenuItemHeaderCell'></td>";
                writer[writer.length] = "<td class='is-MenuItemSpacerCell'></td>";
                writer[writer.length] = "<td class='is-MenuItemCell'>" + item.Title + "</td>";
                writer[writer.length] = "<td class='is-MenuItemSpacerCell'></td>";
                //writer[writer.length] = "<td class='is-MenuItemCell'>‣</td>";
                writer[writer.length] = "<td class='is-MenuItemCell'></td>";
            }
            else
            {
                writer[writer.length] = "<tr>";

                writer[writer.length] = "<td class='is-MenuItemHeaderCell'></td>";
                writer[writer.length] = "<td class='is-MenuItemSpacerCell'></td>";
                writer[writer.length] = "<td class='is-MenuItemCell is-MenuItemSeparator'></td>";
                writer[writer.length] = "<td class='is-MenuItemSpacerCell is-MenuItemSeparator'></td>";
                writer[writer.length] = "<td class='is-MenuItemCell is-MenuItemSeparator'></td>";
            }

            writer[writer.length] = "</tr>";
        }

        writer[writer.length] = "</table>";
    }
};
                    
