// -----------------------------------------------------------------------
//  MenuItem
// -----------------------------------------------------------------------
Infoshare.Web.Control.MenuItem = function Infoshare$Web$Conrtol$MenuItem(id, title, action)
{
    this.Id     = id;
    this.Title  = title;
    this.Action = action;
}
iMenuItem = Infoshare.Web.Control.MenuItem;
iMenuItem.TypeName = 'Infoshare.Web.Control.MenuItem';
iMenuItem.Type = { Item:      'Item',
                   Separator: 'Separator' };

iMenuItem.FromXml = function(menu, xml)
{
    // <MenuItem Id='1234' Type='Item|Separator' DisplayName='' DisplayNameResourceKey=''>
    //   <Action ClassName='Infoshare.MenuItemAction' Source=''>
    //     <Options>
    //       <Option Key='key' Value='value' />
    //     </Options>
    //   </Action>
    // </MenuItem>

    var element = xml;
    if (iObject.TypeOf(xml) == 'string')
    {
        var doc = iXml.LoadXml(xml);
        element = iXml.GetDocumentElement(doc);
    }

    var item = new iMenuItem();
    item.Menu = menu;
    item.Id               = iXml.GetAttributeValue(element, ['Id', 'Name']);
    item.Title            = iXml.GetAttributeValue(element, ['Title', 'DisplayName']);
    item.TitleResourceKey = iXml.GetAttributeValue(element, ['TitleResourceKey', 'DisplayNameResourceKey']);

    // fix title
    if (iString.IsNullOrEmpty(item.Title) &&
        !iString.IsNullOrEmpty(item.TitleResourceKey))
    {
        item.Title = iResxResource.GetString(item.TitleResourceKey);
    }

    var type = iXml.GetAttributeValue(element, 'Type');
    item.Type = iString.Equals(type, iMenuItem.Type.Item, true) ? iMenuItem.Type.Item : iMenuItem.Type.Separator;

    // actions
    var actionElement = iXml.SelectNodeByPath(element, 'MenuItemAction');
    if (actionElement)
    {
        item.Action = iMenuItemAction.FromXml(item, actionElement);
    }

    return item;
}

iMenuItem.prototype = {
    TypeName: iMenuItem.TypeName,

    Id: '',
    Title: '',
    TitleResourceKey: '',
    
    Type: iMenuItem.Type.Item,

    Menu: null,
    Action: null,

    IsEnabled: function()
    {
        var enabled = true;
        if (iObject.TypeOf(this.Action) == 'object')
        {
            enabled = this.Action.IsEnabled();
        }

        return enabled;
    },

    ExecuteAction: function()
    {
        if (iObject.TypeOf(this.Action) == 'function')
        {
            this.Action(this);
        }
        else
        {
            this.Action.ExecuteAction();
        }
    }
};


// -----------------------------------------------------------------------
//  MenuItemAction
// -----------------------------------------------------------------------
Infoshare.Web.Control.MenuItemAction = function Infoshare$Web$Conrtol$MenuItemAction()
{
    this.Options = new Array();
}
iMenuItemAction = Infoshare.Web.Control.MenuItemAction;
iMenuItemAction.TypeName = 'Infoshare.Web.Control.MenuItemAction';

iMenuItemAction.FromXml = function (menuItem, xml)
{
    // <Action ClassName='Infoshare.MenuItemAction' Source=''>
    //   <Options>
    //     <Option Key='key' Value='value' />
    //   </Options>
    // </Action>

    var element = xml;
    if (iObject.TypeOf(xml) == 'string')
    {
        var doc = iXml.LoadXml(xml);
        element = iXml.GetDocumentElement(doc);
    }

    var classInfo = iClass.CreateFromXml(element);
    var action = iClass.New(classInfo);
    action.MenuItem = menuItem;

    // options
    var optionsElement = iXml.SelectNodeByPath(element, 'Options');
    if (optionsElement)
    {
        var optionElements = iXml.GetChildElements(optionsElement, function (childElement)
        {
            return iString.Equals(childElement.nodeName, 'Option', true)
        });

        for (var i = 0; i < optionElements.length; i++)
        {
            var optionElement = optionElements[i];
            var key   = iXml.GetAttributeValue(optionElement, 'Key');
            var value = iXml.GetAttributeValue(optionElement, 'Value');

            action.Options[key] = value;
        }
    }

    return action;
}

iMenuItemAction.prototype = {
    TypeName: iMenuItemAction.TypeName,

    MenuItem: null,
    Options: null,

    IsEnabled: function()
    {
        return iPersonalConfiguration.HasEditPermission;
    },

    ExecuteAction: function()
    {
    }
};


