// -----------------------------------------------------------------------
Infoshare.Web.Control.NavigateMenuItemAction = function Infoshare$Web$Conrtol$NavigateMenuItemAction()
{
    Infoshare.Web.Control.MenuItemAction.apply(this, arguments);
}
iNavigateMenuItemAction = Infoshare.Web.Control.NavigateMenuItemAction;
iNavigateMenuItemAction.TypeName = 'Infoshare.Web.Control.NavigateMenuItemAction';
iNavigateMenuItemAction.prototype = new Infoshare.Web.Control.MenuItemAction();

iNavigateMenuItemAction.prototype.ExecuteAction = function()
{
    var url    = this.Options['Url'];
    var method = this.Options['Method'];
    var name   = this.Options['NewWindowName'];
    var option = this.Options['NewWindowOption'];

    if (!iString.IsNullOrEmpty(method) &&
        iString.Equals(method, 'Navigate', true))
    {
        iNavigation.Navigate(url);
    }
    else
    {
        iNavigation.OpenWindow(url, name, option);
    }
};


