// -----------------------------------------------------------------------
Infoshare.Web.Control.ListContainer = function Infoshare$Web$Control$ListContainer(style)
{
    Infoshare.Web.Control.ContainerControl.apply(this, arguments);

    this.Style = style ? style : new iListContainerStyle();
}
iListContainer = Infoshare.Web.Control.ListContainer;
iListContainer.TypeName = 'Infoshare.Web.Control.ListContainer';

iListContainer.prototype = new Infoshare.Web.Control.ContainerControl();
iListContainer.prototype.TypeName = iListContainer.TypeName;
iListContainer.prototype.RenderingMode = iControl.RenderingMode.Append;
iListContainer.prototype.IsRunningOnScrolledToBottomEvent = false;

iListContainer.prototype.RenderMarkup = function(writer)
{
    // レンダリング
    writer[writer.length] = "<div id='" + this.GetElementId() + "' ";
    writer[writer.length] =      "class='" + this.GetClassName() + "' />";

    writer[writer.length] =     "<div id='" + this.GetElementId() + "_Header'  ></div>";
    writer[writer.length] =     "<span id='" + this.GetElementId() + "_Content' ></span>";
    
    writer[writer.length] = "</div>";
}

iListContainer.prototype.PostRender = function()
{
    // Header
    if (this.Header)
    {
        var headerDiv = document.getElementById(this.GetElementId() + "_Header");
        this.Header.Render(headerDiv);
    }

    // Items
    // アイテム取得の関数が設定済
    if (this.RetrieveItems)
    {
        // コールバックでアイテムをレンダリングする
        this.RetrieveItems(ISFunction.CreateDelegate(function (items)
        {
            this.Append(items);
        }, this));
    }
    // アイテムが設定済
    else if (this.Items)
    {
        var contentDiv = document.getElementById(this.GetElementId() + "_Content");
        for (var i = 0; i < this.Items.length; i++)
        {
            var item = this.Items[i];
            item.Render(contentDiv);
        }
    }

    // ページングイベント
    var contentDiv = document.getElementById(this.GetElementId() + "_Content");
    contentDiv.onscroll = ISFunction.CreateDelegate(function (event)
    {
        if (this.IsRunningOnScrolledToBottomEvent)
        {
            return;
        }

        var innerHeight  = ISDomAccessor.GetInnerHeight(contentDiv);
        var scrollTop    = contentDiv.scrollTop;
        var scrollHeight = contentDiv.scrollHeight;

        // 末尾10pxまできた場合
        if (innerHeight + scrollTop > scrollHeight - 10)
        {
            event.preventDefault();
            this.IsRunningOnScrolledToBottomEvent = true;
            var container = this;
            // ToDo: Event
            this.OnScrolledToBottom(function ()
            {
                container.IsRunningOnScrolledToBottomEvent = false;
            });
        }
    }, this);
}

iListContainer.prototype.OnScrolledToBottom = function(callback)
{
}


iListContainer.prototype.Append = function(items)
{
    if (this.Items)
    {
        this.Items.concat(items);
    }
    else
    {
        this.Items = items;
    }

    // レンダリング処理
    var contentDiv = document.getElementById(this.GetElementId() + "_Content");
    for (var i = 0; i < items.length; i++)
    {
        var item = items[i];
        item.Render(contentDiv);
    }    
}

iListContainer.prototype.Show = function()
{
    this.Hidden = false;
    this.ApplyStyle();
}

iListContainer.prototype.Hide = function()
{
    this.Hidden = true;
    this.ApplyStyle();
}

iListContainer.prototype.Clear = function()
{
    // Header
    var rootElement = this.GetElement()
    if (rootElement)
    {
        rootElement.outerHTML = "";
    }    
}

