//  LicenseCard
// -----------------------------------------------------------------------
Infoshare.Web.Control.LicenseCard = function Infoshare$Web$Control$LicenseCard(licenseInfo, style)
{
    this.LicenseInfo = licenseInfo;

    // エレメントの作成
    this.Element = this.CreateLicenseCardElement();
}

iLicenseCard = Infoshare.Web.Control.LicenseCard;

iLicenseCard.DisplayPropertyDefinition = null;
iLicenseCard.GetDisplayPropertyDefinition = function()
{
    if (iLicenseCard.DisplayPropertyDefinition)
    {
        return iLicenseCard.DisplayPropertyDefinition;
    }

    var definition = {
        Online:    [ iLicense.PropertyDefinitions.Key,
                     iLicense.PropertyDefinitions.Publisher,
                     iLicense.PropertyDefinitions.IssueDate,
                     iLicense.PropertyDefinitions.Type,
                     iLicense.PropertyDefinitions.Platform,
                     iLicense.PropertyDefinitions.ProductName,
                     iLicense.PropertyDefinitions.ProductVersion,
                     iLicense.PropertyDefinitions.SeatCount,
                     iLicense.PropertyDefinitions.TenantNames,
                     iLicense.PropertyDefinitions.ExpirationDate,
                     iLicense.PropertyDefinitions.UserName,
                     iLicense.PropertyDefinitions.Remarks ],

        Onpremise: [ iLicense.PropertyDefinitions.Key,
                     iLicense.PropertyDefinitions.Publisher,
                     iLicense.PropertyDefinitions.IssueDate,
                     iLicense.PropertyDefinitions.Type,
                     iLicense.PropertyDefinitions.Platform,
                     iLicense.PropertyDefinitions.ProductName,
                     iLicense.PropertyDefinitions.ProductVersion,
                     iLicense.PropertyDefinitions.FarmServerCount,
                     iLicense.PropertyDefinitions.FarmServerNames,
                     iLicense.PropertyDefinitions.ExpirationDate,
                     iLicense.PropertyDefinitions.UserName,
                     iLicense.PropertyDefinitions.Remarks ]
    };

    iLicenseCard.DisplayPropertyDefinition = definition;
    return definition;
};

// {0}:ヘッダー要素
// {1}:ライセンス属性テーブル
iLicenseCard.LicenseCardTemplate =
"<div class='is-LicenseCard' >" +
"{0}" +
"{1}" +
"</div>";

// {0}:プロダクト名
iLicenseCard.LicenseCardHeaderTemplate =
"<div class='is-LicenseCardHeader' >" +
"{0}" +
"</div>";

// {0}:ライセンス属性tr
iLicenseCard.LicenseCardTableTemplate =
"<table class='is-LicenseCardTable' >" +
  "<tbody>" +
    "{0}" +
  "</tbody>" +
"</table>";

// {0}:プロパティ名
// {1}:値
iLicenseCard.LicensePropertyRowTemplate =
"<tr class='is-LicenseCardTableRow'>" +
  "<td>{0}</td>" +
  "<td style='width: 5px;'></td>" +
  "<td>{1}</td>" +
"</tr>";

iLicenseCard.prototype = {
    LicenseInfo: null,
    Element: null,
        
    CreateLicenseCardElement: function()
    {
        // ライセンスカードヘッダー
        var productNameFormat = iResxResource.GetString('Page.ProductInfo.License.Format.ProductName');
        var productName = this.LicenseInfo.Properties[iLicense.PropertyDefinitions.ProductName.Name];
        var liceseHeaderHtml = ISString.Format(iLicenseCard.LicenseCardHeaderTemplate, ISString.Format(productNameFormat, productName));

        // ライセンス詳細情報テーブル
        var licensePlatform = this.LicenseInfo.Properties[iLicense.PropertyDefinitions.Platform.Name];
        var definition = iLicenseCard.GetDisplayPropertyDefinition();
        var displayPropertyDefinition = licensePlatform == "OnPremises" ? definition.Onpremise
                                                                        : definition.Online;
        // ライセンス詳細情報テーブル
        var tableHtml = this.GetLicenseTableHtml(displayPropertyDefinition);

        var licenseCardHtml = ISString.Format(iLicenseCard.LicenseCardTemplate, liceseHeaderHtml, tableHtml);

        var element = document.createElement("div");
        element.innerHTML = licenseCardHtml;

        return element;
    },

    GetLicenseTableHtml: function(displayPropertyDifinitions)
    {
        var html = "";

        var trHtml = "";
        for (var i = 0; i < displayPropertyDifinitions.length; i++)
        {
            var propertyDefinition = displayPropertyDifinitions[i];
            var propertyDisplayName = iLicense.GetPropertyDisplayName(propertyDefinition.Name);
            var propertyValue = this.LicenseInfo.Properties[propertyDefinition.Name];

            var formattedValue = this.GetFormattedPropertyValue(propertyDefinition, this.LicenseInfo.Properties);
            trHtml += ISString.Format(iLicenseCard.LicensePropertyRowTemplate, propertyDisplayName, formattedValue);
        }

        html = ISString.Format(iLicenseCard.LicenseCardTableTemplate, trHtml)
        return html;
    },

    GetFormattedPropertyValue: function(propertyDefinition, property)
    {
        var propertyValue = property[propertyDefinition.Name];
        var formattedValue = propertyValue;
        var type = propertyDefinition.Type;
        for (; ;)
        {
            if (type == iLicense.PropertyType.Boolean)
            {
                formattedValue = ISBoolean.TryParse(propertyValue, false);
                break;
            }
            if (type == iLicense.PropertyType.Date)
            {
                if (ISString.IsNullOrEmpty(propertyValue))
                {
                    formattedValue = "";
                }
                else
                {
                    var date = new Date(propertyValue);
                    var format = iResxResource.GetString('License.Format.Date');
                    formattedValue = iDate.Format(date, format);
                }

                // 有効期限の場合はライセンス種別も確認する
                if (propertyDefinition == iLicense.PropertyDefinitions.ExpirationDate)
                {
                    var licenseType = this.LicenseInfo.Properties[iLicense.PropertyDefinitions.Type.Name];
                    if (iLicense.IsPerpetualType(licenseType))
                    {
                        formattedValue = "";
                    }
                }

                break;
            }
            break;
        }

        if (type == iLicense.PropertyType.Custom)
        {
            for (; ;)
            {
                if (propertyDefinition == iLicense.PropertyDefinitions.Valid)
                {
                    var valid = ISBoolean.TryParse(propertyValue, false);
                    formattedValue = iLicense.GetStatusDisplayName(propertyValue);
                    break;
                }
                if (propertyDefinition == iLicense.PropertyDefinitions.Type)
                {
                    formattedValue = iLicense.GetTypeDisplayName(propertyValue);
                    break;
                }
                if (propertyDefinition == iLicense.PropertyDefinitions.Platform)
                {
                    formattedValue = iLicense.GetPlatformDisplayName(propertyValue);
                    break;
                }
                if (propertyDefinition == iLicense.PropertyDefinitions.FarmServerCount ||
                    propertyDefinition == iLicense.PropertyDefinitions.SeatCount)
                {
                    var count = ISNumber.TryParse(propertyValue, 0);
                    if (count <= 0)
                    {
                        formattedValue = "";
                    }
                    else
                    {
                        // フォーマットの取得
                        var format = iResxResource.GetString(ISString.Format('License.Format.{0}', propertyDefinition.Name));
                        formattedValue = ISString.Format(format, formattedValue);
                    }
                    break;
                }
                if (propertyDefinition == iLicense.PropertyDefinitions.FarmServerNames)
                {
                    // サーバー名は "," を改行コードに置き換える
                    formattedValue = ISString.Replace(propertyValue, ",", "<br>");
                    break;
                }

                break;
            }            
        }        

        return formattedValue;
    }
}
					 
                                         
