Infoshare.Globalization.ResxResource = function Infoshare$Globalization$ResxResource()
{
}
iResxResource = Infoshare.Globalization.ResxResource;
iResxResource.Extionsion = '.resx.xml';
iResxResource.Load = function (locator, callback)
{
    var resource = new iResxResource();
    resource.Locator = locator;
    resource.FullName = locator.FullName;
    resource.Name     = locator.Name;
    resource.LocaleId = locator.LocaleId;

    resource.Initialize(locator.Path, function ()
    {
        callback(resource);
    });
}
iResxResource.prototype = {
    Config: null,
    Locator: null,

    FullName: '',
    Name: '',
    LocaleId: '',

    Initialize: function (resourceUrl, callback)
    {
        if (!this.Config)
        {
            var config = new iBaseConfig('data', 'name', 'value');

            // 値取得実装を上書き
            config.GetConfigElementValue = function (configElement)
            {
                var valueElement = iXml.GetElementByTagName(configElement, config.ValueAttributeName);
                var value = valueElement.text ? valueElement.text
                                              : valueElement.textContent;
                return value;
            }

            // 初期化
            var resource = this;
            config.Initialize(resourceUrl, function ()
            {
                resource.Config = config;

                callback(resource);
            }, null);
        }
        else
        {
            var resource = this;
            setTimeout(function ()
            {
                callback(resource);
            }, 1);
        }
    },

    GetString: function (key)
    {
        // ToDo(skomatsu): ファイル名指定に対応
        var file = '';
        if (iString.Contains(key, ','))
        {
            file = key.split(',')[0];
            key  = key.split(',')[1];
        }

        return this.Config.GetSetting(key);
    }
}


