// -----------------------------------------------------------------------
//  BaseConfig
// -----------------------------------------------------------------------
Infoshare.Configuration.BaseConfig = function Infoshare$Configuration$BaseConfig(configElementName, keyAttributeName, valueAttributeName, configUrl)
{
    this.ConfigElementName  = ISString.IsNullOrEmpty(configElementName)  ? this.ConfigElementName  : configElementName;
    this.KeyAttributeName   = ISString.IsNullOrEmpty(keyAttributeName)   ? this.KeyAttributeName   : keyAttributeName;
    this.ValueAttributeName = ISString.IsNullOrEmpty(valueAttributeName) ? this.ValueAttributeName : valueAttributeName;

    this.ConfigUrl = ISString.IsNullOrEmpty(configUrl) ? this.ConfigUrl : configUrl;
}
iBaseConfig = Infoshare.Configuration.BaseConfig;
iBaseConfig.prototype = {
    ConfigElementName:  'add',
    KeyAttributeName:   'key',
    ValueAttributeName: 'value',

    ConfigUrl: null,
    ConfigXml: null,
    Settings:  null,

    Initialize: function(configUrl, callbackHandler, callbackParameter)
    {
        // URLを特定
        if (!ISString.IsNullOrEmpty(configUrl))
        {
            this.ConfigUrl = configUrl;
        }

        // ファイルを取得
        var request = new ISWebRequest();
        request.Url = this.ConfigUrl;
        request.Asynchronous = true;
        request.CallbackParameter = this;
        request.CallbackHandler = function(config)
        {
            var response = request.GetResponseXml();
            config.InitializeFromXml(response);

            callbackHandler(callbackParameter);
        };
        request.Invoke();
    },

    InitializeFromXml: function(xml)
    {
        if (this.ConfigXml && this.Settings)
        {
            return;
        }

        var element = xml;
        if (typeof(element) == 'string')
        {
            element = iXml.LoadXml(element);
        }

        var settings = new ISDictionary();
        var configs = element.getElementsByTagName(this.ConfigElementName);
        for (var i = 0; i < configs.length; i++)
        {
            var key   = this.GetConfigElementKey(configs[i]);
            var value = this.GetConfigElementValue(configs[i]);
            settings.Set(key, value);
        }

        this.ConfigXml = element;
        this.Settings = settings;
    },

    GetConfigElementKey: function(configElement)
    {
        return iXml.GetAttributeValue(configElement, this.KeyAttributeName);
    },

    GetConfigElementValue: function(configElement)
    {
        return iXml.GetAttributeValue(configElement, this.ValueAttributeName);
    },

    GetSetting: function(key)
    {
        var value = '';
        if (this.Settings &&
            this.Settings.Contains(key))
        {
            value = this.Settings.Get(key);
        }

        return value;
    },

    SetSetting: function(key, value)
    {
        var element = this.FindConfigElementByKey(key);
        if (element)
        {
            iXml.SetAttributeValue(element, this.ValueAttributeName, value);            
        }
        else
        {
            element = this.ConfigXml.ownerDocument.createElement(this.ConfigElementName);
            iXml.SetAttributeValue(element, key, value);
            
            this.ConfigXml.ownerDocument.documentElement.appendChild(element);
        }

        this.Settings.Set(key, value);
    },

    FindConfigElementByKey: function(key)
    {
        var element = null;
        if (this.ConfigXml &&
            this.Settings &&
            this.Settings.Contains(key))
        {
            var configs = this.ConfigXml.getElementsByTagName(this.ConfigElementName);
            for (var i = 0; i < configs.length; i++)
            {
                var keyValue = iXml.GetAttributeValue(configs[i], this.KeyAttributeName);
                if (ISString.Equals(key, keyValue, true))
                {
                    element = configs[i];
                    break;
                }
            }
        }

        return element;
    }
}


// -----------------------------------------------------------------------
//  CombinedConfig
// -----------------------------------------------------------------------
Infoshare.Configuration.CombinedConfig = function Infoshare$Configuration$CombinedConfig(sysConfig, appConfig)
{
    this.OverrideConfiguration    = new ISDictionary();
    this.SystemConfiguration      = sysConfig;
    this.ApplicationConfiguration = appConfig;
}
iCombinedConfig = Infoshare.Configuration.CombinedConfig;
iCombinedConfig.Create = function(sysConfig, appConfig, callback)
{
    var config = new iCombinedConfig();
    var count = 0;

    if (sysConfig)
    {
        sysConfig.Initialize(null, function()
        {
            config.SystemConfiguration = sysConfig;

            count++;
            if (count >= 2)
            {
                callback(config);
            }
        }, null);
    }
    else { count++; }

    if (appConfig)
    {
        appConfig.Initialize(null, function()
        {
            config.ApplicationConfiguration = appConfig;

            count++;
            if (count >= 2)
            {
                callback(config);
            }
        }, null);
    }
    else { count++; }
}
iCombinedConfig.prototype = {
    OverrideConfiguration: null,
    SystemConfiguration: null,
    ApplicationConfiguration: null,

    EnableCookie: true,
    EnableQueryString: true,

    GetSetting: function(key)
    {
        var setting = null;
        for (;;)
        {
            // 上書き設定から値を取得
            if (this.OverrideConfiguration.Contains(key))
            {
                setting = this.OverrideConfiguration.Get(key);
                if (this.HasValue(setting))
                {
                    break;
                }
            }

            // クエリストリングから値を取得
            setting = ISQueryString.GetValue(key);
            if (this.HasValue(setting))
            {
                break;
            }

            // クッキーから値を取得
            setting = ISCookie.Get(key);
            if (this.HasValue(setting))
            {
                break;
            }

            // アプリケーション構成から値を取得
            if (this.ApplicationConfiguration)
            {
                setting = this.ApplicationConfiguration.GetSetting(key);
                if (this.HasValue(setting))
                {
                    break;
                }
            }

            // システム構成から値を取得
            if (this.SystemConfiguration)
            {
                setting = this.SystemConfiguration.GetSetting(key);
                if (this.HasValue(setting))
                {
                    break;
                }
            }

            break;
        }

        return setting;
    },

    SetSetting: function(key, value)
    {
        this.OverrideConfiguration.Set(key, value);
    },

    HasValue: function(source)
    {
        return !ISObject.IsNullOrUndefined(source) &&
               !ISString.IsNullOrEmpty(source);
    }
}


