// -----------------------------------------------------------------------
Infoshare.Configuration.XmlBasedConfigurationParser = function Infoshare$Configuration$XmlBasedConfigurationParser() { };
iXConfigurationParser = Infoshare.Configuration.XmlBasedConfigurationParser;
iXConfigurationParser.TypeName = 'Infoshare.Configuration.XmlBasedConfigurationParser';

iXConfigurationParser.prototype = {
    TypeName: iXConfigurationParser.TypeName,

    keyAttribuetNames: ['Key', 'key', 'Name', 'name'],
    valueAttributeNames: ['Value', 'value'],
    BuildDictionaryFromKeyValuePair: function(elements)
    {
        // <KeyValuePair Key='X' Value='xxx' />
        // <KeyValuePair Key='Y' Value='yyy' />
        // <KeyValuePair Key='Z' Value='zzz' />

        var options = new ISDictionary();
        if (elements)
        {
            for (var i = 0; i < elements.length; i++)
            {
                var element = elements[i];
                var key   = iXml.GetAttributeValue(element, this.keyAttribuetNames);
                var value = iXml.GetAttributeValue(element, this.valueAttributeNames);

                if (!iString.IsNullOrEmpty(key) && 
                    !iString.IsNullOrEmpty(value))
                {
                    options.Set(key, value);
                }
            }
        }

        return options;
    },

    BuildOptionDictionary: function(optionsElement)
    {
        // <Options>
        //   <Option Key='X' Value='xxx' />
        //   <Option Key='Y' Value='yyy' />
        //   <Option Key='Z' Value='zzz' />
        // </Options>

        var options = new ISDictionary();
        if (optionsElement)
        {
            var optionElements = iXml.GetChildElementsByName(optionsElement, 'Option');
            options = this.BuildDictionaryFromKeyValuePair(optionElements);
        }

        return options;
    }
};
						  
