// -----------------------------------------------------------------------
//  BaseCSVConfig
// -----------------------------------------------------------------------
Infoshare.Configuration.BaseCSVConfig = function Infoshare$Configuration$BaseCSVConfig(keyFieldName, configUrl)
{
    this.KeyFieldName = ISString.IsNullOrEmpty(keyFieldName) ? this.KeyFieldName : keyFieldName;

    this.ConfigUrl = ISString.IsNullOrEmpty(configUrl) ? this.ConfigUrl : configUrl;
}
iBaseCSVConfig = Infoshare.Configuration.BaseCSVConfig;
iBaseCSVConfig.prototype = {
    ConfigUrl  : null,
    ConfigCSV  : null,
    Rows       : null,
    RowObjects : null,

    HasHeaderRow: true,
    KeyFieldName: '',

    Initialize : function(configUrl, callbackHandler, callbackParameter)
    {
        // fix url
        if (!ISString.IsNullOrEmpty(configUrl))
        {
            this.ConfigUrl = configUrl;
        }

        // retrieve config file
        var request = new ISWebRequest();
        request.Url               = this.ConfigUrl;
        request.Asynchronous      = true;
        request.CallbackParameter = this;
        request.CallbackHandler   = function (config)
        {
            var response = request.GetRawResponse();
            if (ISString.IsNullOrEmpty(response))
            {
                response = request.GetResponseText();
            }
            config.ConfigCSV = response;

            var parser = new ISCSVParser();
            config.Rows = parser.Parse(response);
            
            callbackHandler(callbackParameter);
        };
        request.Invoke();
    },

    GetRow: function(index)
    {
        var actualIndex = index;
        if (this.HasHeaderRow)
        {
            actualIndex += 1;
        }

        return this.Rows[actualIndex];
    },

    GetRowObject: function(key)
    {
        this.EnsureRowObjects();

        return this.RowObjects.Get(key);
    },

    EnsureRowObjects: function()
    {
        if (this.RowObjects)
        {
            return;
        }

        if (!this.HasHeaderRow)
        {
            throw new Error('Cannot create row object, since there is no header on this csv.');
        }

        // create row objects
        var rowObjects = new Array();
        var header = this.Rows[0];
        for (var i = 1; i < this.Rows.length; i++)
        {
            var row = this.Rows[i];
            var obj = new Object();
            for (var j = 0; j < header.length; j++)
            {
                obj[header[j]] = row[j];
                obj.Row = row;
            }

            rowObjects.push(obj);
        }

        // set to dictionary
        this.RowObjects = new ISDictionary();
        this.RowObjects.AddRange(rowObjects, this.KeyFieldName);
    }
}


