// -----------------------------------------------------------------------
//  Configuration
// -----------------------------------------------------------------------
Infoshare.Configuration.FeatureConfig = function Infoshare$Configuration$FeatureConfig()
{

}
iFeatureConfig = Infoshare.Configuration.FeatureConfig;
iFeatureConfig.ConfigurationFileSiteRelativePath = 'InfoshareProductLibrary/Configurations/Configuration.Feature.xml';

iFeatureConfig.Initialize = function(callback)
{
    var config = new Infoshare.Configuration.FeatureConfig();
    config.Initialize(function()
    {
        callback(config);
    });
}

iFeatureConfig.prototype = {
    Configuration : null,

    Features : null,
    
    Initialize: function(callback)
    {    
        if (iFeatureConfig.Initialized ||
            iFeatureConfig.Initializing)
        {
            ISTrace.TraceVerbose('Skipped iFeatureConfig.Initialize');
            callback();
            return;
        }
        iFeatureConfig.Initializing = true;

        var stopwatch = new ISStopwatch();
        stopwatch.Start();
        ISTrace.TraceVerbose('[BEGIN] iFeatureConfig.Initialize');

        this.Load(ISFunction.CreateDelegate(function(config)
        {
            var configXml = config.ApplicationConfiguration.ConfigXml;
            var featureConfig = this;
            this.EnsureFeatures(configXml, function()
            {
                featureConfig.Configuration = config;

                ISTrace.TraceVerbose('[END] iFeatureConfig.Initialize (spent: ' + stopwatch.Stop() + ')');
                iFeatureConfig.Initialized  = true;
                iFeatureConfig.Initializing = false;

                if (callback)
                {
                    callback();
                }
            });
        }, this));
    },

    Load: function(callback)
    {
        var configUrl = this.BuildUrl(iVxContext.MasterSiteAbsolutePath);
        var appConfig = new iBaseConfig('Setting', 'Key', 'Value', configUrl);
        iCombinedConfig.Create(null, appConfig, function(config)
        {
            callback(config);
        });
    },

    BuildUrl: function(baseUrl)
    {
        var url = ISString.TrimEnd(baseUrl, '/')
                + '/'
                + ISString.TrimStart(iFeatureConfig.ConfigurationFileSiteRelativePath, '/');

        return url;
    },
    
    EnsureFeatures: function(configXml, callback)
    {
        var featureInfos = new Array();

        // Features要素を取得
        var featuresElement = iXml.SelectNodeByPath(configXml, 'Configuration/Features');
        var featureElements = featuresElement.getElementsByTagName('Feature');
        for (var i = 0; i < featureElements.length; i++)
        {
            // Featureを初期化
            var featureElement = featureElements[i];
            // クラス情報の取得
            var classElement = iXml.SelectNodeByPath(featureElement, 'Class');
            var className = iXml.GetAttributeValue(classElement, 'Name');
            var source = iXml.GetAttributeValue(classElement, 'Source');
            
            var featureInfo = new iFeatureClassInfo(className, source);
            // リソース情報の取得
            if (!ISString.IsNullOrEmpty(source))
            {
                var resourceElement = iXml.SelectNodeByPath(featureElement, 'Resource');
                var resourceId = iXml.GetAttributeValue(resourceElement, 'Id');
                var resourceLocation = iXml.GetAttributeValue(resourceElement, 'Location');
                featureInfo.ResourceInfo = {
                    Id: resourceId,
                    Location: resourceLocation
                };
            }

            // コレクションに追加
            featureInfos.push(featureInfo);
        }

        // フィーチャークラスの初期化
        this.InitializeFeatures(featureInfos, callback);
    },


    InitializeFeatures: function(featureInfos, callback)
    {        
        // 非同期で初期化される為、並び順の制御用にDictionaryを用意する
        var featuresDictionary = new ISDictionary();
        var featuresCount = featureInfos.length;
        var featureContext = {
            InitializedCount : 0,
            Completed: function()
            {
                return this.InitializedCount == featuresCount;
            }
        };

        var featureConfiguration = this;
        var featureInitializedCallback = function()
        {
            featureContext.InitializedCount++;
            if (featureContext.Completed())
            {
                featureConfiguration.Features = featuresDictionary.GetValues();
                callback();
            }
        };

        for (var i = 0; i < featuresCount; i++)
        {
            var featureInfo = featureInfos[i]; 
            featuresDictionary.Set(featureInfo.ClassName, null);
        }

        // 追加スクリプト読みこみ完了イベントを作成する
        var additionalScriptCallBackDictionary = new ISDictionary();
        for (var i = 0; i < featuresCount; i++)
        {           
            var featureInfo = featureInfos[i];
            var scriptLoaded = function(featureClassName, resource)
            {
                try
                {
                    var feature = eval("new " + featureClassName + "()");
                    feature.Resource = resource;
                    featuresDictionary.Set(featureClassName, feature);
                    featureInitializedCallback();
                }
                catch(e){}
            }
                        
            // ソースの確認（別JSに定義されている場合はファイルを読み込み後にクラスを初期化
            if (!ISString.IsNullOrEmpty(featureInfo.SourceRelativePath))
            {
                if (!additionalScriptCallBackDictionary.Contains(featureInfo.SourceRelativePath))
                {
                    additionalScriptCallBackDictionary.Set(featureInfo.SourceRelativePath, []);

                    // スクリプトの読み込み
                    this.LoadExternalFiles(featureInfo, function (featureInfoWithResource)
                    {
                        scriptLoaded(featureInfoWithResource.ClassName, featureInfoWithResource.Resource);

                        // そのたフィーチャーの完了イベント実行
                        var othersFeatureInfomations = additionalScriptCallBackDictionary.Get(featureInfoWithResource.SourceRelativePath);
                        for(var j = 0; j < othersFeatureInfomations.length; j++)
                        {
                            scriptLoaded(othersFeatureInfomations[j].ClassName, featureInfoWithResource.Resource);
                        }
                    });
                }
                else
                {
                    additionalScriptCallBackDictionary.Get(featureInfo.SourceRelativePath).push(featureInfo);
                }
            }
            else
            {
                scriptLoaded(featureInfo.ClassName, null);
            }
        }
    },

    LoadExternalFiles: function (featureInfo, callback)
    {
        var externalFilesContext = {
            ScriptLoaded: false,
            ResourceLoaded: false,

            Complete: function()
            {
                return this.ScriptLoaded && this.ResourceLoaded;
            }
        };

        var loaded = function ()
        {
            if (externalFilesContext.Complete())
            {
                callback(featureInfo);
            }
        };

        // スクリプト読み込み
        var scriptPath = iVxContext.MasterSourcesPath + featureInfo.SourceRelativePath;
        ISScript.Load(scriptPath, null, function ()
        {
            externalFilesContext.ScriptLoaded = true;
            loaded();
        });

        // リソース読み込み
        // ToDo: フォールバックとしてニュートラルリソースも読み込むか検討
        var locators = new Array();

        // Infoshare
        var basePath = ISString.TrimEnd(iVxContext.MasterSourcesPath, '/') + '/Infoshare';
        var revisionSuffix = '?rev=' + ISPackageInfo.PackageTimestamp;

        locators.push(new iResxResourceLocator(basePath, 'Infoshare', iVxContext.Language, revisionSuffix));
        //locators.push(new iResxResourceLocator(basePath, 'Infoshare', null, revisionSuffix));

        // Infoshare.GroupPicker
        basePath = ISString.TrimEnd(iVxContext.MasterSourcesPath, '/') + '/Infoshare.InfoCall';
        //revisionSuffix = '?rev=' + GPPackageInfo.PackageTimestamp;
        revisionSuffix = '?rev=' + ISPackageInfo.PackageTimestamp;

        locators.push(new iResxResourceLocator(basePath, 'Infoshare.GroupPicker', iVxContext.Language, revisionSuffix));
        //locators.push(new iResxResourceLocator(basePath, 'Infoshare.GroupPicker', null, revisionSuffix));

        // 初期化
        iCompoundResource.Initialize(locators, function ()
        {
            externalFilesContext.ResourceLoaded = true;
            featureInfo.Resource = iCompoundResource;
            loaded();
        });

    },

    GetSetting: function(key)
    {
        return this.Configuration.GetSetting(key);
    },

    SetSetting: function(key, value)
    {
        this.Configuration.SetSetting(key, value);
    }
}


