// -----------------------------------------------------------------------
Infoshare.SharePoint.Utility = function Infoshare$SharePoint$Utility() { }
iSPUtility = Infoshare.SharePoint.Utility;

iSPUtility.RegisterOnLoadFunction = function(functionName)
{
    if (typeof(_spBodyOnLoadFunctionNames) != 'undefined' &&
        _spBodyOnLoadFunctionNames instanceof Array)
    {
        _spBodyOnLoadFunctionNames.push(functionName);
    }
    else if (typeof($) != 'undefined')
    {
        $.ready(function()
        {
            eval(functionName + '();');
        });
    }
    else if (typeof(i$) != 'undefined')
    {
        i$.ready(function()
        {
            eval(functionName + '();');
        });
    }
    else
    {
        ISDomAccessor.AttachEvent(window, 'load', function ()
        {
            eval(functionName + '();');
        });
    }
}
iSPUtility.RegisterOnLoadFunctionForMDS = function(scriptUrl, functionName)
{
    // MDS（ダウンロード最小化戦略）が有効化されている場合
    if (typeof g_mdsReady != "undefined")
    {
        RegisterModuleInit(scriptUrl, function ()
        {
            iSPUtility.RegisterOnLoadFunction(functionName);
        });
    }
    
    iSPUtility.RegisterOnLoadFunction(functionName);
}
iSPUtility.PageBack = function()
{
    if (!ISString.IsNullOrEmpty(ISQueryString.GetValue('source')))
    {
        var source = unescape(ISQueryString.GetValue('source'));
        window.location.href = source;
    }
    else
    {
        // use history badk
        window.parent.history.back();
    }
}
iSPUtility.EscapeForListUrl = function(text)
{
    // 主にリスト作成時に名称設定する場合に使
    // リスト名に処理対象文字が含まれるとその文字が取り除かれた名称となる
    // List-リスト → List | ハイフンとマルチバイト文字が消失したリスト名（URL）となる

    var escapeChars = [' ', '!', '"', '#', '$', '%', '&', '\'',
                        '(',  ')', '-', '*', '+', ',', '.', '/',
                        ':',  ';', '<', '=', '>', '?', '@', '[', 
                        '\\', ']', '^', '`', '{', '|', '}', '~' ];

    var map = new iDictionary();
    for (var i = 0; i < escapeChars.length; i++)
    {
        var escapeChar = escapeChars[i];
        map.Add(escapeChar, '' + escapeChar.charCodeAt()); // 文字列として格納
    }

    var escaped = '';
    for (var i = 0; i < text.length; i++)
    {
        // ASCII 範囲をシングルバイト、それ以外をマルチバイトと判断
        var c = text.charAt(i);
        if (c.match(/[ -~]/))
        {
            // シングルバイト（ASCII）の場合は、必要な物のみエスケープ
            if (map.Contains(c))
            {
                escaped += '' + map.Get(c); // 文字列として連結
            }
            else
            {
                escaped += c;
            }
        }
        else
        {
            // マルチバイト（非ASCII）の場合は、すべてエスケープ
            escaped += '' + c.charCodeAt(); // 文字列として連結
        }
    }

    return escaped;
}


// -----------------------------------------------------------------------
//  Notify
// -----------------------------------------------------------------------
Infoshare.SharePoint.Notify = function Infoshare$SharePoint$Notify() { }
iSPNotify = Infoshare.SharePoint.Notify;

iSPNotify.NotificationsCount = 0;
iSPNotify.NotificationArea = null;
iSPNotify.BaseNotificationStyle = null;
iSPNotify.Notify = function (message, x, y, interval)
{
    // SharePointの通知実装を利用する為、コンテキスト差などでエラーが発生する可能性を考慮してTry-Catchする
    try
    {
        iSPNotify.NotifyInternal(message, x, y, interval);
    }
    catch (e)
    {
        ISTrace.TraceError('[Error] iSPNotify.Notify');
        ISTrace.TraceError(e);
    }
}

iSPNotify.NotifyInternal = function(message, x, y, interval)
{   
    // 通知エリアの取得
    var notiArea = document.getElementById("notificationArea");
    if (!notiArea &&
        iSPNotify.NotificationArea)
    {
        document.body.appendChild(iSPNotify.NotificationArea);
        notiArea = document.getElementById("notificationArea");
    }

    // 元のnotificationAreaのスタイルをキャッシュ
    if (!iSPNotify.BaseNotificationStyle)
    {
        iSPNotify.BaseNotificationStyle = { zIndex : notiArea.style["z-index"],
                                            right  : notiArea.style["right"],
                                            left   : notiArea.style["left"],
                                            top    : notiArea.style["top"] };
    }
    
    // リボンが開いた状態では縦方向の補正が必要なので、開いたリボンが存在するかを確認する
    var offsetY = 110;
    var ribbon = SP && SP.Ribbon && SP.Ribbon.PageManager ? SP.Ribbon.PageManager.get_instance().get_ribbon()
                                                          : null;
    if (ribbon)
    {
        var selectedTabId = ribbon.get_selectedTabId();
        if (selectedTabId &&
            selectedTabId != "Ribbon.Read") // 参照タブはリボン領域が存在しない
        {
            offsetY += 90;
        }
    }

    // z-index
    notiArea.style["z-index"] = '50000'; // スクリーンブロッカーの上で表示する為

    // position
    // 位置指定が無い場合設定しない
    if (x && y)
    {
        // 表示位置の修正
        notiArea.style["right"] = 'auto';　// corev15.cssの定義の上書き
        x = x < 0 ? 0 : x;
        y = y < offsetY ? offsetY : y;
        notiArea.style["left"] = x + 'px';
        notiArea.style["top"]  = y - offsetY + 'px';
    }
    
    var notificationId = addNotification(message);
    iSPNotify.NotificationsCount ++;

    interval = interval ? interval : 5000;
    setTimeout(function()
    {
        removeNotification(notificationId);
        iSPNotify.NotificationsCount --;

        if (iSPNotify.NotificationsCount <= 0)
        {
            // 暫定実装：removeNotificationの完了まで待つ
            setTimeout(function()
            {
                // スタイルを元に戻す
                notiArea.style["z-index"] = iSPNotify.BaseNotificationStyle.zIndex;
                notiArea.style["right"]   = iSPNotify.BaseNotificationStyle.right;
                notiArea.style["left"]    = iSPNotify.BaseNotificationStyle.left;
                notiArea.style["top"]     = iSPNotify.BaseNotificationStyle.top;

                iSPNotify.BaseNotificationStyle = null;
            }, 1000);
        }
    }, interval);
}

// -----------------------------------------------------------------------
//  Alert：window.alertが使用できない場合にiSPNotifyを利用する
// -----------------------------------------------------------------------
Infoshare.SharePoint.Alert = function Infoshare$SharePoint$Alert() { }
iSPAlert = Infoshare.SharePoint.Alert;

iSPAlert.Alert = function(message)
{
    try
    {
        alert(message);
    }
    catch(e)
    {
        iSPNotify.Notify(message, 100, 115, 2000)
    }
}                          
