// -----------------------------------------------------------------------
//  UserCustomActions (UserCustomActionCollection)
// -----------------------------------------------------------------------
Infoshare.SharePoint.UserCustomActions = function Infoshare$SharePoint$UserCustomActions() { }
ISSPUserCustomActions = Infoshare.SharePoint.UserCustomActions;
ISSPUserCustomActions.FromRestXml = function (request) {

    var ucas = new Array();

    var responseElement = request.GetResponseXml();
    var ucasElement = responseElement.documentElement;
    for (var i = 0; i < ucasElement.childNodes.length; i++) {
        var ucaElement = ucasElement.childNodes.item(i);
        var nodeName = ucaElement.baseName ? ucaElement.baseName
                                           : ucaElement.tagName;

        if (nodeName == 'entry') {
            
            var uca = new ISSPUserCustomAction();

            var propertiesElement = iXml.SelectNodeByPath(ucaElement, 'content/m:properties');
            uca.Properties = iXml.GetChildElementsByArray(propertiesElement, 'd:');

            var descriptionString = uca.Properties['Description'];
            if (!ISString.IsNullOrEmpty(descriptionString))
            {
                // エスケープされたタグを置換する
                descriptionString = ISString.Replace(descriptionString, "&lt;", "<");
                descriptionString = ISString.Replace(descriptionString, "&gt;", ">");
            }

            uca.Description = descriptionString;
            uca.Id          = uca.Properties['Id'];
            uca.Location    = uca.Properties['Location'];
            uca.ScriptSrc   = uca.Properties['ScriptSrc'];
            uca.Sequence    = uca.Properties['Sequence'];
            uca.Title       = uca.Properties['Title'];

            ucas.push(uca);
        }
    }

    return ucas;
}
ISSPUserCustomActions.FromJson = function (request) {

    var ucas = new Array();

    var responseText = request.GetResponseText();
    var responseObject = ISJSON.parse(responseText);
    var results = responseObject.d.results;

    for (var i = 0; i < results.length; i++) {
        
        var uca = new ISSPUserCustomAction();

        uca.Properties = results[i];

        uca.Description = uca.Properties['Description'];
        uca.Id          = uca.Properties['Id'];
        uca.Location    = uca.Properties['Location'];
        uca.ScriptSrc   = uca.Properties['ScriptSrc'];
        uca.Sequence    = uca.Properties['Sequence'];
        uca.Title       = uca.Properties['Title'];

        ucas.push(uca);
    }

    return ucas;
}
