// -----------------------------------------------------------------------
Infoshare.SharePoint.List = function Infoshare$SharePoint$List()
{
    this.Properties = new Array();
}
ISSPList = Infoshare.SharePoint.List;
ISSPList.FromXml = function(element)
{
    var list = new ISSPList();
    list.Properties = iXml.GetAttributesByArray(element);

    list.Id             = list.Properties['ID'];
    list.Title          = list.Properties['Title'];
    list.Description    = list.Properties['Description'];
    list.ServerTemplate = ISNumber.TryParse(list.Properties['ServerTemplate'], list.ServerTemplate);
    list.Hidden         = ISBoolean.TryParse(list.Properties['Hidden'], list.Hidden);

    list.ItemCount                     = ISNumber.TryParse(list.Properties['ItemCount'], list.ItemCount);
    list.NoThrottleListOperations      = ISBoolean.TryParse(list.Properties['NoThrottleListOperations'], list.NoThrottleListOperations);
    list.MaxItemsPerThrottledOperation = ISNumber.TryParse(list.Properties['MaxItemsPerThrottledOperation'], list.MaxItemsPerThrottledOperation);

    // fields
    var fieldsElement = iXml.SelectNodeByPath(element, 'Fields');
    if (fieldsElement)
    {
        var fields = new ISDictionary();
        for (var i = 0; i < fieldsElement.childNodes.length; i++)
        {
            var fieldElement = fieldsElement.childNodes.item(i);
            var field = ISSPField.FromXml(fieldElement);
            fields.Add(field.Name, field);
        }

        list.Fields = fields;
    }

    return list;
}
ISSPList.FromRestXml = function(element)
{
    var list = new ISSPList();

    var propertiesElement = iXml.SelectNodeByPath(element, 'content/m:properties');
    list.Properties = iXml.GetChildElementsByArray(propertiesElement, 'd:');

    list.Id             = list.Properties['Id'];
    list.Title          = list.Properties['Title'];
    list.Description    = list.Properties['Description'];
    list.ServerTemplate = ISNumber.TryParse(list.Properties['BaseTemplate'], list.ServerTemplate);
    list.Hidden         = ISBoolean.TryParse(list.Properties['Hidden'], list.Hidden);

    list.ItemCount                     = ISNumber.TryParse(list.Properties['ItemCount'], list.ItemCount);
    list.NoThrottleListOperations      = ISBoolean.TryParse(list.Properties['NoThrottleListOperations'], list.NoThrottleListOperations);
    list.MaxItemsPerThrottledOperation = ISNumber.TryParse(list.Properties['MaxItemsPerThrottledOperation'], list.MaxItemsPerThrottledOperation);

    return list;
}
ISSPList.FromJson = function(obj)
{
    var list = new ISSPList();
    list.Properties = obj;

    list.Id             = list.Properties['Id'];
    list.Title          = list.Properties['Title'];
    list.Description    = list.Properties['Description'];
    list.ServerTemplate = ISNumber.TryParse(list.Properties['BaseTemplate'], list.ServerTemplate);
    list.Hidden         = ISBoolean.TryParse(list.Properties['Hidden'], list.Hidden);

    list.ItemCount                     = ISNumber.TryParse(list.Properties['ItemCount'], list.ItemCount);
    list.NoThrottleListOperations      = ISBoolean.TryParse(list.Properties['NoThrottleListOperations'], list.NoThrottleListOperations);
    list.MaxItemsPerThrottledOperation = ISNumber.TryParse(list.Properties['MaxItemsPerThrottledOperation'], list.MaxItemsPerThrottledOperation);

    return list;
}
ISSPList.SetFields = function(list, fieldsArray)
{
    var fields = new ISDictionary();
    for (var i = 0; i < fieldsArray.length; i++)
    {
        var field = fieldsArray[i];
        fields.Add(field.Name, field);
    }

    list.Fields = fields;
}
ISSPList.prototype = {
    Id: '',
    Title: '',
    Description: '',
    ServerTemplate: ISSPListTemplateType.InvalidType,
    Hidden: false,

    ItemCount: 0,
    NoThrottleListOperations: false,
    MaxItemsPerThrottledOperation: 0,

    Properties: null,

    Fields: null
}


