Infoshare.SharePoint.Field = function Infoshare$SharePoint$Field()
{
    this.Properties = new Array();
}
ISSPField = Infoshare.SharePoint.Field;
ISSPField.FromXml = function(element)
{
    var field = new ISSPField();
    field.Properties = iXml.GetAttributesByArray(element);

    field.Id          = field.Properties['ID'];
    field.Type        = field.Properties['Type'];
    field.Name        = field.Properties['Name'];
    field.DisplayName = field.Properties['DisplayName'];
    field.Description = field.Properties['Description'];
    field.Hidden      = ISBoolean.TryParse(field.Properties['Hidden'], field.Hidden);

    return field;
}
ISSPField.FromRestXml = function(element)
{
    var propertiesElement = iXml.SelectNodeByPath(element, 'content/m:properties');
    var properties = iXml.GetChildElementsByArray(propertiesElement, 'd:');
    propertiesElement = iXml.LoadXml(properties['SchemaXml']);

    return ISSPField.FromXml(propertiesElement.documentElement);
}
ISSPField.FromJson = function(obj)
{
    var propertiesElement = iXml.LoadXml(obj['SchemaXml']);

    return ISSPField.FromXml(propertiesElement.documentElement);
}
ISSPField.prototype = {
    Id: '',
    Type: '',
    Name: '',
    DisplayName: '',
    Description: '',
    Hidden: false,

    Properties: null
}


