Infoshare.SharePoint.FieldUpdateResult = function Infoshare$SharePoint$FieldUpdateResult() {}
ISSPFieldUpdateResult = Infoshare.SharePoint.FieldUpdateResult;
ISSPFieldUpdateResult.FromXml = function(element)
{
    var result = new ISSPItemUpdateResult();

    // id and command
    var idAttribute = iXml.GetAttributeValue(element, 'ID');
    result.Id      = idAttribute.split(',')[0];

    // error
    result.Error = ISSPUpdateError.FromXml(element);

    // field
    var fieldElement = iXml.GetElementByTagName(element, 'Field');
    if (fieldElement)
    {
        result.Field = ISSPField.FromXml(fieldElement);
    }

    return result;
}
ISSPFieldUpdateResult.FromJson = function(obj)
{
    // ToDo: implement
    return null;
}
ISSPFieldUpdateResult.prototype = {
    Id: '',
    Error: null,

    Field: null
}



// -----------------------------------------------------------------------
//  View
// -----------------------------------------------------------------------
Infoshare.SharePoint.View = function Infoshare$SharePoint$View() { }
ISSPView = Infoshare.SharePoint.View;
ISSPView.FromXml = function(element)
{
    var view = new ISSPView();
    view.Properties = iXml.GetAttributesByArray(element);

    view.Id          = view.Properties['Name'];
    view.Type        = view.Properties['Type'];
    view.Name        = view.Properties['Name'];
    view.DisplayName = view.Properties['DisplayName'];
    view.Description = view.Properties['Description'];
    view.DefaultView = ISBoolean.TryParse(view.Properties['DefaultView'], view.Hidden);
    view.Hidden      = ISBoolean.TryParse(view.Properties['Hidden'], view.Hidden);
    view.Url         = view.Properties['Url'];

    // query
    var queryElement = iXml.SelectNodeByPath(element, 'Query');
    if (queryElement)
    {
        view.Query = iXml.GetOuterXml(queryElement);
    }

    // view fields
    var viewFieldsElement = iXml.SelectNodeByPath(element, 'ViewFields');
    if (viewFieldsElement)
    {
        // view fields
        view.ViewFields = iXml.GetOuterXml(viewFieldsElement);

        // array of field refs
        var fields = new ISDictionary();
        for (var i = 0; i < viewFieldsElement.childNodes.length; i++)
        {
            var fieldElement = viewFieldsElement.childNodes.item(i);
            var field = ISSPField.FromXml(fieldElement);
            fields.Add(field.Name, field);
        }

        view.ViewFieldRefs = fields;
    }

    // row limit
    var rowLimitElement = iXml.SelectNodeByPath(element, 'RowLimit');
    if (rowLimitElement)
    {
        this.RowLimit = ISNumber.TryParse(rowLimitElement.innerText, this.RowLimit);
    }

    return view;
}
ISSPView.FromRestXml = function(element)
{
    var propertiesElement = iXml.SelectNodeByPath(element, 'content/m:properties');
    var properties = iXml.GetChildElementsByArray(propertiesElement, 'd:');
    propertiesElement = iXml.LoadXml(properties['ListViewXml']);

    return ISSPView.FromXml(propertiesElement.documentElement);
}
ISSPView.FromJson = function(obj)
{
    var propertiesElement = iXml.LoadXml(obj.ListViewXml);

    return ISSPView.FromXml(propertiesElement.documentElement);
}
ISSPView.prototype = {
    Id: '',
    Type: '',
    Name: '',
    DisplayName: '',
    Description: '',
    DefaultView: '',
    Hidden: false,
    Url: '',

    Properties: null,

    Query: '',
    ViewFields: '',
    ViewFieldRefs: null,
    RowLimit: 0
}


