ISSPItem.FromXml = function(element)
{
    var item = new ISSPItem();
    item.Properties = iXml.GetAttributesByArray(element, 'ows_');

    item.Id       = ISNumber.TryParse(item.Properties['ID'], ISSPItem.InvalidItemId);
    item.Title    = item.Properties['Title'];
    item.Created  = item.Properties['Created'];
    item.Modified = item.Properties['Modified'];

    return item;
}
ISSPItem.FromJson = function(obj)
{
    var item = new ISSPItem();
    item.Properties = obj;

    item.Id       = ISNumber.TryParse(item.Properties['ID'], ISSPItem.InvalidItemId);
    item.Title    = item.Properties['Title'];
    item.Created  = item.Properties['Created'];
    item.Modified = item.Properties['Modified'];

    return item;
}
