// -----------------------------------------------------------------------
Infoshare.SharePoint.ItemUpdateResult = function Infoshare$SharePoint$ItemUpdateResult() {}
ISSPItemUpdateResult = Infoshare.SharePoint.ItemUpdateResult;
ISSPItemUpdateResult.FromXml = function(element)
{
    var result = new ISSPItemUpdateResult();

    // id and command
    var idAttribute = iXml.GetAttributeValue(element, 'ID');
    result.Id      = idAttribute.split(',')[0];
    result.Command = idAttribute.split(',')[1];

    // error
    result.Error = ISSPUpdateError.FromXml(element);

    // item
    var rowElement = iXml.GetElementByTagName(element, 'z:row');
    if (rowElement)
    {
        result.Item = ISSPItem.FromXml(rowElement);
    }

    return result;
}
ISSPItemUpdateResult.FromJson = function(obj)
{
    // ToDo: implement
    return null;
}
ISSPItemUpdateResult.prototype = {
    Id: '',
    Command: '',
    Error: null,

    Item: null
}


// -----------------------------------------------------------------------
//  UpdateError
// -----------------------------------------------------------------------
Infoshare.SharePoint.UpdateError = function Infoshare$SharePoint$UpdateError(code, text)
{
    this.Code = code;
    this.Text = ISString.IsNullOrEmpty(text) ? '' : text;
}
ISSPUpdateError = Infoshare.SharePoint.UpdateError;
ISSPUpdateError.FromXml = function(element)
{
    var error = null;

    var codeElement = iXml.GetElementByTagName(element, 'ErrorCode');
    var textElement = iXml.GetElementByTagName(element, 'ErrorText');

    if (codeElement && codeElement.value)
    {
        error = new ISSPUpdateError(codeElement.value);
        error.Code = codeElement.text;
        error.Text = textElement == null ? '' : textElement.text;
    }

    return error;
}
ISSPUpdateError.prototype = {
    Code: '',
    Text: ''
}


// -----------------------------------------------------------------------
//  Query
// -----------------------------------------------------------------------
Infoshare.SharePoint.Query = function Infoshare$SharePoint$Query(query, queryOptions, viewFields, rowLimit, tryQuery, enableIterativeQueries)
{
    this.Query        = query;
    this.QueryOptions = queryOptions;
    this.ViewFields   = viewFields;
    this.RowLimit     = rowLimit;

    // settings for query iteration
    this.TryQuery               = ISObject.IsNullOrUndefined(tryQuery) ? true : tryQuery;
    this.EnableIterativeQueries = ISObject.IsNullOrUndefined(enableIterativeQueries) ? true : enableIterativeQueries;
}
ISSPQuery = Infoshare.SharePoint.Query;
ISSPQuery.prototype = {
    Query        : '',
    QueryOptions : '',
    ViewFields   : '',
    RowLimit     : 0,

    // settings for query iteration
    TryQuery               : true,
    EnableIterativeQueries : true,
    
    Ensure: function()
    {
        this.Query        = !this.Query           ? ''   : this.Query;
        this.QueryOptions = !this.QueryOptions    ? ''   : this.QueryOptions;
        this.ViewFields   = !this.ViewFields      ? ''   : this.ViewFields;
        this.RowLimit     = isNaN(this.RowLimit)  ? 0    : this.RowLimit;

        this.TryQuery               = ISObject.IsNullOrUndefined(this.TryQuery) ? true : this.TryQuery;
        this.EnableIterativeQueries = ISObject.IsNullOrUndefined(this.EnableIterativeQueries) ? true : this.EnableIterativeQueries;
    },

    Clone: function()
    {
        var query = new ISSPQuery(this.Query, this.QueryOptions, this.ViewFields, this.RowLimit, this.TryQuery, this.EnableIterativeQueries);

        return query;
    }
}
                          
