Infoshare.SharePoint.WebService.ServiceCommon = function Infoshare$SharePoint$WebService$ServiceCommon() { }
SPServiceCommon = Infoshare.SharePoint.WebService.ServiceCommon;

SPServiceCommon.SoapNamespace          = 'http://schemas.microsoft.com/sharepoint/soap/';
SPServiceCommon.DirectorySoapNamespace = 'http://schemas.microsoft.com/sharepoint/soap/directory/';
SPServiceCommon.BuildRequest = function(webUrl, serviceFile, serviceNamespace, operationName)
{
    var request = new ISSoapRequest();
    request.Url              = ISString.TrimEnd(webUrl, '/') + '/_vti_bin/' + serviceFile;
    request.ServiceNamespace = serviceNamespace;
    request.OperationName    = operationName;

    return request;
}
SPServiceCommon.BuildResultElementXPath = function(operationName, elementName)
{
    if (!elementName)
    {
        elementName = '';
    }

    var xpath = 'soap:Envelope/soap:Body/' + operationName + 'Response/' + operationName + 'Result/' + elementName;
    xpath = ISString.TrimEnd(xpath, '/');

    return xpath;
}
                                   
