Infoshare.SharePoint.WebService.SitesService = function Infoshare$SharePoint$WebService$SitesService(webUrl)
{
    this.WebUrl = webUrl;
}
SPSitesService = Infoshare.SharePoint.WebService.SitesService;

SPSitesService.ServiceFile = 'Sites.asmx';
SPSitesService.ServiceNamespace = SPServiceCommon.SoapNamespace;
SPSitesService.Operations = { GetSite: 'GetSite' };

SPSitesService.prototype = {
    WebUrl: '',

    BuildRequest: function(operationName)
    {
        var request = SPServiceCommon.BuildRequest(this.WebUrl,
                                                   SPSitesService.ServiceFile,
                                                   SPSitesService.ServiceNamespace,
                                                   operationName);

        return request;
    },

    GetSite: function(siteUrl, callback)
    {
        // create initialize request
        var request = this.BuildRequest(SPSitesService.Operations.GetSite);
        request.Body = '<SiteUrl>' + siteUrl + '</SiteUrl>';

        // invocation
        if (callback)
        {
            request.Asynchronous = true;
            request.CallbackHandler = ISFunction.CreateDelegate(function()
            {
                var responseElement = request.GetResponseXml();
                var site = this.GetSiteFromXml(responseElement);

                callback(site);
            }, this);

            request.Invoke();
        }
        else
        {
            request.Invoke();
            var responseElement = request.GetResponseXml();
            var site = this.GetSiteFromXml(responseElement);

            return site;
        }
    },

    GetSiteFromXml: function(responseElement)
    {
        var site = null;

        var xpath = SPServiceCommon.BuildResultElementXPath(SPSitesService.Operations.GetSite);
        var resultElement = iXml.SelectNodeByPath(responseElement, xpath);

        if (resultElement)
        {
            var value = resultElement.nodeTypedValue;
            if (!value)
            {
                var innerHtml = resultElement.innerHTML;
                // エスケースされたタグを置換する
                innerHtml = ISString.Replace(innerHtml, "&lt;", "<");
                innerHtml = ISString.Replace(innerHtml, "&gt;", ">");
                value = innerHtml;
            }

            if (value)
            {
                var siteElement = iXml.LoadXml(value);
                site = ISSPSite.FromXml(siteElement.documentElement);
            }
        }

        return site;
    }
}
                                   
