//  ListsService
// -----------------------------------------------------------------------
Infoshare.SharePoint.WebService.ListsService = function Infoshare$SharePoint$WebService$ListsService(webUrl)
{
    this.WebUrl = webUrl;
}
SPListsService = Infoshare.SharePoint.WebService.ListsService;

SPListsService.ServiceFile = 'Lists.asmx';
SPListsService.ServiceNamespace = SPServiceCommon.SoapNamespace;
SPListsService.Operations = { GetList:           'GetList',
                              AddList:           'AddList',
                              DeleteList:        'DeleteList',
                              UpdateList:        'UpdateList',
                              GetListCollection: 'GetListCollection',
                              GetListItems:      'GetListItems',
                              UpdateListItems:   'UpdateListItems' };

SPListsService.prototype = {
    WebUrl: '',

    BuildRequest: function(operationName)
    {
        var request = SPServiceCommon.BuildRequest(this.WebUrl,
                                                   SPListsService.ServiceFile,
                                                   SPListsService.ServiceNamespace,
                                                   operationName);

        return request;
    },

    BuildListFromXml: function(responseElement, operationName)
    {
        var xpath = SPServiceCommon.BuildResultElementXPath(operationName, 'List');
        var listElement = iXml.SelectNodeByPath(responseElement, xpath);
        var list = ISSPList.FromXml(listElement);

        return list;
    },

    BuildListArrayFromXml: function(responseElement)
    {
        var xpath = SPServiceCommon.BuildResultElementXPath(SPListsService.Operations.GetListCollection, 'Lists');
        var listsElement = iXml.SelectNodeByPath(responseElement, xpath);
                
        var lists = new Array();

        if (listsElement &&
            listsElement.childNodes)
        {
            for (var i = 0; i < listsElement.childNodes.length; i++)
            {
                var listElement = listsElement.childNodes.item(i);
                var list = ISSPList.FromXml(listElement);
                lists.push(list);
            }
        }

        return lists;
    },

    BuildListUpdateResultArrayFromXml: function(responseElement)
    {
        var xpath = SPServiceCommon.BuildResultElementXPath(SPListsService.Operations.UpdateList, 'Results');
        var resultsElement = iXml.SelectNodeByPath(responseElement, xpath);

        var results = new Array();

        if (!resultsElement || !resultsElement.childNodes)
        {
            return null;
        }

        // new fields
        var newFieldsResultsElement = iXml.SelectNodeByPath(resultsElement, 'NewFields');
        var newFieldsResults = new Array();
        for (var i = 0; i < newFieldsResultsElement.childNodes.length; i++)
        {
            var resultElement = newFieldsResultsElement.childNodes.item(i);
            var result = ISSPFieldUpdateResult.FromXml(resultElement);
            newFieldsResults.push(result);
        }
        results['NewFields'] = newFieldsResults;

        // update fields
        var updateFieldsResultsElement = iXml.SelectNodeByPath(resultsElement, 'UpdateFields');
        var updateFieldsResults = new Array();
        for (var i = 0; i < updateFieldsResultsElement.childNodes.length; i++)
        {
            var resultElement = updateFieldsResultsElement.childNodes.item(i);
            var result = ISSPFieldUpdateResult.FromXml(resultElement);
            updateFieldsResults.push(result);
        }
        results['UpdateFields'] = updateFieldsResults;

        // delete fields
        var deleteFieldsResultsElement = iXml.SelectNodeByPath(resultsElement, 'DeleteFields');
        var deleteFieldsResults = new Array();
        for (var i = 0; i < deleteFieldsResultsElement.childNodes.length; i++)
        {
            var resultElement = deleteFieldsResultsElement.childNodes.item(i);
            var result = ISSPFieldUpdateResult.FromXml(resultElement);
            deleteFieldsResults.push(result);
        }
        results['DeleteFields'] = deleteFieldsResults;

        return results;
    },

    BuildItemArrayFromXml: function(responseElement)
    {
        var xpath = SPServiceCommon.BuildResultElementXPath(SPListsService.Operations.GetListItems, 'listitems/rs:data');
        var dataElement = iXml.SelectNodeByPath(responseElement, xpath);

        var items = new Array();

        // XMLが不正な場合は、nullを返す（5000アイテム問題のケース）
        if (!dataElement || !dataElement.childNodes)
        {
            return null;
        }

        for (var i = 0; i < dataElement.childNodes.length; i++)
        {
            var node = dataElement.childNodes[i];
            if (node.nodeName == "z:row")
            {
                var rowElement = dataElement.childNodes.item(i);
                var item = ISSPItem.FromXml(rowElement);
                items.push(item);
            }
        }

        return items;
    },

    BuildItemUpdateResultArrayFromXml: function(responseElement)
    {
        var xpath = SPServiceCommon.BuildResultElementXPath(SPListsService.Operations.UpdateListItems, 'Results');
        var resultsElement = iXml.SelectNodeByPath(responseElement, xpath);

        var results = new Array();

        if (!resultsElement || !resultsElement.childNodes)
        {
            return null;
        }

        for (var i = 0; i < resultsElement.childNodes.length; i++)
        {
            var resultElement = resultsElement.childNodes.item(i);
            var result = ISSPItemUpdateResult.FromXml(resultElement);
            results.push(result);
        }

        return results;
    },

    BuildMetaDataFromXml: function(responseElement)
    {
        var xpath = SPServiceCommon.BuildResultElementXPath(SPListsService.Operations.GetListItems, 'listitems/rs:data');
        var dataElement = iXml.SelectNodeByPath(responseElement, xpath);

        // XMLが不正な場合は、nullを返す（5000アイテム問題のケース）
        if (!dataElement || !dataElement.childNodes)
        {
            return null;
        }

        var dataObject = null;
        if (dataElement && dataElement.attributes)
        {
            var count    = dataElement.attributes.ItemCount ? dataElement.attributes.ItemCount.value : null;
            var position = dataElement.attributes.ListItemCollectionPositionNext ? dataElement.attributes.ListItemCollectionPositionNext.value : null;

            dataObject = { ItemCount: count,
                           ListItemCollectionPositionNext: position };
        }
        return dataObject;
    },

    AddList: function(name, description, templateId, callback)
    {
        // create initialize request
        var request = this.BuildRequest(SPListsService.Operations.AddList);
        request.Body = '<listName>'    + name        + '</listName>'
                     + '<description>' + description + '</description>'
                     + '<templateID>'  + templateId  + '</templateID>';

        // invocation
        if (callback)
        {
            request.Asynchronous = true;
            request.CallbackHandler = ISFunction.CreateDelegate(function()
            {
                var responseElement = request.GetResponseXml();
                var list = this.BuildListFromXml(responseElement, SPListsService.Operations.AddList);

                callback(list);
            }, this);

            request.Invoke();
        }
        else
        {
            request.Invoke();
            var responseElement = request.GetResponseXml();
            var list = this.BuildListFromXml(responseElement, SPListsService.Operations.AddList);

            return list;
        }    
    },

    GetList: function(listName, callback)
    {
        // create initialize request
        var request = this.BuildRequest(SPListsService.Operations.GetList);
        request.Body = '<listName>' + listName + '</listName>';

        // invocation
        if (callback)
        {
            request.Asynchronous = true;
            request.CallbackHandler = ISFunction.CreateDelegate(function()
            {
                var responseElement = request.GetResponseXml();
                var list = this.BuildListFromXml(responseElement, SPListsService.Operations.GetList);

                callback(list);
            }, this);

            request.Invoke();
        }
        else
        {
            request.Invoke();
            var responseElement = request.GetResponseXml();
            var list = this.BuildListFromXml(responseElement, SPListsService.Operations.GetList);

            return list;
        }
    },

    DeleteList: function(listName, callback)
    {
        // create initialize request
        var request = this.BuildRequest(SPListsService.Operations.DeleteList);
        request.Body = '<listName>' + listName + '</listName>';

        // invocation
        if (callback)
        {
            request.Asynchronous = true;
            request.CallbackHandler = ISFunction.CreateDelegate(function()
            {
                callback();
            }, this);

            request.Invoke();
        }
        else
        {
            request.Invoke();
        }    
    },

    UpdateList: function(listName, listProperties, newFields, updateFields, deleteFields, listVersion, callback)
    {
        // Reference: https://msdn.microsoft.com/en-us/library/lists.lists.updatelist(v=office.12).aspx
        // create initialize request
        var request = this.BuildRequest(SPListsService.Operations.UpdateList);
        request.Body = (ISString.IsNullOrEmpty(listName)       ? '' : '<listName>'       + listName       + '</listName>')
                     + (ISString.IsNullOrEmpty(listProperties) ? '' : '<listProperties>' + listProperties + '</listProperties>')
                     + (ISString.IsNullOrEmpty(newFields)      ? '' : '<newFields>'      + newFields      + '</newFields>')
                     + (ISString.IsNullOrEmpty(updateFields)   ? '' : '<updateFields>'   + updateFields   + '</updateFields>')
                     + (ISString.IsNullOrEmpty(deleteFields)   ? '' : '<deleteFields>'   + deleteFields   + '</deleteFields>')
                     + (ISString.IsNullOrEmpty(listVersion)    ? '' : '<listVersion>'    + listVersion    + '</listVersion>');

        // invocation
        if (callback)
        {
            request.Asynchronous = true;
            request.CallbackHandler = ISFunction.CreateDelegate(function()
            {
                var responseElement = request.GetResponseXml();
                var results = this.BuildListUpdateResultArrayFromXml(responseElement);

                callback(results);
            }, this);

            request.Invoke();
        }
        else
        {
            request.Invoke();
            var responseElement = request.GetResponseXml();
            var results = this.BuildListUpdateResultArrayFromXml(responseElement);

            return results;
        }
    },

    GetLists: function(callback)
    {
        this.GetListCollection(callback);
    },

    GetListCollection: function(callback)
    {
        // create initialize request
        var request = this.BuildRequest(SPListsService.Operations.GetListCollection);
        request.Body = '';

        // invocation
        if (callback)
        {
            request.Asynchronous = true;
            request.CallbackHandler = ISFunction.CreateDelegate(function()
            {
                var responseElement = request.GetResponseXml();
                var lists = this.BuildListArrayFromXml(responseElement);

                callback(lists);
            }, this);

            request.Invoke();
        }
        else
        {
            request.Invoke();
            var responseElement = request.GetResponseXml();
            var lists = this.BuildListArrayFromXml(responseElement);

            return lists;
        }
    },

    GetListItems: function(listName, viewName, query, viewFields, rowLimit, queryOptions, webId, callback)
    {
        // create initialize request
        var request = this.BuildRequest(SPListsService.Operations.GetListItems);
        request.Body = (ISString.IsNullOrEmpty(listName)     ? '' : '<listName>'     + listName     + '</listName>')
                     + (ISString.IsNullOrEmpty(viewName)     ? '' : '<viewName>'     + viewName     + '</viewName>')
                     + (ISString.IsNullOrEmpty(query)        ? '' : '<query>'        + query        + '</query>')
                     + (ISString.IsNullOrEmpty(viewFields)   ? '' : '<viewFields>'   + viewFields   + '</viewFields>')
                     + (ISString.IsNullOrEmpty(rowLimit)     ? '' : '<rowLimit>'     + rowLimit     + '</rowLimit>')
                     + (ISString.IsNullOrEmpty(queryOptions) ? '' : '<queryOptions>' + queryOptions + '</queryOptions>')
                     + (ISString.IsNullOrEmpty(webId)        ? '' : '<webID>'        + webId        + '</webID>');

        // invocation
        if (callback)
        {
            request.Asynchronous = true;
            request.CallbackHandler = ISFunction.CreateDelegate(function()
            {
                var responseElement = request.GetResponseXml();
                var items = this.BuildItemArrayFromXml(responseElement);

                // メタデータの確認（件数、ポジション）
                var metadata = this.BuildMetaDataFromXml(responseElement);

                callback(items, metadata);
            }, this);

            request.Invoke();
        }
        else
        {
            request.Invoke();
            var responseElement = request.GetResponseXml();
            var items = this.BuildItemArrayFromXml(responseElement);

            return items;
        }
    },

    UpdateListItems: function(listName, batch, callback)
    {
        // create initialize request
        var request = this.BuildRequest(SPListsService.Operations.UpdateListItems);
        request.Body = (ISString.IsNullOrEmpty(listName) ? '' : '<listName>' + listName + '</listName>')
                     + (ISString.IsNullOrEmpty(batch)    ? '' : '<updates>'  + batch    + '</updates>');

        // invocation
        if (callback)
        {
            request.Asynchronous = true;
            request.CallbackHandler = ISFunction.CreateDelegate(function()
            {
                var responseElement = request.GetResponseXml();
                var results = this.BuildItemUpdateResultArrayFromXml(responseElement);

                callback(results);
            }, this);

            request.Invoke();
        }
        else
        {
            request.Invoke();
            var responseElement = request.GetResponseXml();
            var results = this.BuildItemUpdateResultArrayFromXml(responseElement);

            return results;
        }
    }
}
                                   
