Infoshare.SharePoint.WebService.ViewsService = function Infoshare$SharePoint$WebService$ViewsService(webUrl)
{
    this.WebUrl = webUrl;
}
SPViewsService = Infoshare.SharePoint.WebService.ViewsService;

SPViewsService.ServiceFile = 'Views.asmx';
SPViewsService.ServiceNamespace = SPServiceCommon.SoapNamespace;
SPViewsService.Operations = { GetView: 'GetView',
                              GetViewCollection: 'GetViewCollection',
                              UpdateView: 'UpdateView'
};

SPViewsService.prototype = {
    WebUrl: '',

    BuildRequest: function(operationName)
    {
        var request = SPServiceCommon.BuildRequest(this.WebUrl,
                                                   SPViewsService.ServiceFile,
                                                   SPViewsService.ServiceNamespace,
                                                   operationName);

        return request;
    },

    GetView: function(listName, viewName, callback)
    {
        // create initialize request
        var request = this.BuildRequest(SPViewsService.Operations.GetView);
        request.Body = '<listName>' + listName + '</listName>'
                     + '<viewName>' + viewName + '</viewName>';

        // invocation
        if (callback)
        {
            request.Asynchronous = true;
            request.CallbackHandler = ISFunction.CreateDelegate(function()
            {
                var responseElement = request.GetResponseXml();
                var view = this.GetViewFromXml(responseElement);

                callback(view);
            }, this);

            request.Invoke();
        }
        else
        {
            request.Invoke();
            var responseElement = request.GetResponseXml();
            var view = this.GetViewFromXml(responseElement);

            return view;
        }
    },

    GetViewByViewFileName: function(listTitle, viewFileName, callback)
    {
        // 全てのViewを取得
        this.GetViewCollection(listTitle, ISFunction.CreateDelegate(function (views)
        {
            var view = null;
            for (var i = 0; i < views.length; i++)
            {
                if (ISString.EndsWith(views[i].Url, "/" + viewFileName))
                {
                    view = views[i];
                    break;
                }
            }

            if (view)
            {
                this.GetView(listTitle, view.Name, callback);
            }
            else
            {
                callback(null);
            }

        }, this));
    },
    
    GetViewFromXml: function(responseElement)
    {
        var xpath = SPServiceCommon.BuildResultElementXPath(SPViewsService.Operations.GetView, 'View');
        var viewElement = iXml.SelectNodeByPath(responseElement, xpath);
        var view = ISSPView.FromXml(viewElement);

        return view;
    },

    GetViewCollection: function(listName, callback)
    {
        // create initialize request
        var request = this.BuildRequest(SPViewsService.Operations.GetViewCollection);
        request.Body = '<listName>' + listName + '</listName>'

        // invocation
        if (callback)
        {
            request.Asynchronous = true;
            request.CallbackHandler = ISFunction.CreateDelegate(function()
            {
                var responseElement = request.GetResponseXml();
                var views = this.GetViewArrayFromXml(responseElement);

                callback(views);
            }, this);

            request.Invoke();
        }
        else
        {
            request.Invoke();
            var responseElement = request.GetResponseXml();
            var views = this.GetViewArrayFromXml(responseElement);

            return views;
        }
    },

    GetViewArrayFromXml: function(responseElement)
    {
        var xpath = SPServiceCommon.BuildResultElementXPath(SPViewsService.Operations.GetViewCollection, 'Views');
        var viewsElement = iXml.SelectNodeByPath(responseElement, xpath);

        var views = new Array();
        for (var i = 0; i < viewsElement.childNodes.length; i++)
        {
            var viewElement = viewsElement.childNodes.item(i);
            var view = ISSPView.FromXml(viewElement);
            views.push(view);
        }

        return views;
    },

    UpdateView: function(listGuid, viewGuid, viewFields, callback)
    {
        // ViewFieldをstringに変換
        var stringViewFields = "";
        for(var i = 0; i < viewFields.length; i++)
        {
            stringViewFields += SPQueryBuilder.BuildFieldRef(viewFields[i].Properties.Name);
        }

        this.UpdateViewInternal(listGuid, viewGuid, stringViewFields, callback);
    },

    UpdateViewInternal: function(listGuid, viewGuid, viewFields, callback)
    {
        // Reference: https://docs.microsoft.com/en-us/previous-versions/office/developer/sharepoint-services/ms774898(v%3doffice.12)
        // create initialize request
        var request = this.BuildRequest(SPViewsService.Operations.UpdateView);
        request.Body = (ISString.IsNullOrEmpty(listGuid)   ? '' : '<listName>'   + listGuid   + '</listName>')
                     + (ISString.IsNullOrEmpty(viewGuid)   ? '' : '<viewName>'   + viewGuid   + '</viewName>')
                     + (ISString.IsNullOrEmpty(viewFields) ? '' : '<viewFields><ViewFields>' + viewFields + '</ViewFields></viewFields>');

        // invocation
        if (callback)
        {
            request.Asynchronous = true;
            request.CallbackHandler = ISFunction.CreateDelegate(function()
            {
                // ToDo: Result処理
                var responseElement = request.GetResponseXml();
                callback();
            }, this);

            request.Invoke();
        }
        else
        {
            // ToDo: Result処理
            request.Invoke();
            var responseElement = request.GetResponseXml();
            var results = null;

            return results;
        }
    }
}
                                   
