Infoshare.SharePoint.REST.RestCommon = function Infoshare$SharePoint$REST$RestCommon() { }
SPRestCommon = Infoshare.SharePoint.REST.RestCommon;
SPRestCommon.EndpointPath = '_vti_bin/client.svc';
SPRestCommon.BuildRequest = function(service, restPath)
{
    var request = new ISWebRequest();
    request.Method = 'GET';

    // headres
    if (SPService.ResponseType == ISWebRequest.AcceptResponseType.JSON)
    {
        SPRestCommon.AppendJSONHeader(request);
    }

    // endpoint
    var endpointUrl = '';
    if (ISString.TrimEnd(service.HostWebUrl, '/').toUpperCase()  == ISString.TrimEnd(service.AppWebUrl, '/').toUpperCase())
    {
        endpointUrl = ISString.TrimEnd(service.HostWebUrl, '/') + '/' + SPRestCommon.EndpointPath + '/' + ISString.TrimStart(restPath, '/');
    }
    else
    {
        endpointUrl = ISString.TrimEnd(service.AppWebUrl, '/') + '/' + SPRestCommon.EndpointPath + '/SP.AppContextSite(@target)/' + ISString.TrimStart(restPath, '/')
                    + "?@target='" + ISString.TrimEnd(service.HostWebUrl, '/') + "'";
    }
    request.Url = endpointUrl;

    return request;
}
SPRestCommon.AppendJSONHeader = function(request)
{
    request.Headers.push(new ISWebRequestHeader('Accept', 'application/json; odata=verbose'));
    request.Headers.push(new ISWebRequestHeader('Content-Type', 'application/json; odata=verbose'));
}
SPRestCommon.AppendRequestDigestHeader = function(request)
{
    request.Headers.push(new ISWebRequestHeader('X-RequestDigest', ISSPContextWebInformation.Current.FormDigestValue));
}
                               
