Infoshare.SharePoint.REST.ListsService = function Infoshare$SharePoint$REST$ListsService(hostWebUrl, appWebUrl)
{
    this.HostWebUrl = hostWebUrl;
    this.AppWebUrl  = appWebUrl ? appWebUrl : hostWebUrl;

    this.ResponseType = SPService.ResponseType;
}
SRListsService = Infoshare.SharePoint.REST.ListsService;
SRListsService.prototype = {
    HostWebUrl: '',
    AppWebUrl: '',

    ResponseType: '',

    GetList: function(listId, callback)
    {
        if (callback)
        {
            var list, fields = null;
            this.GetListWithoutFields(listId, function(l)
            {
                list = l;
                if (fields)
                {
                    ISSPList.SetFields(list, fields);
                    callback(list);
                }
            });
            this.GetFields(listId, function(f)
            {
                fields = f;
                if (list)
                {
                    ISSPList.SetFields(list, fields);
                    callback(list);
                }
            });
        }
        else
        {
            var list = this.GetListWithoutFields(listId)
            var fields = this.GetFields(listId);
            ISSPList.SetFields(list, fields);

            return list;
        }
    },

    GetListWithoutFields: function(listId, callback)
    {
        // create, initialize request
        var restPath = "Web/Lists(guid'" + ISGuid.TrimBrace(listId) + "')";
        var request = SPRestCommon.BuildRequest(this, restPath);

        // invocation
        if (callback)
        {
            request.Asynchronous = true;
            request.CallbackHandler = ISFunction.CreateDelegate(function()
            {
                var list = this.GetListFromRequest(request);

                callback(list);
            }, this);

            request.Invoke();
        }
        else
        {
            request.Invoke();
            var list = this.GetListFromRequest(request);

            return list;
        }
    },

    GetListFromRequest: function(request)
    {
        var list = null;
        if (this.ResponseType == ISWebRequest.AcceptResponseType.JSON)
        {
            var responseText = request.GetResponseText();
            var responseObject = ISJSON.parse(responseText);
            list = ISSPList.FromJson(responseObject.d);
        }
        else
        {
            var responseElement = request.GetResponseXml();
            list = ISSPList.FromRestXml(responseElement.documentElement);
        }

        return list;
    },

    GetLists: function(callback)
    {
        // create, initialize request
        var restPath = "Web/Lists";
        var request = SPRestCommon.BuildRequest(this, restPath);

        // invocation
        if (callback)
        {
            request.Asynchronous = true;
            request.CallbackHandler = ISFunction.CreateDelegate(function()
            {
                var lists = this.GetListArrayFromRequest(request);

                callback(lists);
            }, this);

            request.Invoke();
        }
        else
        {
            request.Invoke();
            var lists = this.GetListArrayFromRequest(request);

            return lists;
        }
    },

    GetListArrayFromRequest: function(request)
    {
        var lists = null;
        if (this.ResponseType == ISWebRequest.AcceptResponseType.JSON)
        {
            var responseText = request.GetResponseText();
            lists = this.GetListArrayFromJson(responseText);
        }
        else
        {
            var responseElement = request.GetResponseXml();
            lists = this.GetListArrayFromXml(responseElement);
        }

        return lists;
    },

    GetListArrayFromJson: function(responseText)
    {
        var result = ISJSON.parse(responseText);
        var results = result.d.results;

        var lists = new Array();
        for (var i = 0; i < results.length; i++)
        {
            var listJson = results[i];
            var list = ISSPList.FromJson(listJson);
            lists.push(list);
        }

        return lists;
    },

    GetListArrayFromXml: function(responseElement)
    {
        var listsElement = responseElement.documentElement;

        var lists = new Array();
        for (var i = 0; i < listsElement.childNodes.length; i++)
        {
            var listElement = listsElement.childNodes.item(i);
            if (listElement.baseName != 'entry')
            {
                continue;
            }

            var list = ISSPList.FromRestXml(listElement);
            lists.push(list);
        }

        return lists;
    },

    GetFields: function(listId, callback)
    {
        // create, initialize request
        var restPath = "Web/Lists(guid'" + ISGuid.TrimBrace(listId) + "')/Fields";
        var request = SPRestCommon.BuildRequest(this, restPath);

        // invocation
        if (callback)
        {
            request.Asynchronous = true;
            request.CallbackHandler = ISFunction.CreateDelegate(function()
            {
                var fields = this.GetFieldArrayFromRequest(request);

                callback(fields);
            }, this);

            request.Invoke();
        }
        else
        {
            request.Invoke();
            var fields = this.GetFieldArrayFromRequest(request);

            return fields;
        }
    },

    GetFieldArrayFromRequest: function(request)
    {
        var fields = new Array();
        if (this.ResponseType == ISWebRequest.AcceptResponseType.JSON)
        {
            var responseText = request.GetResponseText();
            var responseObject = ISJSON.parse(responseText);
            var results = responseObject.d.results;

            var fields = new Array();
            for (var i = 0; i < results.length; i++)
            {
                var fieldJson = results[i];
                var field = ISSPField.FromJson(fieldJson);
                fields.push(field);
            }

            return fields;
        }
        else
        {
            var responseElement = request.GetResponseXml();
            var fieldsElement = responseElement.documentElement;
            for (var i = 0; i < fieldsElement.childNodes.length; i++)
            {
                var fieldElement = fieldsElement.childNodes.item(i);
                if (fieldElement.baseName != 'entry')
                {
                    continue;
                }

                var field = ISSPField.FromRestXml(fieldElement);
                fields.push(field);
            }
        }

        return fields;
    },

    GetItems: function(listId, viewXml, viewFields, callback)
    {
        this.EnsureContext(ISFunction.CreateDelegate(function()
        {
            this.GetItemsInternal(listId, viewXml, viewFields, callback);
        }, this));
    },

    GetItemsInternal: function(listId, viewXml, viewFields, callback)
    {
        // create, initialize request
        var restPath = "Web/Lists(guid'" + ISGuid.TrimBrace(listId) + "')/GetItems";
        var request = SPRestCommon.BuildRequest(this, restPath);
        SPRestCommon.AppendRequestDigestHeader(request);
        request.Method = "POST";

        // view fields
        if (viewFields && viewFields.length > 0)
        {
            var fieldNames = new Array();
            for (var i = 0; viewFields.length; i++)
            {
                var viewField = viewFields[i];
                fieldNames.push(viewField.Name);
            }
            request.Url = ISQueryString.AddValue(request.Url, '$select', fieldNames.join(','));
        }

        // initialize query
        var query = { 'query': { '__metadata': { 'type': 'SP.CamlQuery' },
                                 'ViewXml':    viewXml } };
        request.Body = ISJSON.stringify(query);

        // invocation
        if (callback)
        {
            request.Asynchronous = true;
            request.CallbackHandler = ISFunction.CreateDelegate(function()
            {
                var items = this.GetItemArrayFromRequest(request);

                callback(items);
            }, this);

            request.Invoke();
        }
        else
        {
            request.Invoke();
            var items = this.GetItemArrayFromRequest(request);

            return items;
        }
    },

    GetItemArrayFromRequest: function(request)
    {
        var items = new Array();
        if (this.ResponseType == ISWebRequest.AcceptResponseType.JSON)
        {
            try
            {
                var responseText = request.GetResponseText();
                var responseObject = ISJSON.parse(responseText);
                var results = responseObject.d.results;

                for (var i = 0; i < results.length; i++)
                {
                    var itemJson = results[i];
                    var item = ISSPItem.FromJson(itemJson);
                    items.push(item);
                }
            }
            catch (e)
            {
                ISTrace.TraceError(e);
            }

            return items;
        }
        else
        {
            throw new Error('Not supported!!');

            var responseElement = request.GetResponseXml();
            var itemsElement = responseElement.documentElement;
            for (var i = 0; i < itemsElement.childNodes.length; i++)
            {
                var itemElement = itemsElement.childNodes.item(i);
                if (itemElement.baseName != 'entry')
                {
                    continue;
                }

                //var item = ISSPField.FromRestXml(itemsElement);
                var item = ISSPField.FromXml(itemsElement);
                items.push(item);
            }
        }

        return items;
    },

    AddListItem: function(list, itemData, callback)
    {
        var restPath = "Web/Lists(guid'" + ISGuid.TrimBrace(list.Id) + "')/Items";
        var requestInfo = {
            "Type": "ADD",
            "Method": "POST",
            "EndPoint": restPath
        };

        this.ExecuteListItemRequest(list, itemData, requestInfo, callback);
    },

    UpdateListItem: function(list, itemData, callback)
    {
        var restPath = "Web/Lists(guid'" + ISGuid.TrimBrace(list.Id) + "')/Items(" + itemData.Id + ")";
        var requestInfo = {
            "Type": "UPDATE",
            "Method": "POST",
            "HTTP-Method": "MERGE",
            "EndPoint": restPath
        };

        this.ExecuteListItemRequest(list, itemData, requestInfo, callback);
    },

    DeleteListItem: function(list, itemData, callback)
    {
        var restPath = "Web/Lists(guid'" + ISGuid.TrimBrace(list.Id) + "')/Items(" + itemData.Id + ")";
        var requestInfo = {
            "Type": "DELETE",
            "Method": "DELETE",
            "HTTP-Method": "DELETE",
            "EndPoint": restPath
        };

        this.ExecuteListItemRequest(list, itemData, requestInfo, callback);
    },

    ExecuteListItemRequest: function(list, itemData, requestInfo, callback)
    {
        var service = this;
        this.EnsureContext(function ()
        {
            // 新規作成以外はアイテムIDを確認する
            if (requestInfo.Type != "ADD")
            {
                // アイテムが不正な場合
                if (!itemData ||
                    !itemData.Id ||
                    ISString.IsNullOrEmpty(itemData.Id))
                {
                    callback();
                }
            }

            // リクエストの作成
            var request = SPRestCommon.BuildRequest(service, requestInfo.EndPoint);
            SPRestCommon.AppendJSONHeader(request);
            SPRestCommon.AppendRequestDigestHeader(request);
            request.Method = requestInfo.Method;
            if (requestInfo.Type != "ADD")
            {
                request.Headers.push(new ISWebRequestHeader("X-HTTP-Method", requestInfo["HTTP-Method"]));
                request.Headers.push(new ISWebRequestHeader("If-Match", "*"));
            }
            
            // ボディ
            if (requestInfo.Type != "DELETE")
            {
                var body = service.CreateListItemBody(list, itemData);
                request.Body = ISJSON.stringify(body);
            }

            // invocation
            if (callback)
            {
                request.Asynchronous = true;
                request.CallbackHandler = ISFunction.CreateDelegate(function()
                {
                    callback();
                }, service);

                request.Invoke();
            }
            else
            {
                request.Invoke();
            }
        });
    },

    CreateListItemBody: function(list, itemData)
    {
        var body = { };
        var metaData = { 'type': '' };
        metaData.type = ISString.Format("SP.Data.{0}ListItem", list.Title);
        body['__metadata'] = metaData;

        // プロパティ
        for(var key in itemData.Properties)
        {
            body[key] = itemData.Properties[key];
        }

        return body;
    },

    EnsureContext: function(callback)
    {
        var service = new SRContextService(this.HostWebUrl, this.AppWebUrl);
        service.GetContext(function(context)
        {
            callback();
        });
    }
}
                               
