// -----------------------------------------------------------------------
Infoshare.SharePoint.REST.UserCustomActionsService = function Infoshare$SharePoint$REST$UserCustomActionsService(hostWebUrl, appWebUrl, isTargetOnSitecollection) {
    this.HostWebUrl = hostWebUrl;
    this.AppWebUrl  = appWebUrl ? appWebUrl : hostWebUrl;
    this.RestPathBase =  isTargetOnSitecollection ? "Site" : "Web";
    this.RestPathBase += "/UserCustomActions";
    this.ResponseType = SPService.ResponseType;
    // IE8ではXMLオブジェクトが処理できないのでJSONで処理する
    if (ISBrowser.GetDocumentVersion() <= 8)
    {
        this.ResponseType = ISWebRequest.AcceptResponseType.JSON;  
    }
    
}
SRUserCustomActionsService = Infoshare.SharePoint.REST.UserCustomActionsService;
SRUserCustomActionsService.Location = {
    ScriptLink  : "ScriptLink",
    SiteSettings: "Microsoft.SharePoint.SiteSettings"
};
// https://msdn.microsoft.com/en-us/library/office/bb802730.aspx
SRUserCustomActionsService.SiteSettingsGroup = {
    Customization       : "Customization",
    Galleries           : "Galleries",
    SiteAdministration  : "SiteAdministration",
    SiteCollectionAdmin : "SiteCollectionAdmin",
    UsersAndPermissions : "UsersAndPermissions"
};
SRUserCustomActionsService.prototype = {
    HostWebUrl:   '',
    AppWebUrl:    '',
    RestPathBase: '',
    ResponseType: '',

    // Get SP.UserCustomActionCollection
    GetUserCustomActions: function (callback)
    {
        // create, initialize request
        var restPath = this.RestPathBase;
        var request = SPRestCommon.BuildRequest(this, restPath);
        if (this.ResponseType == ISWebRequest.AcceptResponseType.JSON)
        {
            SPRestCommon.AppendJSONHeader(request);
        }

        // invocation
        if (callback)
        {
            request.Asynchronous = true;
            request.CallbackHandler = ISFunction.CreateDelegate(function ()
            {
                var userCustomActions = this.GetUserCustomActionsFromRequest(request);
                callback(userCustomActions);
            }, this);
            request.Invoke();
        }
        else
        {
            request.Invoke();
            var userCustomActions = this.GetUserCustomActionsFromRequest(request);
            return userCustomActions;
        }
    },

    GetUserCustomActionByTitle: function (title, callback)
    {
        this.GetUserCustomActionsByTitle(title, function (actions)
        {
            var action = null;
            if (actions && actions.length > 0)
            {
                action = actions[0];
            }

            if (iType.GetType(callback) == iType.BuiltinType.Function)
            {
                callback(action);
            }
        });
    },

    GetUserCustomActionsByTitle: function(title, callback)
    {
        this.GetUserCustomActions(function (actions)
        {
            var foundActions = new Array();
            for (var i = 0; i < actions.length; i++)
            {
                var action = actions[i];

                if (iType.GetType(title) == iType.BuiltinType.String)
                {
                    // 文字列として比較
                    if (iString.Equals(title, action.Title, true))
                    {
                        foundActions.push(action);
                    }
                }
                else if (iType.GetType(title) == iType.BuiltinType.RegExp)
                {
                    // 検索位置を先頭からに戻す
                    title.lastIndex = 0;
                    // 正規表現として比較
                    if (title.test(action.Title))
                    {
                        foundActions.push(action);
                    }
                }
                else
                {
                    // 比較不能
                    break;
                }
            }

            if (iType.GetType(callback) == iType.BuiltinType.Function)
            {
                callback(foundActions);
            }
        });
    },

    GetUserCustomActionsFromRequest: function (request)
    {
        var usercustomactions = null;
        if (this.ResponseType == ISWebRequest.AcceptResponseType.JSON)
        {
            usercustomactions = ISSPUserCustomActions.FromJson(request);
        }
        else
        {
            usercustomactions = ISSPUserCustomActions.FromRestXml(request);
        }
        return usercustomactions;
    },

    // Create SP.UserCustomAction
    AddUserCustomActionForScriptLink: function (title, scriptSrc, scriptBlock, sequence, description, callback) {
        var bodyProperties = {};

        bodyProperties['Title']       = title;
        bodyProperties['Location']    = SRUserCustomActionsService.Location.ScriptLink;
        bodyProperties['ScriptSrc']   = scriptSrc;
        if (scriptBlock)
        {
            bodyProperties['ScriptBlock'] = scriptBlock;
        }        
        bodyProperties['Sequence']    = sequence;
        bodyProperties['Description'] = description;

        this.AddUserCustomAction(title, bodyProperties, callback);
    },

    AddUserCustomActionForSiteSettings: function (title, group, description, url, sequence, callback)
    {
        var bodyProperties = {};

        bodyProperties['Title']       = title;
        bodyProperties['Location']    = SRUserCustomActionsService.Location.SiteSettings;
        bodyProperties['Group']       = group;
        bodyProperties['Description'] = description;
        bodyProperties['Url']         = url;
        // Sequenceが並び順になる
        bodyProperties['Sequence']    = sequence;

        this.AddUserCustomAction(title, bodyProperties, callback);
    },

    AddUserCustomAction: function (title, bodyProperties, callback)
    {
        // 存在確認
        var service = this;
        this.GetUserCustomActionByTitle(title, function (ucaResult)
        {
            // 既に存在する場合は追加しない
            if (!ucaResult)
            {
                service.AddUserCustomActionInternal(bodyProperties, callback);
            }
            else
            {
                callback();
            }
        });
    },

    AddUserCustomActionInternal: function (bodyProperties, callback) {
        // FormDigest
        var restPath = this.RestPathBase;
        var request = SPRestCommon.BuildRequest(this, restPath);

        this.EnsureContext(function () {

            // create, initialize request
            SPRestCommon.AppendJSONHeader(request);
            SPRestCommon.AppendRequestDigestHeader(request);
            request.Method = "POST";

            // body
            var query = {
                __metadata:  { type: 'SP.UserCustomAction' }
            };
            for (var key in bodyProperties)
            {
                query[key] = bodyProperties[key];
            }
            request.Body = ISJSON.stringify(query);

            // invocation
            if (callback) {
                request.Asynchronous = true;
                request.CallbackHandler = ISFunction.CreateDelegate(function () {
                    // ToDo:ErrorCheck
                    callback();
                }, this);
                request.Invoke();
            }
            else {
                request.Invoke();
            }
        });
    },

    // Delete SP.UserCustomAction
    DeleteUserCustomAction: function (userCustomActionId, callback) {

        var restPath = this.RestPathBase + "('" + userCustomActionId + "')/deleteObject()";
        var request = SPRestCommon.BuildRequest(this, restPath);

        // FormDigest
        this.EnsureContext(function() {

            // create, initialize request
            SPRestCommon.AppendJSONHeader(request);
            SPRestCommon.AppendRequestDigestHeader(request);
            request.Method = "POST";

            // invocation
            if (callback) {
                request.Asynchronous = true;
                request.CallbackHandler = ISFunction.CreateDelegate(function () {
                    // ToDo:ErrorCheck
                    callback();
                }, this);
                request.Invoke();
            }
            else {
                request.Invoke();
            }
        });
    },

    EnsureContext: function (callback) {
        var service = new SRContextService(this.HostWebUrl, this.AppWebUrl);
        service.GetContext(function (context) {
            callback();
        });
    }
}                               
