SRUsersService.prototype = {
    HostWebUrl: '',
    AppWebUrl: '',

    ResponseType: '',

    GetCurrentUser: function(callback)
    {
        // create, initialize request
        var restPath = "Web/CurrentUser";
        var request = SPRestCommon.BuildRequest(this, restPath);

        // invocation
        if (callback)
        {
            request.Asynchronous = true;
            request.CallbackHandler = ISFunction.CreateDelegate(function()
            {
                var view = this.GetUserFromRequest(request);

                callback(view);
            }, this);

            request.Invoke();
        }
        else
        {
            request.Invoke();
            var user = this.GetUserFromRequest(request);

            return user;
        }
    },

    GetUserFromRequest: function(request)
    {
        var user = null;
        if (this.ResponseType == ISWebRequest.AcceptResponseType.JSON)
        {
            var responseText = request.GetResponseText();
            var responseObject = ISJSON.parse(responseText);
            user = ISSPUser.FromJson(responseObject.d);
        }
        else
        {
            var responseElement = request.GetResponseXml();
            user = ISSPUser.FromRestXml(responseElement.documentElement);
        }

        return user;
    }
}
                               
