// -----------------------------------------------------------------------
Infoshare.SharePoint.SupplementServices.PermissionsService = function Infoshare$SharePoint$SupplementServices$PermissionsService(webUrl)
{
    this.WebUrl = webUrl;
}
iSSPermissionsService = Infoshare.SharePoint.SupplementServices.PermissionsService;

iSSPermissionsService.ServiceFile = 'NativePermissions.aspx';

iSSPermissionsService.prototype = {
    WebUrl: null,

    GetAuthorizedPrincipalsForList: function(listId, permissions, callback)
    {
        var stopwatch = new ISStopwatch();
        stopwatch.Start();
        ISTrace.TraceVerbose('[BEGIN] iSSPermissionsService.GetAuthorizedPrincipalsForList');

        var request = this.BuildRequest();
        request.Url += '?List=' + listId
                     + '&Permissions=' + permissions;
        var permissionService = this;

        request.CallbackHandler = function()
        {
            var principals = permissionService.GetPrincipalsFromResponse(request.GetResponseText());

            ISTrace.TraceVerbose('[END] iSSPermissionsService.GetAuthorizedPrincipalsForList (spent: ' + stopwatch.Stop() + ')');
            callback(principals);
        };
        request.Invoke();
    },

    GetAuthorizedPrincipalsForFolder: function(folderUrl, permissions, callback)
    {
        var stopwatch = new ISStopwatch();
        stopwatch.Start();
        ISTrace.TraceVerbose('[BEGIN] iSSPermissionsService.GetAuthorizedPrincipalsForFolder');

        var request = this.BuildRequest();
        request.Url += '?Folder=' + folderUrl
                     + '&Permissions=' + permissions;
        var permissionService = this;

        request.CallbackHandler = function()
        {
            var principals = permissionService.GetPrincipalsFromResponse(request.GetResponseText());

            ISTrace.TraceVerbose('[END] iSSPermissionsService.GetAuthorizedPrincipalsForFolder (spent: ' + stopwatch.Stop() + ')');
            callback(principals);
        };
        request.Invoke();
    },

    BuildRequest: function()
    {
        var request = new ISWebRequest();
        request.Url = ISString.TrimEnd(this.WebUrl, '/') + '/_layouts/Infoshare/' + iSSPermissionsService.ServiceFile;
        request.Asynchronous = true;

        return request;
    },

    GetPrincipalsFromResponse: function(responseText)
    {
        var principals = new Array();
        try
        {
            var xml = iXml.LoadXml(responseText);
            var principalElements = xml.getElementsByTagName('Principal');
            for (var i = 0; i < principalElements.length; i++)
            {
                var principalElement = principalElements[i];
                principals.push(iXml.GetAttributeValue(principalElement, 'LoginName'));
            }
        }
        catch (e)
        {
            principals = null;
        }

        return principals;
    }
}
                                 
