// -----------------------------------------------------------------------
Infoshare.SharePoint.QueryBuilder = function Infoshare$SharePoint$QueryBuilder() { }
SPQueryBuilder = Infoshare.SharePoint.QueryBuilder;

SPQueryBuilder.MaxConditionCount = 100; // ToDo(skomatsu): check the value
SPQueryBuilder.BuildQuery = function(orderby, where)
{
    var xml = "<Query>"
            +   (iString.IsNullOrEmpty(orderby) ? '' : "<OrderBy>" + orderby + "</OrderBy>")
            +   (iString.IsNullOrEmpty(where)   ? '' : "<Where>"   + where   + "</Where>")
            + "</Query>";

    return xml;
}
SPQueryBuilder.BuildFieldRef = function(fieldName)
{
    var xml = "<FieldRef Name='" + iXml.Escape(fieldName) + "' />";

    return xml;
}
SPQueryBuilder.BuildOrderByFieldRef = function(fieldName, ascending)
{
    var xml = "<FieldRef Name='" + iXml.Escape(fieldName) + "' "
            +           "Ascending='" + (ascending ? 'true' : 'false') + "' />";

    return xml;
}
SPQueryBuilder.BuildFieldCompareCondition = function(fieldName, fieldType, fieldValue)
{
    var xml = "<FieldRef Name='" + iXml.Escape(fieldName) + "' />"
            + "<Value Type='" + fieldType + "'>"
            +   iXml.Escape(fieldValue)
            + "</Value>";

    return xml;
}
SPQueryBuilder.BuildContainsQueryCondition = function(fieldName, fieldType, fieldValue)
{
    var xml = "<Contains>"
            +   SPQueryBuilder.BuildFieldCompareCondition(fieldName, fieldType, fieldValue)
            + "</Contains>";

    return xml;
}
SPQueryBuilder.BuildEqualQueryCondition = function(fieldName, fieldType, fieldValue)
{
    var xml = "<Eq>"
            +   SPQueryBuilder.BuildFieldCompareCondition(fieldName, fieldType, fieldValue)
            + "</Eq>";

    return xml;
}
SPQueryBuilder.BuildGreaterThanEqualQueryCondition = function(fieldName, fieldType, fieldValue)
{
    var xml = "<Geq>"
            +   SPQueryBuilder.BuildFieldCompareCondition(fieldName, fieldType, fieldValue)
            + "</Geq>";

    return xml;
}
SPQueryBuilder.BuildLessThanEqualQueryCondition = function(fieldName, fieldType, fieldValue)
{
    var xml = "<Leq>"
            +   SPQueryBuilder.BuildFieldCompareCondition(fieldName, fieldType, fieldValue)
            + "</Leq>";

    return xml;
}
SPQueryBuilder.BuildIsNullQueryCondition = function(fieldName)
{
    var xml = "<IsNull>"
            +   "<FieldRef Name='" + iXml.Escape(fieldName) + "' />"
            + "</IsNull>";

    xml = iString.Format(xml, fieldName);
    return xml;
}
SPQueryBuilder.BuildAndQueryCondition = function(condition)
{
    var xml = "<And>"
            +   condition
            + "</And>";

    return xml;
}
SPQueryBuilder.BuildOrQueryCondition = function(condition)
{
    var xml = "<Or>"
            +   condition
            + "</Or>";

    return xml;
}
SPQueryBuilder.BuildViewFields = function(fieldRefs)
{
    var xml = "<ViewFields>"
            +   fieldRefs
            + "</ViewFields>";

    return xml;s
}

SPQueryBuilder.ExtractWhereCondition = function(query)
{
    var condition = '';
    if (!iString.IsNullOrEmpty(query) &&
        iString.Contains(query, '<Where>'))
    {
        condition = query.substring(query.indexOf('<Where>') + '<Where>'.length,
                                  query.lastIndexOf('</Where>'))
    }

    return condition;
}
SPQueryBuilder.ExtractOrderByCondition = function(query)
{
    var condition = '';
    if (!iString.IsNullOrEmpty(query) &&
        iString.Contains(query, '<OrderBy>'))
    {
        condition = query.substring(query.indexOf('<OrderBy>') + '<OrderBy>'.length,
                                query.lastIndexOf('</OrderBy>'))
    }

    return condition;
}
SPQueryBuilder.SplitQueryForThrottledOperation = function(query, maxItemsPerThrottledOperation, itemCount)
{
    // retrieve original conditions
    var originalOrderBy = SPQueryBuilder.ExtractOrderByCondition(query.Query);
    var originalWhere   = SPQueryBuilder.ExtractWhereCondition(query.Query);

    // prepare queries
    var queries = new Array();
    for (var i = 0; i < itemCount; i += maxItemsPerThrottledOperation)
    {
        // build splitted where
        var idFilter = SPQueryBuilder.BuildAndQueryCondition(SPQueryBuilder.BuildGreaterThanEqualQueryCondition('ID', 'Counter', i.toString()) +
                                                             SPQueryBuilder.BuildLessThanEqualQueryCondition('ID', 'Counter', (i + maxItemsPerThrottledOperation - 1).toString()));
        var splittedWhere = !iString.IsNullOrEmpty(originalWhere) ? SPQueryBuilder.BuildAndQueryCondition(idFilter + originalWhere)
                                                                   : idFilter;

        // clone and update query
        splittedQuery = query.Clone();
        splittedQuery.Query    = SPQueryBuilder.BuildQuery(originalOrderBy, splittedWhere);
        splittedQuery.RowLimit = maxItemsPerThrottledOperation;

        queries.push(splittedQuery);
    }

    return queries;
}

SPQueryBuilder.BuildQueryOptions = function(options)
{
    var xml = "<QueryOptions>"
            +   options
            + "</QueryOptions>";

    return xml;
}
SPQueryBuilder.BuildMandatoryColumnsOption = function(include)
{
    var xml = "<IncludeMandatoryColumns>"
            +   (include ? ISBoolean.TrueString : ISBoolean.FalseString)
            + "</IncludeMandatoryColumns>";

    return xml;
}
SPQueryBuilder.BuildListItemCollectionPositionNextOption = function(positionNext)
{
    var xml = "";
    if (!iString.IsNullOrEmpty(positionNext))
    {
        xml = "<Paging ListItemCollectionPositionNext='" + positionNext + "' />";
    }

    return xml;
}
SPQueryBuilder.BuildViewAttributesOption = function(attributes)
{
    var builder = new Array();
    builder[builder.length] = "<ViewAttributes ";

    for (var key in attributes)
    {
        var value = attributes[key];
        builder[builder.length] = iString.Format("{0}='{1}' ", key, value);
    }

    builder[builder.length] = " />";

    var xml = builder.join('');
    return xml;
}


// -----------------------------------------------------------------------
//  BatchBuilder
// -----------------------------------------------------------------------
Infoshare.SharePoint.BatchBuilder = function Infoshare$SharePoint$BatchBuilder() { }
SPBatchBuilder = Infoshare.SharePoint.BatchBuilder;

SPBatchBuilder.UpdateCommand = { New :    'New',
                                 Update : 'Update',
                                 Delete : 'Delete' };
SPBatchBuilder.DefaultErrorHandling = 'Continue';

SPBatchBuilder.BuildBatch = function(methods, errorHandling)
{
    // fix error handling
    if (iString.IsNullOrEmpty(errorHandling))
    {
        errorHandling = SPBatchBuilder.DefaultErrorHandling;
    }

    var builder = new Array();
    builder[builder.length] = iString.Format("<Batch OnError='{0}'>", errorHandling);
    for (var i = 0; i < methods.length; i++)
    {
        builder[builder.length] = methods[i];
    }
    builder[builder.length] = "</Batch>";

    var xml = builder.join('');
    return xml;
}
SPBatchBuilder.BuildMethod = function(fields, id, command)
{
    var builder = new Array();
    builder[builder.length] = iString.Format("<Method ID='{0}' Cmd='{1}'>", id, command);
    for (var i = 0; i < fields.length; i++)
    {
        builder[builder.length] = fields[i];
    }
    builder[builder.length] = "</Method>";

    var xml = builder.join('');
    return xml;
}
SPBatchBuilder.BuildField = function(name, value)
{
    var xml = iString.Format("<Field Name='{0}'><![CDATA[{1}]]></Field>", name, value);
    return xml;
}
SPBatchBuilder.BuildFields = function(fields)
{
    var fieldXmls = new Array();
    if (fields.TypeName == ISDictionary.TypeName)
    {
        var keys = fields.GetKeys();
        for (var i = 0; i < keys.length; i++)
        {
            var key = keys[i];
            var value = fields.Get(key);

            fieldXmls.push(SPBatchBuilder.BuildField(key, value));
        }
    }
    else if (fields instanceof Array)
    {
        for (var key in fields)
        {
            var value = fields[key];

            fieldXmls.push(SPBatchBuilder.BuildField(key, value));
        }
    }

    return fieldXmls;
}
                        
