ISNamespace.Register('Infoshare.SharePoint');


// -----------------------------------------------------------------------
//  ListAccessor
// -----------------------------------------------------------------------
Infoshare.SharePoint.ListAccessor = function Infoshare$SharePoint$ListAccessor(hostWebUrl, appWebUrl)
{
    this.HostWebUrl = hostWebUrl;
    this.AppWebUrl  = appWebUrl ? appWebUrl : hostWebUrl;
}
SPListAccessor = Infoshare.SharePoint.ListAccessor;
SPListAccessor.TypeName = 'Infoshare.SharePoint.ListAccessor';

SPListAccessor.prototype = {
    TypeName: SPListAccessor.TypeName,

    HostWebUrl: '',
    AppWebUrl: '',
    List: null,

    Invoking: false,

    ServiceCashe: null,
    GetService: function()
    {
        if (this.ServiceCashe == null)
        {
            this.ServiceCashe = new ISDictionary();
        }

        var service = this.ServiceCashe.Get(SPService.Type);
        if (!service)
        {
            if      (SPService.Type == SPService.ServiceType.WebService) { service = new SPListsService(this.HostWebUrl); }
            else if (SPService.Type == SPService.ServiceType.REST)       { service = new SRListsService(this.HostWebUrl, this.AppWebUrl); }
            this.ServiceCashe.Add(SPService.Type, service);
        }

        return service;
    },

    GetList: function(listId, callback)
    {
        var service = this.GetService();
        service.GetList(listId, function(list)
        {
            callback(list);
        });
    },

    GetListByTitle: function(title, callback)
    {
        this.GetLists(function(lists)
        {
            var listFound = null;
            for (var i = 0; i < lists.length; i++)
            {
                var list = lists[i];
                if (ISString.Equals(list.Title, title, true))
                {
                    listFound = list;
                    break;
                }
            }

            callback(listFound);
        });
    },

    GetLists: function(callback)
    {
        var service = this.GetService();
        service.GetLists(function(lists)
        {
            callback(lists);
        });
    },

    AddList: function(list, callback)
    {
        var title       = list.Properties['Title'];
        var description = list.Properties['Description'];
        var templateId  = list.Properties['ServerTemplate'];

        var service = this.GetService();
        service.AddList(title, description, templateId, function(list)
        {
            callback(list);
        });
    },

    DeleteList: function(listId, callback)
    {
        var service = this.GetService();
        service.DeleteList(listId, function()
        {
            callback();
        });
    },

    UpdateListProperties: function(list, callback)
    {
        var title       = list.Properties['Title'];
        var description = list.Properties['Description'];

        // XML組み立て
        // Reference: https://msdn.microsoft.com/en-us/library/lists.lists.updatelist(v=office.12).aspx
        var format = "<List Title='{0}' "
                   +       "Description='{1}' />";
        var xml = ISString.Format(format, title, description);

        // 更新
        var service = this.GetService();
        service.UpdateList(list.Id, xml, null, null, null, null, function(results)
        {
            callback(results);
        });
    },

    AddFields: function(list, fields, callback)
    {
        // convert type for single item
        if (!(fields instanceof Array))
        {
            fields = [ fields ];
        }

        // 表示名は作成後、更新が必要
        var updateFields = new Array();
        for (var i = 0; i < fields.length; i++)
        {
            var field = fields[i];
            if (!ISString.IsNullOrEmpty(field.Properties['DisplayName']))
            {
                updateFields.push(field);
            }
        }

        var service = this;
        this.AddFieldsInternal(list, fields, function(addFieldsResults)
        {
            if (updateFields.length > 0)
            {
                service.UpdateFields(list, updateFields, function(updateFieldsResults)
                {
                    updateFieldsResults['NewFields'] = addFieldsResults['NewFields'];
                    callback(updateFieldsResults);
                });
            }
        });
    },

    AddFieldsInternal: function(list, fields, callback)
    {
        // XML組み立て
        // Reference: https://msdn.microsoft.com/en-us/library/lists.lists.updatelist(v=office.12).aspx
        // Reference: https://msdn.microsoft.com/ja-jp/library/office/ms437580.aspx
        var builder = new Array();
        for (var i = 0; i < fields.length; i++)
        {
            var field = fields[i];

            // fix name
            var name = field.Properties['Name'];
            if (!name)
            {
                name = field.Properties['DisplayName'];
            }

            builder[builder.length] = "<Method ID='" + i + "'>";
            builder[builder.length] = "<Field ";

            // 作成時は"Name"属性が指定できないため、"DisplayName"属性を設定
            builder[builder.length] = "Type='"        + field.Properties['Type'] + "' ";
            builder[builder.length] = "DisplayName='" + name                     + "' ";
            
            this.AddOptionalFieldAttribute(field, builder);

            builder[builder.length] = "/>";
            builder[builder.length] = "</Method>";
        }
        var xml = ISString.Format("<Fields>{0}</Fields>", builder.join(''));

        // 追加
        var service = this.GetService();
        service.UpdateList(list.Id, null, xml, null, null, null, function(results)
        {
            callback(results);
        });
    },

    UpdateFields: function(list, fields, callback)
    {
        // convert type for single item
        if (!(fields instanceof Array))
        {
            fields = [ fields ];
        }

        // XML組み立て
        // Reference: https://msdn.microsoft.com/en-us/library/lists.lists.updatelist(v=office.12).aspx
        var builder = new Array();
        for (var i = 0; i < fields.length; i++)
        {
            var field = fields[i];
            builder[builder.length] = "<Method ID='" + i + "'>";
            builder[builder.length] = "<Field ";

            // フィールド指定には、"Type"属性と"Name"属性の両方が必要
            builder[builder.length] = "Type='" + field.Properties['Type'] + "' ";
            builder[builder.length] = "Name='" + field.Properties['Name'] + "' ";
            
            if (field.Properties['DisplayName']){ builder[builder.length] = "DisplayName='" + field.Properties['DisplayName'] + "' "; }

            this.AddOptionalFieldAttribute(field, builder);
            if (field.Properties['Default'])
            {
                builder[builder.length] = ">";
                builder[builder.length] = "<Default>" + field.Properties['Default'] + "</Default>";
                builder[builder.length] = "</Field>";
            }
            else
            {
                builder[builder.length] = "/>";
            }            

            builder[builder.length] = "</Method>";
        }
        var xml = ISString.Format("<Fields>{0}</Fields>", builder.join(''));

        // 追加
        var service = this.GetService();
        service.UpdateList(list.Id, null, null, xml, null, null, function(results)
        {
            callback(results);
        });
    },

    AddOptionalFieldAttribute: function(field, builder)
    {
        // basic attributes
        if (field.Properties['Description'])         { builder[builder.length] = "Description='"         + field.Properties['Description']         + "' "; }
        if (field.Properties['Required'])            { builder[builder.length] = "Required='"            + field.Properties['Required']            + "' "; }
        if (field.Properties['Indexed'])             { builder[builder.length] = "Indexed='"             + field.Properties['Indexed']             + "' "; }
        if (field.Properties['Hidden'])              { builder[builder.length] = "Hidden='"              + field.Properties['Hidden']              + "' "; }
        if (field.Properties['EnforceUniqueValues']) { builder[builder.length] = "EnforceUniqueValues='" + field.Properties['EnforceUniqueValues'] + "' "; }        

        if (field.Properties['ShowInNewForm'])       { builder[builder.length] = "ShowInNewForm='"       + field.Properties['ShowInNewForm']       + "' "; }        
        if (field.Properties['ShowInEditForm'])      { builder[builder.length] = "ShowInEditForm='"      + field.Properties['ShowInEditForm']      + "' "; }        
        if (field.Properties['ShowInDisplayForm '])  { builder[builder.length] = "ShowInDisplayForm ='"  + field.Properties['ShowInDisplayForm ']  + "' "; }

        // for Text field
        if (field.Properties['MaxLength']){ builder[builder.length] = "MaxLength='" + field.Properties['MaxLength'] + "' "; }

        // for Note field
        if (field.Properties['RichText'])    { builder[builder.length] = "RichText='"      + field.Properties['RichText']     + "' "; }
        if (field.Properties['RichTextMode']){ builder[builder.length] = "RichTextMode ='" + field.Properties['RichTextMode'] + "' "; }
    }
}
                        
