ISNamespace.Register('Infoshare.SharePoint');


// -----------------------------------------------------------------------
//  ListItemRetriever
// -----------------------------------------------------------------------
Infoshare.SharePoint.ListItemRetriever = function Infoshare$SharePoint$ListItemRetriever(list, hostWebUrl, appWebUrl)
{
    this.HostWebUrl = hostWebUrl;
    this.AppWebUrl  = appWebUrl ? appWebUrl : hostWebUrl;
    this.List = list;
}
SPListItemRetriever = Infoshare.SharePoint.ListItemRetriever;
SPListItemRetriever.TypeName = 'Infoshare.SharePoint.ListItemRetriever';

SPListItemRetriever.Sort = function (items, sortFields)
{
    items.sort(function (x, y)
    {
        var result = 0;
        for (var i = 0; i < sortFields.length; i++)
        {
            var sortField = sortFields[i];

            var xValue = x.Properties[sortField.Name];
            var yValue = y.Properties[sortField.Name];

            if (!sortField.Type)
            {
                continue;
            }

            // null, undefinedは 正しく比較できないので空文字列に置き換える
            // 例： 「 null < "hoge" は false 」「undefined > "hoge" は false 」
            if (ISString.IsNullOrEmpty(xValue))
            {
                xValue = "";
            }
            if (ISString.IsNullOrEmpty(yValue))
            {
                yValue = "";
            }

            // 数値型はNumberに変換
            if (ISString.Equals(sortField.Type, "Integer", true) ||
                ISString.Equals(sortField.Type, "Counter", true) ||
                ISString.Equals(sortField.Type, "Number", true))
            {
                xValue = Number(xValue);
                yValue = Number(yValue);
            }


            if (xValue == yValue)
            {
                continue;
            }

            // テキストはlocalCompareする（演算子比較だとunicode順になるため）
            // https://developer.mozilla.org/ja/docs/Web/JavaScript/Reference/Global_Objects/String/localeCompare
            if (ISString.Equals(sortField.Type, "Text", true))
            {
                var textResult = xValue.localeCompare(yValue);
                if (textResult == 0)
                {
                    continue;
                }

                if (!sortField.Ascending)
                {
                    // 反転させる
                    textResult = textResult == -1 ? 1 : -1;
                }

                result = textResult;
            }
            else
            {
                var condition = sortField.Ascending ? xValue < yValue : xValue > yValue;
                result = condition ? -1 : 1;
            }
            
            break;
        }

        return result;
    });

    return items;
}

SPListItemRetriever.GetSortFields = function (query, fields)
{
    // prepare sort fields
    var sortFields = new Array();
    var xDoc = iXml.LoadXml(query);
    var xOrderBy = iXml.SelectNodeByPath(xDoc.documentElement, 'OrderBy');

    if (xOrderBy)
    {
        for (var i = 0; i < xOrderBy.childNodes.length; i++)
        {
            var xFieldRef = xOrderBy.childNodes[i];
            var name      = iXml.GetAttributeValue(xFieldRef, 'Name');
            var ascending = ISBoolean.TryParse(iXml.GetAttributeValue(xFieldRef, 'Ascending'), false);
            var field = fields.Get(name);
            var type = field ? field.Type : null;
            sortFields.push({ Name: name, Ascending: ascending, Type: type });
        }
    }

    return sortFields;
}

SPListItemRetriever.prototype = {
    TypeName: SPListItemRetriever.TypeName,

    HostWebUrl: '',
    AppWebUrl: '',
    List: null,

    Invoking: false,
    MaxItemIndex: -1,
    TryQuery: true,
    EnableIterativeQueries: true,

    EnsureMaxItemIndex: function(callback)
    {
        if (!this.EnableIterativeQueries ||
            this.MaxItemIndex != -1)
        {
            callback();
            return;
        }

        // build query for getting last item
        var query = new ISSPQuery();
        query.Query    = SPQueryBuilder.BuildQuery(SPQueryBuilder.BuildOrderByFieldRef('ID', false), '');
        query.RowLimit = 1;

        // initialize invocation context
        var context = { List:     this,
                        Callback: callback };

        // issue query
        var retriever = this;
        this.GetListItemsCore(query, function(items)
        {
            // fix index
            var index = 0;
            if (items != null && items.length > 0)
            {
                index = items[0].Id;
            }

            // update index
            retriever.MaxItemIndex = index;

            callback();
        });
    },

    GetListItems: function(query, callback)
    {
        if (this.Invoking)
        {
            throw new Error('Failed to invoke new request, since the previous request does not completed.');
        }
        this.Invoking = true;

        var retriever = this;
        if (this.TryQeuryEnabled(query))
        {
            this.GetListItemsCore(query, function(items, metadata)
            {
                // 5000アイテム問題で500エラーが発生する場合
                // 分割クエリーを用いてアイテムを取得する
                if (items == null)
                {
                    retriever.GetListItemsInternal(query, callback);
                }
                else
                {
                    retriever.Invoking = false;
                    callback(items, metadata);
                }
            });
        }
        else
        {
            this.GetListItemsInternal(query, callback);
        }
    },

    GetListItemsInternal: function(query, callback)
    {
        var retriever = this;
        this.EnsureMaxItemIndex(function()
        {
            if (retriever.List &&
                retriever.List.MaxItemsPerThrottledOperation == 0 ||
                !retriever.IterativeQueryEnabled(query) ||
                retriever.IterativeQueryEnabled(query) && retriever.MaxItemIndex < retriever.List.MaxItemsPerThrottledOperation)
            {
                retriever.GetListItemsCore(query, function(items, metadata)
                {
                    retriever.Invoking = false;
                    callback(items, metadata);
                });
                return;
            }

            // split query for throttled operation
            var queries = SPQueryBuilder.SplitQueryForThrottledOperation(query, retriever.List.MaxItemsPerThrottledOperation, retriever.MaxItemIndex);
            retriever.GetListItemsForMultipleQuery(queries, function(items)
            {
                // prepare sort fields
                var sortFields = SPListItemRetriever.GetSortFields(query.Query, retriever.List.Fields);

                if (sortFields &&
                    sortFields.length > 0)
                {
                    // sort
                    items = SPListItemRetriever.Sort(items, sortFields);                
                }
                
                // apply row limit
                var rowLimit = query.RowLimit;
                if (ISObject.IsNullOrUndefined(rowLimit))
                {
                    rowLimit = 0;
                }
                if (rowLimit != 0 &&
                    items.length > rowLimit)
                {
                    items = items.slice(0, rowLimit);
                }

                retriever.Invoking = false;
                callback(items);
            });
        });
    },

    GetListItemsForMultipleQuery: function(queries, callback)
    {
        // 分割クエリ時にフィールドの詳細を確認するため、フィールドがない場合は取得する
        if (!this.List.Fields)
        {
            var service = new SPListsService(this.HostWebUrl);
            service.GetList(this.List.Id, ISFunction.CreateDelegate(function(list)
            {
                this.List = list;
                this.GetListItemsForMultipleQueryCore(queries, callback);
            }, this));
        }

        else
        {
            this.GetListItemsForMultipleQueryCore(queries, callback);
        }
    },

    GetListItemsForMultipleQueryCore: function(queries, callback)
    {
        var context =
        {
            Callback: callback,

            Items: new Array(),
            Requests: null,
            InvocationCount: 0,
            RequestsCompleted: function()
            {
                return this.Requests.length <= this.InvocationCount;
            }
        };

        // prepare requests management implementation
        context.Requests = new Array();
        for (var i = 0; i < queries.length; i++)
        {
            context.Requests.push(
            {
                ParentContext: context,
                Query: queries[i],
                Completed: false
            });
        }

        // invoke
        for (var i = 0; i < context.Requests.length; i++)
        {
            var request = context.Requests[i];
            this.GetListItemsCore(request.Query, function(items)
            {
                var context = request.ParentContext;
                context.InvocationCount++;
                if (items)
                {
                    context.Items = context.Items.concat(items);
                }
                if (context.RequestsCompleted())
                {
                    context.Callback(context.Items);
                }
            });
        }
    },

    GetListItemsCore: function(query, callback)
    {
        if (SPService.Type == SPService.ServiceType.REST)
        {
            this.GetListItemsByRest(query, callback);
        }
        else
        {
            this.GetListItemsByWebService(query, callback);
        }
    },

    GetListItemsByWebService: function(query, callback)
    {
        // ensure query
        query.Ensure();

        // create service
        var service = new SPListsService(this.HostWebUrl);
        if (callback)
        {
            service.GetListItems(this.List.Id,       // listName
                                 null,               // viewName
                                 query.Query,        // query
                                 query.ViewFields,   // viewFields
                                 query.RowLimit,     // rowLimit
                                 query.QueryOptions, // queryOptions
                                 null,               // webId
            function(items, metadata)
            {
                callback(items, metadata);
            });
        }
        else
        {
            var items = service.GetListItems(this.List.Id,       // listName
                                             null,               // viewName
                                             query.Query,        // query
                                             query.ViewFields,   // viewFields
                                             query.RowLimit,     // rowLimit
                                             query.QueryOptions, // queryOptions
                                             null);              // webId

            return items;
        }
    },

    GetListItemsByRest: function(query, callback)
    {
        // ensure query
        query.Ensure();

        // build query
        var viewXml = '';
        if (query.Query)
        {
            viewXml = '<View>'
                    + query.Query
                    + '</View>';
        }

        // create service
        var service = new SRListsService(this.HostWebUrl, this.AppWebUrl);
        if (callback)
        {
            service.GetItems(this.List.Id,        // listName
                             viewXml,             // viewXml
                             query.ViewFieldRefs, // viewFields
            function(items)
            {
                callback(items);
            });
        }
        else
        {
            var items = service.GetListItems(this.List.Id,         // listName
                                             viewXml,              // viewXml
                                             query.ViewFieldRefs); // viewFields

            return items;
        }
    },

    TryQeuryEnabled: function(query)
    {
        return this.TryQuery && query.TryQuery;
    },

    IterativeQueryEnabled: function(query)
    {
        return this.EnableIterativeQueries && query.EnableIterativeQueries;
    }
}


// -----------------------------------------------------------------------
//  ListItemAccessor
// -----------------------------------------------------------------------
Infoshare.SharePoint.ListItemAccessor = function Infoshare$SharePoint$ListItemAccessor(list, hostWebUrl, appWebUrl)
{
    Infoshare.SharePoint.ListItemRetriever.apply(this, arguments);
}
SPListItemAccessor = Infoshare.SharePoint.ListItemAccessor;
SPListItemAccessor.TypeName = 'Infoshare.SharePoint.ListItemAccessor';
SPListItemAccessor.prototype = new Infoshare.SharePoint.ListItemRetriever();
SPListItemAccessor.prototype.TypeName = SPListItemAccessor.TypeName;
SPListItemAccessor.prototype.UpdateListItems = function(items, callback)
{
    // convert type for single item
    if (!(items instanceof Array))
    {
        items = [ items ];
    }

    if (SPService.Type == SPService.ServiceType.REST)
    {
        this.UpdateListItemsByRest(items, callback);
    }
    else
    {
        this.UpdateListItemsByWebService(items, callback);
    }
}
SPListItemAccessor.prototype.UpdateListItemsByRest = function(items, callback)
{
}
SPListItemAccessor.prototype.UpdateListItemsByWebService = function(items, callback)
{
    // build batch xml
    var methods = new Array();
    for (var i = 0; i < items.length; i++)
    {
        var item = items[i];

        // build fields
        var fields = SPBatchBuilder.BuildFields(item.Properties);

        // fix update command
        var id = null;
        try
        {
            id = item.Properties['ID'];
        }
        catch (e) {}
        var command = SPBatchBuilder.UpdateCommand.New;
        if (id != null)
        {
            if (fields.length == 1) { command = SPBatchBuilder.UpdateCommand.Delete; }
            else                    { command = SPBatchBuilder.UpdateCommand.Update; }
        }

        // build method
        methods.push(SPBatchBuilder.BuildMethod(fields, i, command));
    }
    var batch = SPBatchBuilder.BuildBatch(methods);

    // create service
    var service = new SPListsService(this.HostWebUrl);
    if (callback)
    {
        service.UpdateListItems(this.List.Id, batch, function(results)
        {
            callback(results);
        });
    }
    else
    {
        var results = service.UpdateListItems(this.List.Id, batch);
        return results;
    }
}
                        
