// -----------------------------------------------------------------------
//  Register namespace
// -----------------------------------------------------------------------
ISNamespace.Register('Infoshare.SharePoint');


// -----------------------------------------------------------------------
//  ListContentsExporter
// -----------------------------------------------------------------------
Infoshare.SharePoint.ListContentsExporter = function Infoshare$SharePoint$ListContentsExporter(webUrl, list, view)
{
    this.WebUrl = webUrl;
    this.List   = list;
    this.View   = view;
}
SPListContentsExporter = Infoshare.SharePoint.ListContentsExporter;
SPListContentsExporter.Format = { CSV: 'CSV', 
                                  Xml: 'Xml' }

SPListContentsExporter.prototype = {
    WebUrl: '',
    List: null,
    View: null,

    Format: SPListContentsExporter.Format.CSV,

    EnableIterativeQueries: false,

    Export: function(callback)
    {
        var exporter = this;
        this.Ensure(function()
        {
            var query = new ISSPQuery();
            query.Query      = exporter.View.Query;
            query.ViewFields = exporter.View.ViewFields;

            var retriever = new SPListItemRetriever(exporter.WebUrl, exporter.List);
            retriever.EnableIterativeQueries = exporter.EnableIterativeQueries;
            retriever.GetListItems(query, function(items)
            {
                var contents = '';
                if      (exporter.Format == SPListContentsExporter.Format.CSV) { contents = exporter.ToCSV(items); }
                else if (exporter.Format == SPListContentsExporter.Format.Xml) { contents = exporter.ToXml(items); }

                callback(contents);
            });
        });
    },

    ExportToFile: function(path, callback)
    {
        this.Export(function(contents)
        {
            var file = new ISWebFile();
            file.Upload(path, contents, callback);
        });
    },

    ToCSV: function(items)
    {
        var contents = new Array();

        // retrieve fields
        var fields = this.GetFieldsToExport();

        // write headers
        for (var i = 0; i < fields.length; i++)
        {
            var field = fields[i];

            if (i != 0)
            {
                contents[contents.length] = ',';
            }
            contents[contents.length] = '"' + field.DisplayName + '"';
        }
        contents[contents.length] = '\r\n';

        // write contents
        for (var i = 0; i < items.length; i++)
        {
            var item = items[i];
            for (var j = 0; j < fields.length; j++)
            {
                var field = fields[j];

                if (j != 0)
                {
                    contents[contents.length] = ',';
                }

                // fix value, then set
                var value = item.Properties[field.Name];
                if (ISString.IsNullOrEmpty(value))
                {
                    value = '';
                }
                contents[contents.length] = '"' + value + '"';
            }
            contents[contents.length] = '\r\n';
        }

        return contents.join('');
    },

    ToXml: function(items)
    {
        var contents = new Array();

        // xml content header
        contents[contents.length] = '<?xml version="1.0"?>';
        contents[contents.length] = '<?mso-application progid="Excel.Sheet"?>';
        contents[contents.length] = '<Workbook xmlns="urn:schemas-microsoft-com:office:spreadsheet" ';
        contents[contents.length] =           'xmlns:o="urn:schemas-microsoft-com:office:office" ';
        contents[contents.length] =           'xmlns:x="urn:schemas-microsoft-com:office:excel" ';
        contents[contents.length] =           'xmlns:ss="urn:schemas-microsoft-com:office:spreadsheet" ';
        contents[contents.length] =           'xmlns:html="http://www.w3.org/TR/REC-html40">';
        contents[contents.length] =   '<DocumentProperties xmlns="urn:schemas-microsoft-com:office:office">';
        contents[contents.length] =   '</DocumentProperties>';
        contents[contents.length] =   '<OfficeDocumentSettings xmlns="urn:schemas-microsoft-com:office:office">';
        contents[contents.length] =     '<AllowPNG/>';
        contents[contents.length] =   '</OfficeDocumentSettings>';
        contents[contents.length] =   '<ExcelWorkbook xmlns="urn:schemas-microsoft-com:office:excel">';
        contents[contents.length] =     '<ProtectStructure>False</ProtectStructure>';
        contents[contents.length] =     '<ProtectWindows>False</ProtectWindows>';
        contents[contents.length] =   '</ExcelWorkbook>';
        contents[contents.length] =   '<Styles>';
        contents[contents.length] =   '</Styles>';
        contents[contents.length] =   '<Worksheet ss:Name="Sheet1">';
        contents[contents.length] =     '<Table>';

        // retrieve fields
        var fields = this.GetFieldsToExport();

        // write headers
        contents[contents.length] = '<Row>'
        for (var i = 0; i < fields.length; i++)
        {
            var field = fields[i];

            contents[contents.length] = '<Cell><Data ss:Type="String">';
            contents[contents.length] = iXml.Escape(field.DisplayName);
            contents[contents.length] = '</Data></Cell>';
        }
        contents[contents.length] = '</Row>'

        // write contents
        for (var i = 0; i < items.length; i++)
        {
            contents[contents.length] = '<Row>';
            var item = items[i];
            for (var j = 0; j < fields.length; j++)
            {
                var field = fields[j];

                // fix value, then set
                var value = item.Properties[field.Name];
                if (ISString.IsNullOrEmpty(value))
                {
                    value = '';
                }

                contents[contents.length] = '<Cell><Data ss:Type="String">';
                contents[contents.length] = iXml.Escape(value);
                contents[contents.length] = '</Data></Cell>';
            }
            contents[contents.length] = '</Row>';
        }

        // xml content footer
        contents[contents.length] =     '</Table>';
        contents[contents.length] =   '</Worksheet>';
        contents[contents.length] = '</Workbook>';

        return contents.join('');
    },

    GetFieldsToExport: function()
    {
        var fields = new Array();
        var fieldNames = this.View.ViewFieldRefs.GetKeys();
        for (var i = 0; i < fieldNames.length; i++)
        {
            var fieldName = fieldNames[i];
            var field = this.List.Fields.Get(fieldName);
            if (field)
            {
                fields.push(field);
            }
        }

        return fields;
    },

    Ensure: function(callback)
    {
        var count = 0;
        var exporter = this;
        this.EnsureList(function()
        {
            count++;
            if (count >= 2)
            {
                callback();
            }
        });
        this.EnsureView(function()
        {
            count++;
            if (count >= 2)
            {
                callback();
            }
        });
    },

    EnsureList: function(callback)
    {
        if (ISObject.TypeOf(this.List) != 'string')
        {
            callback();
            return;
        }

        var exporter = this;
        var service = new SPListsService(this.WebUrl);
        service.GetList(this.List, function(list)
        {
            exporter.List = list;
            callback();
        })
    },

    EnsureView: function(callback)
    {
        if (ISObject.TypeOf(this.View) != 'string')
        {
            callback();
            return;
        }

        var listId = this.List;
        if (ISObject.TypeOf(listId) != 'string')
        {
            listId = this.List.Id;
        }

        var exporter = this;
        var service = new SPViewsService(this.WebUrl);
        service.GetView(listId, this.View, function(view)
        {
            exporter.View = view;
            callback();
        })
    }
}
                        
