// -----------------------------------------------------------------------
//  Context
// -----------------------------------------------------------------------
Infoshare.SharePoint.ViewExtenderContext = function Infoshare$SharePoint$ViewExtenderContext() { }
iVxContext = Infoshare.SharePoint.ViewExtenderContext;

iVxContext.SiteUrl     = null;
iVxContext.WebUrl      = null;
iVxContext.LayoutsPath = null;
iVxContext.ImagesPath  = null;

// 製品管理サイトコレクションのパス（MasterSiteContext.ServerRelativePathで定義される）
iVxContext.MasterSiteRelativePath   = null;
iVxContext.MasterSiteAbsolutePath   = null;

// インフォシェア製品ライブラリ（InfoshareProductLibrary）フォルダパス
iVxContext.MasterConfigurationsPath = null;
iVxContext.MasterSourcesPath        = null;
iVxContext.MasterTemplatePath       = null;
iVxContext.MasterTemporaryPath      = null;

iVxContext.ViewExperienceType = { Classic: 'Classic',
                                  Modern:  'Modern' };
iVxContext.ViewExperience = iVxContext.ViewExperienceType.Classic;

iVxContext.ListId = null;
iVxContext.ItemId = null;
iVxContext.ContentTypeId = null;
iVxContext.UserId = null;
iVxContext.RootFolder = null;

iVxContext.IsHighContrastMode = null;

iVxContext.Initialized  = false;
iVxContext.Initializing = false;

// 表示言語関連設定
iVxContext.DefaultLanguage = 'ja-jp';
iVxContext.Language = null;
iVxContext.LanguageDetectionMethods = { BrowserSetting:        'BrowserSetting',
                                        SharePointSiteContext: 'SharePointSiteContext' };
iVxContext.LanguageDetectionMethod = iVxContext.LanguageDetectionMethods.SharePointSiteContext;

iVxContext.IsOnline = function ()
{
    var isOnline = false;
    try
    {
        // 設定ファイルで定義されている場合
        if (iSettings.iVxContext.IsOnline)
        {
            isOnline = true;
        }
    }
    catch (e)
    {
        isOnline = false;
    }

    return isOnline;
}

iVxContext.GetWebUrl = function()
{
    var webUrl = null;
    if (typeof(_spPageContextInfo) != 'undefined')
    {
        webUrl = _spPageContextInfo.webAbsoluteUrl;
        if (!webUrl && typeof(_spPageContextInfo.legacyPageContext) != 'undefined')
        {
            webUrl = _spPageContextInfo.legacyPageContext.webAbsoluteUrl;
        }
    }

    return webUrl;
}

iVxContext.GetListId = function()
{
    var listId = null;
    if (typeof(_spPageContextInfo) != 'undefined')
    {
        listId = _spPageContextInfo.pageListId;
        if (!listId && typeof(_spPageContextInfo.legacyPageContext) != 'undefined')
        {
            listId = _spPageContextInfo.legacyPageContext.pageListId;
        }
    }

    return listId;
}

iVxContext.EnsureMasterSitePath = function()
{
    var ensured = false;
    // UserCustomActionから定義される管理サイトURL情報を元に、iVxContextを設定する
    if (typeof MasterSiteContext == 'object' &&
        MasterSiteContext.ServerRelativePath &&
        !ISString.IsNullOrEmpty(MasterSiteContext.ServerRelativePath))
    {
        iVxContext.MasterSiteRelativePath = MasterSiteContext.ServerRelativePath;
        iVxContext.MasterSiteAbsolutePath = ISUri.GetAbsoluteUrl(iVxContext.MasterSiteRelativePath);

        var productLibraryPath =  ISString.TrimEnd(ISString.TrimStart(iVxContext.MasterSiteAbsolutePath, '/'), '/')
                               + '/InfoshareProductLibrary'; 
        iVxContext.MasterConfigurationsPath = productLibraryPath + '/Configurations';
        iVxContext.MasterSourcesPath        = productLibraryPath + '/Sources';
        iVxContext.MasterTemplatePath       = productLibraryPath + '/Template';
        iVxContext.MasterTemporaryPath      = productLibraryPath + '/Temporary';

        ensured = true;
    }

    return ensured;
}

iVxContext.Initialize = function(callback)
{
    // 製品管理サイトのProductLibrary下のフォルダパスを決定する（パスが確定しない場合は、警告を出し処理を中止）
    if (!iVxContext.MasterSourcesPath)
    {
        var ensured = iVxContext.EnsureMasterSitePath();
        if(!ensured)
        {
            var messageFormat = "[iVxContext.Initialize] {0}";
            var message = "";
            if (typeof MasterSiteContext != 'object')
            {
                message = "MasterSiteContext is not defined.";
            }
            else
            {
                message = ISString.Format("MasterSiteContext.ServerRelativePath is not defined. Value : {0}", MasterSiteContext.ServerRelativePath);
            }

            messageFormat = ISString.Format(messageFormat, message);
            ISTrace.TraceWarning(messageFormat);
            setTimeout(callback, 1);
            return;
        }
    }

    if (!iVxContext.Initialized &&
        iVxContext.Initializing)
    {
        iVxContext.RegisterFunctionToNotifyInitialized(callback);
    }
    
    if (iVxContext.Initialized ||
        iVxContext.Initializing)
    {
        ISTrace.TraceVerbose('Skipped iVxContext.Initialize');
        setTimeout(callback, 1);
        return;
    }
    iVxContext.Initializing = true;

    var stopwatch = new ISStopwatch();
    stopwatch.Start();
    ISTrace.TraceVerbose('[BEGIN] iVxContext.Initialize');

    // MDS(ダウンロード最小化戦略)対応
    //ISQueryString.EnableExtractionParamsFromHash = (typeof g_mdsReady != "undefined");

    iVxContext.EnsureUrls();
    iVxContext.EnsurePageContextInfo();
    iVxContext.EnsureViewExperience();
    iVxContext.EnsureHighContrastMode();
    
    iVxContext.InitializeRemoteResources(function()
    {
        ISTrace.TraceVerbose('[END] iVxContext.Initialize (spent: ' + stopwatch.Stop() + ')');
        iVxContext.Initialized  = true;
        iVxContext.Initializing = false;
        iVxContext.NotifyInitialized();

        if (callback)
        {
            callback();
        }
    });
}
iVxContext.EnsureUrls = function()
{
    // サイトコレクションのURLを生成
    var siteUrl = '';
    var webUrl  = '';
    if (typeof(_spPageContextInfo) != 'undefined')
    {
        siteUrl = _spPageContextInfo.siteAbsoluteUrl;
        webUrl  = _spPageContextInfo.webAbsoluteUrl;
        if (!siteUrl && !webUrl && typeof(_spPageContextInfo.legacyPageContext) != 'undefined')
        {
            siteUrl = _spPageContextInfo.legacyPageContext.siteAbsoluteUrl;
            webUrl  = _spPageContextInfo.legacyPageContext.webAbsoluteUrl;
        }
    }
    else
    {
        var uri = new ISUri(document.location.href);
        // サイトのURLを生成
        for (; ;)
        {
            // サーバーのURLを生成 (ポート番号含む)
            webUrl = uri.Scheme + '://' + uri.Authority;

            // レイアウトページ
            if (ISArray.Contains(uri.Segments, '_layouts'))
            {
                for (var i = 0; i < uri.Segments.length; i++)
                {
                    var segment = uri.Segments[i];
                    if (segment == '_layouts')
                    {
                        break;
                    }

                    webUrl += '/' + segment;
                }

                break;
            }

            // サイトページ
            if (ISArray.Contains(uri.Segments, 'SitePages'))
            {
                for (var i = 0; i < uri.Segments.length; i++)
                {
                    var segment = uri.Segments[i];
                    if (segment == 'SitePages')
                    {
                        break;
                    }

                    webUrl += '/' + segment;
                }

                break;
            }

            // リスト/ライブラリページ
            if (uri.Segments.length > 3 && // セグメントが3個の場合はサーバーのURLまででOK
                (uri.Segments[uri.Segments.length - 3].toUpperCase() == 'Lists'.toUpperCase() ||
                 uri.Segments[uri.Segments.length - 2].toUpperCase() == 'Forms'.toUpperCase()))
            {
                webUrl += '/' + uri.Segments.slice(0, uri.Segments.length - 3).join('/');
            }

            break;
        }

    }

    iVxContext.SiteUrl     = siteUrl;
    iVxContext.WebUrl      = webUrl;
    iVxContext.LayoutsPath = iVxContext.IsOnline() ? ISString.TrimEnd(iVxContext.SiteUrl, "/") + "/Configurations/Packages/Layouts" : ISString.TrimEnd(webUrl, '/') + '/_layouts';
    iVxContext.ImagesPath  = iVxContext.IsOnline() ? ISString.TrimEnd(iVxContext.SiteUrl, "/") + "/Configurations/Packages/Images/" : iVxContext.LayoutsPath + '/images';     
}
iVxContext.EnsurePageContextInfo = function()
{
    if (typeof(_spPageContextInfo) != 'undefined')
    {
        iVxContext.ListId = _spPageContextInfo.pageListId ? _spPageContextInfo.pageListId : null;
        iVxContext.UserId = _spPageContextInfo.userId ? _spPageContextInfo.userId : null;
    }

    if (ISQueryString.Contains('ID'))
    {
        iVxContext.ItemId = ISQueryString.GetValue('ID');
    }

    if (ISQueryString.Contains('ContentTypeId'))
    {
        iVxContext.ContentTypeId = ISQueryString.GetValue('ContentTypeId');
    }

    if (ISQueryString.Contains('RootFolder'))
    {
        iVxContext.RootFolder = ISQueryString.GetValue('RootFolder');
    }

    // 言語関連設定の初期化
    var language = null;
    for (;;)
    {
        // SharePoint Page Contextから初期化
        if (iVxContext.LanguageDetectionMethod == iVxContext.LanguageDetectionMethods.SharePointSiteContext &&
            typeof(_spPageContextInfo) != 'undefined')
        {
            language = _spPageContextInfo.currentUICultureName;
        }
        if (language)
        {
            break;
        }

        // ブラウザ設定から初期化
        if (iVxContext.LanguageDetectionMethod == iVxContext.LanguageDetectionMethods.BrowserSetting)
        {
            language = iBrowser.GetLanguage();
        }
        if (language)
        {
            break;
        }

        language = iVxContext.DefaultLanguage;
        break;
    }

    // ToDo(skomatsu): 日本語|英語以外の言語ハンドリングを検討
    // 以下のケースは規定値（ja-jp）それ以外は、en-us
    // ・言語設定が取得できない場合
    // ・jaで始まる場合
    if (!language ||
        (language && iString.StartsWith(language, 'ja', true)))
    {
        language = 'ja-jp';
    }
    else
    {
        language = 'en-us';
    }
    iVxContext.Language = language;
}
iVxContext.EnsureViewExperience = function ()
{
    iVxContext.ViewExperience = iVxContext.GetViewExperience();
};
iVxContext.GetViewExperience = function ()
{
    var viewExperience = iVxContext.ViewExperienceType.Classic;
    if (typeof g_presenceEnabled == 'undefined')
    {
        viewExperience = iVxContext.ViewExperienceType.Modern;
    }

    return viewExperience;
};
iVxContext.EnsureHighContrastMode = function()
{
    var isHighContrastMode = false;
    try
    {
        var nonExistentImagePath = ISString.TrimEnd(iVxContext.MasterSourcesPath, '/') + '/Infoshare/NonExistentImage.png';
        isHighContrastMode = ISBrowser.IsHighContrastMode(nonExistentImagePath);
    }
    catch (e) { }
    iVxContext.IsHighContrastMode = isHighContrastMode;
}

iVxContext.InitializeRemoteResources = function(callback)
{
    var invocationContext = {
        UserLoaded: false,
        SiteLoaded: false,

        LoadCompleted: function()
        {
            return this.UserLoaded &&
                   this.SiteLoaded;
        }
    };

    // ユーザー
    iVxContext.EnsureCurrentUser(function()
    {
        invocationContext.UserLoaded = true;
        if (invocationContext.LoadCompleted() &&
            callback)
        {
            callback();
        }
    });

    // サイト
    iVxContext.EnsureSite(function()
    {
        invocationContext.SiteLoaded = true;
        if (invocationContext.LoadCompleted() &&
            callback)
        {
            callback();
        }
    });
}

iVxContext.CurrentUser = null;
iVxContext.EnsureCurrentUser = function(callback)
{
    // ToDo(skomatsu): 要不要検討
    //if (iVxContext.UserId)
    //{
    //    callback();
    //    return;
    //}

    if (iVxContext.CurrentUser)
    {
        callback(iVxContext.CurrentUser);
        return;
    }

    iVxService.GetCurrentUser(function(user)
    {
        iVxContext.CurrentUser = user;
        iVxContext.UserId = user.Id;

        callback(iVxContext.CurrentUser);
    });
}

iVxContext.Site = null;
iVxContext.EnsureSite = function(callback)
{
    if (typeof(_spPageContextInfo) != 'undefined' &&
        _spPageContextInfo.siteAbsoluteUrl)
    {
        callback();
        return;
    }

    if (iVxContext.Site)
    {
        callback(iVxContext.Site);
        return;
    }

    iVxService.GetSite(function(site)
    {
        iVxContext.Site    = site;
        iVxContext.SiteUrl = site.Url;

        callback(iVxContext.Site);
    });
}

iVxContext.Events = null;
iVxContext.EventName = { Initialized: 'Initialized' };
iVxContext.NotifyInitialized = function()
{
    if (iVxContext.Events)
    {
        iVxContext.Events.FireEventByName(iVxContext.EventName.Initialized);
    }
}
iVxContext.RegisterFunctionToNotifyInitialized = function(fn)
{
    if (!iVxContext.Events)
    {
        iVxContext.Events = new iEvent();
    }

    iVxContext.Events.AddEvent(iVxContext.EventName.Initialized, fn);
}
										    
