Infoshare.SharePoint.ViewExtenderService = function Infoshare$SharePoint$ViewExtenderService() { }
iVxService = Infoshare.SharePoint.ViewExtenderService;
iVxService.ScreenBlocker = null;
iVxService.ScreenBlockDisplayInterval = 256;
iVxService.EnableObjectCache = true;

iVxService.Initialized = false;
iVxService.EnsureService = function()
{
    if (iVxService.Initialized)
    {
        return;
    }
    iVxService.Initialized = true;

    // サービス種別を設定
    SPService.Type         = SPService.ServiceType.WebService;
    //SPService.ResponseType = ISWebRequest.AcceptResponseType.XML;
    //SPService.Type         = SPService.ServiceType.REST;
    //SPService.ResponseType = ISWebRequest.AcceptResponseType.JSON;
}

// -----------------------------------------------------------------------
//  ViewExtenderService:User
// -----------------------------------------------------------------------
iVxService.UserServices = null;
iVxService.GetUserService = function(webUrl)
{
    if (!iVxService.UserServices)
    {
        iVxService.EnsureService();
        iVxService.UserServices = new ISDictionary();
    }

    if (!webUrl)
    {
        webUrl = iVxContext.WebUrl;
    }

    var service = null;
    if (!iVxService.UserServices.Contains(webUrl))
    {
        if      (SPService.Type == SPService.ServiceType.WebService) { service = new SPUserGroupService(webUrl); }
        else if (SPService.Type == SPService.ServiceType.REST)       { service = new SRUserService(webUrl); }

        iVxService.UserServices.Add(webUrl, service);
    }
    service = iVxService.UserServices.Get(webUrl);

    return service;
}

iVxService.CurrentUserCache = null;
iVxService.GetCurrentUser = function(callback)
{
    if (iVxService.EnableObjectCache)
    {
        if (iVxService.CurrentUserCache)
        {
            callback(iVxService.CurrentUserCache);
        }
        else
        {
            iVxService.GetCurrentUserInternal(null, function(user)
            {
                iVxService.CurrentUserCache = user;
                callback(user);
            });
        }
    }
    else
    {
        iVxService.GetCurrentUserInternal(null, callback);
    }
}
iVxService.GetCurrentUserInternal = function(webUrl, callback)
{
    var service = iVxService.GetUserService(webUrl);
    service.GetCurrentUserInfo(function(user)
    {
        callback(user);
    });
}


// -----------------------------------------------------------------------
//  ViewExtenderService:Site
// -----------------------------------------------------------------------
iVxService.SiteServices = null;
iVxService.GetSiteService = function(webUrl)
{
    if (!iVxService.SiteServices)
    {
        iVxService.EnsureService();
        iVxService.SiteServices = new ISDictionary();
    }

    if (!webUrl)
    {
        webUrl = iVxContext.WebUrl;
    }

    var service = null;
    if (!iVxService.SiteServices.Contains(webUrl))
    {
        if      (SPService.Type == SPService.ServiceType.WebService) { service = new SPSitesService(webUrl); }
        else if (SPService.Type == SPService.ServiceType.REST)       { service = null; }

        iVxService.SiteServices.Add(webUrl, service);
    }
    service = iVxService.SiteServices.Get(webUrl);

    return service;
}

iVxService.SiteCache = null;
iVxService.GetSite = function(callback)
{
    var webUrl = iVxContext.WebUrl;
    if (iVxService.EnableObjectCache)
    {
        if (!iVxService.SiteCache)
        {
            iVxService.SiteCache = new ISDictionary();
        }

        if (iVxService.SiteCache.Contains(webUrl))
        {
            callback(iVxService.SiteCache.Get(webUrl));
        }
        else
        {
            iVxService.GetSiteInternal(webUrl, function(site)
            {
                // ほぼ同じタイミングで実行された場合を考慮してAddではなくSetを使う
                //（Containsチェックをほぼ同時に通過してしまうケース）
                iVxService.SiteCache.Set(webUrl, site);
                callback(site);
            });
        }
    }
    else
    {
        iVxService.GetSiteInternal(webUrl, callback);
    }
}
iVxService.GetSiteInternal = function(webUrl, callback)
{
    var service = iVxService.GetSiteService(webUrl);
    service.GetSite(webUrl, function(site)
    {
        callback(site);
    });
}


// -----------------------------------------------------------------------
//  ViewExtenderService:List
// -----------------------------------------------------------------------
iVxService.ListAccessors = null;
iVxService.GetListAccessor = function(webUrl)
{
    if (!iVxService.ListAccessors)
    {
        iVxService.EnsureService();
        iVxService.ListAccessors = new ISDictionary();
    }

    if (!webUrl)
    {
        webUrl = iVxContext.WebUrl;
    }

    var availableAccessor = null;
    if (!iVxService.ListAccessors.Contains(webUrl))
    {
        var accessor = new SPListAccessor(webUrl);
        iVxService.ListAccessors.Add(webUrl, [ accessor ]);

        availableAccessor = accessor;
    }
    else
    {
        // 呼び出し中のものしかなければ新しいインスタンスを作成して返す
        var accessors = iVxService.ListAccessors.Get(webUrl);
        for (var i = 0; i < accessors.length; i++)
        {
            var accessor = accessors[i];
            if (accessor.Invoking)
            {
                continue;
            }

            availableAccessor = accessor;
            break;
        }

        // 分割クエリ関連情報をコピーして新規インスタンスを作成
        if (!availableAccessor)
        {
            var accessor = new ListAccessors(webUrl);
            iVxService.ListAccessors.Set(webUrl, accessors.concat([accessor]));

            availableAccessor = accessor;
        }
    }

    return availableAccessor;
}

iVxService.ListCache = null;
iVxService.GetList = function(webUrl, listId, callback)
{
    if (iVxService.EnableObjectCache)
    {
        if (!iVxService.ListCache)
        {
            iVxService.ListCache = new ISDictionary();
        }

        var key = ISGuid.TrimBrace(listId);
        if (iVxService.ListCache.Contains(key))
        {
            callback(iVxService.ListCache.Get(key));
        }
        else
        {
            iVxService.GetListInternal(webUrl, listId, function(list)
            {
                // ほぼ同じタイミングで実行された場合を考慮してAddではなくSetを使う
                //（Containsチェックをほぼ同時に通過してしまうケース）
                iVxService.ListCache.Set(key, list);
                callback(list);
            });
        }
    }
    else
    {
        iVxService.GetListInternal(webUrl, listId, callback);
    }
}
iVxService.GetListInternal = function(webUrl, listId, callback)
{
    var accessor = iVxService.GetListAccessor(webUrl);
    accessor.GetList(listId, function(list)
    {
        callback(list);
    });
}
iVxService.GetListByTitle = function(webUrl, title, callback)
{
    // キャッシュを利用している場合は、キャッシュ経由のアクセスが高速なため、Accessorを利用しない
    iVxService.GetLists(webUrl, function(lists)
    {
        var listFound = null;
        for (var i = 0; i < lists.length; i++)
        {
            var list = lists[i];
            if (ISString.Equals(list.Title, title, true))
            {
                listFound = list;
                break;
            }
        }

        callback(listFound);
    });
}

iVxService.GetListByUrlName = function (webUrl, listName, callback)
{
    // キャッシュを利用している場合は、キャッシュ経由のアクセスが高速なため、Accessorを利用しない
    iVxService.GetLists(webUrl, function(lists)
    {
        // DefaultViewUrlと比較する
        // DefaultViewUrl : "/sites/sitename/Lists/listname/AllItems.aspx"
        var name = '/' + listName + '/';
        var listFound = null;
        for (var i = 0; i < lists.length; i++)
        {
            var list = lists[i];
            if (ISString.Contains(list.Properties.DefaultViewUrl, name, true))
            {
                listFound = list;
                break;
            }
        }

        callback(listFound);
    });
}

iVxService.ListCollectionCache = null;
iVxService.GetLists = function(webUrl, callback)
{
    if (iVxService.EnableObjectCache)
    {
        if (!iVxService.ListCollectionCache)
        {
            iVxService.ListCollectionCache = new ISDictionary();
        }

        var key = ISString.TrimEnd(webUrl, '/');
        if (iVxService.ListCollectionCache.Contains(key))
        {
            callback(iVxService.ListCollectionCache.Get(key));
        }
        else
        {
            iVxService.GetListsInternal(webUrl, function(lists)
            {
                // ほぼ同じタイミングで実行された場合を考慮してAddではなくSetを使う
                //（Containsチェックをほぼ同時に通過してしまうケース）
                iVxService.ListCollectionCache.Set(key, lists);
                callback(lists);
            });
        }
    }
    else
    {
        iVxService.GetListsInternal(webUrl, callback);
    }
}
iVxService.GetListsInternal = function(webUrl, callback)
{
    var accessor = iVxService.GetListAccessor(webUrl);
    accessor.GetLists(function(lists)
    {
        callback(lists);
    });
}

iVxService.AddList = function(webUrl, listData, callback)
{
    var accessor = iVxService.GetListAccessor(webUrl);
    accessor.AddList(listData, function(list)
    {
        if (listData.Fields &&
            listData.Fields.length > 0)
        {
            accessor.AddFields(list, listData.Fields, function ()
            {
                if (listData.UpdateFields &&
                    listData.UpdateFields.length > 0)
                {
                    accessor.UpdateFields(list, listData.UpdateFields, function ()
                    {
                        callback(list);
                    });
                }
                else
                {
                    callback(list);
                }                
            });
        }

        else
        {
            callback(list);
        }        
    });
}
iVxService.UpdateList = function(webUrl, listData, callback)
{
    var accessor = iVxService.GetListAccessor(webUrl);
    accessor.UpdateListProperties(listData, function(list)
    {
        callback(list);  
    });
}
iVxService.DeleteList = function(webUrl, listId, callback)
{
    var accessor = iVxService.GetListAccessor(webUrl);
    accessor.DeleteList(listId, function()
    {
        callback();
    });
}

