//  ViewExtenderService:Item
// -----------------------------------------------------------------------
iVxService.ItemAccessors = null;
iVxService.GetItemAccessor = function(list, webUrl)
{
    if (!iVxService.ItemAccessors)
    {
        iVxService.EnsureService();
        iVxService.ItemAccessors = new ISDictionary();
    }

    if (!webUrl)
    {
        webUrl = iVxContext.WebUrl;
    }

    var availableAccessor = null;
    if (!iVxService.ItemAccessors.Contains(list.Id))
    {
        var accessor = new SPListItemAccessor(list, webUrl);
        iVxService.ItemAccessors.Add(list.Id, [ accessor ]);

        availableAccessor = accessor;
    }
    else
    {
        // 呼び出し中のものしかなければ新しいインスタンスを作成して返す
        var accessors = iVxService.ItemAccessors.Get(list.Id);
        for (var i = 0; i < accessors.length; i++)
        {
            var accessor = accessors[i];
            if (accessor.Invoking)
            {
                continue;
            }

            availableAccessor = accessor;
            break;
        }

        // 分割クエリ関連情報をコピーして新規インスタンスを作成
        if (!availableAccessor)
        {
            var referenceAccessor = accessors[0];
            var accessor = new SPListItemAccessor(list, webUrl);
            accessor.EnableIterativeQueries = referenceAccessor.EnableIterativeQueries;
            accessor.MaxItemIndex           = referenceAccessor.MaxItemIndex;
            iVxService.ItemAccessors.Set(list.Id, accessors.concat([accessor]));

            availableAccessor = accessor;
        }
    }

    return availableAccessor;
}
iVxService.RetrieveItems = function(webUrl, list, query, iterateQuery, callback)
{
    var stopwatch = new ISStopwatch();
    stopwatch.Start();
    ISTrace.TraceVerbose('[BEGIN] iVxService.RetrieveItems');

    // AccessorのInvokingの判断ではタイミングイシューが発生する為、このスコープ内でリクエストの状態を管理する
    var requestInvoking = true;

    // スクリーンブロッカーをShowしたかどうかのフラグ
    var isScreenBlockerShown = false;

    var accessor = iVxService.GetItemAccessor(list, webUrl);
    accessor.EnableIterativeQueries = iterateQuery;
    accessor.GetListItems(query, function(items, metadata)
    {
        requestInvoking = false;
        ISTrace.TraceVerbose('[END] iVxService.RetrieveItems (spent ' + stopwatch.Stop() + 'ms)');
        if (isScreenBlockerShown)
        {
            iScreenBlockerUtility.Hide();
        }

        callback(items, metadata);
    });

    // スクリーンブロッカーの設定
    // 指定秒数以内にリクエストが返ってこない場合は画面をブロックする
    setTimeout(function()
    {
        if (requestInvoking)
        {
            iScreenBlockerUtility.Show();
            isScreenBlockerShown = true;
        }
    }, iVxService.ScreenBlockDisplayInterval);
}

iVxService.ItemCache = null;
iVxService.RetrieveItemById = function(webUrl, list, itemId, viewFields, callback)
{
    if (iVxService.EnableObjectCache)
    {
        if (!iVxService.ItemCache)
        {
            iVxService.ItemCache = new ISDictionary();
        }

        var key = ISString.Format('{0}.{1}', ISGuid.TrimBrace(list.Id), itemId);
        if (iVxService.ItemCache.Contains(key))
        {
            callback(iVxService.ItemCache.Get(key));
        }
        else
        {
            iVxService.RetrieveItemByIdInternal(webUrl, list, itemId, viewFields, function(item)
            {
                // ほぼ同じタイミングで実行された場合を考慮してAddではなくSetを使う
                //（Containsチェックをほぼ同時に通過してしまうケース）
                iVxService.ItemCache.Set(key, item);
                callback(item);
            });
        }
    }
    else
    {
        iVxService.RetrieveItemByIdInternal(webUrl, list, itemId, viewFields, callback);
    }
}
iVxService.RetrieveItemByIdInternal = function(webUrl, list, itemId, viewFields, callback)
{
    // Where句
    var where = SPQueryBuilder.BuildEqualQueryCondition('ID', ISSPFieldType.Counter, itemId);

    // ViewField設定
    var fields = viewFields ? viewFields : list.Fields;
    var fieldRefs = '';
    for(var i = 0; i < fields.GetLength(); i++)
    {
        var field = fields.Get(i);
        fieldRefs += SPQueryBuilder.BuildFieldRef(field.Name);
    }

    // クエリ組み立て
    var query = new ISSPQuery();
    query.Query        = SPQueryBuilder.BuildQuery(null, where);
    query.ViewFields   = SPQueryBuilder.BuildViewFields(fieldRefs);
    query.QueryOptions = SPQueryBuilder.BuildQueryOptions(SPQueryBuilder.BuildMandatoryColumnsOption(false) +
                                                          SPQueryBuilder.BuildViewAttributesOption({ Scope: 'RecursiveAll' }));
    query.RowLimit     = 1;

    // Itemの取得
    iVxService.RetrieveItems(webUrl, list, query, false, function(items)
    {
        var item = (items && items.length > 0) ? items[0] : null;
        callback(item);
    });
}

iVxService.RetrieveItemsByKeys = function (webUrl, list, keys, fieldName, fieldType, viewFields, callback)
{
    // 条件が多すぎると呼び出しが失敗するため、クエリを分割する
    if (keys.length < 1)
    {
        callback([]);
        return;
    }

    // ユニークなIdのみ抜粋
    var idDictionary = new ISDictionary();
    for (var i = 0; i < keys.length; i++)
    {
        var id = keys[i];
        idDictionary.Set(id, id);
    }
    var uniqueIds = idDictionary.GetValues();

    // 単位数ごとにまとめる
    var maxCount = 100;
    var idUnitArray = [];
    var currentIdUnit = [];
    idUnitArray.push(currentIdUnit);
    for (var i = 0; i < uniqueIds.length; i++)
    {
        var currentId = uniqueIds[i];        
        if (currentIdUnit.length <= maxCount)
        {
            currentIdUnit.push(currentId);
        }
        // 100を超えた場合
        else
        {            
            currentIdUnit = [];
            idUnitArray.push(currentIdUnit);
            currentIdUnit.push(currentId);
        }
    }

    // 並列呼び出し
    var invocationCount = 0;
    var wholeItems = new Array();
    for (var i = 0; i < idUnitArray.length; i++)
    {
        var idUnit = idUnitArray[i];
        iVxService.RetrieveItemsByKeysInternal(webUrl, list, idUnit, fieldName, fieldType, viewFields, function(items)
        {
            wholeItems = wholeItems.concat(items);

            invocationCount++;
            if (idUnitArray.length <= invocationCount)
            {
                callback(wholeItems);
            }
        });
    }
}

iVxService.RetrieveItemsByKeysInternal = function (webUrl, list, keys, fieldName, fieldType, viewFields, callback)
{
    var query = new ISSPQuery();               
    var queryTemplete = "<Query>"
                      +   "<Where>"
                      +     "%WhareValue%"
                      +   "</Where>"
                      + "</Query>";
    var whreQuery = "";
  
    for (var i = 0; i < keys.length; i++)
    {
        var key = keys[i];
        var condition = SPQueryBuilder.BuildEqualQueryCondition(fieldName, fieldType, key);
        if (whreQuery.length <= 0) { whreQuery = condition; }
        else                       { whreQuery = SPQueryBuilder.BuildOrQueryCondition(whreQuery + condition); }
    }
    query.Query = queryTemplete.replace("%WhareValue%", whreQuery);

    // ViewField設定
    query.ViewFields = iVxService.BuildViewFields(viewFields, list);

    ISTrace.TraceVerbose('[BEGIN] RetrieveItemsByKeysInternal');
    iVxService.RetrieveItems(webUrl, list, query, false, function(items)
    {
        ISTrace.TraceVerbose('[END] RetrieveItemsByKeysInternal');
        callback(items);
    });
}

iVxService.UpdateItems = function(webUrl, list, items, callback)
{
    var stopwatch = new ISStopwatch();
    stopwatch.Start();
    ISTrace.TraceVerbose('[BEGIN] iVxService.UpdateItems');

    var accessor = iVxService.GetItemAccessor(list, webUrl);
    accessor.UpdateListItems(items, function(results)
    {
        ISTrace.TraceVerbose('[END] iVxService.UpdateItems (spent ' + stopwatch.Stop() + 'ms)');
        callback(items, results);

        if (iVxService.ScreenBlocker)
        {
            iVxService.ScreenBlocker.Hide();
        }
    });

    // スクリーンブロッカーの設定
    // 指定秒数以内にリクエストが返ってこない場合は画面をブロックする
    setTimeout(function()
    {
        if (!accessor.Invoking)
        {
            return;
        }

        if (!iVxService.ScreenBlocker)
        {
            iVxService.ScreenBlocker = new iScreenBlocker(new iUltimateScreenBlockerStyle());
            iVxService.ScreenBlocker.Image =  ISString.TrimEnd(iVxContext.MasterSourcesPath, '/') + '/Infoshare/loading.gif';
            iVxService.ScreenBlocker.Render();
        }
        else
        {
            iVxService.ScreenBlocker.Show();
        }
    }, iVxService.ScreenBlockDisplayInterval);
}

iVxService.RetrieveItemsParallel = function(webUrl, list, queries, iterateQuery, callback)
{
    // クエリを並列で投げて、結果をクライアントソートする
    var queryCount = queries.length;
    var pararelQueryContext = {
        CompleteQueryCount: 0,
        Entitites: [],
        Completed: function()
        {
            return this.CompleteQueryCount == queryCount;
        }
    };

    var fields = list.Fields;
    for (var i = 0; i < queryCount; i++)
    {
        var query = queries[i];
        iVxService.RetrieveItems(webUrl, list, query, true, function(entities)
        {
            pararelQueryContext.CompleteQueryCount++;
            pararelQueryContext.Entitites = pararelQueryContext.Entitites.concat(entities);
            if (pararelQueryContext.Completed())
            {
                // prepare sort fields
                var sortFields = SPListItemRetriever.GetSortFields(query.Query, fields);

                // sort
                items = SPListItemRetriever.Sort(pararelQueryContext.Entitites, sortFields);

                callback(items);
            }       
        });
    }
}

iVxService.BuildViewFields = function(viewFields, list)
{
    var fields = viewFields;
    if (!fields && list && list.Fields)
    {
        fields = list.Fields;
    }

    var fieldRefs = '';
    if (fields)
    {
        if (fields.TypeName == ISDictionary.TypeName)
        {
            for(var i = 0; i < fields.GetLength(); i++)
            {
                var field = fields.Get(i);
                var name = field.Name ? field.Name : field;
                fieldRefs += SPQueryBuilder.BuildFieldRef(name);
            }
        }
        else if (ISObject.TypeOf(fields) == 'array')
        {
            for(var i = 0; i < fields.length; i++)
            {
                var field = fields[i];
                var name = field.Name ? field.Name : field;
                fieldRefs += SPQueryBuilder.BuildFieldRef(name);
            }
        }
    }

    var viewFields = SPQueryBuilder.BuildViewFields(fieldRefs);
    return viewFields;
}


