iVxService.SPVersionCache = null;
iVxService.GetSPVersion = function (callback)
{
    if (iVxService.EnableObjectCache)
    {
        if (iVxService.SPVersionCache)
        {
            callback(iVxService.SPVersionCache);
        }
        else
        {
            iVxService.GetSPVersionInternal(function (majorversion) {
                iVxService.SPVersionCache = majorversion;
                callback(majorversion);
            });
        }
    }
    else
    {
        iVxService.GetSPVersionInternal(callback);
    }
}
iVxService.GetSPVersionInternal = function (callback)
{
    var majorVersion = '';
    var request = new ISWebRequest();
    request.Asynchronous = true;
    request.Method = 'GET';
    request.Url = document.location.protocol + '//' + document.location.host + '/_vti_pvt/service.cnf';
    request.CallbackHandler = function () {
        if (request.GetStatusCode() == 200)
        {
            var response = request.GetResponseText();
            var version = response.split('|')[2];
            majorVersion = version.substring(0, 2);
            callback(majorVersion)
        }
        else
        {
            callback(majorVersion)
        }
    };
    request.Invoke();
}


