Infoshare.SharePoint.BehaviorExtender = function Infoshare$SharePoint$BehaviorExtender() { }
iBehaviorExtender = Infoshare.SharePoint.BehaviorExtender;
iBehaviorExtender.TypeName = 'Infoshare.SharePoint.BehaviorExtender';
iBehaviorExtender.ClassInfo = null;

iBehaviorExtender.ExtenderType = { Function: 'Function',
                                   Page:     'Page',
                                   Control:  'Control',
                                   Dialog:   'Dialog' ,
                                   WebPart:  'WebPart'};

iBehaviorExtender.AddExtender = function(parent, type, className)
{
    // initialize 
    if (!parent.Extenders)
    {
        parent.Extenders = new ISDictionary();
    }

    // append
    if (parent.Extenders.Contains(type))
    {
        var extenders = parent.Extenders.Get(type);

        var message = 'Extender {0} is alredy defined';
        message = ISString.Format(message, className);

        // 重複したものは追加しない
        if (extenders instanceof Array &&
            ISArray.Contains(extenders, className))
        {
            ISTrace.TraceWarning(message);
            return;
        }
        if (typeof extenders == "string" &&
            ISString.Equals(extenders, className))
        {
            ISTrace.TraceWarning(message);
            return;
        }

        if (extenders instanceof Array)
        {
            parent.Extenders.Set(type, extenders.concat([ className ]));
        }
        else
        {
            parent.Extenders.Set(type, [extenders, className]);
        }
    }
    else
    {
        parent.Extenders.Add(type, className);
    }
}

iBehaviorExtender.Extenders = null;
iBehaviorExtender.Initialize = function()
{
    // 必要に応じて各継承クラスで実装
}

iBehaviorExtender.CanExtend = function()
{
    // 必要に応じて各継承クラスで実装
    return true;
}

iBehaviorExtender.prototype = {
    TypeName: iBehaviorExtender.TypeName,
    ExtenderType: null,

    Extenders: null,

    Extend: function()
    {
        if (!this.CanExtend())
        {
            return;
        }

        if (typeof this.PreExtend      == 'function') { this.PreExtend(); }
        if (typeof this.ExtendCore     == 'function') { this.ExtendCore(); }
        if (typeof this.ExtendChildren == 'function') { this.ExtendChildren(); }
        if (typeof this.PostExtend     == 'function') { this.PostExtend(); }
    },

    PreExtend: function()
    {
    },

    ExtendCore: function()
    {
    },

    ExtendChildren: function()
    {
        this.Extenders = eval(this.TypeName + '.Extenders;');
        if (!this.Extenders ||
            this.Extenders.GetLength() <= 0)
        {
            return;
        }

        for (var i = 0; i < this.Extenders.GetLength(); i++)
        {
            var className = this.Extenders.Get(i);
            var extender = iClass.New(className);
            if (extender.CanExtend())
            {
                extender.Extend();

                if (!extender.AllowAdditionalExtension())
                {
                    break;
                }
            }
        }
    },

    PostExtend: function()
    {
    },

    CanExtend: function()
    {
        return eval(this.TypeName + '.CanExtend();');
    },

    AllowAdditionalExtension: function()
    {
        return true;
    }
}


// -----------------------------------------------------------------------
//  ExtenderClass : Infoshare.Class
// -----------------------------------------------------------------------
Infoshare.ExtenderClass = function Infoshare$ExtenderClass(name, source)
{
    Infoshare.Class.apply(this, arguments);
}

iExtenderClass = Infoshare.ExtenderClass;
iExtenderClass.CreateFromXml = function(xml)
{
    // expected follwing formats
    // <Class      Name='Infoshare.Class' Source='infoshare.js' EnableDownLevelRendering='false' />
    // <Class ClassName='Infoshare.Class' Source='infoshare.js' EnableDownLevelRendering='false' />
    // <Class ClassName='Infoshare.Class' Source='infoshare.js' ViewExperience='Modern' />

    // create class info
    var cls = iClass.CreateFromXml(xml);
    
    // ViewExperience
    var viewExperience = iXml.GetAttributeValue(xml, 'ViewExperience');
    if (viewExperience)
    {
        if (iString.Eqals(viewExperience, iVxContext.ViewExperienceType.Modern, true))
        {
            cls.ViewExperience = iVxContext.ViewExperienceType.Modern;
        }
        else
        {
            cls.ViewExperience = iVxContext.ViewExperienceType.Classic;
        }
    }  

    // EnableDownLevelRendering
    var enableDownLevelRender = iXml.GetAttributeValue(xml, 'EnableDownLevelRendering');
    if (enableDownLevelRender)
    {
        cls.EnableDownLevelRendering = ISBoolean.TryParse(enableDownLevelRender, false);
    }    

    return cls;
}

iExtenderClass.prototype = new Infoshare.Class();
iExtenderClass.prototype.ViewExperience = iVxContext.ViewExperienceType.Classic;
iExtenderClass.prototype.EnableDownLevelRendering = false;
										    
