Infoshare.SharePoint.ListFormExtender = function Infoshare$SharePoint$ListFormExtender(){}
iSPListFormExtender = Infoshare.SharePoint.ListFormExtender;
iSPListFormExtender.TypeName = 'Infoshare.SharePoint.ListFormExtender';
iSPListFormExtender.ExtenderType = iBehaviorExtender.ExtenderType.Page;
iSPListFormExtender.ClassInfo = null;

iSPListFormExtender.Extenders = new ISDictionary();
iSPListFormExtender.Initialize = function()
{
    if (!iSPListFormExtender.Extenders)
    {
        iSPListFormExtender.Extenders = new ISDictionary();
    }

    iBehaviorExtender.AddExtender(Infoshare.SharePoint.PageExtender, 'Infoshare.SharePoint.ListFormExtender', 'Infoshare.SharePoint.ListFormExtender');
}
iSPListFormExtender.CanExtend = function()
{
    var isTargetForm = iSPListFormExtender.IsListForm() ||
                       iSPListFormExtender.IsMediaLibraryForm() ||
                       iSPListFormExtender.IsAdditionalExtendForm();

    if (iVxContext.GetViewExperience() == iVxContext.ViewExperienceType.Modern)
    {
        isTargetForm = isTargetForm ||
                       iSPListFormExtender.IsListView();
    }

    return isTargetForm;
}

iSPListFormExtender.FormFileName = {
    // リストビュー定義
    ListView: {
        AllItems    : 'AllItems.aspx'
    },
    // リストフォーム定義
    ListForm: {
        NewForm     : 'NewForm.aspx',
        EditForm    : 'EditForm.aspx',
        DisplayForm : 'DispForm.aspx'
    },
    // メディアライブラリフォーム定義
    MediaLibraryForm: {
        NewForm     : 'Upload.aspx',
        EditForm    : 'EditVideoSet.aspx',
        DisplayForm : 'DispForm.aspx'
    }
}

iSPListFormExtender.IsTargetForm = function(fileName)
{
    var isTargetForm= false;
    if (ISString.EndsWith(document.location.pathname, fileName, true) || // URLがファイル名前（*.aspx）で終わっている
        ISHash.EndsWith(fileName))                                　　　 // #末尾にファイル名前（*.aspx）を含む（ダウンロード最小化戦略の表記）
    {
        isTargetForm = true;
    }
    return isTargetForm;
}
iSPListFormExtender.IsListView = function()
{
    return iSPListFormExtender.IsTargetForm(iSPListFormExtender.FormFileName.ListView.AllItems);
}
iSPListFormExtender.IsListForm = function()
{
    return iSPListFormExtender.IsTargetForm(iSPListFormExtender.FormFileName.ListForm.NewForm) ||
           iSPListFormExtender.IsTargetForm(iSPListFormExtender.FormFileName.ListForm.EditForm) ||
           iSPListFormExtender.IsTargetForm(iSPListFormExtender.FormFileName.ListForm.DisplayForm);
}
iSPListFormExtender.IsMediaLibraryForm = function()
{
    return iSPListFormExtender.IsTargetForm(iSPListFormExtender.FormFileName.MediaLibraryForm.NewForm) ||
           iSPListFormExtender.IsTargetForm(iSPListFormExtender.FormFileName.MediaLibraryForm.EditForm) ||
           iSPListFormExtender.IsTargetForm(iSPListFormExtender.FormFileName.MediaLibraryForm.DisplayForm);
}
iSPListFormExtender.IsAdditionalExtendForm = function()
{
    // カスタムフォーム設定の取得
    var isCustomSettingForm = false;
    if (iSettings.iSPListFormExtender &&
        iSettings.iSPListFormExtender.AdditionalExtendForms)
    {
        for(var i = 0; i < iSettings.iSPListFormExtender.AdditionalExtendForms.length; i++)
        {
            var formName = iSettings.iSPListFormExtender.AdditionalExtendForms[i];
            var currentFormIsCustomSettingForm = iSPListFormExtender.IsTargetForm(formName);

            if (currentFormIsCustomSettingForm)
            {
                isCustomSettingForm = true;
                break;
            }
        }
    }

    return isCustomSettingForm;
}

iSPListFormExtender.prototype = {
    TypeName: iSPListFormExtender.TypeName,
    ExtenderType: iSPListFormExtender.ExtenderType,

    EnableListRetrieving: true,
    List: null,

    FormFieldInfos: null,
    Extenders: null,

    FormBodyClassName: 'ms-formbody',

    Extend: function()
    {
        if (!this.CanExtend())
        {
            return;
        }

        this.Extenders = iSPListFormExtender.Extenders;
        if (!this.Extenders ||
            this.Extenders.GetLength() <= 0)
        {
            return;
        }

        if (this.EnableListRetrieving)
        {
            var extender = this;
            this.EnsureList(function()
            {
                extender.ExtendInternal();
            });
        }
        else
        {
            this.ExtendInternal();
        }
    },

    ExtendInternal: function()
    {
        var infos = this.GetFormFieldInfos();
        for (var i = 0; i < infos.GetLength(); i++)
        {
            var info = infos.Get(i);
            var extenderClassNames = this.Extenders.Get(info.Type);
            if (typeof(extenderClassNames) == 'string')
            {
                extenderClassNames = [extenderClassNames];
            }
            if (!(extenderClassNames instanceof Array))
            {
                continue;
            }

            for (var j = 0; j < extenderClassNames.length; j++)
            {
                var extenderClassName = extenderClassNames[j];
                if (extenderClassName)
                {
                    var extender = eval('new ' + extenderClassName + '();');
                    extender.ParentExtender = this;
                    extender.FormFieldInfo = info;
            
                    if (this.List &&
                        this.List.Fields.Contains(info.InternalName))
                    {
                        var field = this.List.Fields.Get(info.InternalName);
                        // モダンUIの場合
                        // ユーザーまたはグループの列でユーザーのみを選択すると0が返ってくるので、PeopleOnlyに変更する
                        // ユーザーまたはグループの列でユーザーとグループを選択すると1が返ってくるので、PeopleAndGroupsに変更する
                        if (field.Properties.UserSelectionMode == "0")
                        {
                            field.Properties.UserSelectionMode = 'PeopleOnly';
                        }
                        else if (field.Properties.UserSelectionMode == "1")
                        {
                            field.Properties.UserSelectionMode = 'PeopleAndGroups';
                        }
                        extender.FieldInfo = field;
                    }
                
                    if (extender.CanExtend())
                    {
                        extender.Extend();

                        if (!extender.AllowAdditionalExtension())
                        {
                            break;
                        }
                    }
                }
            }
        }
    },

    CanExtend: function()
    {
        return iSPListFormExtender.CanExtend();
    },

    AllowAdditionalExtension: function()
    {
        return true;
    },
    
    GetFormFieldInfos: function()
    {
        if (!this.FormFieldInfos)
        {
            if (iVxContext.GetViewExperience() == iVxContext.ViewExperienceType.Modern)
            {
                this.FormFieldInfos = this.GetModernFormFieldInfos();
            }
            else
            {
                this.FormFieldInfos = this.GetClassicFormFieldInfos();
            }
        }       

        return this.FormFieldInfos;
    },

    GetClassicFormFieldInfos: function()
    {
        var formFieldInfos = new ISDictionary();

        var formBodyCells = new Array();
        var cells = document.getElementsByTagName('td');
        for (var i = 0; i < cells.length; i++)
        {
            // form body セルを特定
            var cell = cells[i];
            if (cell.className.toLowerCase() != this.FormBodyClassName.toLowerCase())
            {
                continue;
            }

            // コメント要素を特定
            var comment = null;
            var children = ISDomAccessor.GetChildElements(cell);
            for (var j = 0; j < children.length; j++)
            {
                var child = children[j];
                if (child.nodeType == ISDomAccessor.NodeType.Comment)
                {
                    comment = child;
                    break;
                }
            }
            
            // ダウンレベルレンダリングを行うか否かのフラグ
            var enableDownLevelRender = iSPListFormExtender.ClassInfo.EnableDownLevelRendering;

            if (comment)
            {
                // コメントからフィールド情報を取得
                var doc = iXml.LoadXml('<FieldInfo ' + comment.nodeValue + '/>');
                var info = new iSPFormFieldInfo(iXml.GetAttributeValue(doc.documentElement, 'FieldInternalName'),
                                                iXml.GetAttributeValue(doc.documentElement, 'FieldName'),
                                                iXml.GetAttributeValue(doc.documentElement, 'FieldType'));
                info.RowElement   = ISDomAccessor.GetParentElement(cell);
                info.BodyElement  = cell;
            }
            // コメント要素が存在しない場合にはDOM構造などから列の型を確認する（SPDから編集されたフォーム対応）
            else if (enableDownLevelRender)
            {
                var guid = ISGuid.New();
                var info = new iSPFormFieldInfo(guid, guid, "");
                info.RowElement   = ISDomAccessor.GetParentElement(cell);
                info.BodyElement  = cell;
                var cell = info.BodyElement;

                // コメント要素が存在しないため、単数ユーザー型か複数ユーザー型の判断ができない為
                // ユーザーコントロールが存在する場合にはUserMultiと判断させる（ダウンレベルモード）
                var userEditor = i$(cell).find(".ms-usereditor" + "[id$='_UserField']");
                if (userEditor.length > 0)
                {
                    info.Type = "UserMulti";
                }
            }
            else
            {
                // ToDo: ユーザー列以外のコントロールの場合はコメントが無い場合（列情報にアクセスできない場合）にも
                //       DOM構造から必要な情報が取得できる可能性があるので、その場合にはこのブロックでFieldInfoを作成する
                continue;
            }
            
            formFieldInfos.Add(info.InternalName, info);
        }

        return formFieldInfos;
    },
  
    GetModernFormFieldInfos: function()
    {
        var formFieldInfos = new ISDictionary();

        // サイドローディング
        var overlays = document.getElementsByClassName("od-OverlayHost-overlay");

        var element = overlays.length > 0 ? overlays[overlays.length - 1] : document;
        var fieldDivs = element.getElementsByClassName("ReactFieldEditor");
        for (var i = 0; i < fieldDivs.length; i++)
        {
            // 参照（ReactFieldEditor-core--display）の場合
            if (fieldDivs[i].getElementsByClassName("ReactFieldEditor-core--edit").length == 0)
            {
                continue;
            }
            var rootField = fieldDivs[i].getElementsByClassName("ReactFieldEditor-core--edit")[0];
            var coreField = rootField.firstChild;

            // React要素からフィールド情報のマッピングを取得する
            var fieldInfo = iModernUserFieldEditor.GetReactElement(rootField.parentElement, iModernUserFieldEditor.ReactElementType.Fiber)['return'].stateNode.props.field.schema;

            // ダウンレベルモード
            var guid = ISGuid.New();
            var info = new iSPFormFieldInfo(guid, guid, "");
            
            if (fieldInfo)
            {
                info = new iSPFormFieldInfo(fieldInfo.InternalName, fieldInfo.Name, fieldInfo.FieldType);
            }

            info.RowElement   = rootField;
            info.BodyElement = coreField;
            formFieldInfos.Add(info.InternalName, info);
        }

        return formFieldInfos;
    },    

    EnsureList: function(callback)
    {
        if (this.List)
        {
            callback();
            return;
        }

        var extender = this;
        iVxService.GetList(iVxContext.GetWebUrl(), iVxContext.GetListId(), function (list)
        {
            extender.List = list;
            callback();
        });
    }
}


