Infoshare.SharePoint.UserFieldEntity = function Infoshare$SharePoint$UserFieldEntity(displayName, principalName, type)
{
    this.Properties = new Array();

    this.Properties['EntityDisplayName'] = displayName;
    this.Properties['SpPrincipalName']   = ISString.IsNullOrEmpty(principalName) ? displayName : principalName;
    // 暫定的に両方のプロパティを保持させる
    this.Properties['SpResolveKey']      = ISString.IsNullOrEmpty(principalName) ? displayName : principalName;
    this.Properties['Type']              = type;
}
iUserFieldEntity = Infoshare.SharePoint.UserFieldEntity;
iUserFieldEntity.prototype = {
    Properties: null
}


// -----------------------------------------------------------------------
//  UserFieldExtender
//  Note: teruhirok(20161118)
//  現在ダウンロード最小化戦略絡みの以下の問題点があります。
//  EnsureEditorが同期関数の為、実際にEditorにアクセスするタイミングにてEditorが取得されていない場合に
//  処理（選択種別の取得、値の追加等）に失敗します。
//  これはSPClientPeoplePickerのオブジェクトが更新される前にEnsureEditorが呼ばれるケースで発生します。
//
//  また同期用のEnsureEditor実装にて以下の不具合が発生しました
//  保存時にコントロール上に表示されているエンティティが正しく保存されない
//  URL:http://sp/ProjectX/Infoshare/GroupPicker/Lists/Bugs/DispForm.aspx?ID=316&ContentTypeId=0x0100DA068A1C7FAFC7499788299CF3FB7174
//  これはExtenderが様々なタイミングでEnsureEditorを実行している為
//  SPClientPeoplePicker側の初期化や更新処理がSharePoint側で実行された場合に
//  不整合を生むケースが存在するということです
//  今回の暫定対応では、EnsureEditorに値を更新させるフラグを持たせましたが、正しい対応を早急に実装する必要があります。
//
//  ToDo: 
//  iUserFieldExtenderはベースクラスとして非同期用のEnsureEditor実装を追加する
//  このような実装はTICO.InfoCall.js内で実装されています
//
//  ToDo:
//  以下のような子クラスを作り実装を分離する
//  iUserFieldExtender_ForPicker      ：ピッカーボタンを追加する為のクラス
//  iUserFieldExtender_ForDefoultValue：デフォルト値をセットする為のクラス（非同期用のEnsureEditorを利用する）
//  iUserFieldExtender_ForControl     ：コントロールの状態を変更（無効化など）する為のクラス（非同期用のEnsureEditorを利用する）
// 
//  ToDo: 
//  同期用のEnsureEditorについても正しくSPClientPeoplePickerのオブジェクトの更新を検出する仕組みを実装
// -----------------------------------------------------------------------
Infoshare.SharePoint.UserFieldExtender = function Infoshare$SharePoint$UserFieldExtender(){}
iUserFieldExtender = Infoshare.SharePoint.UserFieldExtender;
iUserFieldExtender.TypeName = 'Infoshare.SharePoint.UserFieldExtender';
iUserFieldExtender.ExtenderType = iBehaviorExtender.ExtenderType.Control;
iUserFieldExtender.ClassInfo = null;

iUserFieldExtender.Initialize = function()
{
    iBehaviorExtender.AddExtender(Infoshare.SharePoint.ListFormExtender, ISSPFieldType.User, 'Infoshare.SharePoint.UserFieldExtender');
    iBehaviorExtender.AddExtender(Infoshare.SharePoint.ListFormExtender, 'UserMulti',        'Infoshare.SharePoint.UserFieldExtender');
}
iUserFieldExtender.CanExtend = function()
{
    return iUserFieldExtender.HasFieldControl();
}

iUserFieldExtender.HasFieldControl = function(target)
{
    return iUserFieldExtender.FindFieldControls(target).length > 0;
}
iUserFieldExtender.FindFieldControls = function(target)
{
    var element = target ? ISDomAccessor.GetElement(target) : document;
    var inputs = element.getElementsByTagName('input');

    var controls = new Array();
    for (var i = 0; i < inputs.length; i++)
    {
        var input = inputs[i];
        if (ISString.EndsWith(input.id, '$ClientPeoplePicker_EditorInput', true))
        {
            controls.push(input);
        }
    }

    return controls;
}
iUserFieldExtender.GetPrincipalNameForResolve = function(principalName)
{
    var principalNameForResolve = principalName;

    // オンプレミスの場合には整形する
    if (!iVxContext.IsOnline())
    {
        var splitedPrincipalValue = principalName.split('|');

        // Windows認証の場合 User  : i:0#.w|NetBiosName\alias
        //                   Group : c:0+.w|SID
        // c:0+.w|SIDの形式ではResolveできない為修正する
        // i:0#.w|NetBiosName\aliasの場合aliasが前方一致するエンティティが区別できない為修正する
        if (splitedPrincipalValue.length == 2 &&
            ISString.StartsWith(principalName, "c:0+.w|", true) ||
            ISString.StartsWith(principalName, "i:0#.w|", true) )
        {
            principalNameForResolve = splitedPrincipalValue[1];
        }

        // Form認証の場合 User  : i:0#.f|membershipProviderName|alias
        //                Group : c:0-.f|roleProviderName|alias
        // membershipProviderName:alias, roleProviderName:aliasの形式でしかResolveできない為修正する
        else if (splitedPrincipalValue.length == 3 &&
                 ISString.StartsWith(principalName, "i:0#.f|", true) ||
                 ISString.StartsWith(principalName, "c:0-.f|", true))
        {
            principalNameForResolve = splitedPrincipalValue[1] + ':' + splitedPrincipalValue[2];
        }
    }

    return principalNameForResolve;
}

iUserFieldExtender.prototype = {
    TypeName: iUserFieldExtender.TypeName,
    ExtenderType: iUserFieldExtender.ExtenderType,

    ParentExtender: null,
    FieldInfo: null,
    FormFieldInfo: null,

    Editor: null,
    EditorElement: null,

    EntitySelection: null,

    GetValue: function()
    {
        this.EnsureEditor();

        var values = new Array();

        // Entitiesをすべて取得してからPrincipalNameを返す
        var entities = this.GetEntities();
        for (var i = 0; i < entities.length; i++)
        {
            values.push(entities[i].Properties.SpPrincipalName);
        }

        return values;
    },

    GetEntities: function()
    {
        this.EnsureEditor();

        var entities = new Array();

        // 名前解決済み項目を処理
        var resolvedEntities = this.GetResolvedEntities();
        entities = entities.concat(resolvedEntities);

        // TextValueの処理
        var textValues = this.GetTextValues();
        for (var i = 0; i < textValues.length; i++)
        {
            // ToDo:　Undefinedの種別の追加
            // 暫定対応：UndefinedはGroupアイコンとして表示する
            var entity = new iUserFieldEntity(textValues[i], textValues[i], "Group");
            entities.push(entity);
        }

        return entities;
    },

    GetResolvedEntities: function()
    {
        this.EnsureEditor();

        var entities = new Array();

        // Entityを生成する
        var resolvedEntities = this.Editor.GetControlValueAsJSObject();
        for (var i = 0; i < resolvedEntities.length; i++)
        {
            var resolvedEntity = resolvedEntities[i];

            // TextValueはResolvedプロパティがundefined
            if ( typeof(resolvedEntity.Resolved) == 'undefined')
            {
                continue
            }
            var entityType = ISString.Equals(resolvedEntity.EntityType, "User", false) ? "User" : "Group";
            // 編集フォーム対応（編集フォームに初期ResolveされているEntityはEntityTypeプロパティがnull）
            if (ISString.IsNullOrEmpty(resolvedEntity.EntityType) &&
                ISString.StartsWith(resolvedEntity.Key, "i:0#.", true))
            {
                entityType = "User";
            }

            var entity = new iUserFieldEntity(resolvedEntity.DisplayText, 
                                              resolvedEntity.Key,
                                              ISString.Equals(entityType, "User", false) ? "User" : "Group");

            entities.push(entity);
        }
        return entities;
    },    

    GetTextValues : function()
    {
        var textValues = new Array();
        var text = this.EditorElement.value;
        if (!ISString.IsNullOrEmpty(text))
        {
            textValues.push(text);
        }

        return textValues;
    },
    
    SetValues: function(values)
    {
        this.EnsureEditor();

        if (this.Editor)
        {
            // 既存のエンティティを削除する
            var totalCount = this.Editor.TotalUserCount;
            for (var i = 0; i < totalCount; i++)
            {
                this.Editor.DeleteProcessedUser(null);
            }
            // 削除後にTotalUserCountを初期化
            this.Editor.TotalUserCount = 0;
            
            // TextValueをクリアする
            this.EditorElement.value = '';

            // PrincipalNameの整形
            for (var i = 0; i < values.length; i++)
            {
                var principalName = values[i];
                var principalNameForResolve = iUserFieldExtender.GetPrincipalNameForResolve(principalName);
                values[i] = principalNameForResolve;
            }

            // 追加するエンティティを文字列として連結して設定する
            var entities = values.join(';');

            this.Editor.AddUserKeys(entities, false);
        }
        else
        {
            this.EditorElement.value = values;
        }
    },
    
    SetEntities: function(entities)
    {
        this.EnsureEditor();
        if (!this.Editor)
        {
            return;
        }

        // 単数選択列は既存のエンティティを削除する
        if (!this.EntitySelection.AllowMultipleSelection)
        {
            this.ClearEntities();
        }
        // 複数選択列は既存のエンティティを取得して、ユニークな値のみ追加対象とする
        else
        {
            entities = this.GetUniqueEntities(entities);
        }
        
        // PrincipalNameを整形した後テキストとして結合する
        var values = '';
        for (var i = 0; i < entities.length; i++)
        {
            var principalName = entities[i].Properties["SpResolveKey"];
            var principalNameForResolve = iUserFieldExtender.GetPrincipalNameForResolve(principalName);
            // 追加するエンティティを文字列として連結して設定する
            values += principalNameForResolve + ';';
        }
        
        this.Editor.AddUserKeys(values, false);
    },

    ClearEntities: function()
    {
        // 既存のエンティティを削除する
        var totalCount = this.Editor.TotalUserCount;
        for (var i = 0; i < totalCount; i++)
        {
            this.Editor.DeleteProcessedUser(null);
        }
        // 削除後にTotalUserCountを初期化
        this.Editor.TotalUserCount = 0;
        
        // TextValueをクリアする
        this.EditorElement.value = '';
    },

    GetUniqueEntities: function(entities)
    {
        // 現在設定されている名前解決済のエンティティを取得する
        var resolvedEntites = this.GetResolvedEntities();
        // 名前解決に利用されているキーを決定し、重複チェック時に利用する
        var resolvedKeys = [];
        for (var i = 0; i < resolvedEntites.length; i++)
        {
            var resolvedEntity = resolvedEntites[i];
            var resolveKey = resolvedEntity.Properties["SpPrincipalName"];

            if (ISArray.Contains(resolvedKeys, resolveKey, true))
            {
                continue;
            }

            resolvedKeys.push(resolveKey);
        }

        // 重複したエンティティは除去する
　      var uniqueArray = [];
        for (var i = 0; i < entities.length; i++)
        {
            var principalName = entities[i].Properties["SpPrincipalName"];
            var resolveKey = entities[i].Properties["SpResolveKey"];
            if (ISArray.Contains(resolvedKeys, principalName, true) ||
                ISArray.Contains(resolvedKeys, resolveKey, true))
            {
                continue;
            }

            uniqueArray.push(entities[i]);
        }

        return uniqueArray;
    },

    CanExtend: function()
    {
        this.EnsureEditor();

        return this.EditorElement != null;
    },

    Extend: function()
    {
    },

    AllowAdditionalExtension: function()
    {
        return true;
    },

    GetEntitySelection: function()
    {
        if (!this.EntitySelection)
        {
            this.EnsureEditor();

            var selection = new iUserFieldEntitySelection();
            selection.AllowUserSelection            = ISString.Contains(this.Editor.PrincipalAccountType, 'User',     true);
            selection.AllowSecurityGroupSelection   = ISString.Contains(this.Editor.PrincipalAccountType, 'SecGroup', true);
            selection.AllowSharePointGroupSelection = ISString.Contains(this.Editor.PrincipalAccountType, 'SPGroup',  true);
            selection.AllowMultipleSelection        = this.Editor.AllowMultipleUsers;

            this.EntitySelection = selection;
        }

        return this.EntitySelection;
    },

    EnsureEditor: function(updateEditorFlag)
    {
        if (updateEditorFlag)
        {
            this.Editor = null;
            this.EditorElement = null;
        }

        // (IE8issue)初回呼び出し時（CanExtendの呼び出しタイミング）でEditorが特定できない
        // 二回目の呼び出し時（GetEntitySelectionの呼び出しタイミング）ではEditorが特定できる
        if (this.Editor &&
            this.EditorElement)
        {
            return;
        }

        this.EditorElement = iUserFieldExtender.FindFieldControls(this.FormFieldInfo.BodyElement)[0];
        if (this.EditorElement)
        {
            // フォーカスが当たるとクラス名が "sp-peoplepicker-topLevel sp-peoplepicker-topLevelFocus"となるのでcontainsを使用する
            // SPClientPeoplePicker.PickerObjectFromSubElement内のSPClientPeoplePicker.GetTopLevelControlはタイミングによって取得できない為、
            // SPClientPeoplePicker.SPClientPeoplePickerDict[topLevelId] から取得する
            var toplevelElm = ISDomAccessor.FindAncestorByContainsClassNames(this.EditorElement, 'sp-peoplepicker-topLevel');

            if (typeof SPClientPeoplePicker == 'function')
            {
                this.Editor = SPClientPeoplePicker.SPClientPeoplePickerDict[toplevelElm.id];
            }
            
            if (!this.Editor)
            {
                ISTrace.TraceVerbose('Failed EnsureEditor');
            }
        }        
    },

    EnsureEditorAsync: function(updateEditorFlag, callback)
    {
        if (typeof SPClientPeoplePicker == 'function')
        {
            this.EnsureEditor(updateEditorFlag);
            callback();
        }
        else
        {
            // SPClientPeoplePickerが読み込まれるまでポーリング
            var timeOut = 5000;
            var timer = 0;
            var interval = 256;

            var extender = this;
            var polingFunction = function ()
            {
                if (timeOut < timer)
                {
                    ISTrace.TraceVerbose('[CANCELED] iUserFieldExtender.prototype.EnsureEditorAsync: Extend is timeout.');
                    return;
                }

                if (typeof SPClientPeoplePicker == 'function')
                {
                    extender.EnsureEditor(updateEditorFlag);
                    callback();
                }
                else
                {
                    timer += interval;
                    setTimeout(polingFunction, interval);
                }          
            };

            polingFunction();
        }
    }
}


// -----------------------------------------------------------------------
//  LegacyUserFieldExtender
// -----------------------------------------------------------------------
Infoshare.SharePoint.LegacyUserFieldExtender = function Infoshare$SharePoint$LegacyUserFieldExtender(){}
iLegacyUserFieldExtender = Infoshare.SharePoint.LegacyUserFieldExtender;
iLegacyUserFieldExtender.TypeName = 'Infoshare.SharePoint.LegacyUserFieldExtender';
iLegacyUserFieldExtender.ExtenderType = iBehaviorExtender.ExtenderType.Control;

iLegacyUserFieldExtender.Initialize = function()
{
    iBehaviorExtender.AddExtender(Infoshare.SharePoint.ListFormExtender, ISSPFieldType.User, 'Infoshare.SharePoint.LegacyUserFieldExtender');
    iBehaviorExtender.AddExtender(Infoshare.SharePoint.ListFormExtender, 'UserMulti',        'Infoshare.SharePoint.LegacyUserFieldExtender');
}
iLegacyUserFieldExtender.CanExtend = function()
{
    return iLegacyUserFieldExtender.HasFieldControl();
}

iLegacyUserFieldExtender.HasFieldControl = function(target)
{
    return iLegacyUserFieldExtender.FindFieldControls(target).length > 0;
}
iLegacyUserFieldExtender.FindFieldControls = function(target)
{
    var element = target ? ISDomAccessor.GetElement(target) : document;
    var divs = element.getElementsByTagName('div');

    var controls = new Array();
    for (var i = 0; i < divs.length; i++)
    {
        var div = divs[i];
        if (ISString.Contains(div.className, 'ms-inputuserfield', true) &&
            ISString.Contains(div.className, 'ms-inputBox', true) &&
            ISString.EndsWith(div.id, "_upLevelDiv", div))
        {
            controls.push(div);
        }
    }

    return controls;
}
iLegacyUserFieldExtender.GetPrincipalNameForResolve = function(principalName)
{
    var principalNameForResolve = principalName;

    // オンプレミスの場合には整形する
    if (!iVxContext.IsOnline())
    {
        var splitedPrincipalValue = principalName.split('|');
        // Form認証の場合 User  : i:0#.f|membershipProviderName|alias
        //                Group : c:0-.f|roleProviderName|alias
        // membershipProviderName:alias, roleProviderName:aliasの形式でしかResolveできない為修正する      
        if (splitedPrincipalValue.length == 3 &&
            ISString.StartsWith(principalName, "i:0#.f|", true) ||
            ISString.StartsWith(principalName, "c:0-.f|", true))
        {
            principalNameForResolve = splitedPrincipalValue[1] + ':' + splitedPrincipalValue[2];
        }
    }

    return principalNameForResolve;
}

iLegacyUserFieldExtender.prototype = {
    TypeName: iLegacyUserFieldExtender.TypeName,
    ExtenderType: iLegacyUserFieldExtender.ExtenderType,

    ParentExtender: null,
    FieldInfo: null,
    FormFieldInfo: null,

    EditorElement: null,
    CheckNameButton: null,
    BrowseDialogButton: null,

    EntitySelection: null,

    GetValue: function()
    {
        this.EnsureEditor();

        var values = new Array();

        // 名前解決済み項目を処理
        var entities = this.GetResolvedEntities();
        for (var i = 0; i < entities.length; i++)
        {
            values.push(entities[i].Properties.SpPrincipalName);
        }

        return values;
    },

    GetEntities: function()
    {
        this.EnsureEditor();

        var entities = new Array();

        // 名前解決済み項目を処理
        var resolvedEntities = this.GetResolvedEntities();
        entities = entities.concat(resolvedEntities);

        // TextValueの処理
        var textArray = this.GetTextValues();
        for (var i = 0; i < textArray.length; i++)
        {
            // 空白文字列と、GroupPickerから追加する場合以下のテキスト要素が含まれるので除外
            if (ISString.Equals(textArray[i], '; ', true) ||
                textArray[i].match(/\S/) ||
                textArray[i] === "")
            {
                continue;
            }
            // ToDo:　Undefinedの種別の追加
            // 暫定対応：UndefinedはGroupアイコンとして表示する
            var entity = new iUserFieldEntity(textArray[i], textArray[i], "Group");
            entities.push(entity);
        }
        return entities;
    },

    GetTextValues: function()
    {
        this.EnsureEditor();
        var textArray = new Array();

        var elements = this.EditorElement.childNodes;
        for (var i = 0; i < elements.length; i++)
        {
            var element = elements[i];
            if (element.nodeName == '#text')
            {
                textArray.push(element.nodeValue);
            }
        }
        return textArray;
    },

    GetResolvedEntities: function()
    {
        this.EnsureEditor();

        var entities = new Array();

        var divs = this.EditorElement.getElementsByTagName('div');
        for (var i = 0; i < divs.length; i++)
        {
            var div = divs[i];
            if (ISString.Equals(div.id, 'divEntityData', true))
            {
                var displayName = div.attributes.getNamedItem("displaytext").value;

                var principalName = div.attributes.getNamedItem("key").value;

                // Claim、Form認証の場合Userのトークンの値からエンティティ種別を判断する（Claim : i:0#.w| , Form : i:0#.f|）
                // Reference : http://blogs.technet.com/b/sharepoint_support/archive/2013/11/07/sharepoint-windows.aspx
                var type = ISString.StartsWith(principalName, "i:0#.", false) ? "User" : "Group";

                var entity = new iUserFieldEntity(displayName, principalName, type);

                entities.push(entity);
            }
        }
        return entities;
    },

    SetValues: function(values)
    {
        this.EnsureEditor();
       
        // PrincipalNameの整形
        for (var i = 0; i < values.length; i++)
        {

            var principalName = values[i];
            var principalNameForResolve = iLegacyUserFieldExtender.GetPrincipalNameForResolve(principalName);
            values[i] = principalNameForResolve;
        }

        // 追加するエンティティを文字列として連結して設定する
        var entities = values.join(';');
        entities = ISString.TrimEnd(entities, ";");
        this.EditorElement.innerHTML = ISString.IsNullOrEmpty(values) ? '' : entities;
        if (this.CheckNameButton)
        {
            this.CheckNameButton.onclick();
        }
    },

    CheckNameResult: null,
    CheckNameError: null,
    SetEntityBlocker: null,
    PrincipalEntities: null,
    SetEntities: function(entities)
    {
        // 単数選択列は既存のエンティティを削除する
        if (!this.EntitySelection.AllowMultipleSelection)
        {
            this.ClearEntities();
        }
        // 複数選択列は既存のエンティティを取得して、ユニークな値のみ追加対象とする
        else
        {
            entities = this.GetUniqueEntities(entities);
        }

        // 名前の確認ボタンを押下するクライアントコールバックでの名前解決を行うユーザーコントロールの場合、
        // 一度に名前解決を行える文字列長は256文字までである

        // その為、名前解決処理中に操作が割り込まれないように操作をブロックする
        if (!this.SetEntityBlocker)
        {
            this.SetEntityBlocker = new iScreenBlocker(new iUltimateScreenBlockerStyle());
            this.SetEntityBlocker.Image = ISString.TrimEnd(iVxContext.MasterSourcesPath, '/') + '/Infoshare/loading.gif';
            this.SetEntityBlocker.Render();
        }
        else
        {
            this.SetEntityBlocker.Show();
        }
        
        this.EnsureEditor();
        this.PrincipalEntities = entities;

        //--------------------------------------------------
        // 名前解決成功イベントのオーバーライド
        //--------------------------------------------------
        if (!this.CheckNameResult)
        {
            this.CheckNameResult = EntityEditorHandleCheckNameResult;
            var instance = this;
            EntityEditorHandleCheckNameResult = function (args1, args2) {
                instance.CheckNameResult(args1, args2);
                instance.SetEntitiesInternal();
            };
        }

        //--------------------------------------------------
        // 名前解決失敗イベントのオーバーライド
        //--------------------------------------------------
        if (!this.CheckNameError)
        {
            this.CheckNameError = EntityEditorHandleCheckNameError;
            var instance = this;
            EntityEditorHandleCheckNameError = function (args1, args2) {
                instance.CheckNameError(args1, args2);
                instance.SetEntitiesInternal();
            };
        }

        this.SetEntitiesInternal();
    },

    SetEntitiesInternal: function()
    {
        var resolveNames = "";
        for (;;)
        {
            // 名前解決対象が残っていいるかチェック
            if (!this.PrincipalEntities || this.PrincipalEntities.length < 1)
            {
                break;
            }

            // 名前解決用の値を生成する
            var principalName = this.PrincipalEntities[0].Properties["SpResolveKey"];
            var principalNameForResolve = iLegacyUserFieldExtender.GetPrincipalNameForResolve(principalName);

            // レガシーコントロールが一度に名前解決を行えるのは256文字までなので、長さのチェックを行う
            // 255で判定しているのは末尾のセミコロン分を予め引いた数字
            if (resolveNames.length + principalNameForResolve.length > 255)
            {
                break;
            }

            resolveNames += principalNameForResolve + ';';
            this.PrincipalEntities.shift();
        }

        if (resolveNames.length > 0)
        {
            resolveNames = ISString.TrimEnd(resolveNames, ";")
            this.EditorElement.innerHTML += resolveNames;
            if (this.CheckNameButton)
            {
                this.CheckNameButton.onclick();
            }
        }
        else
        {
            // 名前解決対象が存在しなくなったのでイベントを元に戻しブロックを消す
            EntityEditorHandleCheckNameResult = this.CheckNameResult;
            EntityEditorHandleCheckNameError  = this.CheckNameError;
            this.SetEntityBlocker.Hide();
            this.CheckNameResult = null;
            this.CheckNameError  = null;
        }
    },

    ClearEntities: function()
    {
        // 解決済のエンティティをクリア
        this.EditorElement.innerHTML = "";
    },

    GetUniqueEntities: iUserFieldExtender.prototype.GetUniqueEntities,
    
    CanExtend: function()
    {
        this.EnsureEditor();

        return this.EditorElement != null;
    },

    Extend: function()
    {
    },

    AllowAdditionalExtension: function()
    {
        return true;
    },

    GetEntitySelection: function()
    {
        if (!this.EntitySelection)
        {          
            this.EnsureEditor();

            var selection = new iUserFieldEntitySelection();

            // ダウンレベルモード：フィールド情報が取得されていない場合には、プロパティを作成する
            if (!this.FieldInfo)
            {
                this.FieldInfo = {
                    Type: "Undefined",
                    Properties: []
                };
            }

            // ダウンレベルモードの場合に選択制限は無しに設定
            if (this.FieldInfo.Type == "Undefined")
            {
                this.FieldInfo.Properties.Mult = "TRUE";
                this.FieldInfo.Properties.UserSelectionMode = "PeopleAndGroups";
            }

            // CSRMode：ServerRenderではUserSelectionModeプロパティが存在しない為（CSRMode：ServerRenderに変更後に列の設定を変更した場合は作成される）、選択種別を全てtrueにする
            var userSelectionMode = this.FieldInfo.Properties.UserSelectionMode;
            selection.AllowUserSelection            = userSelectionMode ? ISString.Contains(userSelectionMode, 'People', true)
                                                                        : true;
            selection.AllowSecurityGroupSelection   = userSelectionMode ? ISString.Contains(userSelectionMode, 'Group', true)
                                                                        : true;            
            selection.AllowSharePointGroupSelection = userSelectionMode ? ISString.Contains(userSelectionMode, 'Group', true)
                                                                        : true;     
            selection.AllowMultipleSelection        = this.FieldInfo.Properties.Mult ? ISBoolean.Parse(this.FieldInfo.Properties.Mult) 
                                                                                     : false;

            this.EntitySelection = selection;
        }

        return this.EntitySelection;
    },

    EnsureEditor: function()
    {
        if (this.EditorElement &&
            this.CheckNameButton)
        {
            return;
        }

        // ダウンレベルモード：FormFieldInfoが確認できない場合はDOM全体を対象とする
        var targetElement = this.FormFieldInfo ? this.FormFieldInfo.BodyElement
                                               : document;

        this.EditorElement = iLegacyUserFieldExtender.FindFieldControls(targetElement)[0];
        if (this.EditorElement)
        {
            var anchors = targetElement.getElementsByTagName('a');
            for (var i = 0; i < anchors.length; i++)
            {
                var anchor = anchors[i];
                if (ISString.EndsWith(anchor.id, '_checkNames', true))
                {
                    this.CheckNameButton = anchor;
                }
                if (ISString.EndsWith(anchor.id, '_browse', true))
                {
                    this.BrowseDialogButton = anchor;
                }
            }
        }
    }
}

// -----------------------------------------------------------------------
//  ModernUserFieldExtender
// -----------------------------------------------------------------------
Infoshare.SharePoint.ModernUserFieldExtender = function Infoshare$SharePoint$ModernUserFieldExtender(){}
iModernUserFieldExtender = Infoshare.SharePoint.ModernUserFieldExtender;
iModernUserFieldExtender.TypeName = 'Infoshare.SharePoint.ModernUserFieldExtender';
iModernUserFieldExtender.ExtenderType = iBehaviorExtender.ExtenderType.Control;
iModernUserFieldExtender.ClassInfo = null;

iModernUserFieldExtender.Initialize = function()
{
    iBehaviorExtender.AddExtender(Infoshare.SharePoint.ListFormExtender, ISSPFieldType.User, 'Infoshare.SharePoint.ModernUserFieldExtender');
    iBehaviorExtender.AddExtender(Infoshare.SharePoint.ListFormExtender, 'UserMulti',        'Infoshare.SharePoint.ModernUserFieldExtender');
}
iModernUserFieldExtender.CanExtend = function()
{
    return iModernUserFieldExtender.HasFieldControl();
}

iModernUserFieldExtender.HasFieldControl = function(target)
{
    return iModernUserFieldExtender.FindReactFieldControls(target).length > 0;
}
iModernUserFieldExtender.FindFieldControls = function(target)
{
    var element = target ? ISDomAccessor.GetElement(target) : document;
    var controls = element.getElementsByClassName("ms-BasePicker-input");
    return controls;
}

iModernUserFieldExtender.FindReactFieldControls = function(target)
{
    var element = target ? ISDomAccessor.GetElement(target) : document;
    var controls = element.getElementsByClassName("ReactFieldEditor-Picker");
    return controls;
}

iModernUserFieldExtender.FindSharingFormControls = function()
{
    var sharingFormControls = new Array();
    // 共有ダイアログ
    var shareFrame = document.getElementById("shareFrame");

    var element = shareFrame ? shareFrame.contentWindow.document : document;
    var controls = element.getElementsByClassName("ms-BasePicker");
    for (var i = 0; i < controls.length; i++)
    {
        if (!iArray.Contains(controls[i].classList, "ReactFieldEditor-Picker"))
        {
            sharingFormControls.push(controls[i]);
        }
    }
    return sharingFormControls;
}

iModernUserFieldExtender.prototype = {
    TypeName: iModernUserFieldExtender.TypeName,
    ExtenderType: iModernUserFieldExtender.ExtenderType,

    ParentExtender: null,
    FieldInfo: null,
    FormFieldInfo: null,

    Editor: null,
    EditorElement: null,

    EntitySelection: null,

    GetEntities: function()
    {
        this.EnsureEditor();
    },

    SetEntities: function(entities)
    {
        var ref = this;
        ref.EnsureEditor(ISFunction.CreateDelegate(function ()
        {
            // 単数選択列は既存のエンティティを削除する
            if (!ref.EntitySelection.AllowMultipleSelection)
            {
                ref.ClearEntities();
            }

            var entityUPNArray = [];
            for (var i = 0; i < entities.length; i++)
            {
                var spPrincipalName = entities[i].Properties.SpPrincipalName;
                if (ref.IsUniqueEntities(spPrincipalName))
                {
                    entityUPNArray.push(spPrincipalName);
                }
            }

            ref.Editor.SetEntities(entityUPNArray, function ()
            {
                ref.Editor = null;
            });
        }, ref));
    },

    ClearEntities: function()
    {
        this.EnsureEditor(ISFunction.CreateDelegate(function ()
        {
            this.Editor.ClearEntities();
        }, this));        
    },

    IsUniqueEntities: function(entityUPN)
    {
        var items = this.Editor.Instance['return'].updateQueue ? this.Editor.Instance['return'].updateQueue.baseState.items : this.Editor.Instance['return']['return'].updateQueue.baseState.items;
        for (var i = 0; i < items.length; i++)
        {
            if (items[i].rawData.Key == entityUPN.toLowerCase())
            {
                return false;
            }
        }
        return true;
    },

    CanExtend: iModernUserFieldExtender.HasFieldControl,

    Extend: function()
    {
    },

    AllowAdditionalExtension: function()
    {
        return true;
    },

    EnsureEditor: function(callback)
    {
        if (!this.Editor)
        {
            this.EditorElement = iModernUserFieldExtender.FindReactFieldControls(this.FormFieldInfo.BodyElement)[0];
            if (!this.EditorElement)
            {
                this.EditorElement = iModernUserFieldExtender.FindSharingFormControls()[0];
            }
            if (this.EditorElement)
            {
                var fieldEditor = new iModernUserFieldEditor(this.EditorElement);            
                fieldEditor.RootElement = this.FormFieldInfo.RowElement.parentElement;
                this.Editor = fieldEditor;
                if (typeof callback == "function")
                {
                    callback();
                }
            }
        }
        else
        {
            if (typeof callback == "function")
            {
                callback();
            }            
        }
    }
}

iModernUserFieldExtender.prototype.GetEntitySelection = iLegacyUserFieldExtender.prototype.GetEntitySelection;

// -----------------------------------------------------------------------
//  ModernUserFieldEditor
// -----------------------------------------------------------------------
Infoshare.SharePoint.ModernUserFieldEditor = function Infoshare$SharePoint$ModernUserFieldEditor(reactFieldEditorElement)
{
    this.EditorElement  = reactFieldEditorElement;
    this.InputElement   = iModernUserFieldExtender.FindFieldControls(this.EditorElement)[0];

    if (iModernUserFieldEditor.GetReactElement(this.EditorElement, iModernUserFieldEditor.ReactElementType.Fiber))
    {
        this.Instance = iModernUserFieldEditor.GetReactElement(this.EditorElement, iModernUserFieldEditor.ReactElementType.Fiber);
    }
    else
    {
        ISTrace.TraceWarning('Infoshare.SharePoint.ModernUserFieldEditor: Instance not found.');
    }
}
iModernUserFieldEditor = Infoshare.SharePoint.ModernUserFieldEditor;

iModernUserFieldEditor.ReactElementType = { Fiber: 'Fiber' };

iModernUserFieldEditor.GetReactElement = function(dom, reactElementType)
{
    for (var key in dom)
    {
        if (key.startsWith("__react" + reactElementType + "$"))
        {
            return dom[key];
        }
    }
    ISTrace.TraceVerbose('iModernUserFieldEditor.GetReactElement: ReactElement not found. ReactElementType: ' + reactElementType);
    return null;
}

iModernUserFieldEditor.prototype = {
    RootElement: null,
    EditorElement: null,
    InputElement: null,
    Instance: null,
    IsBlockingFunction: null,
    
    EnableFormAutoClosing: function (enable)
    {
        var sharingLayer = document.getElementsByClassName('ms-Layer');
        if (sharingLayer.length <= 0)
        {
            // リストフォーム
            // 自動開閉を制御する
            this.disableListFormAutoClosing(enable);
        }
        else
        {
            // 共有
            // 重なり順制御
            if (enable)
            {
                sharingLayer[sharingLayer.length - 1].style.zIndex = "9998";
            }
            else
            {
                sharingLayer[sharingLayer.length - 1].style.zIndex = "1000000";
            }
            
            // ms-Layerの親要素IDがfluent-default-layer-hostの場合、親要素も重なり順制御を行う（Fluent UI Reactに対する調整）
            if (sharingLayer[sharingLayer.length - 1].parentElement.id == "fluent-default-layer-host")
            {
                sharingLayer[sharingLayer.length - 1].parentElement.style.zIndex = sharingLayer[sharingLayer.length - 1].style.zIndex;
            }

            // 自動開閉
            var form = this.getForm();
            if (form != null &&
                form.elementType.defaultProps != undefined &&
                form.elementType.defaultProps.isBlocking != undefined)
            {
                form.elementType.defaultProps.isBlocking = !enable;
            }
        }
    },

    getForm: function()
    {
        var form = null;
        var sharingLayer = document.getElementsByClassName('ms-Layer');
        if (sharingLayer.length > 0)
        {
            var reactElement = iModernUserFieldEditor.GetReactElement(sharingLayer[sharingLayer.length - 1]._virtual.parent, iModernUserFieldEditor.ReactElementType.Fiber);
            if (reactElement)
            {
                form = reactElement['return']['return']['return'];
            }
        }
        return form;
    },

    disableListFormAutoClosing: function (enable)
    {
        var sideLoadingPanel = document.getElementsByClassName('od-Panel');
        if (sideLoadingPanel.length > 0)
        {
            if (enable)
            {
                this.IsBlockingFunction = __ko.dataFor(sideLoadingPanel[0]).isBlocking;
                __ko.dataFor(sideLoadingPanel[0]).isBlocking = null;
            }
            else
            {
                __ko.dataFor(sideLoadingPanel[0]).isBlocking = this.IsBlockingFunction;
            }
        }
    },

    DisableReactStopPropagation: function (disable)
    {
        var dialogMain = document.getElementsByClassName('ms-Dialog-main');
        if (dialogMain.length > 0)
        {
            var reactElement = iModernUserFieldEditor.GetReactElement(dialogMain[0], iModernUserFieldEditor.ReactElementType.Fiber);
            if (reactElement != null)
            {
                // plt.office-ui-fabric-react.js内で処理内容は不明だが、focusStackの比較でstopPropagationを行っているので、
                // 配列に"InfoCallDisableReactStopPropagation"を追加することでstopPropagationが発生しないようにする。
                // 追加した"InfoCallDisableReactStopPropagation"を配列から削除することで元に戻す。
                var focusStackArray = reactElement['return'].elementType.focusStack;
                if (disable)
                {
                    focusStackArray.push("InfoCallDisableReactStopPropagation");
                }
                else
                {
                    for (var i = 0; i < focusStackArray.length; i++)
                    {
                        if (focusStackArray[i] == "InfoCallDisableReactStopPropagation")
                        {
                            focusStackArray.splice(i, 1);
                            break;
                        }
                    }
                }
            }
        }
    },

    ResolveEntities: function(entityUPNArray, callback)
    {
        // 非同期でオブジェクトを問い合わせる
        var callBackContext = {
            Results: [],
            Complete: function(){
                return this.Results.length == entityUPNArray.length;
            }
        };
        
        for (var i = 0; i < entityUPNArray.length; i++)
        {
            var entityUPN = entityUPNArray[i];
            // PickerEntity取得
            var pickerEntityProvider = this.Instance['return'].updateQueue ? this.Instance['return']['return'].pendingProps.dataProvider : this.Instance['return']['return']['return'].pendingProps.dataProvider;
            var peoplePickerQueryParams = this.Instance['return'].updateQueue ? this.Instance['return']['return'].pendingProps.peoplePickerQueryParams : this.Instance['return']['return']['return'].pendingProps.peoplePickerQueryParams;
            // ToDo: 現在1件ずつresolveを行っているが、クラシック側と同じように一括resolveを行えないか？
            pickerEntityProvider.resolve(entityUPN, peoplePickerQueryParams).then(function (result)
            {
                callBackContext.Results.push(result);
                if (callBackContext.Complete())
                {
                    callback(callBackContext.Results);
                }
            });            
        }
    },

    SetEntities: function (entityUPNArray, callback)
    {
        this.ResolveEntities(entityUPNArray, ISFunction.CreateDelegate(function (resolvedEntities)
        {
            // ToDo: SharePoint既定のaddItem関数を使用したかったが、参照モード（ReactFieldEditor-core--display）場合のピッカーから複数Item選択時に１つしか設定されない事象が解消しないため、currentSelectedPeopleに直接設定
            var addItem = this.Instance['return'].updateQueue ? this.Instance['return'].stateNode.addItem : this.Instance['return']['return'].stateNode.addItem;
            var items = this.Instance['return'].updateQueue ? this.Instance['return'].updateQueue.baseState.items : this.Instance['return']['return'].updateQueue.baseState.items;
            var reactElement = iModernUserFieldEditor.GetReactElement(this.RootElement, iModernUserFieldEditor.ReactElementType.Fiber);
            var stateNode = stateNode = reactElement['return'].stateNode;
            if (reactElement['return']['return'] && reactElement['return']['return']['return'] && reactElement['return']['return']['return'].stateNode)
            {
                stateNode = reactElement['return']['return']['return'].stateNode;
            }
            if (stateNode.state && stateNode.state.mode == 0)
            {
                for (var i = 0; i < resolvedEntities.length; i++)
                {
                    items.push(resolvedEntities[i]);
                }
                stateNode.setState({ currentSelectedPeople: items });
            }
            else
            {
                for (var i = 0; i < resolvedEntities.length; i++)
                {
                    addItem(resolvedEntities[i]);
                }
            }

            if (this.RootElement.getElementsByClassName('ReactFieldEditor-core--display').length > 0)
            {
                this.RootElement.getElementsByClassName('ReactFieldEditor-core--display')[0].click();
            }
            callback();
        }, this));
    },

    ClearEntities: function()
    {
        var items = this.Instance['return'].updateQueue ? this.Instance['return'].updateQueue.baseState.items : this.Instance['return']['return'].updateQueue.baseState.items;
        for (var i = 0; i < items.length; i++)
        {
            items.pop();
        }
    }
}										    
