// -----------------------------------------------------------------------
//  TextFieldExtender
// -----------------------------------------------------------------------
Infoshare.SharePoint.TextFieldExtender = function Infoshare$SharePoint$TextFieldExtender(){}
iTextFieldExtender = Infoshare.SharePoint.TextFieldExtender;
iTextFieldExtender.TypeName = 'Infoshare.SharePoint.TextFieldExtender';
iTextFieldExtender.ExtenderType = iBehaviorExtender.ExtenderType.Control;
iTextFieldExtender.ClassInfo = null;

iTextFieldExtender.Initialize = function()
{
    iBehaviorExtender.AddExtender(Infoshare.SharePoint.ListFormExtender, ISSPFieldType.Text, 'Infoshare.SharePoint.TextFieldExtender');
}
iTextFieldExtender.CanExtend = function()
{
    return iTextFieldExtender.HasFieldControl();
}

iTextFieldExtender.HasFieldControl = function(target)
{
    return iTextFieldExtender.FindFieldControls(target).length > 0;
}
iTextFieldExtender.FindFieldControls = function(target)
{
    var element = target ? ISDomAccessor.GetElement(target) : document;
    var inputs = element.getElementsByTagName('input');

    var controls = new Array();
    for (var i = 0; i < inputs.length; i++)
    {
        var input = inputs[i];
        if (ISString.EndsWith(input.id, '_$TextField', true))
        {
            controls.push(input);
        }
    }

    return controls;
}

iTextFieldExtender.prototype = {
    TypeName: iTextFieldExtender.TypeName,
    ExtenderType: iTextFieldExtender.ExtenderType,

    ParentExtender: null,
    FieldInfo: null,
    FormFieldInfo: null,
    InputElement: null,
    MaxLength: 255,

    GetValue: function()
    {
        this.EnsureInput();
        var value = this.InputElement ? this.InputElement.value
                                      : null;
        return value;
    },

    // ToDo: インターフェースを検討
    //       他の型のInputが実装されるタイミングで、Validationや戻り値のハンドリングを再度検討する
    SetValue: function(value)
    {
        this.EnsureInput();
        var setValue = value;
        var trimed = false;
        if (value.length > this.MaxLength)
        {
            setValue = value.substring(0, this.MaxLength);
            ISTrace.TraceWarning("[iTextFieldExtender.SetValue] Value is trimed. Value : " + value);
            trimed = true;
        }

        if (this.InputElement)
        {
            this.InputElement.value = setValue;
        }   

        return trimed;
    },
    
    CanExtend: function()
    {
        return true;
    },

    EnsureInput: function()
    {
        if(this.InputElement)
        {
            return;
        }

        var bodyElement = this.FormFieldInfo.BodyElement;
        var input = ISDomAccessor.GetElementByTagName("Input", bodyElement);
        this.InputElement = input;
        if (this.InputElement)
        {
            this.MaxLength = input.maxLength;
        }        
    },

    Extend: function()
    {
    },

    AllowAdditionalExtension: function()
    {
        return true;
    }
}
										    
