Infoshare.SharePoint.UserControlExtender = function Infoshare$SharePoint$UserControlExtender()
{
    Infoshare.SharePoint.UserFieldExtender.apply(this, arguments);
}
iUserControlExtender = Infoshare.SharePoint.UserControlExtender;
iUserControlExtender.TypeName = 'Infoshare.SharePoint.UserControlExtender';
iUserControlExtender.ExtenderType = iBehaviorExtender.ExtenderType.Control;
iUserControlExtender.ClassInfo = null;

iUserControlExtender.Initialize = function()
{
    iBehaviorExtender.AddExtender(Infoshare.SharePoint.DialogExtender, 'UserMulti', 'Infoshare.SharePoint.UserControlExtender');
}

iUserControlExtender.CanExtend = function()
{
    return iUserControlExtender.HasFieldControl();
}

iUserControlExtender.HasFieldControl = function(target)
{
    return iUserControlExtender.FindFieldControls(target).length > 0;
}
iUserControlExtender.FindFieldControls = function(target)
{
    var element = target ? ISDomAccessor.GetElement(target) : document;
    var inputs = element.getElementsByTagName('input');

    var controls = new Array();
    for (var i = 0; i < inputs.length; i++)
    {
        var input = inputs[i];
        if (ISString.EndsWith(input.id, 'peoplePicker_TopSpan_EditorInput', true))
        {
            controls.push(input);
        }
    }

    return controls;
}

iUserControlExtender.prototype = new Infoshare.SharePoint.UserFieldExtender();
iUserControlExtender.prototype.TypeName = iUserControlExtender.TypeName;
iUserControlExtender.prototype.ExtenderType = iUserControlExtender.ExtenderType;


iUserControlExtender.prototype.GetEntitySelection = function()
{
    if (!this.EntitySelection)
    {
        this.EnsureEditor();

        var selection = new iUserFieldEntitySelection();
        selection.AllowUserSelection            = true;
        selection.AllowSecurityGroupSelection   = true;
        selection.AllowSharePointGroupSelection = true;
        selection.AllowMultipleSelection        = true;

        this.EntitySelection = selection;
    }

    return this.EntitySelection;
}

iUserControlExtender.prototype.EnsureEditor = function(updateEditorFlag)
{
    if (updateEditorFlag)
    {
        this.Editor = null;
        this.EditorElement = null;
    }

    // (IE8issue)初回呼び出し時（CanExtendの呼び出しタイミング）でEditorが特定できない
    // 二回目の呼び出し時（GetEntitySelectionの呼び出しタイミング）ではEditorが特定できる
    if (this.Editor &&
        this.EditorElement)
    {
        return;
    }

    this.EditorElement = iUserControlExtender.FindFieldControls(document)[0];
    if (this.EditorElement)
    {
        // フォーカスが当たるとクラス名が "sp-peoplepicker-topLevel sp-peoplepicker-topLevelFocus"となるのでcontainsを使用する
        // SPClientPeoplePicker.PickerObjectFromSubElement内のSPClientPeoplePicker.GetTopLevelControlはタイミングによって取得できない為、
        // SPClientPeoplePicker.SPClientPeoplePickerDict[topLevelId] から取得する
        var toplevelElm = ISDomAccessor.FindAncestorByContainsClassNames(this.EditorElement, 'sp-peoplepicker-topLevel');

        if (typeof SPClientPeoplePicker == 'function')
        {
            this.Editor = SPClientPeoplePicker.SPClientPeoplePickerDict[toplevelElm.id];
        }
            
        if (!this.Editor)
        {
            ISTrace.TraceVerbose('Failed EnsureEditor');
        }
    }  
}


