{
    if (!this.EntitySelection)
    {
        this.EnsureEditor();

        var selection = new iUserFieldEntitySelection();
        selection.AllowUserSelection            = false;
        selection.AllowSecurityGroupSelection   = true;
        selection.AllowSharePointGroupSelection = true;
        selection.AllowMultipleSelection        = true;

        this.EntitySelection = selection;
    }

    return this.EntitySelection;
}

iLegacyUserControlExtender.prototype.EnsureEditor = function(updateEditorFlag)
{
    if (this.EditorElement &&
        this.CheckNameButton)
    {
        return;
    }
    
    // Todo: documentの参照を辞め、ParentTable属性を用いる
    //       ParentTableは親クラスがエクステンドする際に、定義する
    //       _OuterTable > Tbody > .... > td(div), td(checkNames, browse)
    this.EditorElement = iLegacyUserFieldExtender.FindFieldControls(document)[0];
    if (this.EditorElement)
    {
        var anchors = document.getElementsByTagName('a');
        for (var i = 0; i < anchors.length; i++)
        {
            var anchor = anchors[i];
            if (ISString.EndsWith(anchor.id, '_checkNames', true))
            {
                this.CheckNameButton = anchor;
            }
            if (ISString.EndsWith(anchor.id, '_browse', true))
            {
                this.BrowseDialogButton = anchor;
            }
        }
    }
}

