// -----------------------------------------------------------------------
Infoshare.SharePoint.UserFieldEditPageExtender = function Infoshare$SharePoint$UserFieldEditPageExtender(){}
iSPUserFieldEditPageExtender = Infoshare.SharePoint.UserFieldEditPageExtender;
iSPUserFieldEditPageExtender.TypeName = 'Infoshare.SharePoint.UserFieldEditPageExtender';
iSPUserFieldEditPageExtender.ExtenderType = iBehaviorExtender.ExtenderType.Page;
iSPUserFieldEditPageExtender.ClassInfo = null;

iSPUserFieldEditPageExtender.Initialize = function()
{
    iBehaviorExtender.AddExtender(Infoshare.SharePoint.FieldEditPageExtender, 'Infoshare.SharePoint.UserFieldEditPageExtender', 'Infoshare.SharePoint.UserFieldEditPageExtender');
}

iSPUserFieldEditPageExtender.CanExtend = function ()
{
    var extend = false;
    var elements = document.getElementsByTagName('input');
    for (var i = 0; i < elements.length; i++)
    {
        var element = elements[i];
        if (element.value.toUpperCase() == 'RadSelectionPeopleOnly'.toUpperCase())
        {
            extend = true;
            break;
        }
    }

    return extend;
};

iSPUserFieldEditPageExtender.prototype = {
    TypeName: iSPUserFieldEditPageExtender.TypeName,
    ExtenderType: iSPUserFieldEditPageExtender.ExtenderType,

    ParentExtender: null,
    SettingsTbody: null,
    AdditionalSettingTr: null,

    SettingList: null,
    SettingListItems: null,
    SettingDefinition: null,

    OKButton: null,

    CanExtend: function()
    {
        return iSPUserFieldEditPageExtender.CanExtend();
    },

    Extend: function()
    {
        if (!this.CanExtend())
        {
            return;
        }

        this.Extenders = iSPUserFieldEditPageExtender.Extenders;
        if (!this.Extenders ||
            this.Extenders.GetLength() <= 0)
        {
            return;
        }

        var extender = this;
        this.EnsureList(function()
        {
            extender.EnsureField();
            extender.ExtendInternal();        
        });
    },

    ExtendInternal: function()
    {
        // フォーム要素の確認
        this.EnsureFormElement();

        // 拡張先のTdの作成
        this.CreateAdditionalSeetingTr();

        // 設定のTable要素の確認
        this.EnsureSettingsTbody();
        if (!this.SettingsTbody)
        {
            ISTrace.TraceVerbose('[CANCELLED] iSPUserFieldEditPageExtender.Extend：Faild to define \'ms-propertysheet\' element');
        }

        var fieldType = this.Field.Type;
        var extenderClassName = this.Extenders.Get(fieldType);
        if (extenderClassName)
        {
            var extender = eval('new ' + extenderClassName + '();');
            extender.ParentExtender = this;
            
            if (extender.CanExtend())
            {
                extender.Extend();
            }
        }
    },

    EnsureFormElement: function ()
    {
        if (this.OKButton)
        {
            return;
        }
        var okButton = i$("input[accesskey='o']");
        if (okButton.length == 1)
        {
            this.OKButton = okButton[0];
        }        
    },

    EnsureSettingsTbody: function()
    {
        var table = i$(".ms-propertysheet");

        if (table.length == 1)
        {
            this.SettingsTbody = table[0].children[0];
        }
    },

    EnsureList: function(callback)
    {
        if (this.List)
        {
            callback();
            return;
        }

        var extender = this;
        iVxService.GetList(iVxContext.WebUrl, iVxContext.GetListId(), function (list)
        {
            extender.List = list;
            callback();
        });
    },

    EnsureField: function()
    {
        if (this.Field)
        {
            return;
        }

        if (this.List)
        {
            // クエリストリングからField内部名を取得
            var fieldInternalName = ISQueryString.GetValue('Field');
            // 日本語内部名のエスケープ
            fieldInternalName = ISString.Replace(fieldInternalName, "%5F", "_");
            var field = this.List.Fields.Get(fieldInternalName);
            this.Field = field;
        }
    },

    CreateAdditionalSeetingTr: function()
    {
        // OKボタンが属するTrの一つ上に挿入する
        var okButtonParentTr = ISDomAccessor.FindAncestorByTagName(this.OKButton, "tr");
        var okButtonTr = ISDomAccessor.FindAncestorByTagName(okButtonParentTr, "tr");

        var additionalTr = document.createElement("tr");
        additionalTr.id = "Infoshare.SharePoint.UserFieldEditPageExtender.AdditionalTr";
        okButtonTr.parentElement.insertBefore(additionalTr, okButtonTr);

        this.AdditionalSettingTr = additionalTr;
    }
}
										    
