// -----------------------------------------------------------------------
//  SiteConfiguration
// -----------------------------------------------------------------------
Infoshare.SharePoint.SiteConfiguration = function Infoshare$SharePoint$SiteConfiguration(){}
iSiteConfiguration = Infoshare.SharePoint.SiteConfiguration;

iSiteConfiguration.FieldName = { WebUrl            : 'WebUrl',
                                 ListId            : 'ListId',
                                 FieldInternalName : 'FieldInternalName',
                                 Settings          : 'Settings' };
iSiteConfiguration.SettingsXmlFormat = "<Settings>"
                                     +   "<Setting Key='{0}' Value='{1}' />"
                                     + "</Settings>";

iSiteConfiguration.ConfigurationListName  = "InfoshareSiteConfiguration";
iSiteConfiguration.ConfigurationList      = null;
iSiteConfiguration.ConfigurationListItems = null;

iSiteConfiguration.Initializing = false;
iSiteConfiguration.Initialized = false;

iSiteConfiguration.Refresh = function()
{
    iSiteConfiguration.Initializing = false;
    iSiteConfiguration.Initialized = false;
    iSiteConfiguration.ConfigurationList      = null;
    iSiteConfiguration.ConfigurationListItems = null;
}

iSiteConfiguration.Initialize = function(callback)
{
    // 初期化フラグをチェック, 適切なタイミングで初期化完了を通知
    if (iSiteConfiguration.Initialized)
    {
        ISTrace.TraceVerbose('Skipped iSiteConfiguration.Initialize');
        if (callback)
        {
            setTimeout(function(){ callback(); }, 1);
        }   
        return;
    }
    else if (iSiteConfiguration.Initializing)
    {
        if (callback)
        {
            iSiteConfiguration.RegisterFunctionToNotifyInitialized(function() { callback(); });
        }
        return;
    }
    iSiteConfiguration.Initializing = true;

    // 初期化
    var stopwatch = new ISStopwatch();
    stopwatch.Start();
    ISTrace.TraceVerbose('[BEGIN] iSiteConfiguration.Initialize');
    iSiteConfiguration.EnsureConfigurationList(function ()
    {
        if (iSiteConfiguration.ConfigurationList != null)
        {
            iSiteConfiguration.EnsureConfigurationListItems(function()
            {
                ISTrace.TraceVerbose('[END] iSiteConfiguration.Initialize (spent: ' + stopwatch.Stop() + ')');
                iSiteConfiguration.Initialized  = true;
                iSiteConfiguration.Initializing = false;
                iSiteConfiguration.NotifyInitialized();                
                if (callback)
                {
                    callback();
                }
            });
        }
    });
}

iSiteConfiguration.Events = null;
iSiteConfiguration.EventName = { Initialized: 'Initialized' };
iSiteConfiguration.NotifyInitialized = function()
{
    if (iSiteConfiguration.Events)
    {
        iSiteConfiguration.Events.FireEventByName(iSiteConfiguration.EventName.Initialized);
    }
}
iSiteConfiguration.RegisterFunctionToNotifyInitialized = function(fn)
{
    if (!iSiteConfiguration.Events)
    {
        iSiteConfiguration.Events = new iEvent();
    }

    iSiteConfiguration.Events.AddEvent(iSiteConfiguration.EventName.Initialized, fn);
}

iSiteConfiguration.EnsureConfigurationList = function (callback)
{
    // リスト取得
    if (iSiteConfiguration.ConfigurationList == null)
    {
        iVxService.GetListByUrlName(iVxContext.SiteUrl, iSiteConfiguration.ConfigurationListName, function (list)
        {
            iSiteConfiguration.ConfigurationList = list;
            callback();
        });
    }
    else
    {
        setTimeout(function(){ callback(); }, 1);
    }
};
iSiteConfiguration.EnsureConfigurationListItems = function (callback)
{
    var listId = iSiteConfiguration.GetContextListId();
    if (iSiteConfiguration.ConfigurationListItems == null)
    {
        // クエリ生成
        var query = new ISSPQuery();
        query.Query = "<Query>"
                    +   "<Where>"
                    +     "<Eq>"
                    +       "<FieldRef Name='{0}'/>"
                    +       "<Value Type='text'>{1}</Value>"
                    +     "</Eq>"
                    +   "</Where>"
                    + "</Query>";
        query.Query = ISString.Format(query.Query, iSiteConfiguration.FieldName.ListId, listId);

        // ViewField設定
        var fieldRefs = '';
        fieldRefs += SPQueryBuilder.BuildFieldRef(iSiteConfiguration.FieldName.WebUrl);
        fieldRefs += SPQueryBuilder.BuildFieldRef(iSiteConfiguration.FieldName.ListId);
        fieldRefs += SPQueryBuilder.BuildFieldRef(iSiteConfiguration.FieldName.FieldInternalName);
        fieldRefs += SPQueryBuilder.BuildFieldRef(iSiteConfiguration.FieldName.Settings);
        query.ViewFields = SPQueryBuilder.BuildViewFields(fieldRefs);

        // アイテム取得
        ISTrace.TraceVerbose('[BEGIN] ConfigurationListItemsQuery');
        var cachedItems = new ISDictionary();
        iVxService.RetrieveItems(iVxContext.SiteUrl, iSiteConfiguration.ConfigurationList, query, true, function(items)
        {
            ISTrace.TraceVerbose('[END] ConfigurationListItemsQuery');

            // アイテムをコンテキスト内のディクショナリに追加（key : ListGuid + . + フィールド名）
            for (var i = 0; i < items.length; i++)
            {
                var item = items[i];
                var fieldInternalName = item.Properties[iSiteConfiguration.FieldName.FieldInternalName];
                if (!ISString.IsNullOrEmpty(fieldInternalName))
                {
                    var key = iSiteConfiguration.BuildItemKey(listId, fieldInternalName);
                    if (cachedItems.Contains(key))
                    {
                        var message = ISString.Format('[EnsureConfigurationListItems] This key is already exist. ({0})', key);
                        ISTrace.TraceWarning(message);
                    }
                    cachedItems.Set(key, item);
                }           
            }

            iSiteConfiguration.ConfigurationListItems = cachedItems;
            callback();
        });
    }
    else
    {
        setTimeout(function(){ callback(); }, 1);
    }
};

iSiteConfiguration.EnableListIdCompletion = true;
iSiteConfiguration.GetContextListId = function()
{
    var listId = null;
    if (iSiteConfiguration.EnableListIdCompletion)
    {
        // 暫定対応:ダウンロード最小化戦略でページ遷移後にもListIdが更新されない為
        //listId = iVxContext.ListId;
        if (_spPageContextInfo.pageListId)
        {
            listId = ISGuid.TrimBrace(_spPageContextInfo.pageListId);
        }        
    }

    return listId;
}

iSiteConfiguration.BuildItemKey = function(listId, fieldName)
{
    if (ISObject.IsNullOrUndefined(listId))
    {
        listId = iSiteConfiguration.GetContextListId();
    }

    return ISGuid.TrimBrace(listId) + '.' + fieldName;
}
iSiteConfiguration.GetConfigurationItem = function(listId, fieldName)
{
    var item = null;
    var key = iSiteConfiguration.BuildItemKey(listId, fieldName);
    if (iSiteConfiguration.ConfigurationListItems &&
        iSiteConfiguration.ConfigurationListItems.Contains(key))
    {
        item = iSiteConfiguration.ConfigurationListItems.Get(key);
    }

    return item;
}

iSiteConfiguration.ConfigurationCache = null;
iSiteConfiguration.GetConfiguration = function(listId, fieldName)
{
    // Configuration用のディクショナリを用意
    if (iSiteConfiguration.ConfigurationCache == null)
    {
        iSiteConfiguration.ConfigurationCache = new ISDictionary();
    }

    // Configurationオブジェクトを初期化
    var config = null;
    var key = iSiteConfiguration.BuildItemKey(listId, fieldName);
    if (iSiteConfiguration.ConfigurationCache.Contains(key))
    {
        config = iSiteConfiguration.ConfigurationCache.Get(key);
    }
    else
    {
        // 設定情報取得
        // 以下の形式のXMLを期待
        // <Settings>
        //   <Setting Key='xxx' Value='xxx' />
        // </Settings> 
        var item = iSiteConfiguration.GetConfigurationItem(listId, fieldName);
        if (item)
        {
            var settings = item.Properties[iSiteConfiguration.FieldName.Settings];
            if (!ISString.IsNullOrEmpty(settings))
            {
                config = new iBaseConfig('Setting', 'Key', 'Value');
                config.InitializeFromXml(settings);
            }
        }

        // アイテムがない場合、アイテムはあるが構成情報が空の場合は新規に作成
        if (config == null)
        {
            config = new iBaseConfig('Setting', 'Key', 'Value');
        }

        iSiteConfiguration.ConfigurationCache.Add(key, config);
    }

    return config;
}
iSiteConfiguration.GetSetting = function(listId, fieldName, key)
{
    var config = iSiteConfiguration.GetConfiguration(listId, fieldName);
    return config.GetSetting(key);
}
iSiteConfiguration.GetSettings = function(listId, fieldName)
{
    var config = iSiteConfiguration.GetConfiguration(listId, fieldName);
    return config.Settings;
}
iSiteConfiguration.SetSetting = function(listId, fieldName, key, value)
{
    var config = iSiteConfiguration.GetConfiguration(listId, fieldName);
    if (config.Settings)
    {
        config.SetSetting(key, value);
    }
    else
    {
        // 構成情報が空の場合は新規に作成
        config.InitializeFromXml(ISString.Format(iSiteConfiguration.SettingsXmlFormat, key, value));
    }
}

iSiteConfiguration.CommitSetting = function(listId, fieldName, callback)
{
    // コミットの要不要を確認
    var needCreateItem = false;
    var needUpdate = false;
    var config = iSiteConfiguration.GetConfiguration(listId, fieldName);
    if(config.Settings)
    {
        var item = iSiteConfiguration.GetConfigurationItem(listId, fieldName);
        if (item)
        {
            var originalSettings = item.Properties[iSiteConfiguration.FieldName.Settings];
            var currentSettings  = iXml.GetOuterXml(config.ConfigXml);
            if (!ISString.Equals(originalSettings, currentSettings))
            {
                // 構成情報が更新されていて、アイテムの構成情報と異なる場合は要コミット
                needUpdate = true;
            }
        }
        else
        {
            // 構成情報が更新されていて、アイテムが存在しない場合も要コミット
            needUpdate = true;

            // アイテムが存在しないばあは、アイテムの作成も必要
            needCreateItem = true;
        }
    }

    // コミット処理
    if (needUpdate && needCreateItem)
    {
        // アイテム情報作成
        var item = new ISSPItem();
        item.Properties[iSiteConfiguration.FieldName.WebUrl]            = iVxContext.WebUrl;
        item.Properties[iSiteConfiguration.FieldName.ListId]            = ISGuid.TrimBrace(listId);
        item.Properties[iSiteConfiguration.FieldName.FieldInternalName] = fieldName;
        item.Properties[iSiteConfiguration.FieldName.Settings]          = iXml.GetOuterXml(config.ConfigXml);

        // アイテム作成
        iVxService.UpdateItems(iVxContext.SiteUrl, iSiteConfiguration.ConfigurationList, item, callback);
    }
    else if (needUpdate && !needCreateItem)
    {
        // アイテム情報更新
        var item = iSiteConfiguration.GetConfigurationItem(listId, fieldName);
        item.Properties[iSiteConfiguration.FieldName.Settings] = iXml.GetOuterXml(config.ConfigXml);

        // アイテム更新
        iVxService.UpdateItems(iVxContext.SiteUrl, iSiteConfiguration.ConfigurationList, item, callback);
    }
    else
    {
        callback();
    }
}
										    
