iSPWebPartEditorExtender.CanExtend = function()
{
    return iSPWebPartEditorExtender.IsWebPartEditPage();
}

iSPWebPartEditorExtender.IsWebPartEditPage = function()
{
    var _wikiPageMode = document.getElementById("_wikiPageMode");
    if (_wikiPageMode) 
    {
        return _wikiPageMode.value == "Edit";
    }
    else
    {
        var MSOLayout_InDesignMode = document.getElementById("MSOLayout_InDesignMode");
        return (MSOLayout_InDesignMode) ? (MSOLayout_InDesignMode.value == 1) : false;
    }
}

iSPWebPartEditorExtender.GetWebPartId = function(elementId)
{
    var webPartId = "";

    var searchPartDiv = document.getElementById(elementId);
    var webPartDiv = ISDomAccessor.FindAncestorByContainsClassNames(searchPartDiv, "ms-WPBody");
    
    if (webPartDiv &&
        webPartDiv.attributes)
    {
        if (webPartDiv.attributes.webpartid2)
        {
            webPartId = webPartDiv.attributes.webpartid2.value;
        }
        else if (webPartDiv.attributes.webpartid)
        {
            webPartId = webPartDiv.attributes.webpartid.value;
        }        
    }

    return webPartId;
}


iSPWebPartEditorExtender.GetCurrentEditorPaneWebPartId = function()
{
    var webPartId = "";

    var partPaneTd = document.getElementById("MSOTlPn_MainTD");
    if (partPaneTd)
    {
        var tpBodyDivSelector = ".ms-TPBody";
        var tpBodyDiv = partPaneTd.querySelector(tpBodyDivSelector);
        if (tpBodyDiv)
        {
            webPartId = tpBodyDiv.id;
        }
    }

    return webPartId;
}

iSPWebPartEditorExtender.prototype = {
    TypeName: iSPWebPartEditorExtender.TypeName,
    ExtenderType: iSPWebPartEditorExtender.ExtenderType,

    WebPartEditPane: null,
    SettingDiv: null,
    WebPartSaveActionButtons: [],

    Extend: function()
    {
        if (!this.CanExtend())
        {
            return;
        }

        this.EnsureEditPane();

        if (this.WebPartEditPane)
        {
            this.ExtendInternal();
        }        
    },

    ExtendInternal: function()
    {
        // 子エクステンダーの取得
        if (!this.Extenders)
        {
            this.Extenders = iSPWebPartEditorExtender.Extenders;
        }        
        if (!this.Extenders ||
            this.Extenders.GetLength() <= 0)
        {
            return;
        }

        for(var i = 0; i < this.Extenders.GetLength(); i++)
        {
            var extenderClassName = this.Extenders.Get(i);
            if (extenderClassName)
            {
                var extender = eval('new ' + extenderClassName + '();');
                extender.ParentExtender = this;

                if (extender.CanExtend())
                {
                    extender.Extend();
                }
            }
        }
    },

    CanExtend: function()
    {
        return iSPWebPartEditorExtender.CanExtend();
    },

    EnsureEditPane: function()
    {
        var editPane = null;
        var PaneElement = document.getElementsByClassName('ms-ToolPaneOuter');
        editPane = PaneElement.length == 1 ? PaneElement[0] : editPane;

        this.WebPartEditPane = editPane;

        if (!this.WebPartEditPane)
        {
            return;
        }

        // 設定コンテナの取得
        var msWPBorderTR = editPane.getElementsByClassName('ms-WPBorder');
        if (msWPBorderTR.length == 1)
        {
            this.BorderTR = msWPBorderTR[0];
        }        

        // 設定表示Divの取得
        var sectionTD = editPane.getElementsByClassName('ms-TPSectionTD');
        this.SettingDiv = sectionTD.length == 1 ? sectionTD[0].children[0] : null;

        // 保存ボタン（OK、適応）の取得
        var commandButtonDiv = editPane.getElementsByClassName('ms-toolpanefooter')[0];
        var okButton = commandButtonDiv.children[0];
        var applyButton = commandButtonDiv.children[2];

        this.WebPartSaveActionButtons.push(okButton);
        this.WebPartSaveActionButtons.push(applyButton);
    },

    AllowAdditionalExtension: function()
    {
        return true;
    }
}
										    
