// -----------------------------------------------------------------------
Infoshare.SharePoint.FunctionExtender = function Infoshare$SharePoint$FunctionExtender()
{
    Infoshare.SharePoint.BehaviorExtender.apply(this, arguments);
}
iSPFunctionExtender = Infoshare.SharePoint.FunctionExtender;
iSPFunctionExtender.TypeName = 'Infoshare.SharePoint.FunctionExtender';
iSPFunctionExtender.ClassInfo = null;

iSPFunctionExtender.CanExtend = iBehaviorExtender.CanExtend;
iSPFunctionExtender.ScriptExist = function(scriptName)
{
    // srcの値を後方一致(オンライン環境)または中間一致(オンプレミス環境)で判断する
    var selector = ISString.Format("script[src$='/{0}'], script[src*='/{0}?']", scriptName);
    var scripts = document.querySelectorAll(selector);

    return scripts.length > 0;
}

iSPFunctionExtender.prototype = new Infoshare.SharePoint.BehaviorExtender();
iSPFunctionExtender.prototype.TypeName = iSPFunctionExtender.TypeName;

iSPFunctionExtender.prototype.HookFunction = function(originalFunction)
{
    if (typeof originalFunction == 'string')
    {
        var expression = 'var extender = this;'
                       + 'var hookFunction = function()'
                       + '{'
                       +     'var result = extender.Execute(arguments);'
                       +     'return result;'
                       + '};'
                       + 'this.OriginalFunction = ' + originalFunction + ';'
                       + originalFunction + ' = hookFunction;';
        eval(expression);
    }
    else if (typeof originalFunction == 'function')
    {
        this.OriginalFunction = originalFunction;
        originalFunction = ISFunction.CreateDelegate(this.Execute, this);
    }
}
iSPFunctionExtender.prototype.Execute = function (arguments)
{
    var result = null;
    if (typeof this.PreExecute       == 'function') { this.PreExecute(); }
    if (typeof this.OriginalFunction == 'function') { result = this.OriginalFunction.apply(this, arguments); }
    if (typeof this.PostExecute      == 'function') { this.PostExecute(); }

    return result;
}
iSPFunctionExtender.prototype.OriginalFunction = null;
iSPFunctionExtender.prototype.PreExecute = function() {};
iSPFunctionExtender.prototype.PostExecute = function () { };										    
