Infoshare.SharePoint.ProfileFormExtender = function Infoshare$SharePoint$ProfileFormExtender(){}
iSPProfileFormExtender = Infoshare.SharePoint.ProfileFormExtender;
iSPProfileFormExtender.TypeName = 'Infoshare.SharePoint.ProfileFormExtender';
iSPProfileFormExtender.ExtenderType = iBehaviorExtender.ExtenderType.Page;
iSPProfileFormExtender.ClassInfo = null;

iSPProfileFormExtender.Extenders = new ISDictionary();
iSPProfileFormExtender.Initialize = function()
{
    if (!iSPProfileFormExtender.Extenders)
    {
        iSPProfileFormExtender.Extenders = new ISDictionary();
    }

    iBehaviorExtender.AddExtender(Infoshare.SharePoint.PageExtender, 'Infoshare.SharePoint.ProfileFormExtender', 'Infoshare.SharePoint.ProfileFormExtender');
}
iSPProfileFormExtender.CanExtend = function()
{
    var isTargetForm = iSPProfileFormExtender.IsProfileForm();
    return isTargetForm;
}

iSPProfileFormExtender.FormFileName = {
    // プロファイルフォーム定義
    ProfilForm: {
        EditForm: 'EditProfile.aspx'
    }
}

iSPProfileFormExtender.IsProfileForm = function()
{
    return iSPListFormExtender.IsTargetForm(iSPProfileFormExtender.FormFileName.ProfilForm.EditForm);
}

iSPProfileFormExtender.prototype = {
    TypeName: iSPProfileFormExtender.TypeName,
    ExtenderType: iSPProfileFormExtender.ExtenderType,

    FormControlInfos: null,
    Extenders: null,

    FormBodyClassName: 'ms-authoringcontrols',

    Extend: function()
    {
        if (!this.CanExtend())
        {
            return;
        }

        this.Extenders = iSPProfileFormExtender.Extenders;
        if (!this.Extenders ||
            this.Extenders.GetLength() <= 0)
        {
            return;
        }

        this.ExtendInternal();
    },

    ExtendInternal: function()
    {
        var infos = this.GetFormControlInfos();
        for (var i = 0; i < infos.GetLength(); i++)
        {
            var info = infos.Get(i);
            var extenderClassNames = this.Extenders.Get(info.Type);
            if (typeof(extenderClassNames) == 'string')
            {
                extenderClassNames = [extenderClassNames];
            }
            if (!(extenderClassNames instanceof Array))
            {
                continue;
            }

            for (var j = 0; j < extenderClassNames.length; j++)
            {
                var extenderClassName = extenderClassNames[j];
                if (extenderClassName)
                {
                    var extender = eval('new ' + extenderClassName + '();');
                    extender.ParentExtender = this;
                    extender.FormFieldInfo = info;
            
                    if (this.List &&
                        this.List.Fields.Contains(info.InternalName))
                    {
                        var field = this.List.Fields.Get(info.InternalName);
                        extender.FieldInfo = field;
                    }
                
                    if (extender.CanExtend())
                    {
                        extender.Extend();

                        if (!extender.AllowAdditionalExtension())
                        {
                            break;
                        }
                    }
                }
            }
        }
    },

    CanExtend: function()
    {
        return iSPProfileFormExtender.CanExtend();
    },

    AllowAdditionalExtension: function()
    {
        return true;
    },
    
    GetFormControlInfos: function()
    {
        if (this.FormControlInfos)
        {
            return this.FormControlInfos;
        }
        this.FormControlInfos = new ISDictionary();

        var formBodyCells = new Array();
        var cells = document.getElementsByTagName('td');
        for (var i = 0; i < cells.length; i++)
        {
            // form body セルを特定
            var cell = cells[i];
            if (cell.className.toLowerCase() != this.FormBodyClassName.toLowerCase())
            {
                continue;
            }
                
            // コントロール種別を判断する
            var guid = ISGuid.New();
            var info = new iSPFormFieldInfo(guid, guid, "");
            info.RowElement   = ISDomAccessor.GetParentElement(cell);
            info.BodyElement  = cell;
            var cell = info.BodyElement;

            // UserProfileのフォームでは単数・ユーザーのみのコントロールのみ許可されている
            // ToDo: 他の型のユーザーコントロールが使用できるか要調査
            var userEditor = i$(cell).find(".ms-usereditor");
            if (userEditor.length > 0)
            {
                info.Type = "User";
            }
            
            this.FormControlInfos.Add(info.InternalName, info);
        }

        return this.FormControlInfos;
    }
}
										    
