// -----------------------------------------------------------------------
//  PersonalConfigurationService
// -----------------------------------------------------------------------
Infoshare.PersonalConfigurationService = function Infoshare$PersonalConfigurationService()
{
    this.Configurations = new ISDictionary();

    // スレッドセーフに初期化処理を実施できるように、Initialize関数を拡張
    iAsyncInitializableExtender.Extend(this);
}
iPersonalConfigurationService = Infoshare.PersonalConfigurationService;
iPersonalConfigurationService.ListUrlName = 'InfosharePersonalConfiguration';
iPersonalConfigurationService.prototype = {
    List: null,
    Configurations: null,

    Load: function(callback)
    {
        var stopwatch = new ISStopwatch();
        stopwatch.Start();
        ISTrace.TraceVerbose('[BEGIN] iPersonalConfigurationService.Load');

        var service = this;
        this.Initialize(function()
        {
            var userId = iVxContext.CurrentUser.LoginName;
            if (service.Configurations.Contains(userId))
            {
                ISTrace.TraceVerbose('[END] iPersonalConfigurationService.Load (spent: ' + stopwatch.Stop() + ')');

                // ログインユーザーの構成情報を取得
                var config = service.Configurations.Get(userId);
                callback(config);
            }
            else
            {
                // キャッシュにヒットしない場合は再取得を試みる（新規作成時のキャッシュクリア対応）
                service.ensureConfiguration(userId, function()
                {
                    ISTrace.TraceVerbose('[END] iPersonalConfigurationService.Load (spent: ' + stopwatch.Stop() + ')');

                    config = service.Configurations.Get(userId);
                    callback(config);
                });
            }
        });
    },

    Save: function(config, callback)
    {
        var stopwatch = new ISStopwatch();
        stopwatch.Start();
        ISTrace.TraceVerbose('[BEGIN] iPersonalConfigurationService.Save');

        // 構成情報をテキスト形式（XML）に変換
        config.Serialize();

        // 更新処理
        var service = this;
        var webUrl = iVxContext.WebUrl;
        var list   = this.List;
        var items  = [ config.Item ];
        iVxService.UpdateItems(webUrl, list, items, function(updatedItems, result)
        {
            ISTrace.TraceVerbose('[END] iPersonalConfigurationService.Save (spent: ' + stopwatch.Stop() + ')');

            // 新規作成時にはアイテムの再取得が必要（ItemIDがわからないと更新処理ができない）
            // そのため、アイテムを再取得するようにキャッシュを破棄
            if (!config.Item.Id)
            {
                service.Configurations.Remove(config.Item.Properties[iPersonalConfiguration.FieldName.UserId]);
            }

            callback(updatedItems, result);
        });
    },

    Initialize: function(callback)
    {
        var service = this;
        iVxContext.Initialize(function()
        {
            service.ensureList(function()
            {
                service.ensureConfiguration(iVxContext.CurrentUser.LoginName, function()
                {
                    callback();
                });
            });
        });
    },

    ensureConfiguration: function(userId, callback)
    {
        if (!this.List)
        {
            ISTrace.TraceWarning('iPersonalConfigurationService.ensureConfiguration: Skipped to query the Personal Configuration for login user (no list avalabel).');

            callback();
        }

        // 自身の構成情報を取得する
        if (!this.Configurations.Contains(userId))
        {
            var webUrl     = iVxContext.WebUrl;
            var list       = this.List;
            var keys       = [ userId ];
            var fieldName  = iPersonalConfiguration.FieldName.UserId;
            var fieldType  = 'Text';
            var viewFields = [ iPersonalConfiguration.FieldName.UserId, 
                               iPersonalConfiguration.FieldName.Settings ];
            var service = this;
            iVxService.RetrieveItemsByKeys(webUrl, list, keys, fieldName, fieldType, viewFields, function(items)
            {
                // 複数取得できた場合、IDが最も大きいものを使用する
                var item = null;
                for (var i = 0; i < items.length; i++)
                {
                    if (item == null)
                    { 
                        item = items[i];
                    }
                    else
                    {
                        if (item.Id < items[i].Id)
                        {
                            item = items[i];
                        }
                    }
                }

                // 構成リストにアイテムが存在する場合は、アイテムから初期化
                // 存在しない場合には、新規にオブジェクトを作成
                var config = null;
                if (item) { config = iPersonalConfiguration.Create(item); }
                else      { config = new iPersonalConfiguration(userId); }
                service.Configurations.Add(config.UserId, config);

                callback();
            });
        }
        else
        {
            setTimeout(callback, 1);
        }
    },

    ensureList: function(callback)
    {
        if (!this.List)
        {
            // ToDo: サイトのURLを確認
            var service = this;
            iVxService.GetListByUrlName(iVxContext.WebUrl, iPersonalConfigurationService.ListUrlName, function(list)
            {
                ISTrace.TraceWarning('iPersonalConfigurationService.ensureList: Failed to access the Personal Configuration List.');

                service.List = list;
                callback();
            });
        }
        else
        {
            setTimeout(callback, 1);
        }
    }
};


// -----------------------------------------------------------------------
//  PersonalConfiguration
// -----------------------------------------------------------------------
Infoshare.PersonalConfiguration = function Infoshare$PersonalConfiguration(userId)
{
    this.UserId   = userId;
    this.Settings = new Array();
}
iPersonalConfiguration = Infoshare.PersonalConfiguration;
iPersonalConfiguration.ElementName = 'Settings';
iPersonalConfiguration.FieldName = { UserId:   'UserId',
                                     Settings: 'Settings' };
iPersonalConfiguration.Create = function(item)
{
    if (!item)
    {
        return;
    }

    var config = new Infoshare.PersonalConfiguration();
    config.Item   = item;
    config.UserId = item.Properties[iPersonalConfiguration.FieldName.UserId];

    // Settingsフィールドの値は以下の書式の想定
    // <Settings>
    //   <Setting Id='' Category='' xxx='' />
    //   <Setting Id='' Category='' xxx='' yyy='' />
    //   <Setting Id='' Category='' xxx='' yyy='' zzz='' />
    // </Settings>

    var settings = new Array();
    var settingsText = item.Properties[iPersonalConfiguration.FieldName.Settings];
    if (!ISString.IsNullOrEmpty(settingsText))
    {
        var doc = iXml.LoadXml(settingsText);
        var settingsElement = iXml.GetDocumentElement(doc);

        var settings = new Array();
        for (var i = 0; i < settingsElement.childNodes.length; i++)
        {
            var settingElement = settingsElement.childNodes[i];
            if (settingElement.nodeName.toUpperCase() != iPersonalSetting.ElementName.toUpperCase())
            {
                continue;
            }
        
            var setting = iPersonalSetting.FromXml(settingElement);
            settings.push(setting);
        }
    }
    config.Settings = settings;

    return config;
}
iPersonalConfiguration.prototype = {
    Item: null,

    UserId: null,
    Settings: null,

    GetSettings: function (comparer)
    {
        var settings = new Array();
        if (!comparer)
        {
            settings = this.Settings;
        }
        else
        {
            for (var i = 0; i < this.Settings.length; i++)
            {
                var setting = this.Settings[i];
                if (comparer(setting))
                {
                    settings.push(setting);
                }
            }
        }

        return settings;
    },

    GetSettingsByCategory: function(category)
    {
        var settings = this.GetSettings(function (setting)
        {
            return iString.Equals(setting.Category, category, true);
        });

        return settings;
    },

    // ToDo: いい名前ないかな
    Serialize: function()
    {
        var settings = '';
        for (var i = 0; i < this.Settings.length; i++)
        {
            var setting = this.Settings[i];
            settings += iPersonalSetting.ToXml(setting);
        }

        var template = "<{0}>{1}</{0}>";
        var xml = ISString.Format(template, iPersonalConfiguration.ElementName, settings);

        var item = new ISSPItem();
        if (this.Item)
        {
            // 取得済みのアイテムがある場合は、IDのみ再設定する
            // そのほかの属性を追加すると更新に支障が出るため（バージョン管理）
            item.Properties['ID'] = this.Item.Properties['ID'];
        }
        item.Properties[iPersonalConfiguration.FieldName.UserId]   = this.UserId;
        item.Properties[iPersonalConfiguration.FieldName.Settings] = xml;

        this.Item = item;
    }
};


// -----------------------------------------------------------------------
//  PersonalSetting
// -----------------------------------------------------------------------
Infoshare.PersonalSetting = function Infoshare$PersonalSetting()
{
    var attributes = new Array();
    attributes[iPersonalSetting.AttributeName.Id]       = ISGuid.New();
    attributes[iPersonalSetting.AttributeName.Category] = '';

    this.Properties = attributes;

    this.Id = this.Properties[iPersonalSetting.AttributeName.Id];
}
iPersonalSetting = Infoshare.PersonalSetting;
iPersonalSetting.ElementName = 'Setting';
iPersonalSetting.AttributeName = { Id:       'Id',
                                   Category: 'Category' };
iPersonalSetting.Category = { MyOrganization: 'MyOrganization',
                              Favorite:       'Favorite' };
iPersonalSetting.FromXml = function(element)
{
    // XMLから生成
    // 書式は以下を想定
    // ・Id, Categoryは必須属性
    // ・xxx, yyy, zzzは任意の値
    // <Setting Id='' Category='' xxx='' yyy='' zzz='' />

    var setting = new iPersonalSetting(); 
    setting.Properties = iXml.GetAttributesByArray(element);

    setting.Id       = setting.Properties[iPersonalSetting.AttributeName.Id];
    setting.Category = setting.Properties[iPersonalSetting.AttributeName.Category];

    return setting;
}
iPersonalSetting.ToXml = function(setting)
{
    // 設定情報をXML形式で出力
    // <Setting Id='' Category='' xxx='' yyy='' zzz='' />

    var attributes = '';
    for (var key in setting.Properties)
    {
        var value = setting.Properties[key];
        attributes += key + "='" + iXml.Escape(value) + "' ";
    }
    
    var template = "<{0} {1} />";
    var xml = ISString.Format(template, iPersonalSetting.ElementName, attributes);

    return xml;
}
iPersonalSetting.prototype = {
    Properties: null,

    Id: null,
    Category: null,

    Clone: function()
    {
        var clone = new iPersonalSetting();
        for (var key in this.Properties)
        {
            value = this.Properties[key];
            clone.Properties[key] = value;
        }

        clone.Id       = clone.Properties[iPersonalSetting.AttributeName.Id];
        clone.Category = clone.Properties[iPersonalSetting.AttributeName.Category];

        return clone;
    }
};
										    
