Infoshare.SharePoint.Administration.NavigationPage = function Infoshare$SharePoint$Administration$NavigationPage(parentElement, sectionsInfo, pageBaseName, pageName)
{
    this.ParentElement = parentElement ? parentElement : document;
    this.SectionsInfo  = sectionsInfo;
    this.PageBaseName  = pageBaseName;
    this.PageName      = pageName;
}

iNavigationPage = Infoshare.SharePoint.Administration.NavigationPage;

iNavigationPage.LayoutHtml =
"<table class='ms-linksection-column'>" +
  "<tbody>" +
  "%TableRow%" +
  "</tbody>" +
"</table>";

// {0}：セクションImageのリンク
// {1}：セクションタイトル
iNavigationPage.TableRowTemplateHtml =
"<tr class='ms-linksection-level1'>" +
  // ImageTd
  "<td class='ms-linksection-iconCell'>" +
    "<img alt='' src='{0}' >" +
  "</td>" +
  // MainTd
  "<td class='ms-linksection-textCell'>" +
    "<h3 class='ms-linksection-title'>{1}</h3>" +
    "<ul class='ms-linksection-listRoot'>" +
      "%LinkList%"
    "</ul>"
  "</td>" +
"</tr>";

// {0}：リンクタイトル
// {1}：リンクhref
// {2}：リンクテキスト
iNavigationPage.LinkListTemplate =
"<li class='ms-linksection-listItem'>" +
  "<a title='{0}' href='{1}'>{2}</a>"
"</li>";

// セパレーターRow定義
iNavigationPage.SeparatorRowHtml = "<tr height='30'></tr>";

iNavigationPage.prototype = {
    ParentElement: null,
    SectionsInfo: null,
    PageBaseName: null,
    PageName: null,

    Render: function()
    {
        if (!this.SectionsInfo)
        {
            return;
        }

        // ページタイトルの修正
        var pageName = this.PageName;
        var titleSpan = document.getElementById("DeltaPlaceHolderPageTitleInTitleArea");
        var anchors = titleSpan.getElementsByTagName("a");
        for (var i = 0; i < anchors.length; i++)
        {
            var anchor = anchors[i];
            if (ISString.Equals(anchor.innerHTML, this.PageBaseName, true))
            {
                anchor.innerHTML = pageName;
                break;
            }
        }
        document.title = pageName;

        // テンプレートHTMLの作成
        var tableHtml = "";
        for (var i = 0; i < this.SectionsInfo.GetLength(); i++)
        {
            var sectionInfo = this.SectionsInfo.Get(i);
            var resourceKey = sectionInfo.ResourceKey;
            var imageUrl = sectionInfo.ImageUrl;
            var text  = iResxResource.GetString(resourceKey + ".Text");
            var rowHtml = ISString.Format(iNavigationPage.TableRowTemplateHtml,
                                          imageUrl, text);

            // リンクの追加
            var linkListHtml = "";
            for (var j = 0; j < sectionInfo.LinkList.length; j++)
            {
                var linkListInfo = sectionInfo.LinkList[j];
                var linkListResourceKey = linkListInfo.ResourceKey;
                var linkListTitle = iResxResource.GetString(linkListResourceKey + ".Title");
                var linkListHref  = linkListInfo.Href;
                var linkListText = iResxResource.GetString(linkListResourceKey + ".Text");

                linkListHtml += ISString.Format(iNavigationPage.LinkListTemplate,
                                                linkListTitle, linkListHref, linkListText);
            }
            tableHtml += ISString.Replace(rowHtml, "%LinkList%", linkListHtml);

            //セパレーター用のTRの追加
            tableHtml += iNavigationPage.SeparatorRowHtml;
        }

        var pageContetsHtml = ISString.Replace(iNavigationPage.LayoutHtml, "%TableRow%", tableHtml);
        this.ParentElement.innerHTML = pageContetsHtml;
    }
}


