Infoshare.SharePoint.Administration.FeaturePage = function Infoshare$SharePoint$Administration$FeaturePage(parentElement, pageBaseName, pageName)
{
    this.ParentElement = parentElement ? parentElement : document;
    this.PageBaseName  = pageBaseName;
    this.PageName      = pageName;
}
iFeaturePage = Infoshare.SharePoint.Administration.FeaturePage;
iFeaturePage.TBodyId = "iFeaturePage_TBody";

// {0}: サイトコレクション:, {1}: 対象のサイトURL
iFeaturePage.PageHeader =
"<div style='padding-bottom: 10px; padding-left: 8px; font-size: 14px;'>{0}" +
    "<a href='{1}' >{1}</a>" +
"</div>";

// {0}: 名前 {1}:, 状態
iFeaturePage.Table =
"<table width='100%' border='0' cellspacing='0' cellpadding='0'>" +
  "<colgroup>" +
    "<col style='width: 5%;'>" +
    "<col style='width: 85%;'>" +
    "<col style='width: 5%;'>" +
    "<col style='width: 5%;'>" +
    "<tbody id='" + iFeaturePage.TBodyId + "'>" +
      "<tr>" +
        "<th class='ms-vh2' id='FeatureIcon' style='padding-bottom: 4px;' scope='col'></th>" +
        "<th class='ms-vh2-nofilter' id='FeatureTitleDescription' style='padding-bottom: 4px;' scope='col'>{0}</th>" +
        "<th class='ms-vh2-nofilter' id='FeatureActiveButton' style='padding-bottom: 4px;' scope='col'>&nbsp;</th>" +
        "<th class='ms-vh2-nofilter' id='FeatureActiveState' style='padding-bottom: 4px;' scope='col'>{1}</th>" +
      "</tr>" +
        // ここにそれぞれのフィーチャー用trを定義
  "</colgroup>" +
"</table>";

// {0}: FeatureTitle, {1}: FeatureDescription, {2}: アクティブ化ボタンID, {3}: 非アクティブ化ボタン,  {4}: アクティブ状態ラベル
iFeaturePage.FeatureTrTemplate =
// TD: フィーチャー画像
"<td style='padding: 4px 8px;'>" +
  "<img width='31' height='22' src='/_layouts/15/images/GenericFeature.gif'>" +
"</td>" +
// TD: フィーチャータイトル・説明
"<td style='padding-top: 4px; padding-bottom: 4px;'>" +
  "<table width='100%' border='0' cellspacing='0' cellpadding='0'>" +
    "<tbody>" +
      "<tr>" +
        "<td class='ms-vb2' style='font-weight: bold;'>" +
          "<h3 class='ms-standardheader'>{0}</h3>" + 
        "</td>" +
      "</tr>" +
      "<tr>" +
        "<td>{1}</td>" +
      "</tr>" +
    "</tbody>" +
  "</table>" +
"</td>" +
// TD: フィーチャーアクティブ・非アクティブ化ボタン
"<td style='padding-top: 4px; padding-bottom: 4px;'>" +
  "<div class='ms-vb2'>" +
    "<input id='{2}' class='ms-ButtonHeightWidth' type='button' value='{3}' style='width:80px;'>" +
  "</div>" +
"</td>" +
// TD: フィーチャーアクティブ・非アクティブ状態表示
"<td style='padding-top: 4px; padding-bottom: 4px;'>" +
  "<div class='ms-vb2 ms-featurestatus' id='StatusDiv' style='display:none;'>" +
    "<span class='ms-featurestatustext'>{4}</span>" +
  "</div>" +
"</td>";

iFeaturePage.prototype = {
    ParentElement: null,
    TargetSiteRelativeUrl: "",
    ScriptSiteRalativeUrl: "",
    Features: [],
    PageBaseName: null,
    PageName: null,

    Render: function()
    {
        // ページタイトルの修正
        var pageName = this.PageName;
        var titleSpan = document.getElementById("DeltaPlaceHolderPageTitleInTitleArea");
        var anchors = titleSpan.getElementsByTagName("a");
        for (var i = 0; i < anchors.length; i++)
        {
            var anchor = anchors[i];
            if (ISString.Equals(anchor.innerHTML, this.PageBaseName, true))
            {
                anchor.innerHTML = pageName;
                break;
            }
        }
        document.title = pageName;

        // ページヘッダー
        var pageheaderText = iResxResource.GetString("Page.FeatureManagement.SiteCollection");
        var targetAbsoluteUrl = iUri.GetAbsoluteUrl(this.TargetSiteRelativeUrl);
        var pageHeader = ISString.Format(iFeaturePage.PageHeader, pageheaderText, targetAbsoluteUrl);
        this.ParentElement.innerHTML += pageHeader;

        // テーブル
        var nameHeader = iResxResource.GetString("Page.FeatureManagement.FeatureHeader.Name");
        var statusHeader = iResxResource.GetString("Page.FeatureManagement.FeatureHeader.Status");
        var tableHtml = ISString.Format(iFeaturePage.Table, nameHeader, statusHeader);
        this.ParentElement.innerHTML += tableHtml;
        var bodyElm = document.getElementById(iFeaturePage.TBodyId);

        // Feature定義の取得
        var page = this;
        this.InitializeFeatures(function ()
        {
            // FeatureのTRを追加
            for (var i = 0; i < page.Features.length; i++)
            {
                var featureInfo = page.Features[i];
                var featureTr = page.RenderFeatureTr(bodyElm, featureInfo);

                var tr = document.getElementById(featureInfo.Id + "_Tr");
                // 背景色変更（奇数行）
                if (i % 2 == 1)
                {
                    tr.style.backgroundColor = "rgba(240, 240, 240, 1)";
                }
            }

            // FeatureのStatusの状態を反映
            page.UpdateFeatureStatus();
        });
    },

    InitializeFeatures: function(callback)
    {
        // ライセンス情報の初期化
        iLicenseService.GetCurrent().AdminSiteUrl = iVxContext.MasterSiteAbsolutePath;
        iLicenseService.GetCurrent().GetLicenses(iFunction.CreateDelegate(function (licenses)
        {
            this.InitializeFeaturesInternal(licenses, callback);
        }, this));
    },

    InitializeFeaturesInternal: function (licenses, callback)
    {
        // フィーチャー構成情報の初期化
        var page = this;
        iFeatureConfig.Initialize(function (config)
        {
            // 依存関係処理用のディクショナリを作成
            var featureIdDictionary = new ISDictionary();

            // フィーチャークラスの初期化
            for (var i = 0; i < config.Features.length; i++)
            {
                var feature = config.Features[i];
                feature.Initialize(page.TargetSiteRelativeUrl, page.ScriptSiteRalativeUrl);

                // 非表示フィーチャーは追加しない
                if (feature.FeatureInvisible)
                {
                    continue;
                }

                page.Features.push(feature);

                // ライセンス情報を設定
                if (feature.RequiredLicenseIds)
                {
                    feature.RequiredLicenses = new ISDictionary();
                    for (var j = 0; j < feature.RequiredLicenseIds.length; j++)
                    {
                        var licenseId = feature.RequiredLicenseIds[j];
                        var license = licenses.Get(licenseId);
                        if (license)
                        {
                            feature.RequiredLicenses.Add(licenseId, license);
                        }                        
                    }                    
                }

                featureIdDictionary.Add(feature.Id, feature);
            }

            // 依存関係情報を設定
            for (var i = 0; i < featureIdDictionary.GetLength(); i++)
            {
                var feature = featureIdDictionary.Get(i);
                feature.DependenceParentFeatures = [];
                feature.DependenceChildFeatures  = [];

                // 依存フィーチャー情報を設定：親
                for (var j = 0; j < feature.DependenceParentFeatureIds.length; j++)
                {
                    var featureId = feature.DependenceParentFeatureIds[j];
                    var parentFeature = featureIdDictionary.Get(featureId);
                    if (parentFeature) feature.DependenceParentFeatures.push(parentFeature);
                }

                // 依存フィーチャー情報を設定：子
                for (var j = 0; j < feature.DependenceChildFeatureIds.length; j++)
                {
                    var featureId = feature.DependenceChildFeatureIds[j];
                    var childFeature = featureIdDictionary.Get(featureId);
                    if (childFeature) feature.DependenceChildFeatures.push(childFeature);
                }
            }

            callback();
        });
    },

    RenderFeatureTr: function(bodyElm, featureInfo)
    {
        var featureTr = document.createElement("tr");
        featureTr.id = featureInfo.Id + "_Tr";
        featureInfo.FeatureRow = featureTr;

        // リソース設定
        var resourceObject = featureInfo.Resource ? featureInfo.Resource : iResxResource;
        var featureTitle = resourceObject.GetString(featureInfo.ResourceKey + ".Title");
        featureInfo.Title = featureTitle;
        var featureDescription = resourceObject.GetString(featureInfo.ResourceKey + ".Description");
        var featureButtonId = featureInfo.Id + "_FeatureButton";
        var deactivateButtonLabel = iResxResource.GetString("Feature.Activate");
        var activeStatusLabel = iResxResource.GetString("Feature.Active");
        var trHtml = ISString.Format(iFeaturePage.FeatureTrTemplate,
                                     featureTitle,
                                     featureDescription,
                                     featureButtonId,
                                     deactivateButtonLabel,
                                     activeStatusLabel);
        featureTr.innerHTML = trHtml;
        bodyElm.appendChild(featureTr);

        // アクティブ化関数の定義
        var featureButton = document.getElementById(featureInfo.Id + "_FeatureButton");
        featureButton.onclick = ISFunction.CreateDelegate(featureInfo.OnclickFunction, featureInfo);        

        return featureTr;
    },

    UpdateFeatureStatus: function()
    {
        var featurePage = this;
        for(var i = 0; i < this.Features.length; i++)
        {
            var featureInfo = this.Features[i];            
            featureInfo.EnsureActiveStatus(function (isActive, feature)
            {
                feature.UpdateFeatureDisplayStatus(isActive);
            });
        }
    }
}

														
