// {0}:ライセンスカード
iLicenseControl.LicenseDivTemplate = 
"<div style='padding-top: 15px;'>" +
  "{0}" +
"</div>";

iLicenseControl.prototype = {
    ParentElement: null,
    ResourceKey: null,

    Render: function()
    {
        // 製品情報（登録済ライセンス情報）の取得
        iLicenseService.GetCurrent().AdminSiteUrl = iVxContext.MasterSiteAbsolutePath;
        iLicenseService.GetCurrent().GetLicenses(iFunction.CreateDelegate(function (licenses)
        {
            // テンプレート
            var licenseControlHtml = "";
            if (licenses && licenses.GetLength() > 0)
            {       
                for (var i = 0; i < licenses.GetLength(); i++)
                {                    
                    var license = licenses.Get(i);
                    
                    // ライセンスカードHTML作成
                    var licenseCard = new iLicenseCard(license);

                    var licenseDivHtml = ISString.Format(iLicenseControl.LicenseDivTemplate,
                                                         licenseCard.Element.outerHTML);

                    licenseControlHtml += licenseDivHtml;                    
                }
            }

            this.ParentElement.innerHTML = licenseControlHtml;
        }, this));
    }
}
														
