// -----------------------------------------------------------------------
//  ProductControl
// -----------------------------------------------------------------------
Infoshare.SharePoint.Administration.ProductControl = function Infoshare$SharePoint$Administration$ProductControl() { }

iProductControl = Infoshare.SharePoint.Administration.ProductControl;
iProductControl.TBodyId = "Infoshare.SharePoint.Administration.ProductControl_TBody";

// {0}:TBodyID
iProductControl.TableTemplate =
"<table class='border-collapse: collapse;' style='width: 800px; border-collapse: collapse;' cellspacing='0' cellpadding='0'>" +
  "<tbody id='{0}'>" +
  "</tbody>" +
"</table>";

// {0}：製品名
// {1}：バージョン
// {2}：ライセンス
// {3}：有効期限
// {4}：状態
iProductControl.TableHeaderTemplate =
"<tr align='left'>" +
  "<th width='150' align='left' class='ms-vh2-nofilter'>{0}</th>" +
  "<th width='150' align='left' class='ms-vh2-nofilter'>{1}</th>" +
  "<th width='150' align='left' class='ms-vh2-nofilter'>{2}</th>" +
  "<th width='150' align='left' class='ms-vh2-nofilter'>{3}</th>" +
  "<th width='150' align='left' class='ms-vh2-nofilter'>{4}</th>" +
"</tr>";

// {0}：製品名
// {1}：バージョン
// {2}：ライセンス
// {3}：有効期限
// {4}：状態
iProductControl.ProductRowTemplate =
"<tr>" +
  "<td align='left'>{0}</td>" +
  "<td align='left'>{1}</td>" +
  "<td align='left'>{2}</td>" +
  "<td align='left'>{3}</td>" +
  "<td align='left'>{4}</td>" +
"</tr>";

iProductControl.prototype = {
    ParentElement: null,
    ContentInfo: null,
    TBodyElement: null,
    ResourceKey: null,
    ProductInfomations: null,
    LicenseInfomations: null,

    Render: function()
    {
        // テンプレート
        var tableTemplate = ISString.Format(iProductControl.TableTemplate, this.TBodyId);
        this.ParentElement.innerHTML = tableTemplate;

        // ヘッダーの作成
        this.InitializeHeader();

        // 製品情報、ライセンス情報の取得
        this.EnsureProductAndLicenseInfo(ISFunction.CreateDelegate(function ()
        {
            var productRowsHtml = "";
            if (this.ProductInfomations &&
                this.ProductInfomations.GetLength() > 0)
            {
                for (var i = 0; i < this.ProductInfomations.GetLength(); i++)
                {
                    var productInfo = this.ProductInfomations.Get(i);
                    // 製品名、バージョン、ライセンス種別
                    var productName    = productInfo.Properties.Name    ? productInfo.Properties.Name    : "";
                    var productVersion = productInfo.Properties.Version ? productInfo.Properties.Version : "";
                    var type = "";
                    var remainingDays = "";
                    var status = "";

                    var licenseKey = iLicense.LicenseKeyPrefix + "." + productName;
                    var licenseInfo = this.LicenseInfomations.Get(licenseKey);

                    // GroupPickerライセンスが登録されていない場合、InfoCallライセンスも参照する
                    if (licenseKey == iLicense.GroupPickerKey &&
                        !licenseInfo)
                    {
                        licenseInfo = this.LicenseInfomations.Get(iLicense.InfoCallKey);
                    }

                    if (licenseInfo)
                    {
                        type = iLicense.GetTypeDisplayName(licenseInfo.Properties.Type);

                        // 有効期限
                        remainingDays = 'n/a';
                        if (!iLicense.IsPerpetualType(licenseInfo.Properties.Type))
                        {
                            remainingDays = licenseInfo.Properties.RemainingDays;
                            if (!remainingDays ||
                                remainingDays < -1 * iLicense.GracePeriod)
                            {
                                // 超過、失効ケース
                                remainingDays = iResxResource.GetString(this.ResourceKey + ".Expired");
                            }
                            else if (remainingDays <= 0 && remainingDays >= -1 * iLicense.GracePeriod)
                            {
                                // 超過、猶予期間ケース
                                remainingDays = ISString.Format('{0}{1}', -1 * remainingDays, iResxResource.GetString(this.ResourceKey + ".OverdueUnit"));
                            }
                            else
                            {
                                // 正常ケース
                                remainingDays = ISString.Format('{0}{1}', remainingDays, iResxResource.GetString(this.ResourceKey + ".ExpirationUnit"));
                            }
                        }

                        // 検証までの期間（ライセンスが有効で、期限切れでない場合のみ）
                        if (licenseInfo.Varid &&
                            remainingDays != iResxResource.GetString(this.ResourceKey + ".Expired"))
                        {
                            remainingDaysforValidation = licenseInfo.Properties.RemainingDaysForValidation;
                            if (licenseInfo.Properties.Type == iLicense.Type.Internal)
                            {
                                remainingDays = ISString.Format('{0}', remainingDays);
                            }
                            else
                            {
                                if (!remainingDaysforValidation ||
                                    remainingDaysforValidation <= 0)
                                {
                                    remainingDays = iResxResource.GetString(this.ResourceKey + ".NeedValidate");
                                }
                                else
                                {
                                    remainingDaysforValidation = ISString.Format('{0}{1}', remainingDaysforValidation, iResxResource.GetString(this.ResourceKey + ".ExpirationUnit"));
                                    remainingDays = ISString.Format('{0} ({1})', remainingDays, remainingDaysforValidation);
                                }
                            }
                        }

                        // 状態
                        var statusKeySuffix = '.Status.Valid';
                        if (ISBoolean.TryParse(licenseInfo.Valid, false)) { statusKeySuffix = '.Status.Valid'; }
                        else                                              { statusKeySuffix = '.Status.Invalid'; }

                        // 違反状態を確認
                        if (ISBoolean.TryParse(licenseInfo.Valid, false) && ISBoolean.TryParse(licenseInfo.Violating, false)) { statusKeySuffix = '.Status.Violating'; }

                        status = iResxResource.GetString(this.ResourceKey + statusKeySuffix);
                    }

                    var productRow = ISString.Format(iProductControl.ProductRowTemplate,
                                                     productName,
                                                     productVersion,
                                                     type,
                                                     remainingDays,
                                                     status);
                    productRowsHtml += productRow;
                }
            }            
            this.TBodyElement.innerHTML += productRowsHtml;
        }, this));
    },

    InitializeHeader: function()
    {
        // TBodyの取得
        var tbody = document.getElementById(this.TBodyId);
        this.TBodyElement = tbody;

        var productName   = iResxResource.GetString(this.ResourceKey + ".ProductName");
        var version       = iResxResource.GetString(this.ResourceKey + ".Version");
        var type          = iResxResource.GetString(this.ResourceKey + ".Type");
        var remainingDays = iResxResource.GetString(this.ResourceKey + ".RemainingDays");
        var status        = iResxResource.GetString(this.ResourceKey + ".Status");

        var headerRow = ISString.Format(iProductControl.TableHeaderTemplate,
                                        productName,
                                        version,
                                        type,
                                        remainingDays,
                                        status);

        this.TBodyElement.innerHTML += headerRow;
    },

    EnsureProductAndLicenseInfo: function(callback)
    {
        // Context
        var asyncContext = {
            ProductInfoEnsured: false,
            LicenseInfoEnsured: false,

            Complete: function()
            {
                return this.ProductInfoEnsured && this.LicenseInfoEnsured;
            }
        };

        // プロダクト情報の取得
        iProductService.GetCurrent().AdminSiteUrl = iVxContext.MasterSiteAbsolutePath;
        iProductService.GetCurrent().GetProducts(iFunction.CreateDelegate(function (products)
        {
            this.ProductInfomations = products;
            asyncContext.ProductInfoEnsured = true;
            if (asyncContext.Complete())
            {
                callback();
            }
        }, this));

        // ライセンス情報の取得
        iLicenseService.GetCurrent().AdminSiteUrl = iVxContext.MasterSiteAbsolutePath;
        iLicenseService.GetCurrent().GetLicenses(iFunction.CreateDelegate(function (licenses)
        {
            this.LicenseInfomations = licenses;
            asyncContext.LicenseInfoEnsured = true;
            if (asyncContext.Complete())
            {
                callback();
            }
        }, this));
    }
}
														
