Infoshare.SharePoint.Administration.SiteCollectionControl = function Infoshare$SharePoint$Administration$SiteCollectionControl() { }

iSiteCollectionControl = Infoshare.SharePoint.Administration.SiteCollectionControl;
iSiteCollectionControl.SiteCollectionsUserCustomActionTitle = "Infoshare.ProductManagement.UserCustomAction.SiteCollections";
iSiteCollectionControl.SiteSettingsUserCustomActionTitle    = "インフォシェア製品 機能 / <br> Infoshare Product Features";

iSiteCollectionControl.SiteUserCustomActionInfo = {
    Title      : iSiteCollectionControl.SiteCollectionsUserCustomActionTitle,
    ScriptSrc  : '',
    ScriptBlock: '',
    Sequence   : 10010,
    Description: 'Infoshare ProductManagement SiteCollections'
};

// {0}：展開先のサイト コレクションを入力:
// {1}：展開先のサイト コレクション:
// {2}：PageId: Infoshare.SharePoint.Administration.SiteCollectionControl 
// {3}：_ButtonAddSite       :ボタン表示名
// {4}：_ButtonRemoveSite    :ボタン表示名
iSiteCollectionControl.TableTemplate =
"<table width='750'>" +
  "<tbody>" +
    // ヘッダー行
    "<tr>" +
      "<td class='ms-authoringcontrols' colspan='3'>" +
        "{0}" +
      "</td>" + 
    "</tr>" +
    // サイトコレクション追加行：入力テキストボックス、ボタン
    "<tr>" +
      "<td class='ms-authoringcontrols'>" +
        "<input title='{1}' class='ms-input' id='{2}_SiteTextBox' style='width: 640px;' type='text' size='35' >" +
      "</td>" +
      "<td>" +
        "&nbsp;" +
      "</td>" +
      "<td>" +
        "<input class='ms-ButtonHeightWidth' id='{2}_ButtonAddSite' style='width: 80px;' type='button' value='{3}' >" +
      "</td>" +
    "</tr>" +
    // エラーメッセージ表示行：ラベル
    "<tr>" +
      "<td class='ms-error' colspan='3' height=20>" +
        "<span id='{2}_SiteTextBoxErrorMessageLabel' ></span>" +
      "</td>" + 
    "</tr>" +
    // 改行用の行
    "<tr>" +
      "<td>" +
        "&nbsp;" +
      "</td>" +
    "</tr>" +
    // グリッドラベル：展開先のサイト コレクション:
    "<tr>" +
      "<td class='ms-authoringcontrols' colspan='3'>" +
        "{1}" +
      "</td>" +
    "</tr>" +
    // グリッド行：グリッド、削除ボタン
    "<tr>" +
      "<td class='ms-authoringcontrols'>" +
        "<div id='{2}_SiteCollectionGrid' style='width: 650px; height: 260px; border: 1px solid #ababab;'>" +
      "</td>" +
      "<td>" +
        "&nbsp;" +
      "</td>" +
      "<td valign='top'>" +
        "<input class='ms-ButtonHeightWidth' id='{2}_ButtonRemoveSite' style='width: 80px;margin-bottom: 10px;' type='button' value='{4}'>" +
      "</td>" +
    "</tr>" +
  "</tbody>" +
"</table>";

iSiteCollectionControl.prototype = {
    ParentElement: null,
    Id: null,
    ResourceKey: null,
    SiteTextBox: null,
    SiteTextBoxErrorMessageLabel: null,
    SiteUserCustomAction: null,
    SiteCollections: null,

    AddSiteButton: null,
    RemoveSiteButton: null,
    SiteCollectionView: null,

    ReloadPage: function()
    {
        window.location.reload(true);
    },

    Render: function()
    {
        var page = this;
        // HTMLの生成
        var siteTextBoxHeaderText        = iResxResource.GetString(page.ResourceKey + ".SiteTextBox.HeaderText");
        var siteCollectionGridHeaderText = iResxResource.GetString(page.ResourceKey + ".SiteCollectionGrid.HeaderText");
        var addSiteButtonText            = iResxResource.GetString(page.ResourceKey + ".ButtonAddSite.Text");
        var removeSiteButtonText         = iResxResource.GetString(page.ResourceKey + ".ButtonRemoveSite.Text");

        var tableHtml = ISString.Format(iSiteCollectionControl.TableTemplate,
                                        siteTextBoxHeaderText,
                                        siteCollectionGridHeaderText,
                                        page.Id,
                                        addSiteButtonText,
                                        removeSiteButtonText);
        page.ParentElement.innerHTML = tableHtml;

        page.InitializeContents();
    },

    InitializeContents: function()
    {
        // サイトコレクション一覧の確認
        this.EnsureSiteCollections();

        // グリッドの初期化
        this.InitializeGrid();

        // 各ボタンのクリックイベント・初期状態の設定
        this.InitializeButtons();

        // テキストインプットイベントの初期化
        this.InitializeSiteTextBox();
    },

    EnsureSiteCollections: function()
    {
        if (!this.SiteCollections)
        {
            this.SiteCollections = [];
        }

        if (typeof (ProductManagementPageContext) != 'undefined' &&
            typeof (ProductManagementPageContext.SiteCollectionsString) != 'undefined' &&
            ProductManagementPageContext.SiteCollectionsString)
        {
            this.SiteCollections = ISJSON.parse(ProductManagementPageContext.SiteCollectionsString);
        }
    },

    EnsureSiteUserCustomAction: function()
    {
        // スクリプトブロックの設定
        var scriptBlockUca = iSiteCollectionControl.SiteUserCustomActionInfo;
        var scriptBlock = function ()
        {
            try
            {
                if (typeof (ProductManagementPageContext) == 'undefined')
                {
                    ProductManagementPageContext = {};
                }
                ProductManagementPageContext.SiteCollectionsString = '{0}';
            }
            catch(e){}
        };

        var jsonString = ISJSON.stringify(this.SiteCollections);

        // Releaseビルド用の対応：AjaxMinifierがシングルクォートをダブルクォートに置換する為、ダブルクォートをエスケープする
        jsonString = ISString.Replace(jsonString, "\"", "\\\"");
        var scriptBlockString = ISString.Format(scriptBlock.toString(), jsonString);
        // 無名関数を即時関数で登録する
        scriptBlockUca.ScriptBlock = "(" + scriptBlockString + ")();";

        // インストーラーの参照用プロパティとして、Descriptionにサイトコレクション一覧のURLをカンマ区切りのテキストで設定する
        var description = "";
        for (var i = 0; i < this.SiteCollections.length; i++)
        {
            description += this.SiteCollections[i].RelativeUrl;
            description += ",";
        }
        description = ISString.TrimEnd(description, ',');
        scriptBlockUca.Description = description;

        this.SiteUserCustomAction = scriptBlockUca;
    },    

    InitializeGrid: function()
    {
        // igGridの初期化
        var page = this;
        var gridParentElent = document.getElementById(page.Id + "_SiteCollectionGrid");
        iIgFileLoader.Load(function ()
        {
            // アイテム定義の作成
            var items = page.GetGridItems();
            var siteCollectionView = new iSiteCollectionView();            
            siteCollectionView.Render(gridParentElent);
            siteCollectionView.UpdateGrid(items);

            // アイテム選択関連のイベント定義
            siteCollectionView.ItemSelectedEventHandler = ISFunction.CreateDelegate(page.OnViewItemSelected, page);

            // Viewをキャッシュ
            page.SiteCollectionView = siteCollectionView;
        });
    },

    GetGridColumns: function ()
    {
        var columnDefinitions = [];

        var columns = iIgGridUtility.BuildColumns(columnDefinitions);
        return columns;
    },

    GetGridItems: function ()
    {
        var items = [];
        for (var i = 0; i < this.SiteCollections.length; i++)
        {
            var siteCollection = this.SiteCollections[i];
            var gridItem = {
                RelativeUrl: siteCollection.RelativeUrl,
                AbsoluteUrl: iUri.GetAbsoluteUrl(siteCollection.RelativeUrl),
                SiteSettingsLink: iUri.GetAbsoluteUrl(iVxContext.MasterSourcesPath) 
                                  + "/Infoshare/FeatureManagement.aspx?site="
                                  + siteCollection.RelativeUrl
            };

            items.push(gridItem);
        }

        return items;
    },
    
    OnViewItemSelected: function()
    {
        // 削除ボタンを有効化
        this.RemoveSiteButton.disabled = false;
    },

    InitializeSiteTextBox: function ()
    {      
        var siteTextBox = document.getElementById(this.Id + "_SiteTextBox");
        this.SiteTextBox = siteTextBox;

        // URL検証のイベント追加
        // oninput：http://www.w3schools.com/jsref/event_oninput.asp
        this.SiteTextBox.oninput = ISFunction.CreateDelegate(this.ValidateSiteTextBoxValue, this);
    },

    ValidateSiteTextBoxValue: function()
    {
        var valid = true;
        var errorMessage = "";
        // エラー表示ラベルの確認
        if (!this.SiteTextBoxErrorMessageLabel)
        {
            var alertLabel = document.getElementById(this.Id + "_SiteTextBoxErrorMessageLabel");
            this.SiteTextBoxErrorMessageLabel = alertLabel;
        }

        for (; ;)
        {
            var inputValue = this.SiteTextBox.value;

            // 空の場合
            if(ISString.IsNullOrEmpty(inputValue))
            {
                errorMessage = "";
                valid = false;
                break;
            }

            // ホスト名の確認（現在のURLとホスト名が異なる場合警告）
            var hostUrl = location.protocol + "//" + location.host;
            var hostUrlWithEndSlash = hostUrl + "/";
            var inputValueWithEndSlash = inputValue + "/";
            // ホスト名の前方一致の確認（エラーメッセージは空で出すが、ボタンは非アクティブ状態にする）
            if (!ISString.Equals(hostUrl, inputValue, true) &&
                ISString.StartsWith(hostUrl, inputValue, true))
            {
                errorMessage = "";
                valid = false;
                break;
            }
            else if (!ISString.StartsWith(inputValueWithEndSlash, hostUrlWithEndSlash, true))
            {
                errorMessage = iResxResource.GetString(this.ResourceKey + ".SiteTextBoxErrorMessageLabel.InvalidHost");
                valid = false;
                break;
            }
        
            // 重複確認
            if (this.SiteCollections.length > 0)
            {
                var duplicate = false;
                for(var i = 0; i< this.SiteCollections.length; i++)
                {
                    var site = this.SiteCollections[i];
                    var siteRelativeUrl = site.RelativeUrl;
                    var inputAsRelativeUrl = this.GetSiteTextBoxValueAsRelativeUrl();
                    if(ISString.Equals(inputAsRelativeUrl, siteRelativeUrl, true))
                    {
                        duplicate = true;
                        break;
                    }
                }
                if(duplicate)
                {
                    errorMessage = iResxResource.GetString(this.ResourceKey + ".SiteTextBoxErrorMessageLabel.Dupulicate");
                    valid = false;
                }
                break;
            }

            break;
        }

        if(valid)
        {
            this.SiteTextBoxErrorMessageLabel.innerHTML = "";
            this.AddSiteButton.disabled = false; 
        }
        else
        {
            this.SiteTextBoxErrorMessageLabel.innerHTML = errorMessage;
            this.AddSiteButton.disabled = true; 
        }
    },

    InitializeButtons: function()
    {
        var addSiteButton = document.getElementById(this.Id + "_ButtonAddSite");
        var removeSiteButton = document.getElementById(this.Id + "_ButtonRemoveSite");

        addSiteButton.onclick = ISFunction.CreateDelegate(this.AddSite, this);
        removeSiteButton.onclick = ISFunction.CreateDelegate(this.RemoveSite, this);

        // 各ボタンは初期化時は無効
        addSiteButton.disabled = true;
        removeSiteButton.disabled = true;

        this.AddSiteButton = addSiteButton;
        this.RemoveSiteButton = removeSiteButton;
    },

    AddSite: function()
    {
        // ダブルクリック対応
        if (this.RunningAddSite)
        {
            return;
        }

        this.RunningAddSite = true;
        var siteRelativeUrl = this.GetSiteTextBoxValueAsRelativeUrl();
        var page = this;
        this.ValidateSiteUrl(function(valid)
        {
            if (valid)
            {
                // 対象サイトのサイト設定に機能管理ページへのリンクを追加
                page.AddSiteSettingsUserCustomAction(function ()
                {
                    // サイトオブジェクトの作成
                    var siteObject = {
                        RelativeUrl: siteRelativeUrl
                    }
                    page.SiteCollections.push(siteObject);

                    // スクリプトブロックUserCustomActionの更新
                    page.UpdateSiteUserCustomActions(function ()
                    {
                        page.RunningAddSite = false;
                        page.ReloadPage();
                    })       
                });         
            }
            else
            {
                page.RunningAddSite = false;
            }
        });        
    },

    RemoveSite: function()
    {
        // ダブルクリック対応
        if (this.RunningRemoveSite)
        {
            return;
        }
        this.RunningRemoveSite = true;

        // Deactivate処理
        var page = this;
        this.RemoveSiteSettingsUserCustomActions(function ()
        {
            var newSiteCollections = [];
            var selectedSiteCollections = page.SiteCollectionView.SelectedItems;
            // SiteCollections設定の更新（選択されたサイトコレクションを削除する）
            for (var i = 0; i < page.SiteCollections.length; i++)
            {
                var removeFlag = false;
                var site = page.SiteCollections[i];
                for (var j = 0; j < selectedSiteCollections.length; j++)
                {
                    var selectedSite = selectedSiteCollections[j];
                    if (ISString.Equals(site.RelativeUrl, selectedSite.RelativeUrl, true))
                    {
                        removeFlag = true;
                        break;
                    }
                }

                if(!removeFlag)
                {
                    newSiteCollections.push(site);
                }
            }

            page.SiteCollections = newSiteCollections;
            // スクリプトブロックUserCustomActionの更新
            page.UpdateSiteUserCustomActions(function ()
            {
                this.RunningRemoveSite = false;
                page.ReloadPage();
            });
        });
    },
    
    AddSiteSettingsUserCustomAction: function(callback)
    {
        var targetSiteRelativeUrl = this.GetSiteTextBoxValueAsRelativeUrl();
        var absoluteUrl = iUri.GetAbsoluteUrl(targetSiteRelativeUrl);
        var ucaService = new SRUserCustomActionsService(absoluteUrl, absoluteUrl, false);
        var ucaTitle = iSiteCollectionControl.SiteSettingsUserCustomActionTitle;

        // クエリストリング相対パスで登録
        var linkUrl = iUri.GetAbsoluteUrl(iVxContext.MasterSourcesPath)
                    + "/Infoshare/FeatureManagement.aspx?site="
                    + targetSiteRelativeUrl;
        ucaService.AddUserCustomActionForSiteSettings(ucaTitle,
                                                      SRUserCustomActionsService.SiteSettingsGroup.SiteCollectionAdmin,
                                                      "Infoshare FeatureManagement Link",
                                                      linkUrl,
                                                      "10000",
                                                      function ()
        {
            callback();
        });
    },

    RemoveSiteSettingsUserCustomActions: function(callback)
    {
        var selectedSiteCollections = this.SiteCollectionView.SelectedItems;
        if (selectedSiteCollections.length < 1)
        {
            callback();
        }

        var siteCount = selectedSiteCollections.length;
        var removeUcaContext = {
            removedCount: 0,
            Completed: function()
            {
                return this.removedCount == siteCount;
            }
        };

        var removeUcaCallback = function()
        {
            removeUcaContext.removedCount ++;
            if(removeUcaContext.Completed())
            {
                callback();
            }
        };
                
        for (var i = 0; i < siteCount; i++)
        {
            var targetSite = selectedSiteCollections[i];
            // 別サイトへのリクエストを実行するため、コンテキストキャッシュを削除
            ISSPContextWebInformation.Current = null;
            var ucaService = new SRUserCustomActionsService(targetSite.AbsoluteUrl, targetSite.AbsoluteUrl, false);          
            var page = this;
            page.RemoveSiteSettingsUserCustomAction(ucaService, function ()
            {
                removeUcaCallback();
            });
        }
    },

    RemoveSiteSettingsUserCustomAction: function(ucaService, callback)
    {
        var ucaTitle = iSiteCollectionControl.SiteSettingsUserCustomActionTitle;
        ucaService.GetUserCustomActionByTitle(ucaTitle, function (userCustomAction)
        {
            if (userCustomAction)
            {
                ucaService.DeleteUserCustomAction(userCustomAction.Id, function ()
                {
                    callback();
                });
            }
            else
            {
                callback();
            }
        });
    },
    GetSiteTextBoxValueAsRelativeUrl: function()
    {
        var value = null;
        if (!this.SiteTextBox)
        {
            this.SiteTextBox = document.getElementById(this.Id + "_SiteTextBox");
        }
        var value = this.SiteTextBox.value;
        var relativeUrl = iUri.GetRelativeUrl(value);

        return relativeUrl;        
    },

    ValidateSiteUrl: function(callback)
    {
        var valid = false;
        var relativeUrl = this.GetSiteTextBoxValueAsRelativeUrl();
        var absoluteUrl = iUri.GetAbsoluteUrl(relativeUrl);

        // サイトURLの検証（存在チェック）
        var getSiteCallback = ISFunction.CreateDelegate(function (site)
        {
            if (site)
            {
                valid = true;
            }
            // 存在しない場合
            else
            {
                // アラートラベルに警告
                var errorMessage = iResxResource.GetString(this.ResourceKey + ".SiteTextBoxErrorMessageLabel.NotFound");
                this.SiteTextBoxErrorMessageLabel.innerHTML = errorMessage;
                this.AddSiteButton.disabled = true; 
            }

            callback(valid);
        }, this);

        // サイトの取得
        var service = iVxService.GetSiteService(absoluteUrl);
        service.GetSite(absoluteUrl, getSiteCallback);    
    },

    UpdateSiteUserCustomActions: function(callback)
    {
        // 別サイトへのリクエストを実行するため、コンテキストキャッシュを削除
        ISSPContextWebInformation.Current = null;
        var ucaService = new SRUserCustomActionsService(iVxContext.SiteUrl, iVxContext.SiteUrl, false);
        var ucaTitle = iSiteCollectionControl.SiteCollectionsUserCustomActionTitle;
        var page = this;
        ucaService.GetUserCustomActionByTitle(ucaTitle, function (userCustomAction)
        {
            if (userCustomAction)
            {
                ucaService.DeleteUserCustomAction(userCustomAction.Id, function ()
                {
                    page.AddSiteUserCustomActions(ucaService, callback);
                });
            }
            else
            {
                page.AddSiteUserCustomActions(ucaService, callback);
            }
        });
    },

    AddSiteUserCustomActions: function(ucaService, callback)
    {
        this.EnsureSiteUserCustomAction();
        ucaService.AddUserCustomActionForScriptLink(this.SiteUserCustomAction.Title,
                                                    this.SiteUserCustomAction.ScriptSrc,
                                                    this.SiteUserCustomAction.ScriptBlock,
                                                    this.SiteUserCustomAction.Sequence,
                                                    this.SiteUserCustomAction.Description,
                                                    function ()
        {
            callback();
        });
    }
}
														
