// -----------------------------------------------------------------------
//  Feature
// -----------------------------------------------------------------------
Infoshare.SharePoint.Administration.FeatureControl = function Infoshare$SharePoint$Administration$Feature() { }
iFeatureControl = Infoshare.SharePoint.Administration.FeatureControl;
iFeatureControl.Status = {
    Active: "Active",
    Inactive: "Inactive",
    Unknown: "Unknown"
};
iFeatureControl.prototype = {
    Id: null,
    ResourceKey: null,
    Service: null,
    TargetSiteRelativeUrl: "",
    ScriptSiteRelativeUrl: "",
    
    FeatureRow: null,
    TargetIsMasterSite: false,

    // フィーチャーの項目自体の表示制御フラグ（通常サイトと管理サイト）
    HiddenInMasterSite: false,
    HiddenInNormalSite: false,
    FeatureInvisible: false,

    // 依存するフィーチャー
    DependenceParentFeatures: null,
    DependenceParentFeatureIds: null,

    // 依存されているフィーチャー
    DependenceChildFeatures: null,
    DependenceChildFeatureIds: null,

    // ライセンス情報
    RequiredLicenses: null,
    RequiredLicenseIds: null,

    OnclickFunction: function()
    {
        if (this.Status == iFeatureControl.Status.Active)
        {
            // 依存フィーチャーの検証：依存されているフィーチャーすべてが非アクティブな場合のみ非アクティブイベントを実行
            var activeFeatures = this.GetActiveDependFeatures(this.DependenceChildFeatures);
            if (activeFeatures.length > 0)
            {
                // 警告
                var message = iResxResource.GetString("Feature.Validation.ExistActiveDependentFeatures");
                var featuresLine = "";
                for (var i = 0; i < activeFeatures.length; i++)
                {
                    featuresLine += ISString.Format("{0}\n\r", activeFeatures[i].Title);
                }

                alert(ISString.Format(message, featuresLine));                
            }
            else
            {
                iScreenBlockerUtility.Show();
                this.Deactivate(ISFunction.CreateDelegate(function ()
                {
                    this.UpdateFeatureStatus(function()
                    {
                        // スクリーンブロッカーを消す
                        iScreenBlockerUtility.Hide();
                    });
                }, this));
            }            
        }
        else if (this.Status == iFeatureControl.Status.Inactive)
        {
            // 依存フィーチャーの検証：依存しているフィーチャーすべてがアクティブな場合のみアクティブイベントを実行
            var inactiveFeatures = this.GetInActiveDependFeatures(this.DependenceParentFeatures);
            if (inactiveFeatures.length > 0)
            {
                // 警告
                var message = iResxResource.GetString("Feature.Validation.ExistInActiveDependentFeatures");
                var featuresLine = "";
                for (var i = 0; i < inactiveFeatures.length; i++)
                {
                    featuresLine += ISString.Format("{0}\n\r", inactiveFeatures[i].Title);
                }

                alert(ISString.Format(message, featuresLine));   
            }
            else
            {
                iScreenBlockerUtility.Show();
                this.Activate(ISFunction.CreateDelegate(function ()
                {
                    this.UpdateFeatureStatus(function()
                    {
                        // スクリーンブロッカーを消す
                        iScreenBlockerUtility.Hide();
                    });
                }, this));
            }            
        }
    },

    UpdateFeatureStatus: function(callback)
    {
        // 一時的にUnKnownな状態にして状態を確認する
        this.Status = iFeatureControl.Status.Unknown;
        // リストサービスキャッシュをクリアする（リストの存在確認で誤った検出を防ぐ為）
        this.ListService.ListCollectionCache = null;
        this.EnsureActiveStatus(ISFunction.CreateDelegate(function (isActive, feature)
        {
            // 表示の修正
            this.UpdateFeatureDisplayStatus(isActive);

            callback();
        }, this));
    },

    UpdateFeatureDisplayStatus: function(isActive)
    {
        var rowElement = this.FeatureRow;
        var featureButton = rowElement.getElementsByClassName("ms-ButtonHeightWidth")[0];
        var featureStatusDiv = rowElement.getElementsByClassName("ms-vb2 ms-featurestatus");
        featureStatusDiv = featureStatusDiv.length == 1 ? featureStatusDiv[0] : null;

        if (isActive)
        {
            // ボタンの表示の修正                
            featureButton.value = iResxResource.GetString("Feature.Deactivate");
            // ステータスDivを表示
            featureStatusDiv.style.display = "";
        }
        else
        {
            // ボタンの表示の修正                
            featureButton.value = iResxResource.GetString("Feature.Activate");
            // ステータスDivを非表示
            featureStatusDiv.style.display = "none";
        }
    },

    ReloadPage: function()
    {
        window.location.reload(true);
    },

    Initialize: function(targetSiteRelativeUrl, scriptSiteRelativeUrl)
    {
        this.TargetSiteRelativeUrl = targetSiteRelativeUrl;
        this.ScriptSiteRelativeUrl = scriptSiteRelativeUrl;
        this.TargetIsMasterSite = ISString.Equals(this.TargetSiteRelativeUrl, this.ScriptSiteRelativeUrl, true);
        
        this.ScriptSiteAbsoluteUrl = iUri.GetAbsoluteUrl(scriptSiteRelativeUrl);
        this.ListService = iVxService;
        this.UserCustomActionsService = new SRUserCustomActionsService(this.TargetSiteRelativeUrl, this.TargetSiteRelativeUrl, true);
        this.FileService = new iWebFile();
        this.FolderService = new iWebFolder();
        this.ListViewService = new SPViewsService(this.TargetSiteRelativeUrl);

        // フィーチャーの表示・非表示フラグ
        var featureInvisible = false;
        // 管理サイト
        if (this.TargetIsMasterSite)
        {
            featureInvisible = this.HiddenInMasterSite;
        }
        // 非管理サイト
        else
        {
            featureInvisible = this.HiddenInNormalSite;
        }
        this.FeatureInvisible = featureInvisible;
        this.InitializeInternal();
    },

    InitializeInternal: function()
    {
        // それぞれの継承クラスで実装
    },

    EnsureActiveStatus: function(callback)
    {
        if (this.Status == iFeatureControl.Status.Active)
        {
            callback(true, this);
        }
        else if (this.Status == iFeatureControl.Status.Inactive)
        {
            // 必要なライセンスが不足している場合にはRowを無効化
            if (this.RequiredLicenseIds &&
                !this.ValidRequredLicenseExist())
            {
                this.DisabledFeatureRow();
            }

            callback(false, this);
        }
        else
        {
            var feature = this;
            this.EnsureActiveStatusInternal(function(isActive)
            {
                if (isActive)
                {
                    feature.Status = iFeatureControl.Status.Active;
                    callback(true, feature);
                }
                else
                {
                    feature.Status = iFeatureControl.Status.Inactive;

                    // 必要なライセンスが不足している場合にはRowを無効化
                    if (feature.RequiredLicenseIds &&
                        !feature.ValidRequredLicenseExist())
                    {
                        feature.DisabledFeatureRow();
                    }
                    callback(false, feature);
                }
            });
        }       
    },

    EnsureActiveStatusInternal: function(callback)
    {
        // それぞれの継承クラスで実装
    },

    CreateList: function (listData, renameListTitle, callback)
    {
        var feature = this;
        this.ListService.AddList(this.TargetSiteRelativeUrl, listData, function (list)
        {
            if (list)
            {
                // タイトルのアップデート
                var listTite = renameListTitle;
            
                listData.Id = list.Id;
                listData.Properties["Title"] = listTite;

                feature.ListService.UpdateList(feature.TargetSiteRelativeUrl, listData, function ()
                {
                    callback(list);
                });
            }
            else
            {
                callback();
            }
        });
    },

    GetActiveDependFeatures: function(dependFeatures)
    {
        var features = [];
        if (dependFeatures)
        {
            for (var i = 0; i < dependFeatures.length; i++)
            {
                var feature = dependFeatures[i];
                var status = feature.Status;
                if (status == iFeatureControl.Status.Active)
                {
                    features.push(feature);
                }
            }
        }

        return features;
    },

    GetInActiveDependFeatures: function(dependFeatures)
    {
        var features = [];
        if (dependFeatures)
        {
            for (var i = 0; i < dependFeatures.length; i++)
            {
                var feature = dependFeatures[i];
                var status = feature.Status;
                if (status != iFeatureControl.Status.Active)
                {
                    features.push(feature);
                }
            }
        }

        return features;
    },

    ValidRequredLicenseExist: function()
    {
        var validRequredLicenseExist = false;

        for (var i = 0; i < this.RequiredLicenseIds.length; i++)
        {
            var licenseId = this.RequiredLicenseIds[i];
            var licenseInfo = this.RequiredLicenses.Get(licenseId);

            if (licenseInfo &&
                licenseInfo.Valid)
            {
                validRequredLicenseExist = true;
                break;
            }
        }

        return validRequredLicenseExist;
    },

    DisabledFeatureRow: function ()
    {
        var activateButton = document.getElementById(this.Id + "_FeatureButton");
        activateButton.disabled = true;
        this.FeatureRow.style.opacity = 0.5;
    },

    GetFields: function(fieldsInfo)
    {
        var fields = [];
        for (var i = 0; i < fieldsInfo.length; i++)
        {
            var fieldInfo = fieldsInfo[i];

            // システム列は更新しない
            if (ISBoolean.TryParse(fieldInfo.System, false))
            {
                continue;
            }

            var field = new ISSPField();
            field.Properties = [];
            field.Properties["Name"]                = fieldInfo.InternalName;                 
            field.Properties["Type"]                = fieldInfo.FieldType;
            field.Properties["Description"]         = fieldInfo.Description;
            field.Properties["Required"]            = fieldInfo.Required;
            field.Properties["Indexed"]             = fieldInfo.Indexed;
            field.Properties["Hidden"]              = fieldInfo.Hidden;
            field.Properties["EnforceUniqueValues"] = fieldInfo.EnforceUniqueValues;
            field.Properties["MaxLength"]           = fieldInfo.MaxLength;
            field.Properties["RichText"]            = fieldInfo.RichText;
            field.Properties["RichTextMode"]        = fieldInfo.RichTextMode;
            field.Properties["Default"]             = fieldInfo.Default;

            // DisplayName
            var displayName = fieldInfo.InternalName;
            if (!ISString.IsNullOrEmpty(fieldInfo.DisplayName))
            {
                displayName = fieldInfo.DisplayName;
            }
            else if (!ISString.IsNullOrEmpty(fieldInfo.DisplayNameResourceKey) &&
                     this.Resource)
            {                
                displayName = this.Resource.GetString(fieldInfo.DisplayNameResourceKey);              
            }
            field.Properties["DisplayName"] = displayName;   

            fields.push(field);
        }

        return fields;
    },

    GetViewFields: function(fieldsInfo)
    {        
        var fields = [];
        for (var i = 0; i < fieldsInfo.length; i++)
        {
            var fieldInfo = fieldsInfo[i];
            var showInView = fieldInfo.ShowInView;
            if (showInView)
            {
                showInView = ISBoolean.TryParse(showInView, false);
            }
            if (!showInView) continue;

            var field = new ISSPField();
            field.Properties = [];
            field.Properties["Name"] = fieldInfo.InternalName;

            fields.push(field);
        }

        return fields;
    }
}

// -----------------------------------------------------------------------
//  Feature.InfoshareCommon
// -----------------------------------------------------------------------
Infoshare.SharePoint.InfoshareCommonFeature = function Infoshare$SharePoint$InfoshareCommonFeature()
{
    Infoshare.SharePoint.Administration.FeatureControl.apply(this, arguments);

    this.Id = "Feature.InfoshareCommon";
    this.ResourceKey = "Feature.InfoshareCommon";
}

iInfoshareCommonFeature = Infoshare.SharePoint.InfoshareCommonFeature;

iInfoshareCommonFeature.UserCustomActionInfos = [
    {
        Title      : 'InfoshareConfigurationScriptBlock',
        ScriptSrc  : '',
        ScriptBlock: '',
        Sequence   : 10000,
        Description: 'Infoshare Configuration ScriptBlock'
    },
    {
        Title      : 'InfoshareJS',
        ScriptSrc  : '~SiteCollection/InfoshareProductLibrary/Sources/Infoshare/Infoshare.js',
        Sequence   : 10100,
        Description: 'InfoshareJS'
    },
    {
        Title      : 'Infoshare.Settings.js',
        ScriptSrc  : '~SiteCollection/InfoshareProductLibrary/Sources/Infoshare/Infoshare.Settings.js',
        Sequence   : 10110,
        Description: 'Infoshare.Settings.js'
    }
];

iInfoshareCommonFeature.SiteConfigurationFieldsInfo = [
    { InternalName: "WebUrl",            FieldType: ISSPFieldType.Text, Indexed: "TRUE" },
    { InternalName: "ListId",            FieldType: ISSPFieldType.Text, Indexed: "TRUE" },
    { InternalName: "FieldInternalName", FieldType: ISSPFieldType.Text, Indexed: "TRUE" },
    { InternalName: "Settings",          FieldType: ISSPFieldType.Note, Indexed: "" }
];

iInfoshareCommonFeature.InfoshareFiles = [
    {
        FromUrl: "/Infoshare/InfoshareForCopy.js",
        ToUrl  : "/Infoshare/Infoshare.js"
    },
    {
        FromUrl: "/Infoshare/Infoshare.Settings.js",
        ToUrl  : "/Infoshare/Infoshare.Settings.js"
    }
];

iInfoshareCommonFeature.ProductLibraryName = "InfoshareProductLibrary";
iInfoshareCommonFeature.SiteConfigurationListName = "InfoshareSiteConfiguration";
iInfoshareCommonFeature.prototype = new Infoshare.SharePoint.Administration.FeatureControl();
iInfoshareCommonFeature.prototype.Status =iFeatureControl.Status.Unknown;
iInfoshareCommonFeature.prototype.ExistUserCustomActions = [];
iInfoshareCommonFeature.prototype.DependenceParentFeatureIds = [];
iInfoshareCommonFeature.prototype.DependenceChildFeatureIds = ["Feature.InfoCall.Common"];

iInfoshareCommonFeature.prototype.InitializeInternal = function()
{
    // ユーザーカスタムアクション情報の設定
    if (!this.UserCustomActionInfos)
    {
        this.UserCustomActionInfos = iInfoshareCommonFeature.UserCustomActionInfos;
    }

    // スクリプトブロックの設定
    var scriptBlockUca = this.UserCustomActionInfos[0];
    if (scriptBlockUca.Title == "InfoshareConfigurationScriptBlock")
    {
        var scriptBlock = function ()
        {
            if (typeof (MasterSiteContext) == 'undefined')
            {
                MasterSiteContext = {};
            }

            MasterSiteContext.ServerRelativePath = '{0}';
        };

        var scriptBlockString = ISString.Format(scriptBlock.toString(), this.ScriptSiteRelativeUrl);
        // 無名関数を即時関数で登録する
        scriptBlockUca.ScriptBlock = "(" + scriptBlockString + ")();";
    }
}

iInfoshareCommonFeature.prototype.EnsureActiveStatusInternal = function(callback)
{
    // それぞれの要素事に状態の確認
    // Infoshare製品ライブラリ
    // Infoshareサイト構成リスト
    // Infoshare UserCustomAction

    var feature = this;
    var ensureContext = {
        ProductLibraryComplete: false,
        SiteConfigurationListComplete: false,
        UserCustomActionComplete: false,

        ProductLibraryIsActive: false,
        SiteConfigurationListIsActive: false,
        UserCustomActionIsActive: false,
        Completed: function()
        {
            return this.ProductLibraryComplete &&
                   this.SiteConfigurationListComplete &&
                   this.UserCustomActionComplete;
        },

        AllFeatureIsActive: function()
        {
            return this.ProductLibraryIsActive &&
                   this.SiteConfigurationListIsActive &&
                   this.UserCustomActionIsActive;
        }
    };
    var ensureCompleted = function ()
    {
        if (ensureContext.Completed())
        {
            callback(ensureContext.AllFeatureIsActive());
        }
    };

    // Infoshare製品ライブラリ
    this.EnsureActiveStatusForProductLibrary(function (isActive)
    {
        ensureContext.ProductLibraryComplete = true;
        ensureContext.ProductLibraryIsActive = isActive;
        ensureCompleted();
    });

    // Infoshareサイト構成リスト
    this.EnsureActiveStatusForSiteConfigurationList(function (isActive)
    {
        ensureContext.SiteConfigurationListComplete = true;
        ensureContext.SiteConfigurationListIsActive = isActive;
        ensureCompleted();
    });

    // UserCustomAction
    this.EnsureActiveStatusForUserCustomAction(function (isActive)
    {
        ensureContext.UserCustomActionComplete = true;
        ensureContext.UserCustomActionIsActive = isActive;
        ensureCompleted();
    });
};
iInfoshareCommonFeature.prototype.EnsureActiveStatusForProductLibrary = function(callback)
{
    var feature = this;
    this.ListService.GetListByUrlName(this.TargetSiteRelativeUrl, iInfoshareCommonFeature.ProductLibraryName, function (list)
    {
        feature.ProductLibraryList = list;
        // アクティブ状態
        if (feature.ProductLibraryList)
        {
            callback(true);
        }
        // 非アクティブ状態 
        else
        {
            callback(false);
        }
    });
}
iInfoshareCommonFeature.prototype.EnsureActiveStatusForSiteConfigurationList = function(callback)
{
    var feature = this;
    this.ListService.GetListByUrlName(this.TargetSiteRelativeUrl, iInfoshareCommonFeature.SiteConfigurationListName, function (list)
    {
        feature.SiteConfigurationList = list;
        // アクティブ状態
        if (feature.SiteConfigurationList)
        {
            callback(true);
        }
        // 非アクティブ状態 
        else
        {
            callback(false);
        }
    });
}
iInfoshareCommonFeature.prototype.EnsureActiveStatusForUserCustomAction = function(callback)
{
    var feature = this;
    this.UserCustomActionsService.GetUserCustomActions(function (ucas) 
    {
        var existUcaCount = 0;
        for (var i = 0; i < feature.UserCustomActionInfos.length; i++)
        {
            for (var n = 0; n < ucas.length; n++)
            {
                if (feature.UserCustomActionInfos[i].Title === ucas[n].Title)
                {
                    existUcaCount++;
                    // 削除の際利用するためIdをキャッシュ
                    feature.UserCustomActionInfos[i].Id = ucas[n].Id;
                    feature.ExistUserCustomActions.push(ucas[n]);
                    break;
                }
            }
        }
        
        // アクティブ状態
        if (feature.UserCustomActionInfos.length === existUcaCount)
        {
            feature.Status = iFeatureControl.Status.Active;
            callback(true);
        }
        // 非アクティブ状態 
        else
        {
            feature.Status = iFeatureControl.Status.Inactive;
            callback(false);
        }
    });  
}

iInfoshareCommonFeature.prototype.Activate = function(callback)
{
    // 以下三つの要素をアクティベートする
    // Infoshare製品ライブラリ
    // Infoshareサイト構成リスト
    // Infoshare UserCustomAction
    // コンテキスト
    var activateContext = {
        ProductLibraryComplete: false,
        SiteConfigurationListComplete: false,
        UserCustomActionComplete: false,
        Completed: function()
        {
            return this.ProductLibraryComplete &&
                   this.SiteConfigurationListComplete &&
                   this.UserCustomActionComplete;
        }
    };
    var activateCompleted = function ()
    {
        if (activateContext.Completed())
        {
            callback();
        }
    };

    // Infoshare製品ライブラリ
    // 管理サイトに対しては、ライブラリ操作を行わない
    if (this.TargetIsMasterSite)
    {
        activateContext.ProductLibraryComplete = true;
        activateCompleted();
    }
    else
    {
        this.ActivateProductLibrary(function ()
        {
            activateContext.ProductLibraryComplete = true;
            activateCompleted();
        });
    }

    // Infoshareサイト構成リスト
    // 管理サイトに対しては、リスト操作を行わない
    if (this.TargetIsMasterSite)
    {
        activateContext.SiteConfigurationListComplete = true;
        activateCompleted();
    }
    else
    {
        this.ActivateSiteConfigurationList(function ()
        {
            activateContext.SiteConfigurationListComplete = true;
            activateCompleted();
        });
    }

    // UserCustomAction
    this.ActivateUserCustomAction(function ()
    {
        activateContext.UserCustomActionComplete = true;
        activateCompleted();
    });
};
iInfoshareCommonFeature.prototype.ActivateProductLibrary = function(callback)
{
    // ライブラリデータの作成
    var listData = new ISSPList();
    listData.Properties = [];
    listData.Properties["Title"] = iInfoshareCommonFeature.ProductLibraryName;
    listData.Properties["ServerTemplate"] = ISSPListTemplateType.DocumentLibrary;
    listData.Properties["Description"] = "";

    var renameListTitle = iResxResource.GetString("Infoshare.ProductLibrary.Title");
    var feature = this;
    if (this.ProductLibraryList)
    {
        callback();
    }
    else
    {
        this.CreateList(listData, renameListTitle, function ()
        {
            // フォルダ・ファイルの作成
            feature.CopyFiles(callback);
        });
    }
};
iInfoshareCommonFeature.prototype.ActivateSiteConfigurationList = function(callback)
{
    // リストデータの作成
    var listData = new ISSPList();

    listData.Properties = [];
    listData.Properties["Title"] = iInfoshareCommonFeature.SiteConfigurationListName;
    listData.Properties["ServerTemplate"] = ISSPListTemplateType.GenericList;
    listData.Properties["Description"] = "";

    // フィールドデータの作成    
    var fields = this.GetFields(iInfoshareCommonFeature.SiteConfigurationFieldsInfo);
    listData.Fields = fields;

    var renameListTitle = iResxResource.GetString("Infoshare.SiteConfigurationList.Title");
    if (this.SiteConfigurationList)
    {
        callback();
    }
    else
    {
        this.CreateList(listData, renameListTitle, callback);
    }
};
iInfoshareCommonFeature.prototype.ActivateUserCustomAction = function (callback)
{
    var ucaCount = this.UserCustomActionInfos.length;
    var activateContext = {
        activatedCount: 0,
        Completed: function()
        {
            return this.activatedCount == ucaCount;
        }
    };

    var activateCallback = function()
    {
        activateContext.activatedCount ++;
        if(activateContext.Completed())
        {
            callback();
        }
    };

    for (var i = 0; i < ucaCount; i++)
    {
        var ucaInfo = this.UserCustomActionInfos[i];
        this.UserCustomActionsService.AddUserCustomActionForScriptLink(ucaInfo.Title,
                                                                       ucaInfo.ScriptSrc,
                                                                       ucaInfo.ScriptBlock,
                                                                       ucaInfo.Sequence,
                                                                       ucaInfo.Description,
                                                                       activateCallback);
    }
};

iInfoshareCommonFeature.prototype.Deactivate = function(callback)
{
    // 以下三つの要素をディアクティベートする
    // Infoshare製品ライブラリ
    // Infoshareサイト構成リスト
    // Infoshare UserCustomAction
    // コンテキスト
    var deactivateContext = {
        ProductLibraryComplete: false,
        SiteConfigurationListComplete: false,
        UserCustomActionComplete: false,
        Completed: function()
        {
            return this.ProductLibraryComplete &&
                   this.SiteConfigurationListComplete &&
                   this.UserCustomActionComplete;
        }
    };
    var deactivateCompleted = function ()
    {
        if (deactivateContext.Completed())
        {
            callback();
        }
    };

    // Infoshare製品ライブラリ
    // 管理サイトに対しては、ライブラリ操作を行わない
    if (this.TargetIsMasterSite)
    {
        deactivateContext.ProductLibraryComplete = true;
        deactivateCompleted();
    }
    else
    {
        this.DeactivateProductLibrary(function ()
        {
            deactivateContext.ProductLibraryComplete = true;
            deactivateCompleted();
        });
    }

    // Infoshareサイト構成リスト
    // 管理サイトに対しては、リスト操作を行わない
    if (this.TargetIsMasterSite)
    {
        deactivateContext.SiteConfigurationListComplete = true;
        deactivateCompleted();
    }
    else
    {
        this.DeactivateSiteConfigurationList(function ()
        {
            deactivateContext.SiteConfigurationListComplete = true;
            deactivateCompleted();
        });
    }

    // UserCustomAction
    this.DeactivateUserCustomAction(function ()
    {
        deactivateContext.UserCustomActionComplete = true;
        deactivateCompleted();
    });
};
iInfoshareCommonFeature.prototype.DeactivateProductLibrary = function(callback)
{
    if (this.ProductLibraryList)
    {
        this.ListService.DeleteList(this.TargetSiteRelativeUrl, this.ProductLibraryList.Id, callback);
    }
};
iInfoshareCommonFeature.prototype.DeactivateSiteConfigurationList = function(callback)
{
    if (this.SiteConfigurationList)
    {
        this.ListService.DeleteList(this.TargetSiteRelativeUrl, this.SiteConfigurationList.Id, callback);
    }
};
iInfoshareCommonFeature.prototype.DeactivateUserCustomAction = function(callback)
{
    var ucaCount = this.ExistUserCustomActions.length;
    var deactivateContext = {
        deactivatedCount: 0,
        Completed: function()
        {
            return this.deactivatedCount == ucaCount;
        }
    };

    var deactivateCallback = function()
    {
        deactivateContext.deactivatedCount ++;
        if(deactivateContext.Completed())
        {
            callback();
        }
    };

    for (var i = 0; i < ucaCount; i++)
    {
        var ucaInfo = this.ExistUserCustomActions[i];
        this.UserCustomActionsService.DeleteUserCustomAction(ucaInfo.Id,
                                                             deactivateCallback);
    }
};

iInfoshareCommonFeature.prototype.CopyFiles = function (callback)
{
    // コンテキスト
    var copyFilesContext = {
        ConfigurationsFolderComplete: false,
        TemporaryFolderComplete: false,
        SourcesFolderComplete: false,
        Completed: function ()
        {
            return this.ConfigurationsFolderComplete &&
                   this.TemporaryFolderComplete &&
                   this.SourcesFolderComplete;
        }
    };
    var folderAndFilesCreated = function ()
    {
        if (copyFilesContext.Completed())
        {
            callback();
        }
    };

    var feature = this;

    var targetProductLibraryUrl = ISString.TrimEnd(this.TargetSiteRelativeUrl, '/')
                                + "/InfoshareProductLibrary";
    // Configurationsフォルダ
    var targetConfigurationsFolderUrl = targetProductLibraryUrl + "/Configurations";
    this.FolderService.Create(targetConfigurationsFolderUrl, function ()
    {
        copyFilesContext.ConfigurationsFolderComplete = true;
        folderAndFilesCreated();
    });

    // Temporaryフォルダ
    var targetTemporaryFolderUrl = targetProductLibraryUrl + "/Temporary";
    this.FolderService.Create(targetTemporaryFolderUrl, function ()
    {
        // DoNotDeleteThisFolder.icsのコピー
        var fileUrl = iVxContext.MasterTemporaryPath + "/DoNotDeleteThisFolder.ics";
        var targetFileUrl = targetTemporaryFolderUrl + "/DoNotDeleteThisFolder.ics";
        feature.FileService.Download(fileUrl, function(downloadResult, contents, downloadStatus)
        {
            feature.FileService.Upload(targetFileUrl, contents, function (uploadResult, uploadStatud)
            {
                copyFilesContext.TemporaryFolderComplete = true;
                folderAndFilesCreated();
            });
        });
    });

    // Sourcesフォルダ（スクリプトリンクの指定で絶対URLを指定できない為、利用するサイトコレクションにjsをコピーする）
    var targetSourcesFolderUrl = targetProductLibraryUrl + "/Sources";
    this.FolderService.Create(targetSourcesFolderUrl, function ()
    {
        var targetSourcesFolderUrl = ISString.TrimEnd(feature.TargetSiteRelativeUrl, '/')
                                   + "/InfoshareProductLibrary/Sources";
        var targetInfoshareFolderUrl = targetSourcesFolderUrl + "/Infoshare";
        feature.FolderService.Create(targetInfoshareFolderUrl, function ()
        {
            feature.CopyFolderFiles(iInfoshareCommonFeature.InfoshareFiles, function ()
            {
                copyFilesContext.SourcesFolderComplete = true;
                folderAndFilesCreated();
            });
        });
    });
};
iInfoshareCommonFeature.prototype.CopyFolderFiles = function (filesInfo, callback)
{
    // コンテキスト
    var copyFilesContext = {
        CopyCompleteFileCount: 0,
        Completed: function()
        {
            return this.CopyCompleteFileCount == filesInfo.length;
        }
    };
    var copyCompleted = function ()
    {
        if (copyFilesContext.Completed())
        {
            callback();
        }
    };

    var feature = this;
    var fromSourcesFolderUrl = iVxContext.MasterSourcesPath;
    var toSourcesFolderUrl = ISString.TrimEnd(this.TargetSiteRelativeUrl, '/')
                           + "/InfoshareProductLibrary/Sources";

    for (var i = 0; i < filesInfo.length; i++)
    {
        var copyFileInfo = filesInfo[i];
        var fromFileUrl = fromSourcesFolderUrl + copyFileInfo.FromUrl;
        var toFileUrl = toSourcesFolderUrl + copyFileInfo.ToUrl;

        this.CopyFile(fromFileUrl, toFileUrl, function ()
        {
            copyFilesContext.CopyCompleteFileCount ++;
            copyCompleted();
        });
    }
};
iInfoshareCommonFeature.prototype.CopyFile = function(fromFileUrl, toFileUrl, callback)
{
    var feature = this;
    this.FileService.Download(fromFileUrl, function(downloadResult, contents, downloadStatus)
    {
        feature.FileService.Upload(toFileUrl, contents, function (uploadResult, uploadStatud)
        {
            callback();
        });
    });
};														
