// -----------------------------------------------------------------------
Infoshare.SharePoint.SiteCollectionView = function InfoInfoshare$Infoshare$SiteCollectionView() { }
iSiteCollectionView = Infoshare.SharePoint.SiteCollectionView;

iSiteCollectionView.ColumnDefinitions = [
    { DisplayName: '',
      DisplayNameResourceKey: 'SiteCollectionView.Cloumn.AbsoluteUrl',
      ColumnType: 'Link',
      Key: 'AbsoluteUrl',
      Width: '320'},
    { DisplayName: '',
      DisplayNameResourceKey: 'SiteCollectionView.Cloumn.SiteSettingsLink',
      ColumnType: 'LinkWithText',  
      Key: 'SiteSettingsLink',
      DesplayKey: 'Page.FeatureManagement.Name',
      Width: '320'},
    { DisplayName: '',
      DisplayNameResourceKey: '',
      ColumnType: 'Hidden',  
      Key: 'RelativeUrl',
      Width: '0'}
];

iSiteCollectionView.prototype = {
    GridDataSource: [],
    DataSourceDictinary: null,
    ColumnDefinitions: iSiteCollectionView.ColumnDefinitions,
    IgGridFeatures: [
        { name: "Selection",
          mode: "row",
          multipleSelection: true },
        { name: "Resizing",
          allowDoubleClickToResize: true }
    ],

    GridParentElement: null,
    GridElementId: 'Infoshare_SiteCollectionView_Grid',
    SelectedItems: [],
    
    Render: function(parentElement)
    {
        // Gridの親要素をキャッシュ
        this.GridParentElement = parentElement;
        
        // グリッド用のテーブルを描画
        var table = document.createElement('table');
        table.id = this.GridElementId;
        table.oncontextmenu = function() { return false; }; // コンテキストメニューを無効化
        table.style.whiteSpace = "nowrap"; // 折り返しを禁止
        this.GridParentElement.appendChild(table);

        // グリッド描画
        (function($, view)
        {
            // DataSourceの初期化
            view.GridDataSource.clear();

            view.Columns = iIgGridUtility.BuildColumns(view.ColumnDefinitions);
            // igGridを描画
            $('#' + view.GridElementId).igGrid({
                columns: view.Columns,
                width:  ISDomAccessor.GetInnerWidth(view.GridParentElement)  + 'px',
                height: "100px", // 値に意味は無し（Headerを固定する為に指定する必要がある）
                dataSource: view.GridDataSource,
                alternateRowStyles: false,
                autofitLastColumn : false,
                primaryKey: "AbsoluteUrl",
                features: view.IgGridFeatures
            });

            // SelectionChangeのイベント
            $('#' + view.GridElementId).on("iggridselectionrowselectionchanged", ISFunction.CreateDelegate(view.OnGridSelectionChanged, view));
        }(ig$, this));

        // サイズ調整のためリサイズ
        this.OnResize();
    },

    UpdateGrid: function(entities)
    {
        var items = iIgGridUtility.BuildGridItems(entities, this.Columns);

        this.DataSourceDictinary = new ISDictionary();
        for (var i = 0; i < items.length; i++)
        {
            var item = items[i];
            this.DataSourceDictinary.Set(item.AbsoluteUrl, item);
        }        

        (function ($, view)
        {            
            // DataBindの際に定義したArrayを参照するので配列要素を詰め替える
            view.GridDataSource.clear();
          
            for (var i = 0; i < items.length; i++)
            {
                view.GridDataSource.push(items[i]);
            }                        

            $("#" + view.GridElementId).igGrid("dataBind");
        })(ig$, this);
    },

    OnResize: function()
    {
        (function($, view)
        {
            $('#' + view.GridElementId).igGrid({
                width:  ISDomAccessor.GetInnerWidth(view.GridParentElement) + 'px',
                height: ISDomAccessor.GetInnerHeight(view.GridParentElement) + 'px'
            });
        })(ig$, this);
    },

    OnGridSelectionChanged: function(evt)
    {
        (function ($, view)
        {
            // 複数回呼ばれるイベントをキャンセルする
            // DataBindを実行するたびにイベント（iggridselectionrowselectionchanged）が登録される為、二回目以降のイベントを処理しない
            evt.preventDefault();

            // 選択アイテムのクリア
            view.SelectedItems.clear();
            var selectedRows = $('#' + view.GridElementId).igGridSelection("selectedRows");

            for (var i = 0; i < selectedRows.length; i++)
            {
                // 選択アイテムに追加
                var selectedItem = view.DataSourceDictinary.Get(selectedRows[i].id);
                if (selectedItem)
                {
                    view.SelectedItems.push(selectedItem);
                }                
            }

            // 選択メソッドを呼ぶ
            view.OnItemSelected();               
        }(ig$, this));
    },
    
    ItemSelectedEventHandler: null,
    OnItemSelected: function()
    {
        // 選択状態の変更を通知
        if (this.ItemSelectedEventHandler)
        {
            this.ItemSelectedEventHandler(this);
        }
    }
}
														
                                         
