iAnkListFormExtender.prototype.GetFormFieldInfos = function ()
{
    if (this.FormFieldInfos)
    {
        return this.FormFieldInfos;
    }
    this.FormFieldInfos = new ISDictionary();

    var formBodyCells = new Array();
    // 標準フォームと異なり、（tdではなく）spna下にコントロールが配置される
    var cells = document.getElementsByTagName('span');
    for (var i = 0; i < cells.length; i++)
    {
        // form body セルを特定
        var cell = cells[i];
        // ToDo(skomatsu): 親TDのクラスを確認すべきか
        //if (cell.className.toLowerCase() != this.FormBodyClassName.toLowerCase())
        //{
        //    continue;
        //}

        // コメント要素を特定
        var comment = null;
        var children = ISDomAccessor.GetChildElements(cell);
        for (var j = 0; j < children.length; j++)
        {
            var child = children[j];
            if (child.nodeType == ISDomAccessor.NodeType.Comment)
            {
                comment = child;
                break;
            }
        }
            
        if (comment)
        {
            // コメントからフィールド情報を取得
            var doc = iXml.LoadXml('<FieldInfo ' + comment.nodeValue + '/>');
            var info = new iSPFormFieldInfo(iXml.GetAttributeValue(doc.documentElement, 'FieldInternalName'),
                                            iXml.GetAttributeValue(doc.documentElement, 'FieldName'),
                                            iXml.GetAttributeValue(doc.documentElement, 'FieldType'));
            info.RowElement   = ISDomAccessor.GetParentElement(cell);
            info.BodyElement  = cell;
        }
        else
        {
            // ToDo: ユーザー列以外のコントロールの場合はコメントが無い場合（列情報にアクセスできない場合）にも
            //       DOM構造から必要な情報が取得できる可能性があるので、その場合にはこのブロックでFieldInfoを作成する
            continue;
        }
            
        this.FormFieldInfos.Add(info.InternalName, info);
    }

    return this.FormFieldInfos;
};

iAnkListFormExtender.prototype.AllowAdditionalExtension = function()
{
    return false;
};
                                 
                                         
