//  Reference: http://msdn.microsoft.com/en-us/library/office/jj860569(v=office.15).aspx
// -----------------------------------------------------------------------
Infoshare.Nintex.REST.RestCommon = function Infoshare$Nintex$REST$RestCommon() { }
iNRestCommon = Infoshare.Nintex.REST.RestCommon;
iNRestCommon.EndpointPath = '_vti_bin/NintexFormsServices/NfRestService.svc';
iNRestCommon.BuildRequest = function(service, restPath)
{
    var request = new ISWebRequest();
    request.Method = 'POST';

    // headres
    if (iNService.ResponseType == ISWebRequest.AcceptResponseType.JSON)
    {
        iNRestCommon.AppendJSONHeader(request);
    }

    // endpoint
    var endpointUrl = '';
    if (ISString.TrimEnd(service.HostWebUrl, '/').toUpperCase()  == ISString.TrimEnd(service.AppWebUrl, '/').toUpperCase())
    {
        endpointUrl = ISString.TrimEnd(service.HostWebUrl, '/') + '/' + iNRestCommon.EndpointPath + '/' + ISString.TrimStart(restPath, '/');
    }
    else
    {
        endpointUrl = ISString.TrimEnd(service.AppWebUrl, '/') + '/' + iNRestCommon.EndpointPath + '/SP.AppContextSite(@target)/' + ISString.TrimStart(restPath, '/')
                    + "?@target='" + ISString.TrimEnd(service.HostWebUrl, '/') + "'";
    }
    request.Url = endpointUrl;

    return request;
}
iNRestCommon.AppendJSONHeader = function(request)
{
    request.Headers.push(new ISWebRequestHeader('Accept', 'application/json, text/javascript, */*; q=0.01'));
    request.Headers.push(new ISWebRequestHeader('Content-Type', 'application/json; charset=utf-8'));
}
iNRestCommon.AppendRequestDigestHeader = function(request)
{
    request.Headers.push(new ISWebRequestHeader('X-RequestDigest', ISSPContextWebInformation.Current.FormDigestValue));
}
                                      
