// -----------------------------------------------------------------------
Infoshare.Nintex.REST.FormService = function Infoshare$Nintex$REST$ListsService(hostWebUrl, appWebUrl)
{
    this.HostWebUrl = hostWebUrl;
    this.AppWebUrl  = appWebUrl ? appWebUrl : hostWebUrl;

    this.ResponseType = iNService.ResponseType;
}
iNFormService = Infoshare.Nintex.REST.FormService;
iNFormService.prototype = {
    HostWebUrl: '',
    AppWebUrl: '',

    ResponseType: '',

    GetForm: function(listId, contentTypeId, callback)
    {
        var stopwatch = new ISStopwatch();
        stopwatch.Start();
        ISTrace.TraceVerbose('[BEGIN] iNFormService.GetForm');

        this.EnsureContext(ISFunction.CreateDelegate(function()
        {
            // build request
            var restPath = "GetForm";
            var request = iNRestCommon.BuildRequest(this, restPath);
            SPRestCommon.AppendRequestDigestHeader(request);
            request.Method = "POST";

            var body = { 'listId':        listId,
                         'contentTypeId': contentTypeId };
            request.Body = ISJSON.stringify(body);

            // invocation
            if (callback)
            {
                request.Asynchronous = true;
                request.CallbackHandler = ISFunction.CreateDelegate(function()
                {
                    var responseText   = request.GetResponseText();
                    var responseObject = ISJSON.parse(responseText);

                    ISTrace.TraceVerbose('[END] iNFormService.GetForm (spent: ' + stopwatch.Stop() + ')');
                    callback(responseObject);
                }, this);

                request.Invoke();
            }
            else
            {
                request.Invoke();
                var responseText   = request.GetResponseText();
                var responseObject = ISJSON.parse(responseText);

                ISTrace.TraceVerbose('[END] iNFormService.GetForm (spent: ' + stopwatch.Stop() + ')');
                return responseObject;
            }
        }, this));
    },

    ResolvePrincipals: function(principalNames, resolveTypes, callback)
    {
        var stopwatch = new ISStopwatch();
        stopwatch.Start();
        ISTrace.TraceVerbose('[BEGIN] iNFormService.ResolvePrincipals');

        if (callback)
        {
            var invocationCount = 0;
            var principals = new Array();
            for (var i = 0; i < principalNames.length; i++)
            {
                var principalName = principalNames[i];
                principals[principalName] = null;
                this.ResolvePrincipal(principalName, resolveTypes, function(result, name)
                {
                    principals[name] = result;

                    invocationCount++;
                    if (invocationCount >= principalNames.length)
                    {
                        callback(principals);
                    }
                });
            }
        }
        else
        {
            throw new Error('Not supported operation.');
        }
    },

    ResolvePrincipal: function(principalName, resolveTypes, callback)
    {
        this.AutoCompleteValue(principalName, resolveTypes, callback);
    },

    AutoCompleteValue: function(principalName, types, callback)
    {
        var stopwatch = new ISStopwatch();
        stopwatch.Start();
        ISTrace.TraceVerbose('[BEGIN] iNFormService.ResolvePrincipal');

        this.EnsureContext(ISFunction.CreateDelegate(function()
        {
            // build request
            var restPath = 'AutoCompleteValue/PeoplePicker'
                         + '?term=' + encodeURIComponent(principalName)
                         + '&types=' + encodeURIComponent(types)
                         + '&group= ';
            var request = iNRestCommon.BuildRequest(this, restPath);
            SPRestCommon.AppendRequestDigestHeader(request);
            request.Method = 'GET';

            // invocation
            if (callback)
            {
                request.Asynchronous = true;
                request.CallbackHandler = ISFunction.CreateDelegate(function()
                {
                    var responseText   = request.GetResponseText();
                    var responseObject = ISJSON.parse(responseText);

                    ISTrace.TraceVerbose('[END] iNFormService.ResolvePrincipal (spent: ' + stopwatch.Stop() + ')');
                    callback(responseObject, principalName);
                }, this);

                request.Invoke();
            }
            else
            {
                throw new Error('Not supported operation.');
            }
        }, this));
    },

    EnsureContext: function(callback)
    {
        var service = new SRContextService(this.HostWebUrl, this.AppWebUrl);
        service.GetContext(function(context)
        {
            callback();
        });
    }
}
                                      
