Infoshare.Nintex.FormsFormExtender = function Infoshare$Nintex$FormsFormExtender(){}
iNFFormExtender = Infoshare.Nintex.FormsFormExtender;
iNFFormExtender.TypeName = 'Infoshare.Nintex.FormsFormExtender';
iNFFormExtender.ExtenderType = iBehaviorExtender.ExtenderType.Page;
iNFFormExtender.ClassInfo = null;

iNFFormExtender.FormControlTypeId = { UserControl:       'c0a89c70-0781-4bd4-8623-f73675005e12',
                                      LegacyUserControl: 'a0a89c70-0781-4bd4-8623-f73675005e12' };

iNFFormExtender.WorkFlowTaskContentTypeId = { TaskByForms:               '0x0108010079DBDE612F7B46928C6A2516BA2CAE3700D4A837248A47E040ABD1A569613E898B',
                                              MultiSelectionTaskByForms: '0x0108010064E42B14ADA442C78E98D686760A8493000568DBB766D0491684897A230753AAF9' };

iNFFormExtender.FormFileName = { InitiationForm: 'InitiateWorkflow.aspx',
                                 TaskEditForm:   'EditForm.aspx' };

iNFFormExtender.FormControlInfos = null;

iNFFormExtender.Extenders = new ISDictionary();
iNFFormExtender.Initialize = function()
{
    if (!iNFFormExtender.Extenders)
    {
        iNFFormExtender.Extenders = new ISDictionary();
    }

    iBehaviorExtender.AddExtender(Infoshare.SharePoint.PageExtender, 'Infoshare.Nintex.FormsFormExtender', 'Infoshare.Nintex.FormsFormExtender');
}
iNFFormExtender.CanExtend = function()
{
    return iNFFormExtender.IsListForm() ||
           iNFFormExtender.IsWorkflowForm();
}

iNFFormExtender.IsNewForm = function()
{
    return iSPListFormExtender.IsTargetForm(iSPListFormExtender.FormFileName.ListForm.NewForm) &&
           iNFFormExtender.HasNintexLibrary();
}
iNFFormExtender.IsEditForm = function()
{
    return iSPListFormExtender.IsTargetForm(iSPListFormExtender.FormFileName.ListForm.EditForm) &&
           iNFFormExtender.HasNintexLibrary();
}
iNFFormExtender.IsDisplayForm = function()
{
    return iSPListFormExtender.IsTargetForm(iSPListFormExtender.FormFileName.ListForm.DisplayForm) &&
           iNFFormExtender.HasNintexLibrary();
}
iNFFormExtender.IsInitiationForm = function()
{
    return ISString.EndsWith(document.location.pathname, iNFFormExtender.FormFileName.InitiationForm, true) &&
           iNFFormExtender.HasNintexLibrary();
}
iNFFormExtender.IsTaskEditForm = function(contentTypeId)
{
    // PageExtender等上のレイヤーから呼ばれる場合はtrueを返し、このクラス内でもう一度判断する
    var isTaskEditFormByForms = false;
    if (ISObject.IsNullOrUndefined(contentTypeId) ||
        ISString.StartsWith(contentTypeId, iNFFormExtender.WorkFlowTaskContentTypeId.TaskByForms, true) ||
        ISString.StartsWith(contentTypeId, iNFFormExtender.WorkFlowTaskContentTypeId.MultiSelectionTaskByForms, true))
    {
        isTaskEditFormByForms = true;
    }

    return ISString.EndsWith(document.location.pathname, iNFFormExtender.FormFileName.TaskEditForm, true) &&
           iNFFormExtender.HasNintexLibrary() &&
           isTaskEditFormByForms;
}
iNFFormExtender.HasNintexLibrary = function()
{
    return typeof(NWF$) != 'undefined';
}
iNFFormExtender.IsListForm = function()
{
    return iNFFormExtender.IsNewForm() ||
           iNFFormExtender.IsEditForm() ||
           iNFFormExtender.IsDisplayForm();
}
iNFFormExtender.IsWorkflowForm = function(contentTypeId)
{
    return iNFFormExtender.IsInitiationForm() ||
           iNFFormExtender.IsTaskEditForm(contentTypeId);
}

iNFFormExtender.prototype = {
    TypeName: iNFFormExtender.TypeName,
    ExtenderType: iNFFormExtender.ExtenderType,
    
    Extenders: null,
    Service: null,
    FormInfo: null,
    FormControlInfos: null,
    FormContentTypeId: null,

    Extend: function()
    {
        if (!this.CanExtend())
        {
            return;
        }

        this.Extenders = iNFFormExtender.Extenders;
        if (!this.Extenders ||
            this.Extenders.GetLength() <= 0)
        {
            return;
        }

        var extender = this;
        this.InitializeForm(function()
        {
            extender.ExtendControls();

            // 繰り返しセクションのイベント定義
            NWF.FormFiller.Events.RegisterRepeaterRowAdded(ISFunction.CreateDelegate(extender.ExtendRepeterSection, extender));
        });
    },

    InitializeForm : function(callback)
    {
        // 初期化時の非同期処理を制御する
        var invocationContext = {
            NintexFormsReady: false,
            ContentTypeEnsured: false,

            Completed: function()
            {
                return this.NintexFormsReady &&
                       this.ContentTypeEnsured;
            }
        };

        var formExtender = this;
        NWF.FormFiller.Events.RegisterAfterReady(function ()
        {
            invocationContext.NintexFormsReady = true;
            if (invocationContext.Completed())
            {
                formExtender.EnsureFormControlInfos(function ()
                {
                    callback();
                });            
            }
        });

        this.EnsureFormContentTypeId(function ()
        {
            invocationContext.ContentTypeEnsured = true;
            if (invocationContext.Completed())
            {
                formExtender.EnsureFormControlInfos(function ()
                {
                    callback();
                });            
            }
        });
    },

    ExtendControls: function(target)
    {
        var controlInfos = this.FormControlInfos;
        for (var i = 0; i < controlInfos.length; i++)
        {
            var controlInfo = controlInfos[i];

            var extenderClassNames = this.Extenders.Get(controlInfo.FormControlTypeUniqueId);
            if (typeof(extenderClassNames) == 'string')
            {
                extenderClassNames = [extenderClassNames];
            }
            if (!(extenderClassNames instanceof Array))
            {
                continue;
            }

            for (var j = 0; j < extenderClassNames.length; j++)
            {
                var extenderClassName = extenderClassNames[j];
                if (extenderClassName)
                {
                    var extender = eval('new ' + extenderClassName + '();');
                    extender.ParentExtender = this;
                    extender.UniqueId = controlInfo.UniqueId;
                    extender.ControlInfo = controlInfo;

                    if (extender.CanExtend(target))
                    {
                        extender.Extend();

                        if (!extender.AllowAdditionalExtension())
                        {
                            break;
                        }
                    }
                }
            }
        }
    },

    ExtendRepeterSection: function()
    {
        this.ExtendControls(NWF$(arguments[0][0])[0]);
    },

    CreateWorkFlowControlInfos: function()
    {
        var formControlInfos = [];

        // V2コントロールの場合
        var userControls = iNFUserFieldExtender.FindFieldControls();
        for (var i = 0; i < userControls.length; i++)
        {
            // UniqueIdの取得 (暫定対応 : Infoshare.Nintex.UserFieldExtenderにGetUniqueId実装を持つべき）
            var formControlIdAttribute = userControls[i].attributes.getNamedItem("formcontrolid");
            var formControlId = formControlIdAttribute ? formControlIdAttribute.value : null;

            formControlInfos.push(this.CreateWorkFlowControlInfo(formControlId, iNFFormExtender.FormControlTypeId.UserControl));
        }

        // V1コントロールの場合
        var legacyUserControls = iNFLegacyUserFieldExtender.FindFieldControls();
        for (var i = 0; i < legacyUserControls.length; i++)
        {
            // UniqueIdの取得 (暫定対応 : Infoshare.Nintex.LegacyUserFieldExtenderにGetUniqueId実装を持つべき）
            var textArea = legacyUserControls[i].parentElement.getElementsByTagName("textarea")[0];
            var formControlIdAttribute =  textArea.attributes.getNamedItem("formcontrolid");
            var formControlId = formControlIdAttribute ? formControlIdAttribute.value : null;

            formControlInfos.push(this.CreateWorkFlowControlInfo(formControlId, iNFFormExtender.FormControlTypeId.LegacyUserControl));
        }

        return formControlInfos;
    },

    CreateWorkFlowControlInfo: function(uniqueId, formControlTypeUniqueId)
    {
        var formControlInfo = {};

        // FormControlTypeUniqueIdの作成
        formControlInfo.FormControlTypeUniqueId = formControlTypeUniqueId;

        // UniqueIdの作成
        formControlInfo.UniqueId = uniqueId;
            
        // SelectionSet（全てのエンティティを取得できるようにする 0 : User, 2 : SecGroup, 3 ; SPGroup）
        formControlInfo.SelectionSet = [0, 2, 3];

        // MultiSelectの設定（複数選択可能とする）
        formControlInfo.MultiSelect = true;

        // MaxItemの設定（超えないであろう値999とする）
        formControlInfo.MaximumEntities = 999;

        return formControlInfo;
    },

    CanExtend: function()
    {
        return iNFFormExtender.CanExtend();
    },

    AllowAdditionalExtension: function()
    {
        return false;
    },

    EnsureFormControlInfos: function(callback)
    {
        if (this.FormControlInfos)
        {
            callback(this.FormControlInfos);
            return;
        }
        
        // WorkFlow上のFormの場合サービスからControlInfosが取得できないのでControlInfosを作成する
        if (iNFFormExtender.IsWorkflowForm(this.FormContentTypeId))
        {
            this.FormControlInfos = this.CreateWorkFlowControlInfos();
            callback();
        }
        else
        {
            var extender = this;
            var service = this.GetService();
            service.GetForm(iVxContext.GetListId(), '', function (result)
            {
                extender.FormInfo = result;
                if (result.GetFormResult.Form)
                {
                    extender.FormControlInfos = result.GetFormResult.Form.FormControls;
                }

                callback();
            });
        }
    },

    GetService: function()
    {
        if (!this.Service)
        {
            this.Service = new iNFormService(iVxContext.WebUrl);
        }

        return this.Service;
    },

    EnsureFormContentTypeId: function(callback)
    {
        // QueryStringに含まれる場合
        if (iVxContext.ContentTypeId)
        {
            this.FormContentTypeId = iVxContext.ContentTypeId;
            callback();
            return;
        }

        // 含まれない場合WebServiceから取得する
        var listId = iVxContext.GetListId();
        var itemId = iVxContext.ItemId;
        if (!listId || !itemId)
        {
            callback();
            return;
        }

        // リストとアイテムの取得
        var formExtender = this;
        iVxService.GetList(iVxContext.WebUrl, listId, function(list)
        {
            // 暫定対応（リストアイテムのキャッシュロジックの為別箇所で必要なFileDirRefを取得する）
            // ToDo : ListFormExtenderのリスト取得箇所に実装を移す
            var viewFields = new ISDictionary;
            viewFields.Add("FileDirRef", list.Fields.Get("FileDirRef"));
            viewFields.Add("ContentTypeId", list.Fields.Get("ContentTypeId"));

            iVxService.RetrieveItemById(iVxContext.WebUrl, list, itemId, viewFields, function(item)
            {
                formExtender.FormContentTypeId = item != null ? item.Properties.ContentTypeId : null;
                callback();
            });
        });      
    }
}
                                      
