// -----------------------------------------------------------------------
//  UserFieldExtender
// -----------------------------------------------------------------------
Infoshare.Nintex.UserFieldExtender = function Infoshare$Nintex$UserFieldExtender(){}
iNFUserFieldExtender = Infoshare.Nintex.UserFieldExtender;
iNFUserFieldExtender.TypeName = 'Infoshare.Nintex.UserFieldExtender';
iNFUserFieldExtender.ExtenderType = iBehaviorExtender.ExtenderType.Control;
iNFUserFieldExtender.ClassInfo = null;

iNFUserFieldExtender.Initialize = function()
{
    iBehaviorExtender.AddExtender(Infoshare.Nintex.FormsFormExtender, iNFFormExtender.FormControlTypeId.UserControl, 'Infoshare.Nintex.UserFieldExtender');
}
iNFUserFieldExtender.CanExtend = function()
{
    return iNFUserFieldExtender.HasFieldControl();
}

iNFUserFieldExtender.HasFieldControl = function(target)
{
    return iNFUserFieldExtender.FindFieldControls(target).length > 0;
}
iNFUserFieldExtender.FindFieldControls = function(target)
{
    var element = target ? ISDomAccessor.GetElement(target) : document;
    var inputs = element.getElementsByTagName('input');

    var controls = new Array();
    for (var i = 0; i < inputs.length; i++)
    {
        var input = inputs[i];
        if (ISString.StartsWith(input.className, 'nf-peoplepicker nf-associated-control', true))
        {
            controls.push(input);
        }
    }

    return controls;
}

iNFUserFieldExtender.FindFieldControlByUniqueId = function(uniqueId, target)
{
    var control = null;
    if (uniqueId)
    {
        var element = target ? ISDomAccessor.GetElement(target) : document;

        var inputContainers = i$(".ip-container", element);
        for (var i = 0; i < inputContainers.length; i++)
        {
            var input = i$(".nf-peoplepicker", inputContainers[i])[0];
            if (typeof(input) == "undefined")
            {
                break;
            }
            // uniqueIdの判断
            var formControlIdAttribute = input.attributes.getNamedItem("formcontrolid");
            var formControlId = formControlIdAttribute ? formControlIdAttribute.value : null;
            if (formControlId == uniqueId)
            {
                control = input;
                break;
            }
        }
    }
    return control;
}

iNFUserFieldExtender.prototype = {
    TypeName: iNFUserFieldExtender.TypeName,
    ExtenderType: iNFUserFieldExtender.ExtenderType,

    EditorElement: null,
    TextArea: null,
    PickerAPI: null,

    EntitySelection: null,

    GetValue: function()
    {
        this.EnsureEditor();

        var values = new Array();

        // Entitiesをすべて取得してからSpPrincipalNameを返す
        var entities = this.GetEntities();
        for (var i = 0; i < entities.length; i++)
        {
            values.push(entities[i].Properties["SpPrincipalName"]);
        }

        return values;
    },

    GetEntities: function()
    {
        this.EnsureEditor();

        var entities = new Array();

        // 名前解決済み項目を処理
        var resolvedEntities = this.GetResolvedEntities();
        entities = entities.concat(resolvedEntities);

        // TextValueの処理
        var textValues = this.GetTextValues();
        for (var i = 0; i < textValues.length; i++)
        {
            // ToDo:　Undefinedの種別の追加
            // 暫定対応：UndefinedはGroupアイコンとして表示する
            var entity = new iUserFieldEntity(textValues[i], textValues[i], "Group");
            entities.push(entity);
        }

        return entities;
    },

    GetResolvedEntities: function()
    {
        this.EnsureEditor();

        var entities = new Array();

        // Entityを生成する
        var resolveInput = i$(".ip-item", this.EditorElement.parentElement);
        for (var i = 0; i < resolveInput.length; i++)
        {
            var item = resolveInput[i];

            var displayName = item.innerText.replace("\r\n", "");
            
            var principalName = item.attributes.getNamedItem("data-val").value;

            // Claim、Form認証の場合Userのトークンの値からエンティティ種別を判断する（Claim : i:0#.w| , Form : i:0#.f|）
            // Reference : http://blogs.technet.com/b/sharepoint_support/archive/2013/11/07/sharepoint-windows.aspx
            var type = ISString.StartsWith(principalName, "i:0#.", false) ? "User" : "Group";

            var entity = new iUserFieldEntity(displayName, principalName, type);

            entities.push(entity);
        }
        return entities;
    },

    GetTextValues : function()
    {
        var textValues = new Array();
        var textArray = this.TextArea.value.split(';');
        for (var i = 0; i < textArray.length; i++)
        {
            if (!ISString.IsNullOrEmpty(textArray[i]))
            {
                textValues.push(textArray[i]);
            }
        }
        return textValues;
    },

    SetValues: function(values)
    {
        this.EnsureEditor();

        var extender = this;
        var cashValues = values;
        var service = this.ParentExtender.GetService();

        // 値の初期化
        extender.PickerAPI.clear();

        // Form認証対応 (ClaimTokenを含むとResolvePrincipalsが取得できない為除去する）
        for (var i = 0; i < values.length; i++)
        {
            if (ISString.StartsWith(values[i], "i:0#.f|", true) ||
                ISString.StartsWith(values[i], "c:0-.f|", true))
            {
                var splitedPrincipalValue = values[i].split('|');
                if (splitedPrincipalValue.length == 2)
                {
                    values[i] = splitedPrincipalValue[1];
                }
            }
        }

        // ControlInfoのSelectionSetとはスキーマが異なるのでPickerAPIから取得する
        service.ResolvePrincipals(values, this.PickerAPI.$elem.data("selectionset"), function(results)
        {
            var principals = [];
            var textValues = "";

            for (var i = 0; i < cashValues.length; i++)
            {
                var result = results[cashValues[i]];
                if (result &&
                    result.length == 1 && // 単一のデータが取得される
                    result[0].type)       // Resolveできる
                {
                    principals.push(result[0]);
                }
                else 
                {
                    textValues += cashValues[i] ;
                }
            }

            for (var i = 0; i < principals.length; i++)
            {
                // Entity同期時の種別判断の為Windows認証の場合キャッシュした値をセットする
                if (ISString.StartsWith(cashValues[i], "i:0#.w|", true) ||
                    ISString.StartsWith(cashValues[i], "c:0+.w|", true))
                {
                    principals[i].id = cashValues[i];
                    principals[i].value = cashValues[i];
                }
                extender.PickerAPI.add(principals[i]);
            }
            // ResolveできなかったEntityをテキストとして追加
            extender.TextArea.innerText = textValues;
        });
    },     

    SetEntities: function(entities)
    {
        this.EnsureEditor();

        var extender = this;
        var cashValues = entities;        
        var service = this.ParentExtender.GetService();
        
        // 単数選択列は既存のエンティティを削除する
        if (!this.EntitySelection.AllowMultipleSelection)
        {
            this.ClearEntities();
        }
        // 複数選択列は既存のエンティティを取得して、ユニークな値のみ追加対象とする
        else
        {
            entities = this.GetUniqueEntities(entities);
        }

        // Form認証対応 (ClaimTokenを含むとResolvePrincipalsが取得できない為除去する）
        var searchPrincipals = new Array();
        for (var i = 0; i < entities.length; i++)
        {
            var principalName = entities[i].Properties["SpResolveKey"];
            searchPrincipals.push(principalName);
        }

        // ControlInfoのSelectionSetとはスキーマが異なるのでPickerAPIから取得する
        service.ResolvePrincipals(searchPrincipals, this.PickerAPI.$elem.data("selectionset"), function(results)
        {
            var textArray  = new Array();

            for (var i = 0; i < cashValues.length; i++)
            {
                var result = results[cashValues[i].Properties["SpResolveKey"]];
                // ResolveできるエンティティはResolveする
                if (result &&
                    result.length == 1 && // 単一のデータが取得される
                    result[0].type)       // Resolveできる
                {
                    var principalName = cashValues[i].Properties["SpResolveKey"];
                    // Entity同期時の種別判断の為Windows認証の場合キャッシュした値をセットする
                    if (ISString.StartsWith(principalName, "i:0#.w|", true) ||
                        ISString.StartsWith(principalName, "c:0+.w|", true))
                    {
                        result[0].id    = principalName;
                        result[0].value = principalName;
                    }
                    extender.PickerAPI.add(result[0]);
                }
                else 
                {
                    textArray.push(cashValues[i].Properties["SpResolveKey"]);
                }
            }

            // ResolveできなかったEntityをテキストとして追加
            extender.TextArea.innerText = textArray.join(';');
        });
    },

    ClearEntities: function()
    {
        // 値の初期化
        this.PickerAPI.clear();
    },
    
    GetUniqueEntities: iUserFieldExtender.prototype.GetUniqueEntities,

    CanExtend: function(targetElement)
    {
        this.EnsureEditor(targetElement);

        return this.EditorElement != null;
    },

    Extend: function()
    {
    },

    AllowAdditionalExtension: function()
    {
        return true;
    },

    GetEntitySelection: function()
    {
        if (!this.EntitySelection)
        {
            this.EnsureEditor();

            var selection = new iUserFieldEntitySelection();
            selection.AllowUserSelection            = ISArray.Contains(this.ControlInfo.SelectionSet, 0);
            selection.AllowSecurityGroupSelection   = ISArray.Contains(this.ControlInfo.SelectionSet, 2);
            selection.AllowSharePointGroupSelection = ISArray.Contains(this.ControlInfo.SelectionSet, 3);
            selection.AllowMultipleSelection        = this.ControlInfo.MultiSelect;
            selection.MaxSelectionCount             = this.ControlInfo.MaximumEntities;
            this.EntitySelection = selection;
        }

        return this.EntitySelection;
    },

    EnsureEditor: function(targetElement)
    {
        if (this.EditorElement &&
            this.PickerAPI &&
            this.TextArea)
        {
            return;
        }

        this.EditorElement = iNFUserFieldExtender.FindFieldControlByUniqueId(this.UniqueId, targetElement);
        if (this.EditorElement)
        {
            this.PickerAPI = new NF.PeoplePickerApi(this.EditorElement);
            this.TextArea  = this.EditorElement.parentElement.getElementsByTagName("textarea")[0];
        }
    }
}


// -----------------------------------------------------------------------
//  LegacyUserFieldExtender
// -----------------------------------------------------------------------
Infoshare.Nintex.LegacyUserFieldExtender = function Infoshare$Nintex$LegacyUserFieldExtender()
{
    Infoshare.SharePoint.LegacyUserFieldExtender.apply(this, arguments);
}
iNFLegacyUserFieldExtender = Infoshare.Nintex.LegacyUserFieldExtender;
iNFLegacyUserFieldExtender.TypeName = 'Infoshare.Nintex.LegacyUserFieldExtender';
iNFLegacyUserFieldExtender.ExtenderType = iBehaviorExtender.ExtenderType.Control;

iNFLegacyUserFieldExtender.Initialize = function()
{
    iBehaviorExtender.AddExtender(Infoshare.Nintex.FormsFormExtender, iNFFormExtender.FormControlTypeId.LegacyUserControl, 'Infoshare.Nintex.LegacyUserFieldExtender');
}
iNFLegacyUserFieldExtender.CanExtend = function()
{
    return iNFLegacyUserFieldExtender.HasFieldControl();
}

iNFLegacyUserFieldExtender.HasFieldControl = function(target)
{
    return iNFLegacyUserFieldExtender.FindFieldControls(target).length > 0;
}
iNFLegacyUserFieldExtender.FindFieldControls = function(target)
{
    var element = target ? ISDomAccessor.GetElement(target) : document;
    var divs = element.getElementsByTagName('div');

    var controls = new Array();
    for (var i = 0; i < divs.length; i++)
    {
        var div = divs[i];
        if (ISString.Contains(div.className, 'ms-inputuserfield', true) &&
            ISString.Contains(div.className, 'ms-inputBox', true) &&
            div.nextSibling &&
            ISString.StartsWith(div.nextSibling.className, 'ms-inputuserfield ms-inputBox nf-associated-control', true))
        {
            controls.push(div);
        }
    }

    return controls;
}
iNFLegacyUserFieldExtender.FindFieldControlByUniqueId = function(uniqueId)
{
    var control = null;
    if (uniqueId)
    {
        var divs = document.getElementsByTagName('div');
        for (var i = 0; i < divs.length; i++)
        {
            var div = divs[i];
            if (ISString.Contains(div.className, 'ms-inputuserfield', true) &&
                ISString.Contains(div.className, 'ms-inputBox', true) &&
                div.nextSibling &&
                ISString.StartsWith(div.nextSibling.className, 'ms-inputuserfield ms-inputBox nf-associated-control', true))
            {
                // uniqueIdの判断
                var textArea = div.parentElement.getElementsByTagName("textarea")[0];
                var formControlIdAttribute =  textArea.attributes.getNamedItem("formcontrolid");
                var formControlId = formControlIdAttribute ? formControlIdAttribute.value : null;
                
                if (formControlId == uniqueId)
                {
                    control = div;
                    break;
                }
            }
        }
    }
    return control;
}

iNFLegacyUserFieldExtender.prototype = new Infoshare.SharePoint.LegacyUserFieldExtender();
iNFLegacyUserFieldExtender.prototype.TypeName = iNFLegacyUserFieldExtender.TypeName;
iNFLegacyUserFieldExtender.prototype.ExtenderType = iNFLegacyUserFieldExtender.ExtenderType,

iNFLegacyUserFieldExtender.prototype.UniqueId = null;
iNFLegacyUserFieldExtender.prototype.ControlInfo = null;

iNFLegacyUserFieldExtender.prototype.GetEntitySelection = function()
{
    if (!this.EntitySelection)
    {          
        this.EnsureEditor();

        var info = this.ControlInfo;
        var selection = new iUserFieldEntitySelection();

        selection.AllowUserSelection            = ISArray.Contains(this.ControlInfo.SelectionSet, 0);
        selection.AllowSecurityGroupSelection   = ISArray.Contains(this.ControlInfo.SelectionSet, 2);
        selection.AllowSharePointGroupSelection = ISArray.Contains(this.ControlInfo.SelectionSet, 3);
        selection.AllowMultipleSelection        = this.ControlInfo.MultiSelect;
        selection.MaxSelectionCount             = this.ControlInfo.MaximumEntities;

        this.EntitySelection = selection;
    }

    return this.EntitySelection;
}
iNFLegacyUserFieldExtender.prototype.EnsureEditor = function()
{
    if (this.EditorElement)
    {
        return;
    }

    this.EditorElement = iNFLegacyUserFieldExtender.FindFieldControlByUniqueId(this.UniqueId);
    if (this.EditorElement)
    {
        var userEditor = ISDomAccessor.FindAncestorByClassName(this.EditorElement, "ms-usereditor");
        var anchors = userEditor.getElementsByTagName('a');
        for (var i = 0; i < anchors.length; i++)
        {
            var anchor = anchors[i];
            if (ISString.EndsWith(anchor.id, '_checkNames', true))
            {
                this.CheckNameButton = anchor;
            }
            if (ISString.EndsWith(anchor.id, '_browse', true))
            {
                this.BrowseDialogButton = anchor;
            }
        }
    }
}
                                      
                                         
