Infoshare.Infragistics.IgFileLoader = function Infoshare$Infragistics$IgFileLoader() { }
iIgFileLoader = Infoshare.Infragistics.IgFileLoader;

iIgFileLoader.LoadjQuery = true;
iIgFileLoader.LoadCoreCss = false;
iIgFileLoader.BaseFileLoaded = false;
iIgFileLoader.ExtendedFileLoaded = false;

iIgFileLoader.Load = function(callback)
{
    // すでに初期化済の場合読み込まない
    if (typeof (ig$) != 'undefined')
    {
        callback();
    }

    var context = {
        CssLoaded: false,
        ScriptLoaded: false,

        LoadCompleted: function()
        {
            return this.CssLoaded &&
                   this.ScriptLoaded;
        }
    };
    var count = 0;

    // CSS読み込み
    var masterSourcesPath = ISString.TrimEnd(iVxContext.MasterSourcesPath, '/');
    var baseCss = [ masterSourcesPath + '/Infoshare/Infragistics/css/themes/yeti/infragistics.theme.css',
                    masterSourcesPath + '/Infoshare/Infragistics/css/structure/infragistics.css' ];
    ISScript.Load(baseCss, null, function()
    {
        // infragisticsのCSS読み込みの後に拡張CSSを読み込む
        var css = [ masterSourcesPath + '/Infoshare/infragistics.extension.css'];

        ISScript.Load(css, null, function()
        {
            context.CssLoaded = true;
            if (context.LoadCompleted() && callback)
            {
                callback();
            }
        });
    });

    // スクリプト読み込み
    var baseScript = masterSourcesPath + '/Infoshare/Infragistics/jQuery/jquery.min.js';
    ISScript.Load(baseScript, null, function()
    {
        var script = [ masterSourcesPath + '/Infoshare/Infragistics/jQuery/jquery-ui.min.js',
                       masterSourcesPath + '/Infoshare/Infragistics/js/infragistics.core.js',
                       masterSourcesPath + '/Infoshare/Infragistics/js/infragistics.lob.js' ];
        var type = [ '$.widget', '$.ig.Grid', '$.ig.regional.ja' ];
        ISScript.Load(script, type, function()
        {
            if ($ && typeof (ig$) == 'undefined')
            {
                // infragisticsのjs読み込み時に$が必要なため2段階でスクリプトを読み込み、$をクリアする
                ig$ = $.noConflict(true);
            }

            context.ScriptLoaded = true;
            if (context.LoadCompleted() && callback)
            {
                callback();
            }
        });
    });
}
				  
