Infoshare.Infragistics.IgGridUtility = function Infoshare$Infragistics$IgGridUtility() { }
iIgGridUtility = Infoshare.Infragistics.IgGridUtility;

iIgGridUtility.DefaultColumnWidth = 100;
iIgGridUtility.Columns = null;
iIgGridUtility.BuildColumns = function (columnDefinitions)
{
    var columns = new Array();
    for (var i = 0; i < columnDefinitions.length ; i++)
    {
        // 列情報取得: ColumnTypeが指定されているもののみグリッドに表示する
        var columnDefinition = columnDefinitions[i];
        if (ISString.IsNullOrEmpty(columnDefinition.ColumnType))
        {
            continue;
        }

        // グリッドカラムの初期化
        var column = { headerText: ISString.IsNullOrEmpty(columnDefinition.DisplayName) ? iResxResource.GetString(columnDefinition.DisplayNameResourceKey) : columnDefinition.DisplayName,
                       key:        columnDefinition.Key,
                       datatype: 'string',                       
                       width:      (ISString.IsNullOrEmpty(columnDefinition.Width) ? iIgGridUtility.DefaultColumnWidth : columnDefinition.Width) + 'px' }
        if (columnDefinition.ColumnType.toUpperCase() == 'LINK')
        {
            var template = "<a href= '${" + columnDefinition.Key + "}'>" + "${" + columnDefinition.Key + "}</a>";
            column.template = template; 
        }
        if (columnDefinition.ColumnType.toUpperCase() == 'LINKWITHTEXT')
        {
            var dispayName = iResxResource.GetString(columnDefinition.DesplayKey);
            var template = "<a href= '${" + columnDefinition.Key + "}'>" + dispayName + "</a>";
            column.template = template; 
        }
        else if (columnDefinition.ColumnType.toUpperCase() == 'HIDDEN')
        {
            column.hidden = true;
        }

        columns.push(column);
    }
    return columns;
};

iIgGridUtility.BuildGridItems = function(entities, columns)
{
    var items = new Array();
    for (var i = 0; i < entities.length; i++)
    {
        var entity = entities[i];
        var item = new Object();
        for (var j = 0; j < columns.length; j++)
        {
            var key = columns[j].key;
            var value = entity[key];
            item[key] = value;
        }

        items.push(item);
    }

    return items;
};
				  	
										  
