Infoshare.Teams.Teams = function Infoshare$Teams$Teams()
{
    // スレッドセーフに初期化処理を実施できるように、Initialize関数を拡張
    iAsyncInitializableExtender.Extend(this);
};
iTeams = Infoshare.Teams.Teams;
iTeams.TypeName = 'Infoshare.Teams.Teams';

iTeams.IsInTeams = function(callback)
{
    var isInTeams = false;

    // デスクトップ版/Web 版 ともに iframe 経由で開かれるため、親ウィンドウがない場合は、Teams から開かれていないと判断する
    if (window.parent && window.parent == window)
    {
        setTimeout(function () {
            if (iType.GetType(callback) == iType.BuiltinType.Function) {
                callback(isInTeams);
            }
        }, 1);
        return;
    }

    // まず、ブラウザのユーザーエージェントで確認
    // userAgent sample
    // Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Teams/1.2.00.34161 Chrome/66.0.3359.181 Electron/3.1.13 Safari/537.36
    var userAgent = window.navigator.userAgent;
    var values = userAgent.split(' ');
    for (var i = 0; i < values.length; i++)
    {
        var value = values[i];
        if (iString.StartsWith(value, 'Teams', true))
        {
            isInTeams = true;

            break;
        }
    }

    // Web 版は、ブラウザのユーザーエージェントでは判別ができてないため、コンテキストを取得して確認する
    if (!isInTeams)
    {
        (new iTeams()).GetContext(function (context)
        {
            if (iType.GetTypeName(context) == iTeamsContext.TypeName &&
                (context.HostClientType == iTeamsContext.HostClientType.Desktop || // 念のためデスクトップ版もチェックしておく
                 context.HostClientType == iTeamsContext.HostClientType.Web))
            {
                isInTeams = true;
            }

            if (iType.GetType(callback) == iType.BuiltinType.Function)
            {
                callback(isInTeams);
            }
        });
    }
    else
    {
        setTimeout(function () {
            if (iType.GetType(callback) == iType.BuiltinType.Function) {
                callback(isInTeams);
            }
        }, 1);
    }
}

iTeams.Version       = '1.6.0';
iTeams.ScriptBaseUrl = '';
iTeams.ScriptFile    = 'MicrosoftTeams.js';

iTeams.prototype = {
    TypeName: iTeams.TypeName,

    UseCDN: true,
    Teams: null,

    Context: null,
    Settings: null,


    Initialize: function(callback)
    {
        var ref = this;
        this.loadScript(function () {
            if (typeof microsoftTeams != 'undefined' &&
                iType.GetType(microsoftTeams.initialize) == iType.BuiltinType.Function)
            {
                ref.Teams    = microsoftTeams;
                ref.Settings = new iTeamsSettings(microsoftTeams.settings);

                ref.Teams.initialize();

                if (iType.GetType(callback) == iType.BuiltinType.Function)
                {
                    callback();
                }
            }
        });
    },

    ExecuteDeepLink: function(deepLink, callback)
    {
        var ref = this;
        this.Initialize(function () {
            ref.Teams.executeDeepLink(deepLink, function (status, reason)
            {
                if (iType.GetType(callback) == iType.BuiltinType.Function)
                {
                    callback(status, reason);
                }
            });
        });
    },

    GetContext: function(callback)
    {
        if (!this.Context)
        {
            var ref = this;
            this.Initialize(function () {
                ref.Teams.getContext(function (context) {
                    ref.Context = new iTeamsContext(context);

                    if (iType.GetType(callback) == iType.BuiltinType.Function) {
                        callback(ref.Context);
                    }
                })
            })
        }
        else
        {
            var ref = this;
            setTimeout(function () {
                if (iType.GetType(callback) == iType.BuiltinType.Function) {
                    callback(ref.Context);
                }
            }, 1);
        }
    },

    GetTabInstances: function(callback, parameters)
    {
        var ref = this;
        this.Initialize(function () {
            ref.Teams.getTabInstances(function (tabInstances)
            {
                var tabs = new Array();
                if (!iType.IsNullOrUndefined(tabInstances) &&
                    iType.GetType(tabInstances.teamTabs) == iType.BuiltinType.Array)
                {
                    for (var i = 0; i < tabInstances.teamTabs.length; i++)
                    {
                        var tab = new iTeamsTabInstance(tabInstances.teamTabs[i]);
                        tabs.push(tab);
                    }
                }

                if (iType.GetType(callback) == iType.BuiltinType.Function)
                {
                    callback(tabs);
                }
            }, parameters);
        });
    },

    loadScript: function(callback)
    {
        if (typeof microsoftTeams === 'undefined')
        {
            var stopwatch = new ISStopwatch();
            stopwatch.Start();
            ISTrace.TraceVerbose('[BEGIN] iTeams.loadScript (UseCDN: ' + this.UseCDN + ')');

            var path = '';
            if (this.UseCDN)
            {
                // https://statics.teams.cdn.office.net/sdk/v1.6.0/js/MicrosoftTeams.min.js
                path = iString.Format('https://statics.teams.cdn.office.net/sdk/v{0}/js/{1}', iTeams.Version, iTeams.ScriptFile);
            }
            else
            {
                path = iString.Format('{0}/{1}',
                                      iString.TrimEnd(iTeams.ScriptBaseUrl, '/'),
                                      iTeams.ScriptFile);
            }

            ISScript.Load(path, null, function()
            {
                ISTrace.TraceVerbose('[END] iTeams.loadScript (spent: ' + stopwatch.Stop() + ')');
                if (iType.GetType(callback) == iType.BuiltinType.Function)
                {
                    callback();
                }
            });
        }
        else
        {
            setTimeout(function ()
            {
                if (iType.GetType(callback) == iType.BuiltinType.Function)
                {
                    callback();
                }
            }, 1);
        }
    }
};


