// -----------------------------------------------------------------------
//  TeamsLinker
// -----------------------------------------------------------------------
Infoshare.Teams.TeamsLinker = function Infoshare$Teams$TeamsLinker(clientType)
{
    Infoshare.Web.UrlApplicationLinker.apply(this, arguments);

    // ターゲットによって、遷移方法とスキームを変える
    if (clientType == iTeamsContext.HostClientType.Desktop)
    {
        // クライアント版 Teams 連携の場合、
        // ブラウザから開く場合は、iframe経由、
        // クライアントから開く場合は、Teams SDK 経由で開く
        this.ClientType = iTeamsContext.HostClientType.Desktop;
        this.OpenBy = iUrlApplicationLinker.OpenBy.Background;
        this.Schema = iTeamsLinker.Schema.MSTeams;
    }
    else if (clientType == iTeamsContext.HostClientType.Web)
    {
        // ブラウザ版 Teams 連携の場合は、別ウィンドウで開く
        // クライアントから、ブラウザ版を呼び出すケースは考慮しない
        this.ClientType = iTeamsContext.HostClientType.Web;
        this.OpenBy = iUrlApplicationLinker.OpenBy.WindowOpen;
        this.Schema = iTeamsLinker.Schema.HTTPS;
    }
    else
    {
        var message = iString.Format('[Infoshare.Teams.TeamsLinker] Unknown client type "{0}" specified.', clientType);
        ISTrace.TraceWarning(message);
    }
};
iTeamsLinker = Infoshare.Teams.TeamsLinker;
iTeamsLinker.TypeName = 'Infoshare.Teams.TeamsLinker';

iTeamsLinker.OpenBy = iObject.Clone(iUrlApplicationLinker.OpenBy);
iTeamsLinker.OpenBy.TeamsSDK = 'TeamsSDK';

iTeamsLinker.Schema = { HTTPS:   'HTTPS',
                        MSTeams: 'MSTeams' };

iTeamsLinker.prototype = new Infoshare.Web.UrlApplicationLinker();
iTeamsLinker.prototype.TypeName = iTeamsLinker.TypeName;

iTeamsLinker.prototype.ClientTypeAutoDetection = false;
iTeamsLinker.prototype.ClientType = iTeamsContext.HostClientType.Desktop;
iTeamsLinker.prototype.Schema = iTeamsLinker.Schema.MSTeams;
iTeamsLinker.prototype.OriginalOpen = iTeamsLinker.prototype.Open;
iTeamsLinker.prototype.Open = function()
{
    var ref = this;
    iTeams.IsInTeams(function(isInTeams)
    {
        if (isInTeams)
        {
            if (ref.ClientTypeAutoDetection)
            {
                var teams = new iTeams();
                teams.GetContext(function (context)
                {
                    if (context.HostClientType == iTeamsContext.HostClientType.Desktop)
                    {
                        ref.ClientType = iTeamsContext.HostClientType.Desktop;
                        ref.OpenBy = iUrlApplicationLinker.OpenBy.Background;
                        ref.Schema = iTeamsLinker.Schema.MSTeams;

                        // Teams 内で実行されている場合、sdk の executeDeepLink 経由で呼び出し、警告表示を抑止
                        var url = ref.BuildUrl();
                        ISTrace.TraceVerbose('iTeamsLinker.Open [Url: ' + url + ' | OpenBy: ' + iTeamsLinker.OpenBy.TeamsSDK + ']');

                        (new iTeams()).ExecuteDeepLink(url);
                    }
                    else if (context.HostClientType == iTeamsContext.HostClientType.Web)
                    {
                        ref.ClientType = iTeamsContext.HostClientType.Web;
                        ref.OpenBy = iUrlApplicationLinker.OpenBy.WindowOpen;
                        ref.Schema = iTeamsLinker.Schema.HTTPS;

                        ref.OriginalOpen();
                    }
                    else
                    {
                        var message = iString.Format('[Infoshare.Teams.TeamsLinker] Unknown client type "{0}" specified.', context.HostClientType);
                        ISTrace.TraceWarning(message);
                    }
                });
            }
            else
            {
                if (ref.ClientType == iTeamsContext.HostClientType.Desktop)
                {
                    // Teams 内で実行されている場合、sdk の executeDeepLink 経由で呼び出し、警告表示を抑止
                    var url = ref.BuildUrl();
                    ISTrace.TraceVerbose('iTeamsLinker.Open [Url: ' + url + ' | OpenBy: ' + iTeamsLinker.OpenBy.TeamsSDK + ']');

                    (new iTeams()).ExecuteDeepLink(url);
                }
                else if (ref.ClientType == iTeamsContext.HostClientType.Web)
                {
                    ref.OriginalOpen();
                }
                else
                {
                    var message = iString.Format('[Infoshare.Teams.TeamsLinker] Unknown client type "{0}" specified.', ref.ClientType);
                    ISTrace.TraceWarning(message);
                }
            }
        }
        else
        {
            ref.OriginalOpen();
        }
    });
};


// -----------------------------------------------------------------------
//  TeamsChatLinker
// -----------------------------------------------------------------------
Infoshare.Teams.TeamsChatLinker = function Infoshare$Teams$TeamsChatLinker()
{
    Infoshare.Teams.TeamsLinker.apply(this, arguments);
}
