iTeamsChatLinker.TypeName = 'Infoshare.Teams.TeamsChatLinker';

iTeamsChatLinker.prototype = new Infoshare.Teams.TeamsLinker();
iTeamsChatLinker.prototype.TypeName = iTeamsChatLinker.TypeName;

iTeamsChatLinker.prototype.Users   = null;
iTeamsChatLinker.prototype.Message = null;
iTeamsChatLinker.prototype.buildBaseUrl = function ()
{
    // https://docs.microsoft.com/en-us/microsoftteams/platform/concepts/build-and-test/deep-links
    // sample formats
    // msteams:/l/chat/0/0?users=​aaa@xxx.com,bbb@xxx.com&message=hogehoge
    // https://teams.microsoft.com/l/chat/0/0?users=​aaa@xxx.com,bbb@xxx.com&message=hogehoge
    // https://teams.microsoft.com/_#/l/chat/0/0?users=​aaa@xxx.com,bbb@xxx.com&message=hogehoge
    var format = '{0}/{1}l/chat/0/0';

    // schema
    var schema = 'https://teams.microsoft.com';
    if (this.Schema == iTeamsLinker.Schema.MSTeams)
    {
        schema = 'msteams:';
    }

    // client type
    var clientType = '';
    if (this.ClientType == iTeamsContext.HostClientType.Web)
    {
        clientType = '_#/';
    }

    var url = iString.Format(format, schema, clientType);
    return url;
};
iTeamsChatLinker.prototype.buildQuery = function ()
{
    // ?users={0}&message={1}
    var parameter = new iUriParameter();
    this.valueJoinSeparator = ',';
    parameter.Set('users',   this.buildParameterValueText(this.Users));
    parameter.Set('message', this.buildParameterValueText(this.Message));

    var query = '?' + parameter.ToString();
    return query;
};


