// -----------------------------------------------------------------------
//  Platform
// -----------------------------------------------------------------------
Infoshare.UnifiedCommunications.Platform = { Online:    'Online',
                                             OnPremise: 'OnPremise' };
UCPlatform = Infoshare.UnifiedCommunications.Platform;


// -----------------------------------------------------------------------
//  ApiKey
// -----------------------------------------------------------------------
Infoshare.UnifiedCommunications.ApiKey = { Online:    'a42fcebd-5b43-4b89-a065-74450fb91255',
                                           OnPremise: 'SWX-BUILD-SDK' };
UCApiKey = Infoshare.UnifiedCommunications.ApiKey;


// -----------------------------------------------------------------------
//  Service
// -----------------------------------------------------------------------
Infoshare.UnifiedCommunications.Service = function Infoshare$UnifiedCommunications$Service(platform, useCDN, version)
{
    this.Platform = platform;
    if      (platform == UCPlatform.Online)    { this.ApiKey = UCApiKey.Online; }
    else if (platform == UCPlatform.OnPremise) { this.ApiKey = UCApiKey.OnPremise; }

    this.UseCDN = useCDN;

    if (!iString.IsNullOrEmpty(version))
    {
        this.Version = version;
    }

    this.Users = new ISDictionary();
}
UCService = Infoshare.UnifiedCommunications.Service;
UCService.DefaultVersion = '1.2.35';
UCService.ScriptBaseUrl = '';
UCService.UcwaScriptFile = 'ucwa.sdk.js';

UCService.prototype = {
    Service: null,
    Client: null,

    Platform: null,
    UseCDN: true,
    Version: UCService.DefaultVersion,

    ApiKey: null,
    ClientId: null,
    DomainName: null,
    SignedIn: false,

    Users: null,
    Me: null,


    GetUser: function (sipAddress, callback)
    {
        this.GetUsers([sipAddress], function (users) 
        {
            callback(users[0]);
        });
    },

    GetUsers: function (sipAddresses, callback)
    {
        var usersFound = [];

        var querySipAddresses = [];
        for (var i = 0; i < sipAddresses.length; i++)
        {
            var sipAddress = sipAddresses[i];
            if (this.Users.Contains(sipAddress))
            {
                var user = this.Users.Get(sipAddress);
                if (user)
                {
                    usersFound.push(user);
                }
            }
            else
            {
                querySipAddresses.push(sipAddress);
            }
        }

        if (querySipAddresses.length > 0)
        {
            var service = this;
            this.QueryUsers(querySipAddresses, function (users, errors)
            {
                if (users && users.length > 0)
                {
                    service.Users.AddRange(users);
                    usersFound = usersFound.concat(users);
                }

                // 取得できないユーザーを延々取得しないようにディクショナリにnullを詰める
                if (errors && errors.length > 0)
                {
                    for (var i = 0; i < errors.length; i++)
                    {
                        var error = errors[i];
                        service.Users.Set(error.queryKey, null);
                    }
                }

                callback(usersFound);
            });
        }
        else
        {
            setTimeout(function ()
            {
                callback(usersFound);
            }, 1);
        }
    },

    QueryUser: function (sipAddress, callback)
    {
        var service = this;
        this.QueryUsers([sipAddress], function (users, errors)
        {
            callback(users[0], errors[0]);
        });
    },

    QueryUsers: function (sipAddresses, callback)
    {
        var service = this;
        this.initialize(function (initializeError)
        {
            if (initializeError)
            {
                callback(null, initializeError);
                return;
            }

            service.ucQueryUsers(sipAddresses, function (results)
            {
                var users = [];
                var errors = [];
                for (var i = 0; i < results.length; i++)
                {
                    var result = results[i];
                    if (result.Error)
                    {
                        var error = result.Error;
                        error.queryKey = result.Key;
                        errors.push(error);
                    }
                    else
                    {
                        var user = new UCUser(result.Key, result.Object);
                        users.push(user);
                    }
                }

                // sipAddressesにログインユーザーのものが含まれていた場合
                // その情報も追加して返す
                // sipのクエリでは自身の情報が返ってこないため
                var me = service.Client.personsAndGroupsManager.mePerson;
                var sip = ISString.TrimStart(me.id._value, 'sip:');
                if (ISArray.Contains(sipAddresses, sip))
                {
                    var user = new UCUser(sip, me);
                    users.push(user);
                }

                callback(users, errors);
            });
        });
    },

    GetMe: function(callback)
    {
        if (!this.Me)
        {
            this.QueryMe(callback);
        }
        else
        {
            var service = this;
            setTimeout(function ()
            {
                callback(service.Me);
            }, 1);
        }
    },

    QueryMe: function(callback)
    {
        var service = this;
        this.initialize(function (initializeError)
        {
            if (initializeError)
            {
                callback(null, initializeError);
                return;
            }

            service.ucGetMePerson(function (me, error)
            {
                if (error)
                {
                    callback(null, error);
                }

                var user = new UCUser(ISString.TrimStart(me.id._value, 'sip:'), me);
                callback(user, null);
            });
        });
    },

    initialize: function(callback)
    {
        var ref = this;
        this.ucLoadScript(function (service)
        {
            ref.ucInitialize(function (client, initializeError)
            {
                if (initializeError)
                {
                    callback(initializeError);
                    return;
                }

                ref.ucSignIn(function (signInError)
                {
                    if (signInError)
                    {
                        callback(signInError);
                        return;
                    }

                    callback(null);
                });
            });
        });
    },

    ucLoadScript: function (callback)
    {
        if (!this.Service)
        {
            var stopwatch = new ISStopwatch();
            stopwatch.Start();
            ISTrace.TraceVerbose('[BEGIN] UCService.ucLoadScript (Platform: ' + this.Platform + ', UseCDN: ' + this.UseCDN + ')');

            var path = ISString.Format('{0}/{1}',
                                       ISString.TrimEnd(UCService.ScriptBaseUrl, '/'),
                                       UCService.UcwaScriptFile);
            if (!this.UseCDN)
            {
                // CDN（Bootstrapper）を利用しない場合、Skypeオブジェクトを用意する
                if (typeof Skype === "undefined")
                {
                    Skype = {};
                    Skype.onExperienceLoaded = function () { };
                }
            }
            else
            {
                path = ISString.Format('https://swx.cdn.skype.com/shared/v/{0}/SkypeBootstrap.min.js', this.Version);
            }

            var ref = this;
            ISScript.Load(path, null, function ()
            {
                ref.Service = Skype;

                ISTrace.TraceVerbose('[END] UCService.ucLoadScript (spent: ' + stopwatch.Stop() + ')');
                callback(ref.Service);
            });
        }
        else
        {
            var ref = this;
            setTimeout(function ()
            {
                callback(ref.Service);
            }, 1);
        }
    },

    ucInitialize: function (callback)
    {
        if (this.Client == null)
        {
            var stopwatch = new ISStopwatch();
            stopwatch.Start();
            ISTrace.TraceVerbose('[BEGIN] UCService.ucInitialize (Platform: ' + this.Platform + ', UseCDN: ' + this.UseCDN + ')');

            if (!this.UseCDN)
            {
                // CDN（Bootstrapper）を利用しない場合、初期化処理は行わない
                // ToDo: 実装方法要確認
                var jCafe = require('jCafe');
                var client = new jCafe.Application();
                this.Client = client;

                var ref = this;
                setTimeout(function ()
                {
                    ISTrace.TraceVerbose('[END] UCService.ucInitialize (spent: ' + stopwatch.Stop() + ')');
                    callback(ref.Client, null);
                }, 1);
            }
            else
            {
                var ref = this;
                this.Service.initialize(
                    { apiKey: this.ApiKey },
                    function (api)
                    {
                        var client = new api.application();
                        ref.Client = client;

                        ISTrace.TraceVerbose('[END] UCService.ucInitialize (spent: ' + stopwatch.Stop() + ')');
                        callback(client, null);
                    },
                    function (error)
                    {
                        ISTrace.TraceWarning('[END] UCService.ucInitialize: initialize failed: ' + ref.ucBuildErrorMessage(error));
                        callback(null, error);
                    });
            }
        }
        else
        {
            var ref = this;
            setTimeout(function ()
            {
                callback(ref.Client, null);
            }, 1);
        }
    },

    ucSignIn: function (callback)
    {
        if (!this.SignedIn)
        {
            var stopwatch = new ISStopwatch();
            stopwatch.Start();
            ISTrace.TraceVerbose('[BEGIN] UCService.ucSignIn');

            // サインインオブジェクト初期化
            var signInObject = { domain: this.DomainName };
            if (this.Platform == UCPlatform.Online)
            {
                signInObject = { client_id:    this.ClientId,
                                 origins:      ["https://webdir.online.lync.com/autodiscover/autodiscoverservice.svc/root"],
                                 cors:         true,
                                 redirect_uri: location.href };
            }

            // サインイン処理
            var ref = this;
            this.Client.signInManager.signIn(signInObject).then(
                function ()
                {
                    ref.SignedIn = true;

                    ISTrace.TraceVerbose('[END] UCService.ucSignIn (spent: ' + stopwatch.Stop() + ')');
                    callback(null);
                },
                function (error)
                {
                    ISTrace.TraceWarning('[END] UCService.ucSignIn: signedIn failed: ' + ref.ucBuildErrorMessage(error));
                    callback(error);
                });
        }
        else
        {
            setTimeout(function ()
            {
                callback(null);
            }, 1);
        }
    },

    ucQueryUser: function (key, callback)
    {
        var stopwatch = new ISStopwatch();
        stopwatch.Start();
        ISTrace.TraceVerbose('[BEGIN] UCService.ucQueryUser (' + key + ')');

        var query = this.Client.personsAndGroupsManager.createPersonSearchQuery();
        query.text(key);
        query.limit(1);
        query.getMore().then(function (results)
        {
            ISTrace.TraceVerbose('[END] UCService.ucQueryUser (key: ' + key + ', spent: ' + stopwatch.Stop() + ')');
            if (!results || results.length != 1)
            {
                callback(key, null, { message: 'no user found.' });

                ISTrace.TraceWarning('[END] UCService.ucQueryUser: no user found. (' + key + ')');
                return;
            }

            callback(key, results[0].result, null);
        });
    },

    ucQueryUsers: function(keys, callback)
    {
        var stopwatch = new ISStopwatch();
        stopwatch.Start();
        ISTrace.TraceVerbose('[BEGIN] UCService.ucQueryUsers');

        var context = {
            Keys: keys,
            Results: [],

            Complete: function()
            {
                return this.Keys.length == this.Results.length;
            }
        };

        for (var i = 0; i < keys.length; i++)
        {
            var key = keys[i];
            this.ucQueryUser(key, function (key, user, error)
            {
                var result = new UCQueryResult(key);
                if (error) { result.Error  = error; }
                else       { result.Object = user; }
                context.Results.push(result);

                if (context.Complete())
                {
                    ISTrace.TraceVerbose('[END] UCService.ucQueryUsers (spent: ' + stopwatch.Stop() + ')');
                    callback(context.Results);
                }
            });
        }
    },

    ucGetMePerson: function(callback)
    {
        var stopwatch = new ISStopwatch();
        stopwatch.Start();
        ISTrace.TraceVerbose('[BEGIN] UCService.ucGetMePerson');

        var me = this.Client.personsAndGroupsManager.mePerson;
        setTimeout(function ()
        {
            ISTrace.TraceVerbose('[END] UCService.ucGetMePerson (spent: ' + stopwatch.Stop() + ')');
            callback(me, null);
        }, 1);
    },

    ucBuildErrorMessage: function(error)
    {
        var title = ''
        if (!ISString.IsNullOrEmpty(error.name))    { title += error.name + ', '; }
        if (!ISString.IsNullOrEmpty(error.message)) { title += error.message; }
        title = ISString.TrimEnd(title, ', ');

        var details = '';
        if (!ISString.IsNullOrEmpty(error.code))        { details += 'code: '        + error.code        + ', '; }
        if (!ISString.IsNullOrEmpty(error.description)) { details += 'description: ' + error.description + ', '; }
        if (!ISString.IsNullOrEmpty(error.reason))      { details += 'reason: '      + error.reason      + ', '; }

        //if (error.response && !ISString.IsNullOrEmpty(error.response.responseText)) { details = 'responseText: ' + error.response.responseText + ', '; }
        details = ISString.TrimEnd(details, ', ');

        var message = title;
        if (!ISString.IsNullOrEmpty(details))
        {
            message += ' (' + details + ')';
        }

        return message;
    }
};


