{
    this.Id   = id;
    this.User = userObject;
}
UCUser = Infoshare.UnifiedCommunications.User;
UCUser.EventName = { StatusChanged: 'StatusChanged' }
UCUser.prototype = {
    Id: null,
    User: null,
    Status: '',

    Events: null,


    GetStatus: function (callback)
    {
        var stopwatch = new ISStopwatch();
        stopwatch.Start();
        ISTrace.TraceVerbose('[BEGIN] UCUser.GetStatus');

        this.User.status.get().then(function (status)
        {
            ISTrace.TraceVerbose('[END] UCUser.GetStatus (spent: ' + stopwatch.Stop() + ')');
            callback(status);
        });
    },

    RegisterFunctionForStatusChanged: function(func)
    {
        if (this.Events == null)
        {
            this.Events = new iEvent();

            // subscribe直後、changeイベントが呼び出されるので注意（最初の状態取得はこれを利用するのがよいか）
            ISTrace.TraceVerbose('[UCWA.StatusChangeEvent Subscribe] UCUser.RegisterFunctionForStatusChanged (' + this.Id + ')');
            this.User.status.changed(ISFunction.CreateDelegate(this.OnStatusChanged, this));
            this.User.status.subscribe();
        }

        this.Events.AddEvent(UCUser.EventName.StatusChanged, func);
    },

    OnStatusChanged: function (status, user)
    {
        ISTrace.TraceVerbose('[UCWA.StatusChangeEvent Recive] UCUser.OnStatusChanged (' + this.Id + ': ' + status + ')');
        this.Status = status;
        if (this.Events)
        {
            this.Events.FireEventByName(UCUser.EventName.StatusChanged, status);
        }
    }
}


