//  PresenceStatus
// -----------------------------------------------------------------------
Infoshare.UnifiedCommunications.PresenceStatus = function Infoshare$UnifiedCommunications$PresenceStatus(status)
{
    this.Status   = status;
    this.Category = this.GetCategory(status);
    this.Caption  = this.GetCaption(status);
}
UCPresenceStatus = Infoshare.UnifiedCommunications.PresenceStatus;

// https://support.office.com/en-us/article/change-your-presence-status-in-skype-for-business-9b64eef5-47b8-46d8-a744-f490e6f88feb
// https://docs.microsoft.com/en-us/dotnet/api/microsoft.rtc.collaboration.presence.presenceavailability?view=ucma-api
UCPresenceStatus.StatusCategory = { Online:       'Online',
                                    Away:         'Away',
                                    Busy:         'Busy',
                                    DoNotDisturb: 'DoNotDisturb',
                                    OutOfOffice:  'OutOfOffice',
                                    Offline:      'Offline' };
UCPresenceStatus.Status = { Online:            'Online',
                            IdleOnline:        'Idle Online',
                            Available:         'Available',
                            Away:              'Away',
                            AppearAway:        'Appear Away',
                            BeRightBack:       'Be Right Back',
                            OffWork:           'Off Work',
                            Busy:              'Busy',
                            IdleBusy:          'Idle Busy',
                            InACall:           'In a call',
                            InAMeeting:        'In a meeting',
                            InAConferenceCall: 'In a conference call',
                            DoNotDisturb:      'Do Not Disturb',
                            Presenting:        'Presenting',
                            OutOfOffice:       'Out of Office',
                            OutOfTheOffice:    'Out of the office',
                            Offline:           'Offline',
                            None:              'None' };
UCPresenceStatus.StatusHash = null;
UCPresenceStatus.prototype = {
    Status: null,
    Category: null,
    Caption: null,

    GetCategory: function(status)
    {
        this.EnsureStatusHash();

        var category = UCPresenceStatus.StatusHash.Get(status);
        if (!category)
        {
            category = UCPresenceStatus.StatusCategory.Offline;
        }

        return category;
    },

    GetCaption: function(status)
    {
        var state = status;
        if (ISString.Contains(state, ' '))
        {
            state = ISString.Replace(state, ' ', '');
        }

        var caption = iResxResource.GetString('UnifiedCommunications.Status.Caption.' + state);
        if (ISString.IsNullOrEmpty(caption))
        {
            var category = this.GetCategory(state);
            caption = iResxResource.GetString('UnifiedCommunications.Status.Category.Caption.' + category);
        }

        return caption;
    },

    EnsureStatusHash: function()
    {
        if (UCPresenceStatus.StatusHash)
        {
            return;
        }

        var registerCategory = function (hash, status, category)
        {
            if (ISObject.TypeOf(status) != 'array')
            {
                status = [ status ];
            }

            for (var i = 0; i < status.length; i++)
            {
                var state = status[i];
                hash.Add(state, category);

                if (ISString.Contains(state, ' '))
                {
                    state = ISString.Replace(state, ' ', '');
                    hash.Add(state, category);
                }
            }
        };

        var hash = new ISDictionary();
        registerCategory(hash,
                         [ UCPresenceStatus.Status.Online, 
                           UCPresenceStatus.Status.Available ],
                         UCPresenceStatus.StatusCategory.Online);

        registerCategory(hash,
                         [ UCPresenceStatus.Status.Away,
                           UCPresenceStatus.Status.AppearAway,
                           UCPresenceStatus.Status.IdleOnline,
                           UCPresenceStatus.Status.BeRightBack,
                           UCPresenceStatus.Status.OffWork],
                         UCPresenceStatus.StatusCategory.Away);

        registerCategory(hash,
                         [ UCPresenceStatus.Status.Busy,
                           UCPresenceStatus.Status.IdleBusy,
                           UCPresenceStatus.Status.InACall,
                           UCPresenceStatus.Status.InAMeeting,
                           UCPresenceStatus.Status.InAConferenceCall ],
                         UCPresenceStatus.StatusCategory.Busy);

        registerCategory(hash,
                         [ UCPresenceStatus.Status.DoNotDisturb,
                           UCPresenceStatus.Status.Presenting ],
                         UCPresenceStatus.StatusCategory.DoNotDisturb);

        registerCategory(hash,
                         [ UCPresenceStatus.Status.OutOfOffice,
                           UCPresenceStatus.Status.OutOfTheOffice ],
                         UCPresenceStatus.StatusCategory.OutOfOffice);

        registerCategory(hash,
                         [ UCPresenceStatus.Status.Offline,
                           UCPresenceStatus.Status.None ],
                         UCPresenceStatus.StatusCategory.Offline);

        UCPresenceStatus.StatusHash = hash;
    }
}
			                   
