// -----------------------------------------------------------------------
Infoshare.UnifiedCommunications.UnifiedCommunicationLinker = function Infoshare$UnifiedCommunications$UnifiedCommunicationLinkerr()
{
    Infoshare.Web.UrlApplicationLinker.apply(this, arguments);

    this.BaseUrl = 'im:';
};
iUnifiedCommunicationLinker = Infoshare.UnifiedCommunications.UnifiedCommunicationLinker;
iUnifiedCommunicationLinker.TypeName = 'Infoshare.UnifiedCommunications.UnifiedCommunicationLinker';

iUnifiedCommunicationLinker.prototype = new Infoshare.Web.UrlApplicationLinker();
iUnifiedCommunicationLinker.prototype.TypeName = iUnifiedCommunicationLinker.TypeName;

iUnifiedCommunicationLinker.prototype.SipAddresses = null;
iUnifiedCommunicationLinker.prototype.buildQuery = function ()
{
    var sips = this.SipAddresses;
    if (iType.GetType(this.SipAddresses) == iType.BuiltinType.Array)
    {
        var builder = new Array();
        var format = '<sip:{0}>';
        for (var i = 0; i < this.SipAddresses.length; i++)
        {
            var sipAddress = this.SipAddresses[i];
            var sip = iString.Format(format, sipAddress);
            builder.push(sip);
        }

        sips = builder.join('');
    }

    return sips;
};
			                   
										                  
