// -----------------------------------------------------------------------
//  Service
// -----------------------------------------------------------------------
Infoshare.Graph.Service = function Infoshare$Graph$Service(clientId, tenantId, version)
{
    this.ClientId = clientId;
    this.TenantId = tenantId;
    if (!iString.IsNullOrEmpty(version))
    {
        this.Version = version;
    }
}
GraphService = Infoshare.Graph.Service;
GraphService.DefaultVersion = '2.17.0';

GraphService.prototype = {
    ClientId: null,
    TenantId: null,
    Version: GraphService.DefaultVersion,
    Loaded: false,
    SignedIn: false,
    MsalClient: null,
    AccessToken: null,
    targetExpression: null,
    Expression: { Guid:        '^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$',
                  MailAddress: '^.+@.+\\..+$' },
    Running: false,


    initialize: function (callback)
    {
        var ref = this;
        if (iQueryString.GetValue('FinderClass') == 'Infoshare.GroupPicker.TeamsFinder' && (iBrowser.IsWindows()))
        {
            (new iTeams()).GetContext(function (context)
            {
                if (context.HostClientType == iTeamsContext.HostClientType.Desktop)
                {
                    // Teamsアプリ
                    ref.teamsClientSignIn(function ()
                    {
                        // ToDo: 初期化時のエラーを返す
                        callback();
                        return;
                    });
                }
                else
                {
                    // TeamsWeb
                    ref.graphLoadScript(function ()
                    {
                        ref.graphInitialize(function ()
                        {
                            ref.graphSignIn(function ()
                            {
                                // ToDo: 初期化時のエラーを返す
                                callback();
                            });
                        });
                    });
                }
            });
        }
        else
        {
            // Web
            ref.graphLoadScript(function ()
            {
                ref.graphInitialize(function ()
                {
                    ref.graphSignIn(function ()
                    {
                        // ToDo: 初期化時のエラーを返す
                        callback();
                    });
                });
            });
        }
    },

    graphLoadScript: function (callback)
    {
        if (this.Loaded || typeof requirejs !== 'undefined')
        {
            return callback();
        }

        var stopwatch = new ISStopwatch();
        stopwatch.Start();
        ISTrace.TraceVerbose('[BEGIN] GraphService.graphLoadScript');

        var ref = this;
        // MSALライブラリスクリプト読み込み
        ISScript.Load(ISString.Format('https://alcdn.msauth.net/browser/{0}/js/msal-browser.min.js', this.Version), null, function ()
        {
            ref.Loaded = true;
            ISTrace.TraceVerbose('[END] GraphService.graphLoadScript (spent: ' + stopwatch.Stop() + ')');
            callback();
        });
    },

    graphInitialize: function (callback)
    {
        if (this.MsalClient)
        {
            return callback();
        }

        var stopwatch = new ISStopwatch();
        stopwatch.Start();
        ISTrace.TraceVerbose('[BEGIN] GraphService.graphInitialize');

        var ref = this;
        var msalConfig = {
            auth: {
                clientId: ref.ClientId,
                authority: 'https://login.microsoftonline.com/' + ref.TenantId,
                redirectUrl: location.href
            }
        };

        // RequireJSが読み込まれている場合、RequireJSを使って初期化する
        if (typeof requirejs !== 'undefined')
        {
            var msalInitialize = requirejs.config({
                paths : {
                    "Msal": ISString.Format('https://alcdn.msauth.net/browser/{0}/js/msal-browser', this.Version)
                }
            });

            msalInitialize([
                'Msal'
            ], function (
                Msal
            ) {
                // インスタンスの生成（MSALクライアントアプリケーション）
                ref.MsalClient = new Msal.PublicClientApplication(msalConfig);
                ISTrace.TraceVerbose('[END] GraphService.graphInitialize (spent: ' + stopwatch.Stop() + ')');
                callback();
            });        
        }
        else
        {
            // インスタンスの生成（MSALクライアントアプリケーション）
            this.MsalClient = new msal.PublicClientApplication(msalConfig);
            ISTrace.TraceVerbose('[END] GraphService.graphInitialize (spent: ' + stopwatch.Stop() + ')');
            callback();
        }
    },

    graphSignIn: function (callback)
    {
        if (this.SignedIn)
        {
            return callback();
        }

        var stopwatch = new ISStopwatch();
        stopwatch.Start();
        ISTrace.TraceVerbose('[BEGIN] GraphService.graphSignIn');

        var ref = this;
        var loginRequest = {
            scopes: [],
            loginHint: iVxContext.CurrentUser.Properties.UserPrincipalName
        };
        
        try
        {
            // シングルサインオン認証
            ref.MsalClient.ssoSilent(loginRequest).then(
                handleResponse,
                function (ssoSilentError)
                {
                    ISTrace.TraceWarning('[END] MsalClient.ssoSilent: failed:' + ssoSilentError.message);
                    // シングルサインオン認証に失敗した場合、ポップアップ認証
                    ref.MsalClient.loginPopup(loginRequest).then(
                        handleResponse,
                        function (loginPopupError)
                        {
                            ISTrace.TraceWarning('[END] MsalClient.loginPopup: failed:' + loginPopupError.message);
                            callback();
                        }
                    );
                }
            );
        }
        catch(e)
        {
            ISTrace.TraceWarning('[END] GraphService.graphSignIn: failed:' + e);
            callback();
        }

        // ssoSilent及びloginPopupのレスポンスに対する処理（サインインの状態確認およびサインイン）
        function handleResponse(response)
        {
            if (response !== null)
            {
                ref.MsalClient.username = response.account.username;
                ref.SignedIn = true;
                ISTrace.TraceVerbose('[END] GraphService.graphSignIn (spent: ' + stopwatch.Stop() + ')');
            }
            else
            {
                // MSALが現在データを保持しているすべてのアカウント情報を取得(アカウントオブジェクトは、ログインが成功したときに作成される)
                var currentAccounts = ref.MsalClient.getAllAccounts();
                if (currentAccounts.length === 1)
                {
                    ref.MsalClient.username = currentAccounts[0].username;
                    ref.SignedIn = true;
                    ISTrace.TraceVerbose('[END] GraphService.graphSignIn (spent: ' + stopwatch.Stop() + ')');
                }
            }
            callback();
        }
    },

    teamsClientSignIn: function (callback)
    {
        if (this.SignedIn)
        {
            return callback();
        }

        var stopwatch = new ISStopwatch();
        stopwatch.Start();
        ISTrace.TraceVerbose('[BEGIN] GraphService.teamsClientSignIn');

        localStorage.setItem("auth.page.clientid", GPContext.Configuration.GetSetting('GraphClientId'));
        localStorage.setItem("auth.page.redirecturi", iTeamsSettingPage.prototype.extractSiteUrl(window.location.href) + "/InfoshareProductLibrary/Sources/Infoshare.InfoCall/AuthPageCallback.aspx");
        var ref = this;
        microsoftTeams.authentication.authenticate({
            url: iTeamsSettingPage.prototype.extractSiteUrl(window.location.href) + "/InfoshareProductLibrary/Sources/Infoshare.InfoCall/AuthPageLoad.aspx",
            width: 500,
            height: 500,
            successCallback: function (result)
            {
                var data = localStorage.getItem(result);
                localStorage.removeItem(result);

                var tokenResult = JSON.parse(data);
                ref.AccessToken = tokenResult.accessToken;
                ref.Loaded = true;
                ref.SignedIn = true;
                ISTrace.TraceVerbose('[END] GraphService.teamsClientSignIn (spent: ' + stopwatch.Stop() + ')');
                callback();
            },
            failureCallback: function (err)
            {
                ISTrace.TraceWarning('[END] GraphService.teamsClientSignIn: failed:' + err);
                callback();
            }
        });
    },

    GetUsersById: function (ids, callback)
    {
        if (ids.length > 0)
        {
            var ref = this;
            if (this.Running)
            {
                ISTrace.TraceWarning('GraphService.GetUsersById: Previous process in progress.');
                this.Running = false;
                return callback(new Array(), new Array());
            }

            this.Running = true;
            this.targetExpression = this.Expression.Guid;
            this.getGraphUsers(ids, function (users, errors)
            {
                ref.Running = false;
                callback(users, errors);
            });
        }
        else
        {
            setTimeout(function ()
            {
                callback(new Array(), new Array());
            }, 1);
        }
    },

    GetUsersByUPN: function (keys, callback)
    {
        if (keys.length > 0)
        {
            var ref = this;
            if (this.Running)
            {
                ISTrace.TraceWarning('GraphService.GetUsersByUPN: Previous process in progress.');
                this.Running = false;
                return callback(new Array(), new Array());
            }

            this.Running = true;
            this.targetExpression = this.Expression.MailAddress;
            this.getGraphUsers(keys, function (users, errors)
            {
                ref.Running = false;
                callback(users, errors);
            });
        }
        else
        {
            setTimeout(function ()
            {
                callback(new Array(), new Array());
            }, 1);
        }
    },


    getGraphUsers: function (keys, callback)
    {
        this.getGraphResults(keys, function (results)
        {
            var users = [];
            var errors = [];
            for (var i = 0; i < results.length; i++)
            {
                var result = results[i];
                if (result.Error)
                {
                    errors.push(result);
                }
                else
                {
                    if (result.Object)
                    {
                        var user = new GraphUser(result.Object.userPrincipalName, result.Object, result.Status);
                        users.push(user);
                    }
                    else
                    {
                        errors.push(result);
                    }
                }
            }

            callback(users, errors);
        });
    },

    getGraphResults: function (keys, callback)
    {
        var service = this;
        this.initialize(function ()
        {
            if (!service.SignedIn)
            {
                // ToDo: 初期化時のエラーを返す
                callback(new Array());
                return;
            }

            service.getGraphResultsInternal(keys, function (results)
            {
                var resultHash = new ISDictionary();
                resultHash.AddRange(results);
                var presenceIds = [];
                for (var i = 0; i < results.length; i++)
                {
                    if (results[i].Object)
                    {
                        presenceIds.push(results[i].Object.id);
                    }
                }
                if (presenceIds.length > 0)
                {
                    service.graphQueryPresences(presenceIds, function (presences)
                    {
                        for (var i = 0; i < presences.length; i++)
                        {
                            var result = resultHash.Get(presences[i].id);
                            result.Status = presences[i].activity;
                        }
                        callback(resultHash.GetValues());
                    });
                }
                else
                {
                    callback(resultHash.GetValues());
                }
            });
        });
    },

    getGraphResultsInternal: function (keys, callback)
    {
        if (this.targetExpression == this.Expression.Guid)
        {
            this.getGraphResultsById(keys, callback);
        }
        else if (this.targetExpression == this.Expression.MailAddress)
        {
            this.getGraphResultsByUPN(keys, callback);
        }
    },

    getGraphResultsById: function (ids, callback)
    {
        var ref = this;
        var results = [];
        var validKeys = ref.getValidKeys(ids);
        
        // 全件フォーマットエラーの場合
        if (validKeys.length == 0)
        {
            for (var i = 0; i < ids.length; i++)
            {
                var result = new GraphQueryResult(ids[i]);
                result.Error = { message: 'Invalid key format.' };
                results.push(result);
            }
            return callback(results);
        }

        ref.graphQueryUsersById(validKeys, function (users, error)
        {
            var userHash = new ISDictionary();
            if (users && users.length > 0)
            {
                userHash.AddRange(users);
            }
            for (var i = 0; i < ids.length; i++)
            {
                var id = ids[i];
                var result = new GraphQueryResult(id);
                if (error)
                {
                    result.Error = error;
                }
                else
                {
                    result.Object = userHash.Get(id);
                    if (!result.Object)
                    {
                        if (!ISArray.Contains(validKeys, id))
                        {
                            result.Error = { message: 'Invalid key format.' };
                        }
                        else
                        {
                            result.Error = { message: 'Unknown error.' };
                        }
                    }
                }
                results.push(result);
            }
            callback(results);
        });
    },

    graphQueryUsersById: function (ids, callback)
    {
        // 一度に取得出来る件数は最大1000件、アプリあたりの制限はユーザー数で変わるが最低で10秒間に3500リクエスト
        // https://learn.microsoft.com/ja-jp/graph/api/directoryobject-getbyids?view=graph-rest-1.0&tabs=http
        // https://learn.microsoft.com/ja-jp/graph/throttling-limits
        var ref = this;
        var tokenUserRequest = { scopes: [] };
        var graphUserEndpoint = 'https://graph.microsoft.com/v1.0/users/microsoft.graph.getByIds';
        var headers = [new ISWebRequestHeader('Content-Type', 'application/json; odata=verbose')];
        var obj = {};
        obj.ids = ids;
        body = ISJSON.stringify(obj);

        if (this.AccessToken)
        {
            var bearer = iString.Format('Bearer {0}', this.AccessToken);
            headers.push(new ISWebRequestHeader('Authorization', bearer));
            this.graphQueryUsersByIdInternal(graphUserEndpoint, headers, body, callback);
        }
        else
        {
            // トークン取得
            this.getAccessToken(tokenUserRequest, function (response)
            {
                if (response.accessToken)
                {
                    var bearer = iString.Format('Bearer {0}', response.accessToken);
                    headers.push(new ISWebRequestHeader('Authorization', bearer));
                    ref.graphQueryUsersByIdInternal(graphUserEndpoint, headers, body, callback);
                }
                else
                {
                    callback(new Array(), response);
                }
            });
        }
    },

    graphQueryUsersByIdInternal: function (endpoint, headers, body, callback)
    {
        var stopwatch = new ISStopwatch();
        stopwatch.Start();
        ISTrace.TraceVerbose('[BEGIN] GraphService.graphQueryUsersByIdInternal');

        // Microsoft Graph API 呼び出し
        this.callMSGraph(endpoint, headers, body, function (result)
        {
            if (result.error)
            {
                ISTrace.TraceWarning('[END] GraphService.graphQueryUsersByIdInternal: failed:' + result.error.message);
                callback(new Array(), result.error);
            }
            else
            {
                ISTrace.TraceVerbose('[END] GraphService.graphQueryUsersByIdInternal (spent: ' + stopwatch.Stop() + ')');
                callback(result.value, null);
            }
        });
    },

    getGraphResultsByUPN: function (keys, callback)
    {
        var stopwatch = new ISStopwatch();
        stopwatch.Start();
        ISTrace.TraceVerbose('[BEGIN] GraphService.getGraphResultsByUPN');

        var ref = this;
        var results = [];
        var validKeys = ref.getValidKeys(keys);

        var context = {
            Keys: validKeys,
            Results: [],

            Complete: function ()
            {
                return this.Keys.length == this.Results.length;
            }
        };
        
        // 全件フォーマットエラーの場合
        if (validKeys.length == 0)
        {
            for (var i = 0; i < keys.length; i++)
            {
                var result = new GraphQueryResult(keys[i]);
                result.Error = { message: 'Invalid key format.' };
                results.push(result);
            }
            return callback(results);
        }

        for (var i = 0; i < validKeys.length; i++)
        {
            var key = validKeys[i];
            ref.graphQueryUserByUPN(key, function (key, user, error)
            {
                var result = new GraphQueryResult(key);
                if (error)
                {
                    result.Error = error;
                }
                else
                {
                    result.Object = user;
                }
                context.Results.push(result);
                if (context.Complete())
                {
                    var resultHash = new ISDictionary();
                    resultHash.AddRange(context.Results);
                    for (var j = 0; j < keys.length; j++)
                    {
                        if (ISArray.Contains(validKeys, keys[j]))
                        {
                            if (resultHash.Get(keys[j]).Object)
                            {
                                resultHash.Get(keys[j]).Key = resultHash.Get(keys[j]).Object.id;
                            }
                            results.push(resultHash.Get(keys[j]));
                        }
                        else
                        {
                            var result = new GraphQueryResult(keys[j]);
                            result.Error = { message: 'Invalid key format.' };
                            results.push(result);
                        }
                    }
                    ISTrace.TraceVerbose('[END] GraphService.getGraphResultsByUPN (spent: ' + stopwatch.Stop() + ')');
                    callback(results);
                }
            });
        }
    },

    graphQueryUserByUPN: function (key, callback)
    {
        var ref = this;
        var tokenUserRequest = { scopes: [] };
        var graphUserEndpoint = iString.Format('https://graph.microsoft.com/v1.0/users/{0}', encodeURIComponent(key));
        var headers = [];

        if (this.AccessToken)
        {
            var bearer = iString.Format('Bearer {0}', this.AccessToken);
            headers.push(new ISWebRequestHeader('Authorization', bearer));
            this.graphQueryUserByUPNInternal(key, graphUserEndpoint, headers, callback);
        }
        else
        {
            // トークン取得
            this.getAccessToken(tokenUserRequest, function (response)
            {
                if (response.accessToken)
                {
                    var bearer = iString.Format('Bearer {0}', response.accessToken);
                    headers.push(new ISWebRequestHeader('Authorization', bearer));
                    ref.graphQueryUserByUPNInternal(key, graphUserEndpoint, headers, callback);
                }
                else
                {
                    callback(key, null, response);
                }
            });
        }
    },

    graphQueryUserByUPNInternal: function (key, endpoint, headers, callback)
    {
        var stopwatch = new ISStopwatch();
        stopwatch.Start();
        ISTrace.TraceVerbose('[BEGIN] GraphService.graphQueryUserByUPNInternal (' + key + ')');

        // Microsoft Graph API 呼び出し
        this.callMSGraph(endpoint, headers, null, function (result)
        {
            if (result.error)
            {
                ISTrace.TraceWarning('[END] GraphService.graphQueryUserByUPNInternal: failed:' + result.error.message);
                callback(key, null, result.error);
            }
            else
            {
                ISTrace.TraceVerbose('[END] GraphService.graphQueryUserByUPNInternal (key: ' + key + ', spent: ' + stopwatch.Stop() + ')');
                callback(key, result, null);
            }
        });
    },

    getValidKeys: function (keys)
    {
        var validKeys = [];

        // フォーマット確認
        var flags      = 'i';
        var regExpression = new RegExp(this.targetExpression, flags);
        for (var i = 0; i < keys.length; i++)
        {
            var key = keys[i];
            if (regExpression.test(key))
            {
                validKeys.push(key);
            }
        }
        return validKeys;
    },

    graphQueryPresences: function (ids, callback)
    {
        // 一度に取得出来る件数は最大650件、アプリあたりの制限は30秒間に1500リクエスト
        // https://learn.microsoft.com/ja-jp/graph/api/cloudcommunications-getpresencesbyuserid?view=graph-rest-1.0&tabs=http
        var ref = this;
        var tokenPresenceRequest = { scopes: [] };
        var graphPresenceEndpoint = 'https://graph.microsoft.com/v1.0/communications/microsoft.graph.getPresencesByUserId';
        var headers = [new ISWebRequestHeader('Content-Type', 'application/json; odata=verbose')];
        var obj = {};
        obj.ids = ids;
        body = ISJSON.stringify(obj);

        if (this.AccessToken)
        {
            var bearer = iString.Format('Bearer {0}', this.AccessToken);
            headers.push(new ISWebRequestHeader('Authorization', bearer));
            this.graphQueryPresencesInternal(graphPresenceEndpoint, headers, body, callback);
        }
        else
        {
            // トークン取得
            this.getAccessToken(tokenPresenceRequest, function (response)
            {
                if (response.accessToken)
                {
                    var bearer = iString.Format('Bearer {0}', response.accessToken);
                    headers.push(new ISWebRequestHeader('Authorization', bearer));
                    ref.graphQueryPresencesInternal(graphPresenceEndpoint, headers, body, callback);
                }
                else
                {
                    callback(new Array());
                }
            });
        }
    },

    graphQueryPresencesInternal: function (endpoint, headers, body, callback)
    {
        var stopwatch = new ISStopwatch();
        stopwatch.Start();
        ISTrace.TraceVerbose('[BEGIN] GraphService.graphQueryPresencesInternal');

        // Microsoft Graph API 呼び出し
        this.callMSGraph(endpoint, headers, body, function (result)
        {
            if (result.error)
            {
                ISTrace.TraceWarning('[END] GraphService.graphQueryPresencesInternal: failed:' + result.error.message);
                callback(new Array());
            }
            else
            {
                ISTrace.TraceVerbose('[END] GraphService.graphQueryPresencesInternal (spent: ' + stopwatch.Stop() + ')');
                callback(result.value);
            }
        });
    },

    GetGraphProfileImages: function (ids, callback)
    {
        var service = this;
        this.initialize(function ()
        {
            if (!service.SignedIn)
            {
                // ToDo: 初期化時のエラーを返す
                callback(new Array());
                return;
            }

            service.getGraphProfileImagesInternal(ids, callback);
        });
    },

    getGraphProfileImagesInternal: function (ids, callback)
    {
        var stopwatch = new ISStopwatch();
        stopwatch.Start();
        ISTrace.TraceVerbose('[BEGIN] GraphService.getGraphProfileImagesInternal');

        var ref = this;
        var results = new ISDictionary();

        var idCount = ids.length;
        var context = {
            Results: [],
            Complete: function ()
            {
                return this.Results.length == idCount;
            }
        };
        
        // Graph JSONバッチリクエストは最大20件のため、20件毎の配列を作成する
        var idPieces = this.divideArrayIntoPieces(ids, 20);
        for (var i = 0; i < idPieces.length; i++)
        {
            var idPiece = idPieces[i];
            ref.graphQueryProfileImages(idPiece, function (responses)
            {
                for  (var i = 0; i < responses.length; i++)
                {
                    var response = responses[i];
                    var result = new GraphQueryResult(response.id);
                    result.Object = response.body;
                    context.Results.push(result);
                }
                if (context.Complete())
                {
                    ISTrace.TraceVerbose('[END] GraphService.getGraphProfileImagesInternal (spent: ' + stopwatch.Stop() + ')');
                    callback(context.Results);
                }
            });
        }
    },

    divideArrayIntoPieces: function (array, count)
    {
        var arrayList = [];
        var idx = 0;
        while (idx < array.length)
        {
            arrayList.push(array.splice(idx, idx + count));
        }
        return arrayList;
    },

    graphQueryProfileImages: function (ids, callback)
    {
        // 一度に取得出来る件数は最大20件、アプリあたりの制限はユーザー数で変わるが最低で10秒間に3500リクエスト
        // https://learn.microsoft.com/ja-jp/graph/json-batching
        var ref = this;
        var tokenUserRequest = { scopes: [] };
        var graphUserEndpoint = 'https://graph.microsoft.com/v1.0/$batch';
        var headers = [new ISWebRequestHeader('Content-Type', 'application/json; odata=verbose'), new ISWebRequestHeader('Accept', 'application/json')];

        var obj = {};
        var requests = [];
        for (var i = 0; i < ids.length; i++)
        {
            var request = {};
            request.url = "/users/" + ids[i] + "/photo/$value";
            request.method = "GET";
            request.id = ids[i];
            requests.push(request);
        }
        obj.requests = requests;
        var body = ISJSON.stringify(obj);

        if (this.AccessToken)
        {
            var bearer = iString.Format('Bearer {0}', this.AccessToken);
            headers.push(new ISWebRequestHeader('Authorization', bearer));
            this.graphQueryProfileImagesInternal(graphUserEndpoint, headers, body, callback);
        }
        else
        {
            // トークン取得
            this.getAccessToken(tokenUserRequest, function (response)
            {
                if (response.accessToken)
                {
                    var bearer = iString.Format('Bearer {0}', response.accessToken);
                    headers.push(new ISWebRequestHeader('Authorization', bearer));
                    ref.graphQueryProfileImagesInternal(graphUserEndpoint, headers, body, callback);
                }
                else
                {
                    callback(new Array());
                }
            });
        }
    },

    graphQueryProfileImagesInternal: function (endpoint, headers, body, callback)
    {
        var stopwatch = new ISStopwatch();
        stopwatch.Start();
        ISTrace.TraceVerbose('[BEGIN] GraphService.graphQueryProfileImagesInternal');

        // Microsoft Graph API 呼び出し
        this.callMSGraph(endpoint, headers, body, function (result)
        {
            if (result.error)
            {
                ISTrace.TraceWarning('[END] GraphService.graphQueryProfileImagesInternal: failed:' + result.error.message);
                callback(new Array());
            }
            else
            {
                ISTrace.TraceVerbose('[END] GraphService.graphQueryProfileImagesInternal (spent: ' + stopwatch.Stop() + ')');
                callback(result.responses);
            }
        });
    },

    getAccessToken: function (request, callback)
    {
        var ref = this;
        request.account = this.MsalClient.getAccountByUsername(this.MsalClient.username);
        // トークン取得に使用しているacquireTokenSilentはキャッシュにトークンがあるかないか確認し、ない場合に取得することで、アクセストークンの有効期間切れをフォローする
        // https://docs.microsoft.com/ja-jp/azure/active-directory/develop/msal-net-acquire-token-silently
        this.MsalClient.acquireTokenSilent(request).then(
            function (response)
            {
                callback(response);
            },
            function (acquireTokenSilentError)
            {

                ISTrace.TraceWarning('[END] GraphService.getAccessToken acquireTokenSilent: failed:' + acquireTokenSilentError.message);
                ref.SignedIn = false;
                callback(acquireTokenSilentError);
            }
        );
    },

    callMSGraph: function (endpoint, headers, body, callback)
    {
        var request = new ISWebRequest();
        request.Headers = headers;
        request.Body = body;
        request.Asynchronous = true;
        request.Method = Infoshare.Web.HttpMethod.Get;
        if (body)
        {
            request.Method = Infoshare.Web.HttpMethod.Post;
        }
        request.Url = endpoint;
        request.ResponseType = ISWebRequest.RequestResponseType.JSON;
        request.CallbackHandler = function ()
        {
            var responseObject = request.GetResponse();
            if (responseObject == null)
            {
                responseObject = { error: { message: 'Bad Request' } };
            }
            callback(responseObject);
        };

        request.Invoke();
    }
}

// -----------------------------------------------------------------------
//  QueryResult
// -----------------------------------------------------------------------
Infoshare.Graph.QueryResult = function Infoshare$Graph$QueryResult(key)
{
    this.Key    = key;
}
GraphQueryResult = Infoshare.Graph.QueryResult;
GraphQueryResult.prototype = {
    Key: null,
    Object: null,
    Error: null,
    Status: null
}


// -----------------------------------------------------------------------
//  User
// -----------------------------------------------------------------------
Infoshare.Graph.User = function Infoshare$Graph$User(id, userObject, status)
{
    this.Id   = id;
    this.User = userObject;
    this.Status = status;
}
GraphUser = Infoshare.Graph.User;
GraphUser.prototype = {
    Id: null,
    User: null,
    Status: ''
}
			                   
						                  
